// ═══════════════════════════════════════════════════════════════════
// Audit-pass additions: extra theory, extra exercises, W6 rewrite, exams
// ═══════════════════════════════════════════════════════════════════
const MAC_EXTRA = {"w1":{"theoryExtra":{"nl":"<h3>Terugblik FM (P1): drie overzichten, drie begrippenparen</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Balans</strong><br>Momentopname: overzicht van bezittingen en schulden op één datum.</div>\n <div class=\"rule-card\"><strong>Resultatenrekening</strong><br>Over een periode: opbrengsten − kosten = winst → toename eigen vermogen.</div>\n <div class=\"rule-card\"><strong>Liquiditeitsbegroting</strong><br>Over een periode: ontvangsten − uitgaven = verandering liquide middelen (bank/kas).</div>\n</div>\n<div class=\"note-box\"><strong>Examenvalkuil:</strong> Een <em>ontvangst</em> is pas een <em>opbrengst</em> wanneer de prestatie (levering) is verricht — niet wanneer het geld binnenkomt. Een <em>uitgave</em> is pas een <em>kost</em> in de periode waarin het productiemiddel wordt verbruikt. Een machine van €70.000 kopen = één uitgave nu, maar kosten (afschrijvingen) gespreid over de levensduur.</div>\n\n<h3>Kostensoorten</h3>\n<p>Kosten worden ingedeeld naar <strong>kostensoorten</strong>:</p>\n<ul>\n<li>Kosten van <strong>hulp- en grondstoffen</strong></li>\n<li>Kosten van <strong>arbeid</strong></li>\n<li>Kosten van <strong>duurzame productiemiddelen</strong> (afschrijvingen!)</li>\n<li>Kosten van <strong>grond</strong></li>\n<li>Kosten van <strong>dienstverlening</strong> (door derden)</li>\n<li>Kosten van <strong>belastingen</strong></li>\n<li>Kosten van <strong>financiering</strong> (interest)</li>\n</ul>\n\n<h3>Waarom daalt een duurzaam productiemiddel in waarde?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Technische slijtage</strong><br>De waarde daalt door <em>gebruik</em> (of zelfs door stilstand). Als het dpm de prestaties niet meer kan leveren waarvoor het is aangeschaft, is de <strong>technische levensduur</strong> verstreken.</div>\n <div class=\"rule-card\"><strong>Economische slijtage</strong><br>De waarde daalt doordat er een <em>goedkoper producerend</em> dpm op de markt verschijnt. De machine werkt nog, maar is economisch verouderd → <strong>economische levensduur</strong>.</div>\n</div>\n<div class=\"tip-box\"><strong>Onthoud:</strong> In afschrijvingsberekeningen gebruik je de <em>economische</em> levensduur (n), die meestal korter is dan de technische.</div>\n\n<h3>Praktijkcase: Basic-Fit en EBITDA</h3>\n<div class=\"example-box\"><strong>Basic-Fit (Financieel Dagblad):</strong> omzet +29% naar €124 mln, ebitda +22% naar €30,2 mln — maar operationeel resultaat €1,3 mln <em>negatief</em> en nettoverlies €26,1 mln. Hoe kan dat? <strong>EBITDA</strong> = resultaat vóór interest, belastingen én <em>afschrijvingen</em>. Basic-Fit schreef fors af, en die afschrijvingen blijven buiten de ebitda. Critici wezen er bovendien op dat leveranciers (Matrix, Technogym) een 'marketingbijdrage' terugbetaalden: lagere marketingkosten zitten <em>wél</em> in de ebitda, hogere afschrijvingen (door de hogere aanschafprijs) <em>niet</em> — zo wordt de ebitda kunstmatig opgepompt.</div>\n<div class=\"note-box\"><strong>Les:</strong> afschrijvingskeuzes (methode en levensduur) beïnvloeden het resultaat direct. Afschrijvingen 'in lijn brengen met de levensduur van de apparatuur' = lagere jaarlijkse afschrijvingskosten.</div>\n\n<h3>Handige extra's bij de methodes</h3>\n<div class=\"formula\">Som rangnummers (cijfersom): S = (n + 1)/2 × n</div>\n→ Alternatieve schrijfwijze van n(n+1)/2, zoals in de slides: (4+1)/2 × 4 = 10.\n<p>Bij <strong>dalend vast bedrag</strong> kan het examen ook vragen om <strong>Δ te berekenen</strong> in plaats van d₁. Zelfde aanpak: stel d₁ = X, schrijf alle jaren uit, stel de som gelijk aan A − R en los op.</p>","en":"<h3>FM (P1) recap: three statements, three concept pairs</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Balance sheet</strong><br>Snapshot: assets and liabilities at one date.</div>\n <div class=\"rule-card\"><strong>Income statement</strong><br>Over a period: revenues − costs = profit → increase in equity.</div>\n <div class=\"rule-card\"><strong>Cash budget</strong><br>Over a period: receipts − expenditures = change in cash (bank/till).</div>\n</div>\n<div class=\"note-box\"><strong>Exam trap:</strong> A <em>receipt</em> only becomes a <em>revenue</em> when the performance (delivery) has taken place — not when the cash arrives. An <em>expenditure</em> only becomes a <em>cost</em> in the period the resource is consumed. Buying a €70,000 machine = one expenditure now, but costs (depreciation) spread over its life.</div>\n\n<h3>Cost categories (kostensoorten)</h3>\n<ul>\n<li>Costs of <strong>raw and auxiliary materials</strong></li>\n<li>Costs of <strong>labour</strong></li>\n<li>Costs of <strong>durable production assets</strong> (depreciation!)</li>\n<li>Costs of <strong>land</strong></li>\n<li>Costs of <strong>services</strong> (by third parties)</li>\n<li>Costs of <strong>taxes</strong></li>\n<li>Costs of <strong>financing</strong> (interest)</li>\n</ul>\n\n<h3>Why does a durable asset lose value?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Technical wear</strong><br>Value falls through <em>use</em> (or even idleness). When the asset can no longer deliver the performance it was bought for, its <strong>technical life</strong> has ended.</div>\n <div class=\"rule-card\"><strong>Economic obsolescence</strong><br>Value falls because a <em>cheaper-producing</em> asset appears on the market. The machine still works but is economically outdated → <strong>economic life</strong>.</div>\n</div>\n<div class=\"tip-box\"><strong>Remember:</strong> in depreciation calculations you use the <em>economic</em> life (n), usually shorter than the technical life.</div>\n\n<h3>Real-world case: Basic-Fit and EBITDA</h3>\n<div class=\"example-box\"><strong>Basic-Fit (Financieele Dagblad):</strong> revenue +29% to €124m, EBITDA +22% to €30.2m — yet operating result was €1.3m <em>negative</em> and net loss €26.1m. How? <strong>EBITDA</strong> = earnings before interest, taxes and <em>depreciation/amortisation</em>. Basic-Fit's heavy depreciation stays outside EBITDA. Critics also noted that equipment suppliers (Matrix, Technogym) paid back a 'marketing contribution': lower marketing costs <em>are</em> in EBITDA, while the higher depreciation (from the higher purchase price) is <em>not</em> — artificially inflating EBITDA.</div>\n<div class=\"note-box\"><strong>Lesson:</strong> depreciation choices (method and useful life) directly affect reported profit. Aligning depreciation 'with the equipment's life' = lower annual depreciation cost.</div>\n\n<h3>Useful extras for the methods</h3>\n<div class=\"formula\">Sum of digits: S = (n + 1)/2 × n</div>\n→ Alternative form of n(n+1)/2, as on the slides: (4+1)/2 × 4 = 10.\n<p>With the <strong>decreasing fixed amount</strong> method, the exam may also ask you to <strong>calculate Δ</strong> instead of d₁. Same approach: set d₁ = X, list all years, set the sum equal to A − R and solve.</p>","fr":"<h3>Rappel FM (P1): trois états, trois paires de notions</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Bilan</strong><br>Photo instantanée: avoirs et dettes à une date donnée.</div>\n <div class=\"rule-card\"><strong>Compte de résultats</strong><br>Sur une période: produits − charges = bénéfice → augmentation des capitaux propres.</div>\n <div class=\"rule-card\"><strong>Budget de trésorerie</strong><br>Sur une période: encaissements − décaissements = variation des liquidités (banque/caisse).</div>\n</div>\n<div class=\"note-box\"><strong>Piège d'examen:</strong> Un <em>encaissement</em> ne devient un <em>produit</em> que lorsque la prestation (livraison) a eu lieu — pas quand l'argent arrive. Un <em>décaissement</em> ne devient une <em>charge</em> que dans la période où le moyen de production est consommé. Acheter une machine de €70.000 = un décaissement maintenant, mais des charges (amortissements) réparties sur la durée de vie.</div>\n\n<h3>Catégories de coûts (kostensoorten)</h3>\n<ul>\n<li>Coûts des <strong>matières premières et auxiliaires</strong></li>\n<li>Coûts du <strong>travail</strong></li>\n<li>Coûts des <strong>moyens de production durables</strong> (amortissements !)</li>\n<li>Coûts du <strong>terrain</strong></li>\n<li>Coûts des <strong>services</strong> (de tiers)</li>\n<li>Coûts des <strong>impôts</strong></li>\n<li>Coûts du <strong>financement</strong> (intérêts)</li>\n</ul>\n\n<h3>Pourquoi un actif durable perd-il de la valeur ?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Usure technique</strong><br>La valeur baisse par <em>l'utilisation</em> (ou même l'inactivité). Quand l'actif ne peut plus fournir les prestations pour lesquelles il a été acheté, sa <strong>durée de vie technique</strong> est écoulée.</div>\n <div class=\"rule-card\"><strong>Obsolescence économique</strong><br>La valeur baisse parce qu'un actif <em>produisant moins cher</em> apparaît sur le marché. La machine fonctionne encore mais est dépassée → <strong>durée de vie économique</strong>.</div>\n</div>\n<div class=\"tip-box\"><strong>À retenir:</strong> dans les calculs d'amortissement, on utilise la durée de vie <em>économique</em> (n), généralement plus courte que la technique.</div>\n\n<h3>Cas pratique: Basic-Fit et l'EBITDA</h3>\n<div class=\"example-box\"><strong>Basic-Fit (Financieele Dagblad):</strong> chiffre d'affaires +29% à €124 mln, ebitda +22% à €30,2 mln — mais résultat opérationnel <em>négatif</em> de €1,3 mln et perte nette de €26,1 mln. Comment ? <strong>EBITDA</strong> = résultat avant intérêts, impôts et <em>amortissements</em>. Les lourds amortissements de Basic-Fit restent hors ebitda. Les critiques notaient aussi que les fournisseurs (Matrix, Technogym) reversaient une « contribution marketing »: les coûts marketing plus bas <em>sont</em> dans l'ebitda, mais les amortissements plus élevés (prix d'achat plus élevé) n'y sont <em>pas</em> — gonflant artificiellement l'ebitda.</div>\n<div class=\"note-box\"><strong>Leçon:</strong> les choix d'amortissement (méthode et durée de vie) influencent directement le résultat. Aligner les amortissements « sur la durée de vie des appareils » = charges d'amortissement annuelles plus faibles.</div>\n\n<h3>Compléments utiles sur les méthodes</h3>\n<div class=\"formula\">Somme des rangs: S = (n + 1)/2 × n</div>\n→ Forme alternative de n(n+1)/2, comme dans les slides: (4+1)/2 × 4 = 10.\n<p>Avec la méthode du <strong>montant dégressif fixe</strong>, l'examen peut aussi demander de <strong>calculer Δ</strong> au lieu de d₁. Même démarche: posez d₁ = X, écrivez toutes les années, égalez la somme à A − R et résolvez.</p>"},"exercises":[{"id":"ex1_9","type":"numeric","style":"technical","diff":"medium","title_nl":"Vast % boekwaarde — technisch","title_en":"Declining balance rate — technical","title_fr":"Taux dégressif — technique","text_nl":"Gegeven: A = €50.000, R = €15.000, n = 4. Bereken het afschrijvingspercentage p (vast % van de boekwaarde), afgerond op een geheel %.","text_en":"Given: A = €50,000, R = €15,000, n = 4. Calculate the depreciation rate p (fixed % of book value), rounded to a whole %.","text_fr":"Donné: A = €50.000, R = €15.000, n = 4. Calculez le taux d'amortissement p (% fixe de la valeur comptable), arrondi à l'unité.","inputs":[{"label_nl":"Afschrijvingspercentage p (%)","label_en":"Depreciation rate p (%)","label_fr":"Taux d'amortissement p (%)","answer":26}],"hint1_nl":"Na n jaar moet de boekwaarde precies gelijk zijn aan R. Elk jaar vermenigvuldig je de boekwaarde met (1−p). Welke factor (R/A) moet je dus over 4 jaar 'verdelen' via een vierdemachtswortel?","hint1_en":"After n years the book value must equal exactly R. Each year you multiply the book value by (1−p). So which ratio (R/A) must you spread over 4 years via a fourth root?","hint1_fr":"Après n ans, la valeur comptable doit être exactement R. Chaque année, on multiplie la valeur comptable par (1−p). Quel rapport (R/A) faut-il donc répartir sur 4 ans via une racine quatrième ?","hint2_nl":"p = [1 − (R/A)^(1/n)] × 100% = [1 − (15.000/50.000)^(1/4)] × 100% = [1 − 0,3^0,25] × 100% = ?","hint2_en":"p = [1 − (R/A)^(1/n)] × 100% = [1 − (15,000/50,000)^(1/4)] × 100% = [1 − 0.3^0.25] × 100% = ?","hint2_fr":"p = [1 − (R/A)^(1/n)] × 100% = [1 − (15.000/50.000)^(1/4)] × 100% = [1 − 0,3^0,25] × 100% = ?","sol_nl":"p = 1 − (15.000/50.000)^(1/4) = 1 − 0,3^0,25 = 1 − 0,7401 = 0,2599 → <strong>p ≈ 26%</strong>. Controle: 50.000 × 0,74⁴ ≈ 15.000. Dit is exact opgave 10 (Jelle Elsinga Schilders) uit de slides.","sol_en":"p = 1 − (15,000/50,000)^(1/4) = 1 − 0.3^0.25 = 1 − 0.7401 = 0.2599 → <strong>p ≈ 26%</strong>. Check: 50,000 × 0.74⁴ ≈ 15,000. This is exactly slide exercise 10 (Jelle Elsinga Schilders).","sol_fr":"p = 1 − (15.000/50.000)^(1/4) = 1 − 0,3^0,25 = 1 − 0,7401 = 0,2599 → <strong>p ≈ 26%</strong>. Vérification: 50.000 × 0,74⁴ ≈ 15.000. C'est exactement l'exercice 10 des slides."},{"id":"ex1_10","type":"numeric","style":"technical","diff":"hard","title_nl":"Bereken Δ — dalend vast bedrag (technisch)","title_en":"Calculate Δ — decreasing fixed amount (technical)","title_fr":"Calculer Δ — montant dégressif fixe (technique)","text_nl":"Gegeven: A = €50.000, R = €15.000, n = 4, en d₁ = €12.500. De afschrijvingen dalen elk jaar met een vast bedrag Δ. Bereken Δ.","text_en":"Given: A = €50,000, R = €15,000, n = 4, and d₁ = €12,500. Depreciation falls by a fixed amount Δ each year. Calculate Δ.","text_fr":"Donné: A = €50.000, R = €15.000, n = 4, et d₁ = €12.500. Les amortissements diminuent chaque année d'un montant fixe Δ. Calculez Δ.","inputs":[{"label_nl":"Jaarlijkse daling Δ (€)","label_en":"Annual decrease Δ (€)","label_fr":"Diminution annuelle Δ (€)","answer":2500}],"hint1_nl":"De vier afschrijvingen zijn d₁, d₁−Δ, d₁−2Δ en d₁−3Δ. Samen moeten ze het totale af te schrijven bedrag (A − R) dekken. Schrijf de som uit en los Δ op.","hint1_en":"The four depreciations are d₁, d₁−Δ, d₁−2Δ and d₁−3Δ. Together they must cover the total depreciable amount (A − R). Write out the sum and solve for Δ.","hint1_fr":"Les quatre amortissements sont d₁, d₁−Δ, d₁−2Δ et d₁−3Δ. Ensemble, ils doivent couvrir le montant total à amortir (A − R). Écrivez la somme et résolvez Δ.","hint2_nl":"4 × 12.500 − Δ × (1+2+3) = 50.000 − 15.000 → 50.000 − 6Δ = 35.000 → Δ = ?","hint2_en":"4 × 12,500 − Δ × (1+2+3) = 50,000 − 15,000 → 50,000 − 6Δ = 35,000 → Δ = ?","hint2_fr":"4 × 12.500 − Δ × (1+2+3) = 50.000 − 15.000 → 50.000 − 6Δ = 35.000 → Δ = ?","sol_nl":"Som = 12.500 + (12.500−Δ) + (12.500−2Δ) + (12.500−3Δ) = 50.000 − 6Δ. Dit moet gelijk zijn aan A − R = 35.000. Dus 6Δ = 15.000 → <strong>Δ = €2.500</strong>. Controle: 12.500 + 10.000 + 7.500 + 5.000 = €35.000 ✓ (zoals opgave 10-2 in de slides).","sol_en":"Sum = 12,500 + (12,500−Δ) + (12,500−2Δ) + (12,500−3Δ) = 50,000 − 6Δ. This must equal A − R = 35,000. So 6Δ = 15,000 → <strong>Δ = €2,500</strong>. Check: 12,500 + 10,000 + 7,500 + 5,000 = €35,000 ✓ (as in slide exercise 10-2).","sol_fr":"Somme = 12.500 + (12.500−Δ) + (12.500−2Δ) + (12.500−3Δ) = 50.000 − 6Δ. Cela doit égaler A − R = 35.000. Donc 6Δ = 15.000 → <strong>Δ = €2.500</strong>. Vérification: 12.500 + 10.000 + 7.500 + 5.000 = €35.000 ✓ (comme l'exercice 10-2 des slides)."},{"id":"ex1_11","type":"mcq","style":"scenario","diff":"easy","title_nl":"Technische of economische slijtage? — Wasserij Lien","title_en":"Technical or economic wear? — Laundry Lien","title_fr":"Usure technique ou économique ? — Blanchisserie Lien","text_nl":"Wasserij Lien gebruikt een industriële wasmachine die nog perfect werkt. Een concurrent installeert echter een nieuw model dat per wasbeurt 40% minder energie verbruikt, waardoor Liens machine plots veel duurder produceert dan de marktstandaard. Welk type waardedaling treft de machine van Lien?","text_en":"Laundry Lien uses an industrial washing machine that still works perfectly. However, a competitor installs a new model that uses 40% less energy per cycle, making Lien's machine suddenly far more expensive to operate than the market standard. Which type of value decline affects Lien's machine?","text_fr":"La blanchisserie Lien utilise une machine à laver industrielle qui fonctionne encore parfaitement. Un concurrent installe toutefois un nouveau modèle consommant 40% d'énergie en moins par cycle, rendant la machine de Lien soudain bien plus coûteuse que le standard du marché. Quel type de perte de valeur touche la machine de Lien ?","options_nl":["Technische slijtage — de machine is versleten door gebruik","Economische slijtage — er is een goedkoper producerend dpm op de markt verschenen","Geen slijtage — de machine werkt nog perfect, dus de waarde blijft gelijk","Lineaire slijtage — de waarde daalt elk jaar met hetzelfde bedrag"],"options_en":["Technical wear — the machine is worn out from use","Economic obsolescence — a cheaper-producing asset has appeared on the market","No wear — the machine still works perfectly, so its value stays the same","Linear wear — the value falls by the same amount every year"],"options_fr":["Usure technique — la machine est usée par l'utilisation","Obsolescence économique — un actif produisant moins cher est apparu sur le marché","Aucune usure — la machine fonctionne encore parfaitement, donc sa valeur reste identique","Usure linéaire — la valeur baisse du même montant chaque année"],"correct":1,"hint1_nl":"De machine is fysiek niet versleten — ze werkt nog perfect. Wat veroorzaakt dan de waardedaling: het gebruik van de machine zelf, of iets dat buiten de machine op de markt gebeurt?","hint1_en":"The machine is not physically worn — it still works perfectly. So what causes the loss in value: the use of the machine itself, or something happening outside it on the market?","hint1_fr":"La machine n'est pas physiquement usée — elle fonctionne encore parfaitement. Qu'est-ce qui cause alors la perte de valeur: l'utilisation de la machine elle-même, ou un événement extérieur sur le marché ?","hint2_nl":"Definitie economische slijtage: de waarde van het dpm daalt doordat er een goedkoper producerend dpm op de markt verschijnt. Dat is hier letterlijk het geval (40% minder energie).","hint2_en":"Definition of economic obsolescence: the asset's value falls because a cheaper-producing asset appears on the market. That is literally the case here (40% less energy).","hint2_fr":"Définition de l'obsolescence économique: la valeur de l'actif baisse parce qu'un actif produisant moins cher apparaît sur le marché. C'est littéralement le cas ici (40% d'énergie en moins).","sol_nl":"Antwoord: <strong>Economische slijtage</strong>. De machine is technisch nog in orde, maar economisch verouderd: een goedkoper producerend alternatief (40% minder energie) maakt haar productie relatief duur. Dit verkort de <em>economische levensduur</em>, ook al loopt de technische levensduur nog door.","sol_en":"Answer: <strong>Economic obsolescence</strong>. The machine is technically fine but economically outdated: a cheaper-producing alternative (40% less energy) makes its output relatively expensive. This shortens the <em>economic life</em>, even though the technical life continues.","sol_fr":"Réponse: <strong>Obsolescence économique</strong>. La machine est techniquement en ordre mais économiquement dépassée: une alternative produisant moins cher (40% d'énergie en moins) rend sa production relativement coûteuse. Cela raccourcit la <em>durée de vie économique</em>, même si la durée technique se poursuit."},{"id":"ex1_12","type":"mcq","style":"scenario","diff":"medium","title_nl":"Ontvangst of opbrengst? — Eventbureau Vos","title_en":"Receipt or revenue? — Event Agency Vos","title_fr":"Encaissement ou produit ? — Agence Vos","text_nl":"Eventbureau Vos ontvangt in december jaar 1 een voorschot van €20.000 van een klant voor een bedrijfsfeest dat pas in maart van jaar 2 plaatsvindt. In welk jaar telt dit bedrag mee als <strong>opbrengst</strong> in de resultatenrekening, en in welk jaar als <strong>ontvangst</strong> in de liquiditeitsbegroting?","text_en":"Event Agency Vos receives a €20,000 advance payment in December of year 1 from a client for a corporate party that only takes place in March of year 2. In which year does this amount count as <strong>revenue</strong> in the income statement, and in which year as a <strong>receipt</strong> in the cash budget?","text_fr":"L'agence événementielle Vos reçoit en décembre de l'année 1 un acompte de €20.000 d'un client pour une fête d'entreprise qui n'aura lieu qu'en mars de l'année 2. En quelle année ce montant compte-t-il comme <strong>produit</strong> au compte de résultats, et en quelle année comme <strong>encaissement</strong> au budget de trésorerie ?","options_nl":["Opbrengst in jaar 1, ontvangst in jaar 1 — geld binnen is omzet","Opbrengst in jaar 2, ontvangst in jaar 1 — de prestatie wordt pas in jaar 2 geleverd","Opbrengst in jaar 2, ontvangst in jaar 2 — alles schuift mee naar het feest","Opbrengst in jaar 1, ontvangst in jaar 2 — eerst boeken, dan innen"],"options_en":["Revenue in year 1, receipt in year 1 — cash in equals sales","Revenue in year 2, receipt in year 1 — the performance is only delivered in year 2","Revenue in year 2, receipt in year 2 — everything shifts to the party","Revenue in year 1, receipt in year 2 — record first, collect later"],"options_fr":["Produit en année 1, encaissement en année 1 — l'argent reçu est du chiffre d'affaires","Produit en année 2, encaissement en année 1 — la prestation n'est livrée qu'en année 2","Produit en année 2, encaissement en année 2 — tout se décale vers la fête","Produit en année 1, encaissement en année 2 — comptabiliser d'abord, encaisser ensuite"],"correct":1,"hint1_nl":"Twee verschillende vragen: wanneer komt het géld binnen (kas/bank), en wanneer wordt de préstatie geleverd? De liquiditeitsbegroting volgt het geld; de resultatenrekening volgt de prestatie.","hint1_en":"Two different questions: when does the cash come in (bank/till), and when is the performance delivered? The cash budget follows the money; the income statement follows the performance.","hint1_fr":"Deux questions différentes: quand l'argent entre-t-il (banque/caisse), et quand la prestation est-elle livrée ? Le budget de trésorerie suit l'argent; le compte de résultats suit la prestation.","hint2_nl":"Ontvangst = moment van geldstroom = december jaar 1. Opbrengst = moment van prestatie (het feest) = maart jaar 2. Tot dan staat het voorschot als schuld (vooruitontvangen bedrag) op de balans.","hint2_en":"Receipt = moment of cash flow = December year 1. Revenue = moment of performance (the party) = March year 2. Until then, the advance sits on the balance sheet as a liability (deferred revenue).","hint2_fr":"Encaissement = moment du flux d'argent = décembre année 1. Produit = moment de la prestation (la fête) = mars année 2. Jusque-là, l'acompte figure au bilan comme dette (produit reçu d'avance).","sol_nl":"Antwoord: <strong>Opbrengst in jaar 2, ontvangst in jaar 1</strong>. De €20.000 komt in december jaar 1 op de bank → ontvangst jaar 1 (liquiditeitsbegroting). Maar de prestatie (het feest) wordt pas in maart jaar 2 geleverd → opbrengst jaar 2 (resultatenrekening). Dit is exact het 'Blauw Geel'-principe uit de slides: ontvangsten zijn pas opbrengsten als de prestatie is verricht.","sol_en":"Answer: <strong>Revenue in year 2, receipt in year 1</strong>. The €20,000 hits the bank in December of year 1 → receipt in year 1 (cash budget). But the performance (the party) is only delivered in March of year 2 → revenue in year 2 (income statement). This is exactly the 'Blauw Geel' principle from the slides: receipts only become revenues once the performance is delivered.","sol_fr":"Réponse: <strong>Produit en année 2, encaissement en année 1</strong>. Les €20.000 arrivent en banque en décembre de l'année 1 → encaissement année 1 (budget de trésorerie). Mais la prestation (la fête) n'est livrée qu'en mars de l'année 2 → produit année 2 (compte de résultats). C'est exactement le principe 'Blauw Geel' des slides: les encaissements ne deviennent des produits qu'une fois la prestation réalisée."}],"replace":false},"w2":{"theoryExtra":{"nl":"<h3>Wat zijn 'kosten' eigenlijk?</h3>\n<p>Kosten zijn <strong>aan perioden of producten toegerekende (toekomstige) gelduitgaven in verband met doelmatig opgeofferde productiemiddelen</strong>. Twee woorden zijn belangrijk: <em>toegerekend</em> (kosten ≠ uitgaven: een machine betaal je één keer, maar de afschrijving reken je over jaren toe) en <em>doelmatig</em> (verspilling is geen kost, maar verlies).</p>\n<div class=\"note-box\"><strong>Kostprijs en marktvorm:</strong> de marktvorm bepaalt de rol van de kostprijs als <em>sturingsinstrument</em>. Bij volkomen concurrentie ligt de prijs vast in de markt en gebruik je de kostprijs vooral om te beslissen óf je produceert; bij meer marktmacht (monopolie, oligopolie) kun je de kostprijs gebruiken als basis voor je verkoopprijs.</div>\n\n<h3>Waarom niet gewoon delen door de werkelijke productie?</h3>\n<p>Je zou de kostprijs kunnen berekenen als totale kosten ÷ werkelijke productie. Maar dan krijg je <strong>steeds wisselende kostprijzen</strong>: bij 1.000 stuks €15,00 per stuk, bij 4.000 stuks €11,60 per stuk. Onbruikbaar als basis voor je verkoopprijs! Daarom gebruikt AC de <em>normale bezetting</em> als noemer.</p>\n\n<h3>Kerndefinities (leer ze letterlijk!)</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Standaardkostprijs</strong><br>De gemiddelde kosten per product bij de <em>normale bezetting</em>.</div>\n <div class=\"rule-card\"><strong>Integrale standaardkostprijs</strong><br>De gemiddelde <em>toegestane</em> kosten per product waarin zowel variabele als vaste kosten zijn opgenomen (o.b.v. normale bezetting).</div>\n <div class=\"rule-card\"><strong>Normale bezetting (N)</strong><br>De <em>gemiddelde productieomvang gedurende een aantal toekomstige jaren</em>. Géén momentopname!</div>\n <div class=\"rule-card\"><strong>Vaste kosten</strong><br>Veranderen niet als de bedrijfsdrukte verandert — <em>binnen de beschikbare capaciteit</em> (de 'relevante bedrijfsdrukte'). Boven die capaciteit springen ze omhoog (extra machine, extra loods).</div>\n</div>\n\n<h3>Hoe verlopen variabele kosten?</h3>\n<p>Variabele kosten veranderen met de bedrijfsdrukte, maar niet altijd op dezelfde manier:</p>\n<ul>\n <li><strong>Proportioneel:</strong> recht evenredig — elke extra eenheid kost evenveel (rechte lijn door de oorsprong). Dit veronderstellen we meestal in de formules.</li>\n <li><strong>Degressief stijgend:</strong> totale variabele kosten stijgen <em>minder dan evenredig</em> — per stuk worden ze goedkoper (kwantumkorting op grondstoffen, leereffecten).</li>\n <li><strong>Progressief stijgend:</strong> totale variabele kosten stijgen <em>meer dan evenredig</em> — per stuk worden ze duurder (overuren, storingen bij hoge drukte).</li>\n <li><strong>Trapsgewijs variabel:</strong> kosten springen per 'blokje' omhoog (bijv. één extra docent per 25 extra cursisten) — een trappetjesgrafiek.</li>\n</ul>\n<div class=\"note-box\"><strong>Gemengde kosten:</strong> kosten met deels een vast en deels een variabel karakter (bijv. energiecontract: vast abonnement + prijs per kWh). Op het examen moet je ze kunnen splitsen.</div>\n\n<h3>Gemengde kosten splitsen: de hoog-laag/vergelijkingsmethode</h3>\n<p>Heb je van twee perioden de totale kosten en de productie, dan vind je v en C zo:</p>\n<div class=\"formula\">v = (K_hoog − K_laag) / (q_hoog − q_laag) &nbsp;&nbsp; daarna: &nbsp; K = C + v × q → C</div>\n<div class=\"example-box\"><strong>Voorbeeld (bonusvraag uit de les):</strong> december: 40.000 stuks, verkoop à €8, verlies €20.000 → kosten = 40.000×8 + 20.000 = €340.000. Januari: 80.000 stuks, winst €50.000 → kosten = 80.000×8 − 50.000 = €590.000.<br>v = (590.000 − 340.000)/(80.000 − 40.000) = 250.000/40.000 = <strong>€6,25</strong><br>C = 340.000 − 6,25 × 40.000 = <strong>€90.000</strong> per maand.</div>\n\n<h3>Fabricagekostprijs vs. commerciële kostprijs</h3>\n<div class=\"formula\">Fabricagekostprijs = C_fabricage/N + v_fabricage<br>Commerciële kostprijs = fabricagekostprijs + C_verkoop/N + v_verkoop</div>\n<p>De <strong>fabricagekostprijs</strong> bevat alleen productiekosten; de <strong>commerciële kostprijs</strong> telt daar de verkoopkosten bij op. <strong>Voorraad waardeer je tegen de integrale fabricagekostprijs</strong> — verkoopkosten maak je immers pas bij verkoop, niet bij productie!</p>\n\n<h3>Bezettingsresultaat op verkoop</h3>\n<p>Zijn er <em>vaste verkoopkosten</em>, dan ontstaat er ook op de verkoop een bezettingsresultaat. Het volledige schema wordt dan:</p>\n<div class=\"formula\">BedR = (p − k_commercieel) × afzet &nbsp;+&nbsp; (W − N) × C_fab/N &nbsp;+&nbsp; (afzet − N) × C_verkoop/N</div>\n<p>→ Bezettingsresultaat <em>productie</em> gebruikt W (productie); bezettingsresultaat <em>verkoop</em> gebruikt afzet (verkopen).</p>\n<div class=\"tip-box\"><strong>Terminologie voor het examen:</strong> W &gt; N = <em>overdekking</em> van de vaste kosten → <em>overbezettingswinst</em>. W &lt; N = <em>onderdekking</em> → <em>onderbezettingsverlies</em>. Beide via dezelfde formule (W − N) × C/N; het teken bepaalt de naam.</div>","en":"<h3>What are 'costs' exactly?</h3>\n<p>Costs are <strong>(future) money outlays allocated to periods or products, related to efficiently sacrificed means of production</strong>. Two key words: <em>allocated</em> (costs ≠ expenditures: you pay for a machine once, but allocate depreciation over years) and <em>efficient</em> (waste is not a cost, it is a loss).</p>\n<div class=\"note-box\"><strong>Cost price and market form:</strong> the market form determines the role of the cost price as a <em>steering instrument</em>. Under perfect competition the price is set by the market and the cost price mainly tells you whether to produce; with more market power (monopoly, oligopoly) the cost price can be the basis for your selling price.</div>\n\n<h3>Why not simply divide by actual production?</h3>\n<p>You could compute total costs ÷ actual production, but you would get <strong>constantly changing cost prices</strong>: €15.00 per unit at 1,000 units, €11.60 at 4,000 units. Useless as a pricing basis! That is why AC uses the <em>normal capacity</em> as the denominator.</p>\n\n<h3>Core definitions (learn them verbatim!)</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Standard cost price</strong><br>The average cost per product at <em>normal capacity</em>.</div>\n <div class=\"rule-card\"><strong>Full standard cost price</strong><br>The average <em>allowed</em> cost per product including both variable and fixed costs (based on normal capacity).</div>\n <div class=\"rule-card\"><strong>Normal capacity (N)</strong><br>The <em>average production volume over a number of future years</em>. Not a snapshot!</div>\n <div class=\"rule-card\"><strong>Fixed costs</strong><br>Do not change when activity changes — <em>within the available capacity</em> (the 'relevant range'). Beyond that capacity they jump (extra machine, extra warehouse).</div>\n</div>\n\n<h3>How do variable costs behave?</h3>\n<ul>\n <li><strong>Proportional:</strong> strictly linear — each extra unit costs the same (straight line through the origin). This is what the formulas usually assume.</li>\n <li><strong>Degressive:</strong> total variable costs rise <em>less than proportionally</em> — cheaper per unit (volume discounts, learning effects).</li>\n <li><strong>Progressive:</strong> total variable costs rise <em>more than proportionally</em> — more expensive per unit (overtime, breakdowns at high activity).</li>\n <li><strong>Step-variable:</strong> costs jump in 'blocks' (e.g. one extra teacher per 25 extra students) — a staircase graph.</li>\n</ul>\n<div class=\"note-box\"><strong>Mixed costs:</strong> costs that are partly fixed and partly variable (e.g. energy contract: fixed subscription + price per kWh). On the exam you must be able to split them.</div>\n\n<h3>Splitting mixed costs: the high-low method</h3>\n<div class=\"formula\">v = (K_high − K_low) / (q_high − q_low) &nbsp;&nbsp; then: &nbsp; K = C + v × q → C</div>\n<div class=\"example-box\"><strong>Example (bonus question from class):</strong> December: 40,000 units sold at €8, loss €20,000 → costs = 40,000×8 + 20,000 = €340,000. January: 80,000 units, profit €50,000 → costs = 80,000×8 − 50,000 = €590,000.<br>v = (590,000 − 340,000)/(80,000 − 40,000) = <strong>€6.25</strong><br>C = 340,000 − 6.25 × 40,000 = <strong>€90,000</strong> per month.</div>\n\n<h3>Manufacturing cost price vs. commercial cost price</h3>\n<div class=\"formula\">Manufacturing cost price = C_manufacturing/N + v_manufacturing<br>Commercial cost price = manufacturing cost price + C_selling/N + v_selling</div>\n<p>The <strong>manufacturing cost price</strong> contains only production costs; the <strong>commercial cost price</strong> adds selling costs. <strong>Inventory is valued at the full manufacturing cost price</strong> — selling costs are only incurred when you sell, not when you produce!</p>\n\n<h3>Capacity result on sales</h3>\n<p>If there are <em>fixed selling costs</em>, a capacity result also arises on sales. The full scheme becomes:</p>\n<div class=\"formula\">BedR = (p − k_commercial) × afzet &nbsp;+&nbsp; (W − N) × C_man/N &nbsp;+&nbsp; (afzet − N) × C_selling/N</div>\n<p>→ The <em>production</em> capacity result uses W (production); the <em>sales</em> capacity result uses afzet (sales).</p>\n<div class=\"tip-box\"><strong>Exam terminology:</strong> W &gt; N = <em>over-absorption</em> of fixed costs → <em>over-utilization profit</em>. W &lt; N = <em>under-absorption</em> → <em>under-utilization loss</em>. Same formula (W − N) × C/N; the sign determines the name.</div>","fr":"<h3>Que sont exactement les 'coûts' ?</h3>\n<p>Les coûts sont des <strong>dépenses (futures) imputées à des périodes ou des produits, liées à des moyens de production sacrifiés de manière efficiente</strong>. Deux mots clés: <em>imputées</em> (coûts ≠ dépenses: une machine se paie une fois, mais l'amortissement s'impute sur plusieurs années) et <em>efficiente</em> (le gaspillage n'est pas un coût mais une perte).</p>\n<div class=\"note-box\"><strong>Coût de revient et forme de marché:</strong> la forme de marché détermine le rôle du coût de revient comme <em>instrument de pilotage</em>. En concurrence parfaite, le prix est fixé par le marché et le coût de revient sert surtout à décider si l'on produit; avec plus de pouvoir de marché (monopole, oligopole), il peut servir de base au prix de vente.</div>\n\n<h3>Pourquoi ne pas simplement diviser par la production réelle ?</h3>\n<p>On pourrait calculer coûts totaux ÷ production réelle, mais on obtiendrait des <strong>coûts de revient sans cesse changeants</strong>: 15,00 € par unité à 1.000 unités, 11,60 € à 4.000 unités. Inutilisable pour fixer un prix ! C'est pourquoi l'AC utilise la <em>capacité normale</em> comme dénominateur.</p>\n\n<h3>Définitions clés (à apprendre par cœur !)</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Coût de revient standard</strong><br>Le coût moyen par produit à la <em>capacité normale</em>.</div>\n <div class=\"rule-card\"><strong>Coût de revient standard complet</strong><br>Le coût moyen <em>autorisé</em> par produit incluant coûts variables et fixes (sur base de la capacité normale).</div>\n <div class=\"rule-card\"><strong>Capacité normale (N)</strong><br>Le <em>volume de production moyen sur plusieurs années futures</em>. Pas un instantané !</div>\n <div class=\"rule-card\"><strong>Coûts fixes</strong><br>Ne changent pas quand l'activité change — <em>dans les limites de la capacité disponible</em> (la 'zone pertinente'). Au-delà, ils sautent (machine supplémentaire, entrepôt supplémentaire).</div>\n</div>\n\n<h3>Comment évoluent les coûts variables ?</h3>\n<ul>\n <li><strong>Proportionnels:</strong> strictement linéaires — chaque unité supplémentaire coûte autant (droite passant par l'origine). C'est l'hypothèse habituelle des formules.</li>\n <li><strong>Dégressifs:</strong> les coûts variables totaux augmentent <em>moins que proportionnellement</em> — moins chers par unité (remises de quantité, effets d'apprentissage).</li>\n <li><strong>Progressifs:</strong> ils augmentent <em>plus que proportionnellement</em> — plus chers par unité (heures supplémentaires, pannes à forte activité).</li>\n <li><strong>Variables par paliers:</strong> les coûts sautent par 'blocs' (p.ex. un enseignant en plus par 25 étudiants supplémentaires) — graphique en escalier.</li>\n</ul>\n<div class=\"note-box\"><strong>Coûts mixtes:</strong> coûts en partie fixes, en partie variables (p.ex. contrat d'énergie: abonnement fixe + prix par kWh). À l'examen, vous devez savoir les scinder.</div>\n\n<h3>Scinder les coûts mixtes: la méthode des points extrêmes</h3>\n<div class=\"formula\">v = (K_haut − K_bas) / (q_haut − q_bas) &nbsp;&nbsp; puis: &nbsp; K = C + v × q → C</div>\n<div class=\"example-box\"><strong>Exemple (question bonus du cours):</strong> décembre: 40.000 unités à 8 €, perte de 20.000 € → coûts = 40.000×8 + 20.000 = 340.000 €. Janvier: 80.000 unités, bénéfice de 50.000 € → coûts = 80.000×8 − 50.000 = 590.000 €.<br>v = (590.000 − 340.000)/(80.000 − 40.000) = <strong>6,25 €</strong><br>C = 340.000 − 6,25 × 40.000 = <strong>90.000 €</strong> par mois.</div>\n\n<h3>Coût de revient de fabrication vs. coût de revient commercial</h3>\n<div class=\"formula\">Coût de fabrication = C_fabrication/N + v_fabrication<br>Coût commercial = coût de fabrication + C_vente/N + v_vente</div>\n<p>Le <strong>coût de fabrication</strong> ne contient que les coûts de production; le <strong>coût commercial</strong> y ajoute les coûts de vente. <strong>Le stock est valorisé au coût de fabrication complet</strong> — les coûts de vente ne surviennent qu'à la vente, pas à la production !</p>\n\n<h3>Résultat d'utilisation sur les ventes</h3>\n<p>S'il existe des <em>coûts de vente fixes</em>, un résultat d'utilisation apparaît aussi sur les ventes:</p>\n<div class=\"formula\">BedR = (p − k_commercial) × afzet &nbsp;+&nbsp; (W − N) × C_fab/N &nbsp;+&nbsp; (afzet − N) × C_vente/N</div>\n<p>→ Le résultat d'utilisation <em>production</em> utilise W; le résultat d'utilisation <em>vente</em> utilise l'afzet (ventes).</p>\n<div class=\"tip-box\"><strong>Terminologie d'examen:</strong> W &gt; N = <em>sur-imputation</em> des coûts fixes → <em>bénéfice de sur-utilisation</em>. W &lt; N = <em>sous-imputation</em> → <em>perte de sous-utilisation</em>. Même formule (W − N) × C/N; le signe détermine le nom.</div>"},"exercises":[{"id":"ex2_8","type":"numeric","style":"technical","diff":"medium","title_nl":"Hoog-laag methode — v en C bepalen","title_en":"High-low method — find v and C","title_fr":"Méthode des points extrêmes — trouver v et C","text_nl":"Gegeven twee maanden van een massaproducent: maand 1: q = 40.000 stuks, totale kosten K = €340.000. Maand 2: q = 80.000 stuks, K = €590.000. Verkoopprijs, vaste kosten en variabele kosten per stuk zijn in beide maanden gelijk. Bereken de variabele kosten per stuk (v) en de maandelijkse constante kosten (C).","text_en":"Given two months of a mass producer: month 1: q = 40,000 units, total costs K = €340,000. Month 2: q = 80,000 units, K = €590,000. Selling price, fixed costs and variable cost per unit are identical in both months. Calculate the variable cost per unit (v) and the monthly fixed costs (C).","text_fr":"Données de deux mois d'un producteur de masse: mois 1: q = 40.000 unités, coûts totaux K = 340.000 €. Mois 2: q = 80.000 unités, K = 590.000 €. Prix de vente, coûts fixes et coût variable unitaire sont identiques les deux mois. Calculez le coût variable par unité (v) et les coûts fixes mensuels (C).","inputs":[{"label_nl":"v (variabele kosten per stuk in €)","label_en":"v (variable cost per unit in €)","label_fr":"v (coût variable par unité en €)","answer":6.25},{"label_nl":"C (constante kosten per maand in €)","label_en":"C (fixed costs per month in €)","label_fr":"C (coûts fixes par mois en €)","answer":90000}],"hint1_nl":"De vaste kosten zijn in beide maanden gelijk, dus het VERSCHIL in totale kosten tussen de twee maanden komt volledig door de extra geproduceerde eenheden. Hoeveel extra kosten per extra eenheid is dat?","hint1_en":"Fixed costs are the same in both months, so the DIFFERENCE in total costs between the two months is entirely caused by the extra units produced. How much extra cost per extra unit is that?","hint1_fr":"Les coûts fixes sont identiques les deux mois, donc la DIFFÉRENCE de coûts totaux provient entièrement des unités supplémentaires produites. Combien de coût supplémentaire par unité supplémentaire ?","hint2_nl":"v = (590.000 − 340.000)/(80.000 − 40.000) = 250.000/40.000. Daarna: C = K − v × q = 340.000 − v × 40.000.","hint2_en":"v = (590,000 − 340,000)/(80,000 − 40,000) = 250,000/40,000. Then: C = K − v × q = 340,000 − v × 40,000.","hint2_fr":"v = (590.000 − 340.000)/(80.000 − 40.000) = 250.000/40.000. Puis: C = K − v × q = 340.000 − v × 40.000.","sol_nl":"<strong>v</strong> = (590.000 − 340.000)/(80.000 − 40.000) = 250.000/40.000 = <strong>€6,25 per stuk</strong>.<br><strong>C</strong> = K − v × q = 340.000 − 6,25 × 40.000 = 340.000 − 250.000 = <strong>€90.000</strong>.<br>Controle met maand 2: 90.000 + 6,25 × 80.000 = 90.000 + 500.000 = €590.000 ✓","sol_en":"<strong>v</strong> = (590,000 − 340,000)/(80,000 − 40,000) = 250,000/40,000 = <strong>€6.25 per unit</strong>.<br><strong>C</strong> = K − v × q = 340,000 − 6.25 × 40,000 = 340,000 − 250,000 = <strong>€90,000</strong>.<br>Check with month 2: 90,000 + 6.25 × 80,000 = €590,000 ✓","sol_fr":"<strong>v</strong> = (590.000 − 340.000)/(80.000 − 40.000) = 250.000/40.000 = <strong>6,25 € par unité</strong>.<br><strong>C</strong> = K − v × q = 340.000 − 6,25 × 40.000 = 340.000 − 250.000 = <strong>90.000 €</strong>.<br>Vérification avec le mois 2: 90.000 + 6,25 × 80.000 = 590.000 € ✓"},{"id":"ex2_9","type":"numeric","style":"scenario","diff":"hard","title_nl":"Commerciële kostprijs en dubbel bezettingsresultaat — Chocolaterie Bo","title_en":"Commercial cost price and double capacity result — Chocolaterie Bo","title_fr":"Coût commercial et double résultat d'utilisation — Chocolaterie Bo","text_nl":"Chocolaterie Bo maakt luxe bonbondozen. Fabricage: vaste fabricagekosten = €200.000/jaar, variabele fabricagekosten = €4 per doos. Verkoop: vaste verkoopkosten = €100.000/jaar, variabele verkoopkosten = €1 per doos. Normale bezetting (productie én afzet) N = 50.000 dozen. Verkoopprijs p = €15. Dit jaar: werkelijke productie W = 50.000 dozen, werkelijke afzet = 45.000 dozen. Bereken de commerciële kostprijs per doos en het bedrijfsresultaat (vergeet het bezettingsresultaat op verkoop niet!).","text_en":"Chocolaterie Bo makes luxury boxes of chocolates. Manufacturing: fixed manufacturing costs = €200,000/year, variable manufacturing costs = €4 per box. Selling: fixed selling costs = €100,000/year, variable selling costs = €1 per box. Normal capacity (production and sales) N = 50,000 boxes. Selling price p = €15. This year: actual production W = 50,000 boxes, actual sales = 45,000 boxes. Calculate the commercial cost price per box and the operating result (do not forget the capacity result on sales!).","text_fr":"La Chocolaterie Bo fabrique des boîtes de pralines de luxe. Fabrication: coûts fixes de fabrication = 200.000 €/an, coûts variables de fabrication = 4 € par boîte. Vente: coûts de vente fixes = 100.000 €/an, coûts de vente variables = 1 € par boîte. Capacité normale (production et vente) N = 50.000 boîtes. Prix de vente p = 15 €. Cette année: production réelle W = 50.000 boîtes, ventes réelles = 45.000 boîtes. Calculez le coût de revient commercial par boîte et le résultat d'exploitation (n'oubliez pas le résultat d'utilisation sur les ventes !).","inputs":[{"label_nl":"Commerciële kostprijs per doos (€)","label_en":"Commercial cost price per box (€)","label_fr":"Coût de revient commercial par boîte (€)","answer":11},{"label_nl":"BedR (bedrijfsresultaat in €)","label_en":"BedR (operating result in €)","label_fr":"BedR (résultat d'exploitation en €)","answer":170000}],"hint1_nl":"De commerciële kostprijs = fabricagekostprijs + verkoopkosten per doos (vast aandeel + variabel deel). Voor het bedrijfsresultaat zijn er nu DRIE componenten: verkoopresultaat, bezettingsresultaat op productie (gebruik W) en bezettingsresultaat op verkoop (gebruik afzet).","hint1_en":"The commercial cost price = manufacturing cost price + selling costs per box (fixed share + variable part). The operating result now has THREE components: sales result, capacity result on production (use W) and capacity result on sales (use afzet).","hint1_fr":"Le coût commercial = coût de fabrication + coûts de vente par boîte (part fixe + part variable). Le résultat d'exploitation comporte maintenant TROIS composantes: résultat des ventes, résultat d'utilisation production (avec W) et résultat d'utilisation vente (avec l'afzet).","hint2_nl":"k = (200.000/50.000 + 4) + (100.000/50.000 + 1) = 8 + 3 = 11. VR = (15 − 11) × 45.000. BezR productie = (50.000 − 50.000) × 4. BezR verkoop = (45.000 − 50.000) × 2. BedR = som.","hint2_en":"k = (200,000/50,000 + 4) + (100,000/50,000 + 1) = 8 + 3 = 11. VR = (15 − 11) × 45,000. Capacity result production = (50,000 − 50,000) × 4. Capacity result sales = (45,000 − 50,000) × 2. BedR = sum.","hint2_fr":"k = (200.000/50.000 + 4) + (100.000/50.000 + 1) = 8 + 3 = 11. VR = (15 − 11) × 45.000. BezR production = (50.000 − 50.000) × 4. BezR vente = (45.000 − 50.000) × 2. BedR = somme.","sol_nl":"<strong>Fabricagekostprijs</strong> = 200.000/50.000 + 4 = 4 + 4 = €8.<br><strong>Commerciële kostprijs</strong> = 8 + 100.000/50.000 + 1 = 8 + 2 + 1 = <strong>€11 per doos</strong>.<br><strong>VR</strong> = (15 − 11) × 45.000 = 4 × 45.000 = €180.000.<br><strong>BezR productie</strong> = (50.000 − 50.000) × (200.000/50.000) = 0 × 4 = €0.<br><strong>BezR verkoop</strong> = (45.000 − 50.000) × (100.000/50.000) = −5.000 × 2 = −€10.000.<br><strong>BedR</strong> = 180.000 + 0 − 10.000 = <strong>€170.000</strong>.","sol_en":"<strong>Manufacturing cost price</strong> = 200,000/50,000 + 4 = 4 + 4 = €8.<br><strong>Commercial cost price</strong> = 8 + 100,000/50,000 + 1 = 8 + 2 + 1 = <strong>€11 per box</strong>.<br><strong>VR</strong> = (15 − 11) × 45,000 = €180,000.<br><strong>Capacity result production</strong> = (50,000 − 50,000) × 4 = €0.<br><strong>Capacity result sales</strong> = (45,000 − 50,000) × 2 = −€10,000.<br><strong>BedR</strong> = 180,000 + 0 − 10,000 = <strong>€170,000</strong>.","sol_fr":"<strong>Coût de fabrication</strong> = 200.000/50.000 + 4 = 4 + 4 = 8 €.<br><strong>Coût commercial</strong> = 8 + 100.000/50.000 + 1 = 8 + 2 + 1 = <strong>11 € par boîte</strong>.<br><strong>VR</strong> = (15 − 11) × 45.000 = 180.000 €.<br><strong>BezR production</strong> = (50.000 − 50.000) × 4 = 0 €.<br><strong>BezR vente</strong> = (45.000 − 50.000) × 2 = −10.000 €.<br><strong>BedR</strong> = 180.000 + 0 − 10.000 = <strong>170.000 €</strong>."},{"id":"ex2_10","type":"mcq","style":"technical","diff":"easy","title_nl":"Verloop van variabele kosten — degressief stijgend","title_en":"Variable cost behavior — degressive","title_fr":"Évolution des coûts variables — dégressifs","text_nl":"De totale variabele kosten van een bedrijf stijgen wanneer de bedrijfsdrukte (q) toeneemt, maar de variabele kosten PER STUK dalen daarbij. Hoe noemen we dit kostenverloop?","text_en":"A firm's total variable costs rise as activity (q) increases, but the variable cost PER UNIT falls at the same time. What is this cost behavior called?","text_fr":"Les coûts variables totaux d'une entreprise augmentent quand l'activité (q) augmente, mais le coût variable PAR UNITÉ diminue. Comment appelle-t-on cette évolution des coûts ?","options_nl":["Proportioneel variabel","Progressief stijgend","Degressief stijgend","Trapsgewijs variabel"],"options_en":["Proportionally variable","Progressive","Degressive","Step-variable"],"options_fr":["Proportionnels","Progressifs","Dégressifs","Variables par paliers"],"correct":2,"hint1_nl":"Stel je kwantumkorting op grondstoffen voor: hoe meer je inkoopt, hoe goedkoper elke eenheid wordt. De totale kosten stijgen nog wel, maar steeds langzamer.","hint1_en":"Think of volume discounts on raw materials: the more you buy, the cheaper each unit becomes. Total costs still rise, but ever more slowly.","hint1_fr":"Pensez aux remises de quantité sur les matières premières: plus vous achetez, moins chaque unité coûte. Les coûts totaux augmentent encore, mais de plus en plus lentement.","hint2_nl":"Degressief = totale variabele kosten stijgen MINDER dan evenredig met q (afvlakkende curve). Progressief = MEER dan evenredig (steeds steiler). Proportioneel = rechte lijn.","hint2_en":"Degressive = total variable costs rise LESS than proportionally with q (flattening curve). Progressive = MORE than proportionally (ever steeper). Proportional = straight line.","hint2_fr":"Dégressif = les coûts variables totaux augmentent MOINS que proportionnellement à q (courbe qui s'aplatit). Progressif = PLUS que proportionnellement. Proportionnel = ligne droite.","sol_nl":"Antwoord C: <strong>degressief stijgend</strong>. De totale variabele kosten stijgen minder dan evenredig met de bedrijfsdrukte, dus de kosten per stuk dalen (bijv. door kwantumkorting of leereffecten). Progressief is het omgekeerde (per stuk duurder, bijv. overuren); proportioneel betekent constante kosten per stuk; trapsgewijs betekent sprongen per blok capaciteit.","sol_en":"Answer C: <strong>degressive</strong>. Total variable costs rise less than proportionally with activity, so cost per unit falls (e.g. volume discounts or learning effects). Progressive is the opposite (more expensive per unit, e.g. overtime); proportional means constant cost per unit; step-variable means jumps per block of capacity.","sol_fr":"Réponse C: <strong>dégressifs</strong>. Les coûts variables totaux augmentent moins que proportionnellement à l'activité, donc le coût unitaire baisse (remises de quantité, effets d'apprentissage). Progressif est l'inverse (plus cher par unité, p.ex. heures supplémentaires); proportionnel = coût unitaire constant; par paliers = sauts par bloc de capacité."},{"id":"ex2_11","type":"mcq","style":"scenario","diff":"medium","title_nl":"Voorraadwaardering — Brouwerij Stan","title_en":"Inventory valuation — Brewery Stan","title_fr":"Valorisation du stock — Brasserie Stan","text_nl":"Brouwerij Stan heeft op het einde van het jaar 2.000 kratten bier in voorraad. Zijn integrale fabricagekostprijs is €6 per krat; zijn commerciële kostprijs (incl. verkoopkosten) is €8 per krat; de verkoopprijs is €12. Tegen welke waarde neemt Stan deze voorraad op de balans op, en waarom?","text_en":"Brewery Stan has 2,000 crates of beer in stock at year-end. His full manufacturing cost price is €6 per crate; his commercial cost price (incl. selling costs) is €8 per crate; the selling price is €12. At what value does Stan record this inventory on the balance sheet, and why?","text_fr":"La Brasserie Stan a 2.000 casiers de bière en stock à la fin de l'année. Son coût de fabrication complet est de 6 € par casier; son coût commercial (frais de vente inclus) est de 8 € par casier; le prix de vente est de 12 €. À quelle valeur Stan inscrit-il ce stock au bilan, et pourquoi ?","options_nl":["€24.000 (2.000 × €12): de verkoopprijs, want zoveel is de voorraad waard op de markt","€16.000 (2.000 × €8): de commerciële kostprijs, want alle kosten moeten gedekt worden","€12.000 (2.000 × €6): de fabricagekostprijs, want verkoopkosten zijn nog niet gemaakt voor onverkochte producten","€8.000 (2.000 × €4): alleen de variabele kosten, want vaste kosten zijn periodekosten"],"options_en":["€24,000 (2,000 × €12): the selling price, because that is the market value of the stock","€16,000 (2,000 × €8): the commercial cost price, because all costs must be covered","€12,000 (2,000 × €6): the manufacturing cost price, because selling costs have not yet been incurred for unsold products","€8,000 (2,000 × €4): only the variable costs, because fixed costs are period costs"],"options_fr":["24.000 € (2.000 × 12 €): le prix de vente, car c'est la valeur de marché du stock","16.000 € (2.000 × 8 €): le coût commercial, car tous les coûts doivent être couverts","12.000 € (2.000 × 6 €): le coût de fabrication, car les frais de vente n'ont pas encore été engagés pour les produits invendus","8.000 € (2.000 × 4 €): uniquement les coûts variables, car les coûts fixes sont des coûts de période"],"correct":2,"hint1_nl":"Welke kosten heeft Stan al écht gemaakt voor deze kratten? Ze zijn gebrouwen, maar nog niet verkocht. Verkoopkosten (transport, commissie, reclame per krat) ontstaan pas op het moment van verkoop. En winst neem je nooit vooraf in de voorraad op.","hint1_en":"Which costs has Stan actually incurred for these crates? They have been brewed, but not yet sold. Selling costs (transport, commission, advertising per crate) only arise at the moment of sale. And profit is never recognized in inventory in advance.","hint1_fr":"Quels coûts Stan a-t-il réellement engagés pour ces casiers ? Ils sont brassés mais pas encore vendus. Les frais de vente (transport, commission, publicité) ne naissent qu'au moment de la vente. Et on n'inscrit jamais de bénéfice anticipé dans le stock.","hint2_nl":"Bij absorption costing: voorraad = aantal × integrale FABRICAGEkostprijs = 2.000 × €6.","hint2_en":"Under absorption costing: inventory = quantity × full MANUFACTURING cost price = 2,000 × €6.","hint2_fr":"En coût complet: stock = quantité × coût de FABRICATION complet = 2.000 × 6 €.","sol_nl":"Antwoord C: <strong>€12.000 (2.000 × €6)</strong>. Bij AC waardeer je de voorraad tegen de <strong>integrale fabricagekostprijs</strong>. Verkoopkosten horen er niet in (die maak je pas bij verkoop) en winst neem je nooit vooraf op. Antwoord D beschrijft direct costing (DC), niet AC.","sol_en":"Answer C: <strong>€12,000 (2,000 × €6)</strong>. Under AC, inventory is valued at the <strong>full manufacturing cost price</strong>. Selling costs are excluded (incurred only upon sale) and profit is never recognized in advance. Answer D describes direct costing (DC), not AC.","sol_fr":"Réponse C: <strong>12.000 € (2.000 × 6 €)</strong>. En coût complet (AC), le stock est valorisé au <strong>coût de fabrication complet</strong>. Les frais de vente en sont exclus (engagés seulement à la vente) et le bénéfice n'est jamais anticipé. La réponse D décrit le direct costing (DC), pas l'AC."}],"replace":false},"w3":{"theoryExtra":{"nl":"<h3>Het officiële AC-winstschema: verkoopresultaat + bezettingsresultaat</h3>\n<p>Op het examen moet je het AC-resultaat in <strong>twee benoemde componenten</strong> kunnen splitsen:</p>\n<div class=\"formula\">Verkoopresultaat = afzet × (p − k)</div>\n<div class=\"formula\">Bezettingsresultaat = (W − N) × C/N</div>\n<div class=\"formula\">NBR (AC) = Verkoopresultaat + Bezettingsresultaat</div>\n<p>Het <strong>bezettingsresultaat</strong> ontstaat omdat de vaste kosten worden doorberekend op basis van de normale bezetting N. Produceer je minder dan normaal (W &lt; N), dan is het bezettingsresultaat <em>negatief</em> (onderdekking); produceer je meer (W &gt; N), dan is het <em>positief</em> (overdekking).</p>\n<div class=\"tip-box\"><strong>Let op:</strong> het bezettingsresultaat wordt berekend op de <em>productie</em> (W), het verkoopresultaat op de <em>afzet</em>. Verwar die twee niet — dit is een klassieke examenvraag (LU4: bezettingsresultaat op productie en verkoop).</div>\n\n<h3>Voorraadwaardering: AC vs DC</h3>\n<div class=\"formula\">Voorraadwaarde AC = voorraadmutatie × k (integrale kostprijs)</div>\n<div class=\"formula\">Voorraadwaarde DC = voorraadmutatie × v (variabele kosten p/e)</div>\n<div class=\"formula\">Verschil = voorraadmutatie × C/N (vaste kosten p/e)</div>\n<p>Bij een voorraadtoename worden bij AC de bijbehorende vaste kosten <strong>geactiveerd</strong> op de balans — ze schuiven door naar een volgende periode. Bij DC waardeer je de voorraad alleen tegen variabele kosten.</p>\n<div class=\"example-box\"><strong>Voorbeeld:</strong> productie 1.000, afzet 900, k = €6, v = €5. Voorraadmutatie = 100 stuks. Waarde AC = 100 × €6 = €600; waarde DC = 100 × €5 = €500. Verschil = 100 × €1 = €100 — precies het winstverschil AC − DC.</div>\n\n<h3>Wanneer gebruik je welke methode?</h3>\n<div class=\"rule-grid\">\n<div class=\"rule-card\"><strong>Direct Costing</strong><br>Alleen variabele kosten in de kostprijs<br>Gericht op <strong>korte termijn</strong><br>Voor <strong>interne</strong> verslaggeving (besluitvorming)</div>\n<div class=\"rule-card\"><strong>Absorption Costing</strong><br>Variabele én vaste kosten in de kostprijs<br>Gericht op <strong>lange termijn</strong><br>Voor <strong>externe</strong> verslaggeving (jaarrekening)</div>\n</div>\n<div class=\"note-box\"><strong>Terminologie:</strong> bij DC zijn variabele kosten <strong>productkosten</strong> (gaan mee met het product) en vaste kosten <strong>periodekosten</strong> (rechtstreeks ten laste van de resultatenrekening van de periode). De prijs die je voor een eenmalige extra order minimaal nodig hebt, heet de <strong>differentiële kostprijs</strong> — bij vrije capaciteit zijn dat de variabele kosten per stuk.</div>\n\n<h3>Fabricagekostprijs vs commerciële kostprijs</h3>\n<p>De <strong>fabricagekostprijs</strong> bevat alleen de productiekosten (grondstoffen, fabricage-arbeid, machinekosten). De <strong>commerciële kostprijs</strong> = fabricagekostprijs + verkoop- en distributiekosten. De <em>voorraad</em> wordt gewaardeerd tegen de (integrale) <strong>fabricage</strong>kostprijs — verkoopkosten activeer je nooit in de voorraad.</p>","en":"<h3>The official AC profit schema: sales result + capacity result</h3>\n<p>On the exam you must split the AC result into <strong>two named components</strong>:</p>\n<div class=\"formula\">Sales result = sales × (p − k)</div>\n<div class=\"formula\">Capacity (occupancy) result = (W − N) × C/N</div>\n<div class=\"formula\">NBR (AC) = Sales result + Capacity result</div>\n<p>The <strong>capacity result</strong> arises because fixed costs are charged based on normal capacity N. If you produce less than normal (W &lt; N), the capacity result is <em>negative</em> (under-absorption); if more (W &gt; N), it is <em>positive</em> (over-absorption).</p>\n<div class=\"tip-box\"><strong>Note:</strong> the capacity result is computed on <em>production</em> (W), the sales result on <em>sales</em>. Do not mix them up — a classic exam question (LO4: capacity result on production and sales).</div>\n\n<h3>Inventory valuation: AC vs DC</h3>\n<div class=\"formula\">Inventory value AC = inventory change × k (full cost)</div>\n<div class=\"formula\">Inventory value DC = inventory change × v (variable cost per unit)</div>\n<div class=\"formula\">Difference = inventory change × C/N (fixed cost per unit)</div>\n<p>When inventory increases, AC <strong>capitalizes</strong> the related fixed costs on the balance sheet — shifting them to a later period. Under DC, inventory is valued at variable costs only.</p>\n<div class=\"example-box\"><strong>Example:</strong> production 1,000, sales 900, k = €6, v = €5. Inventory change = 100 units. Value AC = 100 × €6 = €600; value DC = 100 × €5 = €500. Difference = 100 × €1 = €100 — exactly the AC − DC profit difference.</div>\n\n<h3>When to use which method?</h3>\n<div class=\"rule-grid\">\n<div class=\"rule-card\"><strong>Direct Costing</strong><br>Only variable costs in the cost price<br>Focused on the <strong>short term</strong><br>For <strong>internal</strong> reporting (decision-making)</div>\n<div class=\"rule-card\"><strong>Absorption Costing</strong><br>Variable and fixed costs in the cost price<br>Focused on the <strong>long term</strong><br>For <strong>external</strong> reporting (annual accounts)</div>\n</div>\n<div class=\"note-box\"><strong>Terminology:</strong> under DC, variable costs are <strong>product costs</strong> (travel with the product) and fixed costs are <strong>period costs</strong> (charged directly to the income statement of the period). The minimum price needed for a one-off extra order is the <strong>differential cost price</strong> — with spare capacity this equals the variable cost per unit.</div>\n\n<h3>Manufacturing cost price vs commercial cost price</h3>\n<p>The <strong>manufacturing cost price</strong> contains only production costs (materials, production labor, machine costs). The <strong>commercial cost price</strong> = manufacturing cost price + selling and distribution costs. <em>Inventory</em> is valued at the (full) <strong>manufacturing</strong> cost price — selling costs are never capitalized in inventory.</p>","fr":"<h3>Le schéma officiel AC: résultat sur ventes + résultat d'occupation</h3>\n<p>À l'examen, vous devez décomposer le résultat AC en <strong>deux composantes nommées</strong>:</p>\n<div class=\"formula\">Résultat sur ventes = ventes × (p − k)</div>\n<div class=\"formula\">Résultat d'occupation = (W − N) × C/N</div>\n<div class=\"formula\">RNE (AC) = Résultat sur ventes + Résultat d'occupation</div>\n<p>Le <strong>résultat d'occupation</strong> apparaît parce que les coûts fixes sont imputés sur base de la capacité normale N. Si vous produisez moins que la normale (W &lt; N), le résultat d'occupation est <em>négatif</em> (sous-imputation); si vous produisez plus (W &gt; N), il est <em>positif</em> (sur-imputation).</p>\n<div class=\"tip-box\"><strong>Attention:</strong> le résultat d'occupation se calcule sur la <em>production</em> (W), le résultat sur ventes sur les <em>ventes</em>. Ne les confondez pas — question d'examen classique (AA4: résultat d'occupation sur production et ventes).</div>\n\n<h3>Valorisation des stocks: AC vs DC</h3>\n<div class=\"formula\">Valeur du stock AC = variation de stock × k (coût complet)</div>\n<div class=\"formula\">Valeur du stock DC = variation de stock × v (coût variable par unité)</div>\n<div class=\"formula\">Différence = variation de stock × C/N (coût fixe par unité)</div>\n<p>Lors d'une augmentation de stock, l'AC <strong>active</strong> les coûts fixes correspondants au bilan — ils sont reportés à une période ultérieure. Avec la DC, le stock n'est valorisé qu'aux coûts variables.</p>\n<div class=\"example-box\"><strong>Exemple:</strong> production 1.000, ventes 900, k = €6, v = €5. Variation de stock = 100 unités. Valeur AC = 100 × €6 = €600; valeur DC = 100 × €5 = €500. Différence = 100 × €1 = €100 — exactement la différence de profit AC − DC.</div>\n\n<h3>Quand utiliser quelle méthode ?</h3>\n<div class=\"rule-grid\">\n<div class=\"rule-card\"><strong>Direct Costing</strong><br>Seuls les coûts variables dans le coût de revient<br>Orienté <strong>court terme</strong><br>Pour le reporting <strong>interne</strong> (prise de décision)</div>\n<div class=\"rule-card\"><strong>Absorption Costing</strong><br>Coûts variables et fixes dans le coût de revient<br>Orienté <strong>long terme</strong><br>Pour le reporting <strong>externe</strong> (comptes annuels)</div>\n</div>\n<div class=\"note-box\"><strong>Terminologie:</strong> en DC, les coûts variables sont des <strong>coûts de produit</strong> (suivent le produit) et les coûts fixes des <strong>coûts de période</strong> (imputés directement au compte de résultat de la période). Le prix minimum requis pour une commande supplémentaire unique s'appelle le <strong>coût de revient différentiel</strong> — avec de la capacité libre, il équivaut au coût variable par unité.</div>\n\n<h3>Coût de revient de fabrication vs coût de revient commercial</h3>\n<p>Le <strong>coût de revient de fabrication</strong> ne contient que les coûts de production (matières, main-d'œuvre de fabrication, coûts machines). Le <strong>coût de revient commercial</strong> = coût de fabrication + frais de vente et de distribution. Le <em>stock</em> est valorisé au coût (complet) de <strong>fabrication</strong> — les frais de vente ne sont jamais activés en stock.</p>"},"exercises":[{"id":"ex3_7","type":"numeric","style":"technical","diff":"medium","title_nl":"AC-schema: verkoop- en bezettingsresultaat","title_en":"AC schema: sales and capacity result","title_fr":"Schéma AC: résultat sur ventes et d'occupation","text_nl":"Gegeven: p = €20, v = €8, C = €60.000, N = 10.000 stuks, W = 9.000 stuks, afzet = 9.000 stuks. Bereken volgens de AC-methode: (a) het verkoopresultaat, (b) het bezettingsresultaat, (c) het NBR.","text_en":"Given: p = €20, v = €8, C = €60,000, N = 10,000 units, W = 9,000 units, sales = 9,000 units. Using the AC method, calculate: (a) the sales result, (b) the capacity result, (c) the NBR.","text_fr":"Données: p = €20, v = €8, C = €60.000, N = 10.000 unités, W = 9.000 unités, ventes = 9.000 unités. Selon la méthode AC, calculez: (a) le résultat sur ventes, (b) le résultat d'occupation, (c) le RNE.","hint1_nl":"Bepaal eerst de integrale kostprijs k met de normale bezetting. Het verkoopresultaat kijkt naar wat je per verkochte eenheid verdient bovenop k; het bezettingsresultaat kijkt naar hoeveel je minder (of meer) produceerde dan normaal — daardoor blijft een deel van de vaste kosten ongedekt.","hint1_en":"First find the full cost k using normal capacity. The sales result looks at what you earn per sold unit above k; the capacity result looks at how much less (or more) you produced than normal — leaving part of fixed costs uncovered.","hint1_fr":"Déterminez d'abord le coût complet k avec la capacité normale. Le résultat sur ventes regarde ce que vous gagnez par unité vendue au-dessus de k; le résultat d'occupation regarde combien vous avez produit en moins (ou en plus) que la normale — laissant une partie des coûts fixes non couverte.","hint2_nl":"k = v + C/N = €8 + €60.000/10.000 = €14. Verkoopresultaat = 9.000 × (€20 − €14) = ? Bezettingsresultaat = (9.000 − 10.000) × €6 = ? NBR = som van beide.","hint2_en":"k = v + C/N = €8 + €60,000/10,000 = €14. Sales result = 9,000 × (€20 − €14) = ? Capacity result = (9,000 − 10,000) × €6 = ? NBR = sum of both.","hint2_fr":"k = v + C/N = €8 + €60.000/10.000 = €14. Résultat sur ventes = 9.000 × (€20 − €14) = ? Résultat d'occupation = (9.000 − 10.000) × €6 = ? RNE = somme des deux.","sol_nl":"C/N = €60.000/10.000 = €6; k = €8 + €6 = €14. Verkoopresultaat = 9.000 × (€20 − €14) = <strong>€54.000</strong>. Bezettingsresultaat = (W − N) × C/N = (9.000 − 10.000) × €6 = <strong>−€6.000</strong> (onderdekking). NBR = €54.000 − €6.000 = <strong>€48.000</strong>.","sol_en":"C/N = €60,000/10,000 = €6; k = €8 + €6 = €14. Sales result = 9,000 × (€20 − €14) = <strong>€54,000</strong>. Capacity result = (W − N) × C/N = (9,000 − 10,000) × €6 = <strong>−€6,000</strong> (under-absorption). NBR = €54,000 − €6,000 = <strong>€48,000</strong>.","sol_fr":"C/N = €60.000/10.000 = €6; k = €8 + €6 = €14. Résultat sur ventes = 9.000 × (€20 − €14) = <strong>€54.000</strong>. Résultat d'occupation = (W − N) × C/N = (9.000 − 10.000) × €6 = <strong>−€6.000</strong> (sous-imputation). RNE = €54.000 − €6.000 = <strong>€48.000</strong>.","inputs":[{"label_nl":"Verkoopresultaat (€)","label_en":"Sales result (€)","label_fr":"Résultat sur ventes (€)","answer":54000},{"label_nl":"Bezettingsresultaat (€)","label_en":"Capacity result (€)","label_fr":"Résultat d'occupation (€)","answer":-6000},{"label_nl":"NBR (€)","label_en":"NBR (€)","label_fr":"RNE (€)","answer":48000}]},{"id":"ex3_8","type":"numeric","style":"scenario","diff":"medium","title_nl":"Voorraadwaardering: Speelgoedfabriek Wouter","title_en":"Inventory valuation: Toy Factory Wouter","title_fr":"Valorisation du stock: Fabrique de jouets Wouter","text_nl":"Speelgoedfabriek Wouter produceerde dit jaar <strong>W = 8.000</strong> houten treintjes en verkocht er <strong>7.500</strong>. De variabele kosten zijn <strong>v = €6</strong> per treintje, de vaste kosten <strong>C = €28.000</strong> bij een normale bezetting <strong>N = 8.000</strong>. Bereken de waarde van de voorraadtoename volgens (a) de AC-methode (integrale kostprijs) en (b) de DC-methode, en (c) het verschil tussen beide.","text_en":"Toy factory Wouter produced <strong>W = 8,000</strong> wooden trains this year and sold <strong>7,500</strong>. Variable costs are <strong>v = €6</strong> per train, fixed costs <strong>C = €28,000</strong> at a normal capacity <strong>N = 8,000</strong>. Calculate the value of the inventory increase under (a) the AC method (full cost) and (b) the DC method, and (c) the difference between them.","text_fr":"La fabrique de jouets Wouter a produit <strong>W = 8.000</strong> trains en bois cette année et en a vendu <strong>7.500</strong>. Coûts variables <strong>v = €6</strong> par train, coûts fixes <strong>C = €28.000</strong> pour une capacité normale <strong>N = 8.000</strong>. Calculez la valeur de l'augmentation de stock selon (a) la méthode AC (coût complet) et (b) la méthode DC, et (c) la différence entre les deux.","hint1_nl":"Eerst de voorraadmutatie: hoeveel treintjes bleven onverkocht? Bij AC neemt elk treintje in voorraad óók een stukje vaste kosten mee naar de balans; bij DC waardeer je de voorraad alleen tegen de variabele kosten.","hint1_en":"First the inventory change: how many trains remained unsold? Under AC each train in inventory also carries a piece of fixed costs onto the balance sheet; under DC inventory is valued at variable costs only.","hint1_fr":"D'abord la variation de stock: combien de trains restent invendus ? En AC, chaque train en stock emporte aussi une part de coûts fixes au bilan; en DC, le stock n'est valorisé qu'aux coûts variables.","hint2_nl":"Voorraadmutatie = 8.000 − 7.500 = 500. k = v + C/N = €6 + €28.000/8.000 = €9,50. Waarde AC = 500 × €9,50 = ? Waarde DC = 500 × €6 = ? Verschil = 500 × €3,50 = ?","hint2_en":"Inventory change = 8,000 − 7,500 = 500. k = v + C/N = €6 + €28,000/8,000 = €9.50. Value AC = 500 × €9.50 = ? Value DC = 500 × €6 = ? Difference = 500 × €3.50 = ?","hint2_fr":"Variation de stock = 8.000 − 7.500 = 500. k = v + C/N = €6 + €28.000/8.000 = €9,50. Valeur AC = 500 × €9,50 = ? Valeur DC = 500 × €6 = ? Différence = 500 × €3,50 = ?","sol_nl":"Voorraadmutatie = 8.000 − 7.500 = 500 stuks. C/N = €28.000/8.000 = €3,50; k = €6 + €3,50 = €9,50. Voorraadwaarde AC = 500 × €9,50 = <strong>€4.750</strong>. Voorraadwaarde DC = 500 × €6 = <strong>€3.000</strong>. Verschil = 500 × €3,50 = <strong>€1.750</strong> — dit is precies het winstverschil AC − DC: bij AC worden €1.750 vaste kosten geactiveerd op de balans.","sol_en":"Inventory change = 8,000 − 7,500 = 500 units. C/N = €28,000/8,000 = €3.50; k = €6 + €3.50 = €9.50. Inventory value AC = 500 × €9.50 = <strong>€4,750</strong>. Inventory value DC = 500 × €6 = <strong>€3,000</strong>. Difference = 500 × €3.50 = <strong>€1,750</strong> — exactly the AC − DC profit difference: under AC, €1,750 of fixed costs are capitalized on the balance sheet.","sol_fr":"Variation de stock = 8.000 − 7.500 = 500 unités. C/N = €28.000/8.000 = €3,50; k = €6 + €3,50 = €9,50. Valeur du stock AC = 500 × €9,50 = <strong>€4.750</strong>. Valeur du stock DC = 500 × €6 = <strong>€3.000</strong>. Différence = 500 × €3,50 = <strong>€1.750</strong> — exactement la différence de profit AC − DC: en AC, €1.750 de coûts fixes sont activés au bilan.","inputs":[{"label_nl":"Voorraadwaarde AC (€)","label_en":"Inventory value AC (€)","label_fr":"Valeur du stock AC (€)","answer":4750},{"label_nl":"Voorraadwaarde DC (€)","label_en":"Inventory value DC (€)","label_fr":"Valeur du stock DC (€)","answer":3000},{"label_nl":"Verschil (€)","label_en":"Difference (€)","label_fr":"Différence (€)","answer":1750}]},{"id":"ex3_9","type":"mcq","style":"technical","diff":"easy","title_nl":"MCQ: DC vs AC — kenmerken en kostprijsbegrippen","title_en":"MCQ: DC vs AC — characteristics and cost concepts","title_fr":"QCM: DC vs AC — caractéristiques et notions de coût","text_nl":"Welke uitspraak is <strong>juist</strong>?","text_en":"Which statement is <strong>correct</strong>?","text_fr":"Quelle affirmation est <strong>correcte</strong> ?","options_nl":["Direct Costing is gericht op de lange termijn en wordt gebruikt voor externe verslaggeving","De commerciële kostprijs = fabricagekostprijs + verkoop- en distributiekosten; de voorraad wordt gewaardeerd tegen de fabricagekostprijs","Bij Direct Costing zijn de vaste kosten productkosten en de variabele kosten periodekosten","De voorraad wordt gewaardeerd tegen de commerciële kostprijs, inclusief verkoopkosten"],"options_en":["Direct Costing is long-term oriented and used for external reporting","The commercial cost price = manufacturing cost price + selling and distribution costs; inventory is valued at the manufacturing cost price","Under Direct Costing, fixed costs are product costs and variable costs are period costs","Inventory is valued at the commercial cost price, including selling costs"],"options_fr":["Le Direct Costing est orienté long terme et utilisé pour le reporting externe","Le coût de revient commercial = coût de fabrication + frais de vente et de distribution; le stock est valorisé au coût de fabrication","En Direct Costing, les coûts fixes sont des coûts de produit et les coûts variables des coûts de période","Le stock est valorisé au coût de revient commercial, frais de vente inclus"],"correct":1,"hint1_nl":"Denk aan de rolverdeling: DC dient de interne besluitvorming op korte termijn, AC de externe jaarrekening. En bedenk: mag je verkoopkosten activeren in een voorraad producten die nog verkocht moeten worden?","hint1_en":"Think about the division of roles: DC serves internal short-term decision-making, AC serves external annual accounts. And consider: can you capitalize selling costs in inventory of products yet to be sold?","hint1_fr":"Pensez à la répartition des rôles: la DC sert la décision interne à court terme, l'AC les comptes annuels externes. Et réfléchissez: peut-on activer des frais de vente dans un stock de produits encore à vendre ?","hint2_nl":"Bij DC: variabele kosten = productkosten, vaste kosten = periodekosten (dus optie 3 is omgekeerd). Voorraad = fabricagekostprijs, nooit commerciële kostprijs. Commerciële kostprijs = fabricagekostprijs + verkoopkosten.","hint2_en":"Under DC: variable costs = product costs, fixed costs = period costs (so option 3 is reversed). Inventory = manufacturing cost price, never commercial cost price. Commercial cost price = manufacturing cost price + selling costs.","hint2_fr":"En DC: coûts variables = coûts de produit, coûts fixes = coûts de période (l'option 3 est inversée). Stock = coût de fabrication, jamais coût commercial. Coût commercial = coût de fabrication + frais de vente.","sol_nl":"Antwoord: <strong>optie 2</strong>. De commerciële kostprijs = fabricagekostprijs + verkoop- en distributiekosten, en de voorraad wordt gewaardeerd tegen de (integrale) fabricagekostprijs. Optie 1 beschrijft AC (niet DC), optie 3 draait product- en periodekosten om, en optie 4 is fout omdat verkoopkosten nooit in de voorraad worden geactiveerd.","sol_en":"Answer: <strong>option 2</strong>. The commercial cost price = manufacturing cost price + selling and distribution costs, and inventory is valued at the (full) manufacturing cost price. Option 1 describes AC (not DC), option 3 reverses product and period costs, and option 4 is wrong because selling costs are never capitalized in inventory.","sol_fr":"Réponse: <strong>option 2</strong>. Le coût de revient commercial = coût de fabrication + frais de vente et de distribution, et le stock est valorisé au coût (complet) de fabrication. L'option 1 décrit l'AC (pas la DC), l'option 3 inverse coûts de produit et de période, et l'option 4 est fausse car les frais de vente ne sont jamais activés en stock."},{"id":"ex3_10","type":"numeric","style":"scenario","diff":"hard","title_nl":"Voorraadafname: Kaasmakerij Lotte (AC < DC)","title_en":"Inventory decrease: Cheese Maker Lotte (AC < DC)","title_fr":"Diminution de stock: Fromagerie Lotte (AC < DC)","text_nl":"Kaasmakerij Lotte verkoopt dit jaar méér dan ze produceert: <strong>W = 4.000</strong> kazen geproduceerd, <strong>afzet = 4.500</strong> kazen (de rest komt uit de voorraad). Gegeven: <strong>p = €15</strong>, <strong>v = €4</strong>, <strong>C = €20.000</strong>, <strong>N = 5.000</strong>. Bereken: (a) het NBR via AC (verkoopresultaat + bezettingsresultaat), (b) het NBR via DC, (c) het verschil AC − DC (negatief getal indien AC < DC).","text_en":"Cheese maker Lotte sells more than she produces this year: <strong>W = 4,000</strong> cheeses produced, <strong>sales = 4,500</strong> cheeses (the rest comes from inventory). Given: <strong>p = €15</strong>, <strong>v = €4</strong>, <strong>C = €20,000</strong>, <strong>N = 5,000</strong>. Calculate: (a) NBR via AC (sales result + capacity result), (b) NBR via DC, (c) the difference AC − DC (negative number if AC < DC).","text_fr":"La fromagerie Lotte vend plus qu'elle ne produit cette année: <strong>W = 4.000</strong> fromages produits, <strong>ventes = 4.500</strong> fromages (le reste vient du stock). Données: <strong>p = €15</strong>, <strong>v = €4</strong>, <strong>C = €20.000</strong>, <strong>N = 5.000</strong>. Calculez: (a) le RNE via AC (résultat sur ventes + résultat d'occupation), (b) le RNE via DC, (c) la différence AC − DC (nombre négatif si AC < DC).","hint1_nl":"De voorraad daalt hier (afzet > W). De verkochte kazen uit de oude voorraad brengen bij AC hun 'oude' vaste kosten mee terug naar de resultatenrekening — daardoor toont AC nu juist mínder winst dan DC. Reken AC uit met het schema verkoopresultaat + bezettingsresultaat (bezettingsresultaat op basis van productie W!).","hint1_en":"Inventory falls here (sales > W). The cheeses sold from old inventory bring their 'old' fixed costs back to the income statement under AC — so AC now shows less profit than DC. Compute AC with the schema sales result + capacity result (capacity result based on production W!).","hint1_fr":"Le stock diminue ici (ventes > W). Les fromages vendus du stock ancien ramènent leurs 'anciens' coûts fixes au compte de résultat en AC — l'AC montre donc moins de profit que la DC. Calculez l'AC avec le schéma résultat sur ventes + résultat d'occupation (résultat d'occupation basé sur la production W !).","hint2_nl":"k = €4 + €20.000/5.000 = €8. AC: verkoopresultaat = 4.500 × (€15 − €8) = €31.500; bezettingsresultaat = (4.000 − 5.000) × €4 = −€4.000. DC: Totale DB = (€15 − €4) × 4.500 = €49.500; NBR(DC) = €49.500 − €20.000 = ? Verschil = (W − afzet) × C/N = (4.000 − 4.500) × €4 = ?","hint2_en":"k = €4 + €20,000/5,000 = €8. AC: sales result = 4,500 × (€15 − €8) = €31,500; capacity result = (4,000 − 5,000) × €4 = −€4,000. DC: Total DB = (€15 − €4) × 4,500 = €49,500; NBR(DC) = €49,500 − €20,000 = ? Difference = (W − sales) × C/N = (4,000 − 4,500) × €4 = ?","hint2_fr":"k = €4 + €20.000/5.000 = €8. AC: résultat sur ventes = 4.500 × (€15 − €8) = €31.500; résultat d'occupation = (4.000 − 5.000) × €4 = −€4.000. DC: DB totale = (€15 − €4) × 4.500 = €49.500; RNE(DC) = €49.500 − €20.000 = ? Différence = (W − ventes) × C/N = (4.000 − 4.500) × €4 = ?","sol_nl":"C/N = €20.000/5.000 = €4; k = €4 + €4 = €8. AC: verkoopresultaat = 4.500 × (€15 − €8) = €31.500; bezettingsresultaat = (4.000 − 5.000) × €4 = −€4.000; NBR(AC) = €31.500 − €4.000 = <strong>€27.500</strong>. DC: Totale DB = €11 × 4.500 = €49.500; NBR(DC) = €49.500 − €20.000 = <strong>€29.500</strong>. Verschil AC − DC = (4.000 − 4.500) × €4 = <strong>−€2.000</strong>. De voorraad daalt met 500 stuks → AC < DC: de €2.000 vaste kosten die vroeger in de voorraad zaten, komen nu vrij ten laste van het resultaat.","sol_en":"C/N = €20,000/5,000 = €4; k = €4 + €4 = €8. AC: sales result = 4,500 × (€15 − €8) = €31,500; capacity result = (4,000 − 5,000) × €4 = −€4,000; NBR(AC) = €31,500 − €4,000 = <strong>€27,500</strong>. DC: Total DB = €11 × 4,500 = €49,500; NBR(DC) = €49,500 − €20,000 = <strong>€29,500</strong>. Difference AC − DC = (4,000 − 4,500) × €4 = <strong>−€2,000</strong>. Inventory falls by 500 units → AC < DC: the €2,000 of fixed costs previously sitting in inventory are now released against the result.","sol_fr":"C/N = €20.000/5.000 = €4; k = €4 + €4 = €8. AC: résultat sur ventes = 4.500 × (€15 − €8) = €31.500; résultat d'occupation = (4.000 − 5.000) × €4 = −€4.000; RNE(AC) = €31.500 − €4.000 = <strong>€27.500</strong>. DC: DB totale = €11 × 4.500 = €49.500; RNE(DC) = €49.500 − €20.000 = <strong>€29.500</strong>. Différence AC − DC = (4.000 − 4.500) × €4 = <strong>−€2.000</strong>. Le stock diminue de 500 unités → AC < DC: les €2.000 de coûts fixes auparavant en stock sont maintenant libérés en charge du résultat.","inputs":[{"label_nl":"NBR via AC (€)","label_en":"NBR via AC (€)","label_fr":"RNE via AC (€)","answer":27500},{"label_nl":"NBR via DC (€)","label_en":"NBR via DC (€)","label_fr":"RNE via DC (€)","answer":29500},{"label_nl":"Verschil AC − DC (€)","label_en":"Difference AC − DC (€)","label_fr":"Différence AC − DC (€)","answer":-2000}]}],"replace":false},"w4":{"theoryExtra":{"nl":"<h3>Homogene vs. heterogene productie: welke methode wanneer?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\">\n <strong>Homogene productie</strong><br>\n Eén soort product in een standaarduitvoering (bv. enkel flessen mineraalwater).<br>\n → <strong>Delingscalculatie</strong>\n</div>\n <div class=\"rule-card\">\n <strong>Heterogene productie</strong><br>\n Verschillende producten naast elkaar.<br>\n → <strong>Kostenverbijzondering</strong> (opslagmethode, KPM of ABC)\n</div>\n</div>\n<div class=\"formula\">Delingscalculatie: kostprijs = totale kosten / totale productieomvang</div>\n<div class=\"example-box\"><strong>Voorbeeld:</strong> totale kosten €480.000, productie 120.000 flessen → kp = 480.000 / 120.000 = <strong>€4 per fles</strong>.</div>\n\n<h3>Terminologie die op het examen kan opduiken</h3>\n<div class=\"tip-box\"><ul><li><strong>Primitieve</strong> opslagmethode = <strong>enkelvoudige</strong> opslagmethode (één opslagpercentage)</li><li><strong>Verfijnde</strong> opslagmethode = <strong>meervoudige</strong> opslagmethode (meerdere opslagpercentages)</li><li>Algemene definitie: <strong>kostprijs = directe kosten + een redelijk deel van de indirecte kosten</strong> — hiervoor is een <strong>verdeelsleutel</strong> nodig.</li></ul></div>\n\n<h3>Kostenverbijzondering is subjectief</h3>\n<p>Er bestaat geen \"enige juiste\" verdeling van indirecte kosten: de keuze van methode en opslagbasis is een <strong>subjectief element</strong>. Verschillende keuzes leiden tot verschillende kostprijzen, met effect op:</p>\n<ul><li>de <strong>verkoopprijs</strong>;</li><li>de <strong>voorraadwaarde</strong> (voorraden worden tegen kostprijs gewaardeerd);</li><li>de <strong>berekening van het resultaat</strong> (winst);</li><li><strong>managementbeslissingen</strong> (bv. een product schrappen of behouden).</li></ul>\n\n<h3>De keuze van de opslagbasis</h3>\n<p>Bij de primitieve methode kan de opslagbasis variëren: totale directe kosten, directe materiaalkosten, directe arbeidskosten, het aantal kg grondstof of het aantal arbeidsuren. <strong>De kostprijs varieert met de gekozen basis.</strong> Kies de basis die het best samenhangt met de indirecte kosten — een verkeerd gekozen basis geeft vervelende consequenties (foute prijzen, foute beslissingen).</p>\n<div class=\"note-box\"><strong>Let op:</strong> de basis hoeft geen geldbedrag te zijn. Bij een basis in kg of uren is de opslag geen percentage maar een <strong>tarief per kg of per uur</strong> (indirecte kosten / totaal aantal kg of uren).</div>\n\n<h3>ABC: de vier fasen (examenformulering)</h3>\n<ul>\n<li><strong>Fase 1:</strong> het <strong>identificeren en benoemen</strong> van de activiteiten;</li>\n<li><strong>Fase 2:</strong> het <strong>groeperen</strong> van logisch samenhangende activiteiten → <strong>cost pools</strong>;</li>\n<li><strong>Fase 3:</strong> per cost pool vaststellen waardoor de kosten toe- of afnemen → de <strong>cost driver</strong> (kostenveroorzakende factor);</li>\n<li><strong>Fase 4:</strong> de kosten van de pools <strong>toerekenen</strong> aan producten/diensten via verdeelsleutels gebaseerd op de cost drivers.</li>\n</ul>\n\n<h3>Van kostprijs naar verkoopprijs (winstopslag)</h3>\n<div class=\"formula\">Verkoopprijs = kostprijs × (100 + winstopslag%) / 100</div>\n<div class=\"example-box\"><strong>Opgave 5c-logica:</strong> kostprijs €4.360,04 = 100%; winstopslag 25% = €1.090,01; verkoopprijs = 125/100 × 4.360,04 = <strong>€5.450,05</strong> (≈ €5.450).</div>","en":"<h3>Homogeneous vs. heterogeneous production: which method when?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\">\n <strong>Homogeneous production</strong><br>\n One type of product in a standard version (e.g. only bottles of mineral water).<br>\n → <strong>Division calculation</strong>\n</div>\n <div class=\"rule-card\">\n <strong>Heterogeneous production</strong><br>\n Several different products.<br>\n → <strong>Cost allocation</strong> (surcharge method, cost centre method or ABC)\n</div>\n</div>\n<div class=\"formula\">Division calculation: cost price = total costs / total production volume</div>\n<div class=\"example-box\"><strong>Example:</strong> total costs €480,000, production 120,000 bottles → kp = 480,000 / 120,000 = <strong>€4 per bottle</strong>.</div>\n\n<h3>Terminology that may appear on the exam</h3>\n<div class=\"tip-box\"><ul><li><strong>Primitive</strong> surcharge method = <strong>single</strong> (enkelvoudige) surcharge method (one percentage)</li><li><strong>Refined</strong> surcharge method = <strong>multiple</strong> (meervoudige) surcharge method (several percentages)</li><li>General definition: <strong>cost price = direct costs + a reasonable share of the indirect costs</strong> — this requires an <strong>allocation key</strong>.</li></ul></div>\n\n<h3>Cost allocation is subjective</h3>\n<p>There is no single \"correct\" allocation of indirect costs: the choice of method and surcharge base is a <strong>subjective element</strong>. Different choices lead to different cost prices, affecting:</p>\n<ul><li>the <strong>selling price</strong>;</li><li>the <strong>inventory value</strong> (inventories are valued at cost price);</li><li>the <strong>calculation of the result</strong> (profit);</li><li><strong>management decisions</strong> (e.g. dropping or keeping a product).</li></ul>\n\n<h3>Choosing the surcharge base</h3>\n<p>With the primitive method the base can vary: total direct costs, direct material costs, direct labor costs, kilograms of raw material, or labor hours. <strong>The cost price varies with the chosen base.</strong> Pick the base that correlates best with the indirect costs — a wrongly chosen base has unpleasant consequences (wrong prices, wrong decisions).</p>\n<div class=\"note-box\"><strong>Note:</strong> the base does not have to be a monetary amount. With a base in kg or hours, the surcharge is not a percentage but a <strong>rate per kg or per hour</strong> (indirect costs / total kg or hours).</div>\n\n<h3>ABC: the four phases (exam wording)</h3>\n<ul>\n<li><strong>Phase 1:</strong> <strong>identifying and naming</strong> the activities;</li>\n<li><strong>Phase 2:</strong> <strong>grouping</strong> logically related activities → <strong>cost pools</strong>;</li>\n<li><strong>Phase 3:</strong> per cost pool, determining what makes the costs rise or fall → the <strong>cost driver</strong>;</li>\n<li><strong>Phase 4:</strong> <strong>allocating</strong> the pool costs to products/services using allocation keys based on the cost drivers.</li>\n</ul>\n\n<h3>From cost price to selling price (profit markup)</h3>\n<div class=\"formula\">Selling price = cost price × (100 + profit markup%) / 100</div>\n<div class=\"example-box\"><strong>Exercise 5c logic:</strong> cost price €4,360.04 = 100%; profit markup 25% = €1,090.01; selling price = 125/100 × 4,360.04 = <strong>€5,450.05</strong> (≈ €5,450).</div>","fr":"<h3>Production homogène vs hétérogène: quelle méthode quand?</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\">\n <strong>Production homogène</strong><br>\n Un seul type de produit en version standard (ex. uniquement des bouteilles d'eau minérale).<br>\n → <strong>Calcul par division</strong>\n</div>\n <div class=\"rule-card\">\n <strong>Production hétérogène</strong><br>\n Plusieurs produits différents.<br>\n → <strong>Répartition des coûts</strong> (méthode des surcharges, centres de coûts ou ABC)\n</div>\n</div>\n<div class=\"formula\">Calcul par division: prix de revient = coûts totaux / volume total de production</div>\n<div class=\"example-box\"><strong>Exemple:</strong> coûts totaux 480.000 €, production 120.000 bouteilles → kp = 480.000 / 120.000 = <strong>4 € par bouteille</strong>.</div>\n\n<h3>Terminologie pouvant apparaître à l'examen</h3>\n<div class=\"tip-box\"><ul><li>Méthode <strong>primitive</strong> = méthode à surcharge <strong>unique</strong> (enkelvoudig) — un seul pourcentage</li><li>Méthode <strong>raffinée</strong> = méthode à surcharges <strong>multiples</strong> (meervoudig) — plusieurs pourcentages</li><li>Définition générale: <strong>prix de revient = coûts directs + une part raisonnable des coûts indirects</strong> — cela nécessite une <strong>clé de répartition</strong>.</li></ul></div>\n\n<h3>La répartition des coûts est subjective</h3>\n<p>Il n'existe pas de répartition \"unique et correcte\" des coûts indirects: le choix de la méthode et de la base de surcharge est un <strong>élément subjectif</strong>. Des choix différents donnent des prix de revient différents, avec un effet sur:</p>\n<ul><li>le <strong>prix de vente</strong>;</li><li>la <strong>valeur des stocks</strong> (les stocks sont valorisés au prix de revient);</li><li>le <strong>calcul du résultat</strong> (bénéfice);</li><li>les <strong>décisions de gestion</strong> (ex. abandonner ou garder un produit).</li></ul>\n\n<h3>Le choix de la base de surcharge</h3>\n<p>Avec la méthode primitive, la base peut varier: coûts directs totaux, coûts matériaux directs, coûts salariaux directs, kilogrammes de matières premières ou heures de travail. <strong>Le prix de revient varie selon la base choisie.</strong> Choisissez la base la mieux corrélée aux coûts indirects — une base mal choisie a des conséquences fâcheuses (prix erronés, mauvaises décisions).</p>\n<div class=\"note-box\"><strong>Attention:</strong> la base ne doit pas nécessairement être un montant monétaire. Avec une base en kg ou en heures, la surcharge n'est pas un pourcentage mais un <strong>tarif par kg ou par heure</strong> (coûts indirects / total kg ou heures).</div>\n\n<h3>ABC: les quatre phases (formulation d'examen)</h3>\n<ul>\n<li><strong>Phase 1:</strong> <strong>identifier et nommer</strong> les activités;</li>\n<li><strong>Phase 2:</strong> <strong>regrouper</strong> les activités logiquement liées → <strong>cost pools</strong>;</li>\n<li><strong>Phase 3:</strong> par pool, déterminer ce qui fait augmenter ou diminuer les coûts → le <strong>cost driver</strong> (inducteur de coût);</li>\n<li><strong>Phase 4:</strong> <strong>affecter</strong> les coûts des pools aux produits/services via des clés de répartition basées sur les inducteurs.</li>\n</ul>\n\n<h3>Du prix de revient au prix de vente (marge bénéficiaire)</h3>\n<div class=\"formula\">Prix de vente = prix de revient × (100 + marge%) / 100</div>\n<div class=\"example-box\"><strong>Logique de l'exercice 5c:</strong> prix de revient 4.360,04 € = 100%; marge 25% = 1.090,01 €; prix de vente = 125/100 × 4.360,04 = <strong>5.450,05 €</strong> (≈ 5.450 €).</div>"},"exercises":[{"id":"ex4_7","type":"numeric","style":"technical","diff":"easy","title_nl":"Delingscalculatie — homogene productie","title_en":"Division calculation — homogeneous production","title_fr":"Calcul par division — production homogène","text_nl":"Gegeven (homogene productie): TK = €480.000 (totale kosten), Q = 120.000 stuks (totale productieomvang).<br><br>Bereken de kostprijs kp per stuk met de delingscalculatie.","text_en":"Given (homogeneous production): TK = €480,000 (total costs), Q = 120,000 units (total production volume).<br><br>Calculate the cost price kp per unit using the division calculation.","text_fr":"Données (production homogène): TK = 480.000 € (coûts totaux), Q = 120.000 unités (volume total de production).<br><br>Calculez le prix de revient kp par unité avec le calcul par division.","inputs":[{"label_nl":"Kostprijs per stuk (€)","label_en":"Cost price per unit (€)","label_fr":"Prix de revient par unité (€)","answer":4}],"hint1_nl":"Bij homogene productie maakt het bedrijf maar één soort product, dus elke eenheid draagt precies hetzelfde aandeel van álle kosten. Je hoeft niets te verbijzonderen: gewoon de totale kosten eerlijk verdelen over alle eenheden.","hint1_en":"With homogeneous production the firm makes only one type of product, so every unit carries exactly the same share of ALL costs. No allocation needed: simply spread total costs evenly over all units.","hint1_fr":"En production homogène, l'entreprise ne fabrique qu'un seul type de produit: chaque unité porte exactement la même part de TOUS les coûts. Aucune répartition nécessaire: divisez simplement les coûts totaux par toutes les unités.","hint2_nl":"kp = TK / Q = 480.000 / 120.000 = ?","hint2_en":"kp = TK / Q = 480,000 / 120,000 = ?","hint2_fr":"kp = TK / Q = 480.000 / 120.000 = ?","sol_nl":"kp = totale kosten / totale productieomvang = 480.000 / 120.000 = <strong>€4 per stuk</strong>.","sol_en":"kp = total costs / total production volume = 480,000 / 120,000 = <strong>€4 per unit</strong>.","sol_fr":"kp = coûts totaux / volume total de production = 480.000 / 120.000 = <strong>4 € par unité</strong>."},{"id":"ex4_8","type":"mcq","style":"scenario","diff":"medium","title_nl":"Subjectiviteit van kostenverbijzondering — Drukkerij Vermeer","title_en":"Subjectivity of cost allocation — Print Shop Vermeer","title_fr":"Subjectivité de la répartition — Imprimerie Vermeer","text_nl":"Drukkerij Vermeer twijfelt tussen directe loonkosten en directe materiaalkosten als opslagbasis. De boekhouder waarschuwt: <em>\"Die keuze is subjectief en verandert de kostprijs van elk product.\"</em><br><br>Welke grootheid verandert <strong>NIET</strong> door de keuze van de opslagbasis?","text_en":"Print shop Vermeer hesitates between direct labor costs and direct material costs as surcharge base. The accountant warns: <em>\"That choice is subjective and changes the cost price of every product.\"</em><br><br>Which quantity does <strong>NOT</strong> change with the choice of surcharge base?","text_fr":"L'imprimerie Vermeer hésite entre les coûts salariaux directs et les coûts matériaux directs comme base de surcharge. Le comptable avertit: <em>\"Ce choix est subjectif et modifie le prix de revient de chaque produit.\"</em><br><br>Quelle grandeur ne change <strong>PAS</strong> selon le choix de la base?","options_nl":["De verkoopprijs per product","De voorraadwaarde","Het totaal van de indirecte kosten van het bedrijf","De berekening van het resultaat per product"],"options_en":["The selling price per product","The inventory value","The company's total indirect costs","The result calculated per product"],"options_fr":["Le prix de vente par produit","La valeur des stocks","Le total des coûts indirects de l'entreprise","Le résultat calculé par produit"],"correct":2,"hint1_nl":"Kostenverbijzondering verdeelt een vaststaande pot indirecte kosten over de producten. De manier van verdelen verandert wel hoe de pot over producten wordt gespreid, maar niet de pot zelf.","hint1_en":"Cost allocation distributes a fixed pot of indirect costs over products. The way of distributing changes how the pot is spread across products, but not the pot itself.","hint1_fr":"La répartition distribue une enveloppe fixe de coûts indirects sur les produits. La méthode change la façon dont l'enveloppe est répartie, mais pas l'enveloppe elle-même.","hint2_nl":"PPT slide 7: verschillende keuzes → verschillen in kostprijs, met effect op verkoopprijs, voorraadwaarde, resultaat en managementbeslissingen. De totale indirecte kosten zelf blijven gelijk.","hint2_en":"PPT slide 7: different choices → different cost prices, affecting selling price, inventory value, result and management decisions. Total indirect costs themselves stay the same.","hint2_fr":"Slide 7 du PPT: des choix différents → des prix de revient différents, avec effet sur prix de vente, valeur des stocks, résultat et décisions de gestion. Les coûts indirects totaux restent identiques.","sol_nl":"Juist antwoord: <strong>C</strong>. De totale indirecte kosten (€-bedrag) staan vast; de opslagbasis bepaalt alleen hoe ze over producten verdeeld worden. De kostprijs per product verandert wél, en daarmee de verkoopprijs, de voorraadwaarde, het berekende resultaat en managementbeslissingen — precies het 'subjectieve element' uit de cursus.","sol_en":"Correct answer: <strong>C</strong>. Total indirect costs are fixed; the surcharge base only determines how they are spread over products. The cost price per product DOES change, and with it the selling price, inventory value, calculated result and management decisions — the 'subjective element' from the course.","sol_fr":"Bonne réponse: <strong>C</strong>. Les coûts indirects totaux sont fixes; la base de surcharge détermine seulement leur répartition entre produits. Le prix de revient par produit change, et avec lui le prix de vente, la valeur des stocks, le résultat calculé et les décisions de gestion — l'« élément subjectif » du cours."},{"id":"ex4_9","type":"numeric","style":"technical","diff":"medium","title_nl":"Verfijnde opslagmethode — drie opslagen en kostprijs","title_en":"Refined surcharge method — three surcharges and cost price","title_fr":"Méthode raffinée — trois surcharges et prix de revient","text_nl":"Gegeven: indirecte loonkosten = €48.000 bij totale directe loonkosten = €240.000; indirecte materiaalkosten = €33.000 bij totale directe materiaalkosten = €60.000; overige indirecte kosten = €19.000 bij totale directe kosten = €300.000.<br><br>Voor één order: L = 50 uur à €40 = €2.000 directe arbeid en M = €500 direct materiaal.<br><br>Bereken de drie opslagpercentages en de kostprijs van de order.","text_en":"Given: indirect labor costs = €48,000 on total direct labor costs = €240,000; indirect material costs = €33,000 on total direct material costs = €60,000; other indirect costs = €19,000 on total direct costs = €300,000.<br><br>For one order: L = 50 hours @ €40 = €2,000 direct labor and M = €500 direct material.<br><br>Calculate the three surcharge percentages and the cost price of the order.","text_fr":"Données: coûts salariaux indirects = 48.000 € sur des coûts salariaux directs totaux = 240.000 €; coûts matériaux indirects = 33.000 € sur des coûts matériaux directs totaux = 60.000 €; autres coûts indirects = 19.000 € sur des coûts directs totaux = 300.000 €.<br><br>Pour une commande: L = 50 heures à 40 € = 2.000 € de main-d'œuvre directe et M = 500 € de matériaux directs.<br><br>Calculez les trois pourcentages de surcharge et le prix de revient de la commande.","inputs":[{"label_nl":"Loonopslag (%)","label_en":"Labor surcharge (%)","label_fr":"Surcharge salaires (%)","answer":20},{"label_nl":"Materiaalopslag (%)","label_en":"Material surcharge (%)","label_fr":"Surcharge matériaux (%)","answer":55},{"label_nl":"Overige opslag (%)","label_en":"Other surcharge (%)","label_fr":"Autre surcharge (%)","answer":6.33},{"label_nl":"Kostprijs order (€)","label_en":"Cost price order (€)","label_fr":"Prix de revient commande (€)","answer":3333.25}],"hint1_nl":"Elke categorie indirecte kosten heeft zijn eigen grondslag: deel de indirecte kosten van elke categorie door de bijbehorende totale directe kosten. Pas daarna elk percentage toe op de juiste directe kost van de order — de overige opslag op de totale directe kosten (L+M).","hint1_en":"Each indirect cost category has its own base: divide each category's indirect costs by the corresponding total direct costs. Then apply each percentage to the matching direct cost of the order — the other surcharge applies to total direct costs (L+M).","hint1_fr":"Chaque catégorie de coûts indirects a sa propre base: divisez les coûts indirects de chaque catégorie par les coûts directs totaux correspondants. Appliquez ensuite chaque pourcentage au coût direct correspondant de la commande — l'autre surcharge s'applique aux coûts directs totaux (L+M).","hint2_nl":"loon% = 48.000/240.000 × 100 = 20% · mat% = 33.000/60.000 × 100 = 55% · overig% = 19.000/300.000 × 100 = 6,33%<br>kp = 2.000 + 500 + (20% × 2.000) + (55% × 500) + (6,33% × 2.500) = ?","hint2_en":"labor% = 48,000/240,000 × 100 = 20% · mat% = 33,000/60,000 × 100 = 55% · other% = 19,000/300,000 × 100 = 6.33%<br>kp = 2,000 + 500 + (20% × 2,000) + (55% × 500) + (6.33% × 2,500) = ?","hint2_fr":"salaire% = 48.000/240.000 × 100 = 20% · mat% = 33.000/60.000 × 100 = 55% · autre% = 19.000/300.000 × 100 = 6,33%<br>kp = 2.000 + 500 + (20% × 2.000) + (55% × 500) + (6,33% × 2.500) = ?","sol_nl":"Loonopslag = 48.000/240.000 × 100 = <strong>20%</strong><br>Materiaalopslag = 33.000/60.000 × 100 = <strong>55%</strong><br>Overige opslag = 19.000/300.000 × 100 = <strong>6,33%</strong><br>Directe kosten = 2.000 + 500 = 2.500<br>Opslagen: 20% × 2.000 = 400; 55% × 500 = 275; 6,33% × 2.500 = 158,25 → samen 833,25<br>kp = 2.500 + 833,25 = <strong>€3.333,25</strong>","sol_en":"Labor surcharge = 48,000/240,000 × 100 = <strong>20%</strong><br>Material surcharge = 33,000/60,000 × 100 = <strong>55%</strong><br>Other surcharge = 19,000/300,000 × 100 = <strong>6.33%</strong><br>Direct costs = 2,000 + 500 = 2,500<br>Surcharges: 20% × 2,000 = 400; 55% × 500 = 275; 6.33% × 2,500 = 158.25 → total 833.25<br>kp = 2,500 + 833.25 = <strong>€3,333.25</strong>","sol_fr":"Surcharge salaires = 48.000/240.000 × 100 = <strong>20%</strong><br>Surcharge matériaux = 33.000/60.000 × 100 = <strong>55%</strong><br>Autre surcharge = 19.000/300.000 × 100 = <strong>6,33%</strong><br>Coûts directs = 2.000 + 500 = 2.500<br>Surcharges: 20% × 2.000 = 400; 55% × 500 = 275; 6,33% × 2.500 = 158,25 → total 833,25<br>kp = 2.500 + 833,25 = <strong>3.333,25 €</strong>"},{"id":"ex4_10","type":"numeric","style":"scenario","diff":"easy","title_nl":"Winstopslag en verkoopprijs — Botenbouwer Marends","title_en":"Profit markup and selling price — Boat Builder Marends","title_fr":"Marge bénéficiaire et prix de vente — Constructeur Marends","text_nl":"Botenbouwer Marends heeft via de verfijnde opslagmethode de kostprijs van een roeiboot berekend: <strong>kp = €4.360,04</strong>. Het bedrijf hanteert een <strong>winstopslag van 25% op de kostprijs</strong>.<br><br>Bereken de winstopslag in euro's en de verkoopprijs (exact, op 2 decimalen).","text_en":"Boat builder Marends has calculated the cost price of a rowing boat using the refined surcharge method: <strong>kp = €4,360.04</strong>. The company uses a <strong>profit markup of 25% on cost price</strong>.<br><br>Calculate the profit markup in euros and the selling price (exact, 2 decimals).","text_fr":"Le constructeur Marends a calculé le prix de revient d'une barque avec la méthode raffinée: <strong>kp = 4.360,04 €</strong>. L'entreprise applique une <strong>marge bénéficiaire de 25% sur le prix de revient</strong>.<br><br>Calculez la marge en euros et le prix de vente (exact, 2 décimales).","inputs":[{"label_nl":"Winstopslag (€)","label_en":"Profit markup (€)","label_fr":"Marge bénéficiaire (€)","answer":1090.01},{"label_nl":"Verkoopprijs (€)","label_en":"Selling price (€)","label_fr":"Prix de vente (€)","answer":5450.05}],"hint1_nl":"De kostprijs is hier de basis (100%). De winst komt daar bovenop: de verkoopprijs is dus 100% + winstopslag% van de kostprijs. Reken eerst de winst in euro's uit en tel die bij de kostprijs.","hint1_en":"The cost price is the base (100%). Profit comes on top: the selling price is 100% + markup% of the cost price. First compute the profit in euros, then add it to the cost price.","hint1_fr":"Le prix de revient est la base (100%). Le bénéfice s'y ajoute: le prix de vente vaut 100% + marge% du prix de revient. Calculez d'abord le bénéfice en euros, puis ajoutez-le au prix de revient.","hint2_nl":"Winst = 25% × 4.360,04 = 1.090,01<br>vp = 125/100 × 4.360,04 = ?","hint2_en":"Profit = 25% × 4,360.04 = 1,090.01<br>vp = 125/100 × 4,360.04 = ?","hint2_fr":"Bénéfice = 25% × 4.360,04 = 1.090,01<br>vp = 125/100 × 4.360,04 = ?","sol_nl":"Winstopslag = 25% × 4.360,04 = <strong>€1.090,01</strong><br>Verkoopprijs = 4.360,04 + 1.090,01 = 125/100 × 4.360,04 = <strong>€5.450,05</strong> (afgerond op hele euro's: €5.450). Schema: kostprijs 100% — winstopslag 25% — verkoopprijs 125%.","sol_en":"Profit markup = 25% × 4,360.04 = <strong>€1,090.01</strong><br>Selling price = 4,360.04 + 1,090.01 = 125/100 × 4,360.04 = <strong>€5,450.05</strong> (rounded to whole euros: €5,450). Scheme: cost price 100% — markup 25% — selling price 125%.","sol_fr":"Marge = 25% × 4.360,04 = <strong>1.090,01 €</strong><br>Prix de vente = 4.360,04 + 1.090,01 = 125/100 × 4.360,04 = <strong>5.450,05 €</strong> (arrondi: 5.450 €). Schéma: prix de revient 100% — marge 25% — prix de vente 125%."}],"replace":false},"w5":{"theoryExtra":{"nl":"<h3>Veronderstellingen van de break-evenanalyse</h3>\n<p>De break-evenanalyse werkt alleen onder een aantal vereenvoudigende aannames. Het examen vraagt deze regelmatig letterlijk op!</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Variabele kosten proportioneel</strong><br>De variabele kosten per eenheid zijn constant (lineair verloop).</div>\n <div class=\"rule-card\"><strong>2. Verkoopprijs constant</strong><br>De prijs per eenheid verandert niet, ongeacht het volume (lineaire omzet).</div>\n <div class=\"rule-card\"><strong>3. Constante kosten blijven gelijk</strong><br>C verandert niet binnen het relevante bereik.</div>\n <div class=\"rule-card\"><strong>4. Afzet = productie</strong><br>Alles wat geproduceerd wordt, wordt ook verkocht (geen voorraadvorming).</div>\n <div class=\"rule-card\"><strong>5. Eén product per analyse</strong><br>De analyse kan slechts op één product(soort) tegelijk worden uitgevoerd.</div>\n</div>\n\n<h3>Handelsonderneming met uitgebreid assortiment</h3>\n<p>Een winkel of restaurant met honderden artikelen heeft geen vaste 'prijs per eenheid'. Daarom geldt:</p>\n<div class=\"note-box\"><strong>Onthoud:</strong> bij een handelsonderneming met een uitgebreid assortiment is de break-even<strong>afzet</strong> NIET te bepalen — de break-even<strong>omzet</strong> wél!</div>\n<p>Centraal staat de <strong>brutowinst</strong> = omzet − inkoopkosten. Die brutowinst dient (1) ter dekking van de constante kosten en de overige variabele kosten, en (2) ter realisering van de gewenste nettowinst.</p>\n<p>Stappenplan break-evenomzet:</p>\n<ol>\n <li>Bereken het % brutowinst t.o.v. de omzet</li>\n <li>Bereken het % overige variabele kosten t.o.v. de omzet</li>\n <li>% brutowinst − % overige variabele kosten = dekkingsbijdrage% (CM%)</li>\n <li>Deel de totale constante kosten door dat percentage</li>\n</ol>\n<div class=\"formula\">BEP_omzet = C / CM% (uitkomst in €!)</div>\n\n<h3>Meerdere vaste en variabele kostensoorten (ULTIMA-type)</h3>\n<p>Examenopgaven splitsen kosten vaak op. Tel eerst alles op:</p>\n<div class=\"formula\">C_totaal = vaste fabricagekosten + vaste verkoopkosten<br>v_totaal = variabele fabricagekosten + variabele verkoopkosten per stuk</div>\n<div class=\"example-box\"><strong>Voorbeeld ULTIMA (Van de Hoek BV):</strong> vaste fabricagekosten €2.500.000, vaste verkoopkosten €1.500.000 → C = €4.000.000. Variabel: €20 + €10 = €30 per stuk. Prijs €110 → CM = €80. BEP_afzet = 4.000.000 / 80 = <strong>50.000 stuks</strong>. Bij verwachte verkoop van 90.000 stuks: VM% = (90.000 × 110 − 50.000 × 110) / (90.000 × 110) × 100 = (9.900.000 − 5.500.000) / 9.900.000 × 100 = <strong>44,44%</strong>.</div>\n<div class=\"tip-box\"><strong>Valkuil:</strong> de 'normale productie' (100.000 stuks) is hier een afleider — voor de veiligheidsmarge gebruik je de <em>verwachte/werkelijke</em> afzet (90.000), niet de normale!</div>\n\n<h3>Terminologie budgetten: synoniemen kennen</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Ex-ante budget</strong> = <strong>voorcalculatorisch budget</strong><br>Vooraf, voorlopig budget, vastgesteld o.b.v. <em>geplande</em> productie.</div>\n <div class=\"rule-card\"><strong>Ex-post budget</strong> = <strong>nacalculatorisch budget</strong><br>Achteraf, definitief budget, vastgesteld o.b.v. <em>werkelijke</em> productie.</div>\n</div>\n<p>Verschillenanalyse is de <strong>evaluatiefunctie van budgetteren</strong>: nauwkeurig uitrekenen in hoeverre de normen/standaarden gerealiseerd zijn, en bij afwijkingen tussen norm en resultaat de <em>oorzaken</em> achterhalen. Vooraf bedenk je wat iets mag kosten; achteraf bepaal je of aan de norm voldaan is.</p>","en":"<h3>Assumptions of break-even analysis</h3>\n<p>Break-even analysis only works under simplifying assumptions. Exams regularly ask for these literally!</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Variable costs proportional</strong><br>Variable cost per unit is constant (linear).</div>\n <div class=\"rule-card\"><strong>2. Selling price constant</strong><br>The unit price does not change with volume (linear revenue).</div>\n <div class=\"rule-card\"><strong>3. Fixed costs stay equal</strong><br>C does not change within the relevant range.</div>\n <div class=\"rule-card\"><strong>4. Sales = production</strong><br>Everything produced is sold (no inventory build-up).</div>\n <div class=\"rule-card\"><strong>5. One product per analysis</strong><br>The analysis can only be done for one product (type) at a time.</div>\n</div>\n\n<h3>Trading company with a broad assortment</h3>\n<p>A shop or restaurant with hundreds of items has no single 'price per unit'. Therefore:</p>\n<div class=\"note-box\"><strong>Remember:</strong> for a trading company with a broad assortment, the break-even <strong>volume (units)</strong> CANNOT be determined — the break-even <strong>revenue</strong> CAN!</div>\n<p>Central concept: <strong>gross profit</strong> = revenue − purchase costs. This gross profit serves (1) to cover the fixed costs and the other variable costs, and (2) to realise the desired net profit.</p>\n<p>Step-by-step for break-even revenue:</p>\n<ol>\n <li>Calculate gross profit % (of revenue)</li>\n <li>Calculate other variable costs % (of revenue)</li>\n <li>Gross profit % − other variable costs % = contribution margin % (CM%)</li>\n <li>Divide total fixed costs by that percentage</li>\n</ol>\n<div class=\"formula\">BEP_revenue = C / CM% (answer in €!)</div>\n\n<h3>Multiple fixed and variable cost types (ULTIMA-type)</h3>\n<p>Exam questions often split costs. First add everything up:</p>\n<div class=\"formula\">C_total = fixed manufacturing costs + fixed selling costs<br>v_total = variable manufacturing costs + variable selling costs per unit</div>\n<div class=\"example-box\"><strong>Example ULTIMA (Van de Hoek BV):</strong> fixed manufacturing €2,500,000 + fixed selling €1,500,000 → C = €4,000,000. Variable: €20 + €10 = €30 per unit. Price €110 → CM = €80. BEP_units = 4,000,000 / 80 = <strong>50,000 units</strong>. With expected sales of 90,000 units: VM% = (9,900,000 − 5,500,000) / 9,900,000 × 100 = <strong>44.44%</strong>.</div>\n<div class=\"tip-box\"><strong>Pitfall:</strong> the 'normal production' (100,000 units) is a distractor — for the safety margin use the <em>expected/actual</em> sales (90,000), not the normal volume!</div>\n\n<h3>Budget terminology: know the synonyms</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Ex-ante budget</strong> = <strong>pre-calculated (voorcalculatorisch) budget</strong><br>Set in advance, provisional, based on <em>planned</em> production.</div>\n <div class=\"rule-card\"><strong>Ex-post budget</strong> = <strong>post-calculated (nacalculatorisch) budget</strong><br>Set afterwards, definitive, based on <em>actual</em> production.</div>\n</div>\n<p>Variance analysis is the <strong>evaluation function of budgeting</strong>: precisely calculating to what extent the norms/standards were achieved, and — when norm and result differ — finding the <em>causes</em>. Beforehand you decide what something may cost; afterwards you determine whether the norm was met.</p>","fr":"<h3>Hypothèses de l'analyse du seuil de rentabilité</h3>\n<p>L'analyse du seuil de rentabilité ne fonctionne que sous des hypothèses simplificatrices. L'examen les demande régulièrement !</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Coûts variables proportionnels</strong><br>Le coût variable par unité est constant (linéaire).</div>\n <div class=\"rule-card\"><strong>2. Prix de vente constant</strong><br>Le prix unitaire ne change pas avec le volume (CA linéaire).</div>\n <div class=\"rule-card\"><strong>3. Coûts fixes inchangés</strong><br>C ne change pas dans la zone pertinente.</div>\n <div class=\"rule-card\"><strong>4. Ventes = production</strong><br>Tout ce qui est produit est vendu (pas de stocks).</div>\n <div class=\"rule-card\"><strong>5. Un produit par analyse</strong><br>L'analyse ne peut porter que sur un seul produit (type) à la fois.</div>\n</div>\n\n<h3>Entreprise commerciale avec un large assortiment</h3>\n<p>Un magasin ou un restaurant avec des centaines d'articles n'a pas de 'prix unitaire' fixe. Donc:</p>\n<div class=\"note-box\"><strong>À retenir:</strong> pour une entreprise commerciale avec un large assortiment, le seuil en <strong>unités</strong> ne peut PAS être déterminé — le seuil en <strong>chiffre d'affaires</strong>, OUI !</div>\n<p>Concept central: la <strong>marge brute</strong> = CA − coûts d'achat. Cette marge brute sert (1) à couvrir les coûts fixes et les autres coûts variables, et (2) à réaliser le bénéfice net souhaité.</p>\n<p>Méthode pas à pas pour le seuil en CA:</p>\n<ol>\n <li>Calculez le % de marge brute (par rapport au CA)</li>\n <li>Calculez le % des autres coûts variables (par rapport au CA)</li>\n <li>% marge brute − % autres coûts variables = marge sur coûts variables % (CM%)</li>\n <li>Divisez les coûts fixes totaux par ce pourcentage</li>\n</ol>\n<div class=\"formula\">Seuil_CA = C / CM% (résultat en € !)</div>\n\n<h3>Plusieurs types de coûts fixes et variables (type ULTIMA)</h3>\n<p>Les questions d'examen scindent souvent les coûts. Additionnez d'abord tout:</p>\n<div class=\"formula\">C_total = coûts fixes de fabrication + coûts fixes de vente<br>v_total = coûts variables de fabrication + coûts variables de vente par unité</div>\n<div class=\"example-box\"><strong>Exemple ULTIMA (Van de Hoek BV):</strong> coûts fixes de fabrication €2.500.000 + de vente €1.500.000 → C = €4.000.000. Variables: €20 + €10 = €30 par unité. Prix €110 → CM = €80. Seuil_unités = 4.000.000 / 80 = <strong>50.000 unités</strong>. Avec des ventes attendues de 90.000 unités: MS% = (9.900.000 − 5.500.000) / 9.900.000 × 100 = <strong>44,44%</strong>.</div>\n<div class=\"tip-box\"><strong>Piège:</strong> la 'production normale' (100.000 unités) est un leurre — pour la marge de sécurité, utilisez les ventes <em>attendues/réelles</em> (90.000), pas le volume normal !</div>\n\n<h3>Terminologie des budgets: connaître les synonymes</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Budget ex-ante</strong> = <strong>budget précalculé (voorcalculatorisch)</strong><br>Établi à l'avance, provisoire, basé sur la production <em>planifiée</em>.</div>\n <div class=\"rule-card\"><strong>Budget ex-post</strong> = <strong>budget postcalculé (nacalculatorisch)</strong><br>Établi après coup, définitif, basé sur la production <em>réelle</em>.</div>\n</div>\n<p>L'analyse des écarts est la <strong>fonction d'évaluation de la budgétisation</strong>: calculer précisément dans quelle mesure les normes/standards ont été réalisés et, en cas d'écart entre norme et résultat, en rechercher les <em>causes</em>. À l'avance, on détermine ce que quelque chose peut coûter; après coup, on vérifie si la norme a été respectée.</p>"},"exercises":[{"id":"ex5_8","type":"numeric","style":"technical","diff":"hard","title_nl":"BEP en VM% met gesplitste kosten","title_en":"BEP and VM% with split costs","title_fr":"Seuil et MS% avec coûts scindés","text_nl":"Gegeven: vaste fabricagekosten = €2.500.000, vaste verkoopkosten = €1.500.000, variabele fabricagekosten = €20 per stuk, variabele verkoopkosten = €10 per stuk, verkoopprijs p = €110. Normale productie = 100.000 stuks; verwachte productie en verkoop = 90.000 stuks. Bereken de break-evenafzet en de veiligheidsmarge (%, 2 decimalen).","text_en":"Given: fixed manufacturing costs = €2,500,000, fixed selling costs = €1,500,000, variable manufacturing costs = €20 per unit, variable selling costs = €10 per unit, selling price p = €110. Normal production = 100,000 units; expected production and sales = 90,000 units. Calculate the break-even volume and the safety margin (%, 2 decimals).","text_fr":"Données: coûts fixes de fabrication = €2.500.000, coûts fixes de vente = €1.500.000, coûts variables de fabrication = €20 par unité, coûts variables de vente = €10 par unité, prix de vente p = €110. Production normale = 100.000 unités; production et ventes attendues = 90.000 unités. Calculez le seuil de rentabilité en unités et la marge de sécurité (%, 2 décimales).","hint1_nl":"Tel eerst álle vaste kosten op tot één C, en álle variabele kosten per stuk op tot één v. De normale productie van 100.000 stuks is een afleider: voor de veiligheidsmarge vergelijk je de verwachte afzet met het break-evenpunt.","hint1_en":"First add ALL fixed costs into one C, and ALL variable costs per unit into one v. The normal production of 100,000 units is a distractor: for the safety margin you compare expected sales with the break-even point.","hint1_fr":"Additionnez d'abord TOUS les coûts fixes en un seul C, et TOUS les coûts variables par unité en un seul v. La production normale de 100.000 unités est un leurre: pour la marge de sécurité, comparez les ventes attendues au seuil.","hint2_nl":"C = 2.500.000 + 1.500.000 = 4.000.000; v = 20 + 10 = 30. BEP_afzet = 4.000.000 / (110 − 30) = ? VM% = (90.000 − BEP) / 90.000 × 100 = ?","hint2_en":"C = 2,500,000 + 1,500,000 = 4,000,000; v = 20 + 10 = 30. BEP_units = 4,000,000 / (110 − 30) = ? VM% = (90,000 − BEP) / 90,000 × 100 = ?","hint2_fr":"C = 2.500.000 + 1.500.000 = 4.000.000; v = 20 + 10 = 30. Seuil = 4.000.000 / (110 − 30) = ? MS% = (90.000 − seuil) / 90.000 × 100 = ?","sol_nl":"C = €4.000.000, v = €30, CM = 110 − 30 = €80. BEP_afzet = 4.000.000 / 80 = <strong>50.000 stuks</strong>. VM% = (90.000 − 50.000) / 90.000 × 100 = 40.000 / 90.000 × 100 = <strong>44,44%</strong>. (Met omzet: (9.900.000 − 5.500.000)/9.900.000 = zelfde 44,44%.) De normale productie van 100.000 wordt niet gebruikt.","sol_en":"C = €4,000,000, v = €30, CM = 110 − 30 = €80. BEP_units = 4,000,000 / 80 = <strong>50,000 units</strong>. VM% = (90,000 − 50,000) / 90,000 × 100 = 40,000 / 90,000 × 100 = <strong>44.44%</strong>. (With revenue: (9,900,000 − 5,500,000)/9,900,000 = the same 44.44%.) The normal production of 100,000 is not used.","sol_fr":"C = €4.000.000, v = €30, CM = 110 − 30 = €80. Seuil = 4.000.000 / 80 = <strong>50.000 unités</strong>. MS% = (90.000 − 50.000) / 90.000 × 100 = 40.000 / 90.000 × 100 = <strong>44,44%</strong>. (Avec le CA: (9.900.000 − 5.500.000)/9.900.000 = même 44,44%.) La production normale de 100.000 n'est pas utilisée.","inputs":[{"label_nl":"BEP afzet (stuks)","label_en":"BEP volume (units)","label_fr":"Seuil (unités)","answer":50000},{"label_nl":"Veiligheidsmarge (%)","label_en":"Safety margin (%)","label_fr":"Marge de sécurité (%)","answer":44.44}]},{"id":"ex5_9","type":"mcq","style":"technical","diff":"easy","title_nl":"Veronderstellingen van de break-evenanalyse","title_en":"Assumptions of break-even analysis","title_fr":"Hypothèses de l'analyse du seuil","text_nl":"Welke van de volgende stellingen is GEEN veronderstelling van de break-evenanalyse?","text_en":"Which of the following statements is NOT an assumption of break-even analysis?","text_fr":"Laquelle des affirmations suivantes n'est PAS une hypothèse de l'analyse du seuil de rentabilité ?","options_nl":["De variabele kosten verlopen proportioneel (lineair)","De verkoopprijs per eenheid verandert niet","De afzet is gelijk aan de productie","De constante kosten stijgen mee met de productieomvang"],"options_en":["Variable costs are proportional (linear)","The selling price per unit does not change","Sales equal production","Fixed costs rise with the production volume"],"options_fr":["Les coûts variables sont proportionnels (linéaires)","Le prix de vente par unité ne change pas","Les ventes sont égales à la production","Les coûts fixes augmentent avec le volume de production"],"correct":3,"hint1_nl":"De break-evenanalyse vereenvoudigt de werkelijkheid: alles wat 'vast' is blijft vast, alles wat lineair is blijft lineair. Zoek de stelling die dit principe tegenspreekt.","hint1_en":"Break-even analysis simplifies reality: everything 'fixed' stays fixed, everything linear stays linear. Find the statement that contradicts this principle.","hint1_fr":"L'analyse du seuil simplifie la réalité: tout ce qui est 'fixe' reste fixe, tout ce qui est linéaire reste linéaire. Trouvez l'affirmation qui contredit ce principe.","hint2_nl":"De vijf aannames zijn: variabele kosten proportioneel, verkoopprijs constant, constante kosten blijven GELIJK, afzet = productie, één product per analyse. Welke optie wijkt hiervan af?","hint2_en":"The five assumptions are: variable costs proportional, price constant, fixed costs stay EQUAL, sales = production, one product per analysis. Which option deviates?","hint2_fr":"Les cinq hypothèses: coûts variables proportionnels, prix constant, coûts fixes INCHANGÉS, ventes = production, un produit par analyse. Quelle option s'en écarte ?","sol_nl":"Het juiste antwoord is D. Een kernaanname is juist dat de constante kosten GELIJK blijven binnen het relevante bereik. Stijgende vaste kosten zouden het hele model (C / (p − v)) onderuithalen. A, B en C zijn wél officiële veronderstellingen.","sol_en":"The correct answer is D. A core assumption is precisely that fixed costs stay EQUAL within the relevant range. Rising fixed costs would break the whole model (C / (p − v)). A, B and C are genuine assumptions.","sol_fr":"La bonne réponse est D. Une hypothèse fondamentale est justement que les coûts fixes restent INCHANGÉS dans la zone pertinente. Des coûts fixes croissants invalideraient le modèle (C / (p − v)). A, B et C sont de vraies hypothèses."},{"id":"ex5_10","type":"numeric","style":"scenario","diff":"medium","title_nl":"Boetiek Lotte: break-evenomzet via brutowinst","title_en":"Boutique Lotte: break-even revenue via gross profit","title_fr":"Boutique Lotte: seuil en CA via la marge brute","text_nl":"Modeboetiek 'Lotte' verkoopt honderden verschillende artikelen — een break-evenafzet in stuks is dus niet te bepalen, maar een break-evenomzet wel. De jaaromzet is €400.000. De inkoopwaarde van de verkochte artikelen is 55% van de omzet (brutowinst dus 45%). De overige variabele kosten (verpakking, commissies) zijn 15% van de omzet. De constante kosten bedragen €90.000 per jaar. Bereken de break-evenomzet en de veiligheidsmarge (%).","text_en":"Fashion boutique 'Lotte' sells hundreds of different items — so a break-even volume in units cannot be determined, but a break-even revenue can. Annual revenue is €400,000. The purchase value of goods sold is 55% of revenue (gross profit therefore 45%). Other variable costs (packaging, commissions) are 15% of revenue. Fixed costs are €90,000 per year. Calculate the break-even revenue and the safety margin (%).","text_fr":"La boutique de mode 'Lotte' vend des centaines d'articles différents — un seuil en unités est donc impossible à déterminer, mais un seuil en CA est possible. Le CA annuel est de €400.000. La valeur d'achat des articles vendus est de 55% du CA (marge brute donc 45%). Les autres coûts variables (emballage, commissions) sont de 15% du CA. Les coûts fixes sont de €90.000 par an. Calculez le seuil de rentabilité en CA et la marge de sécurité (%).","hint1_nl":"Volg het stappenplan voor een handelsonderneming: hoeveel procent van elke omzeteuro blijft over na inkoop ÉN na de overige variabele kosten? Dat percentage is de dekkingsbijdrage waarmee de vaste kosten gedekt worden.","hint1_en":"Follow the trading-company step plan: what percentage of each revenue euro remains after purchases AND after other variable costs? That percentage is the contribution margin that covers fixed costs.","hint1_fr":"Suivez la méthode pour entreprise commerciale: quel pourcentage de chaque euro de CA reste après les achats ET après les autres coûts variables ? Ce pourcentage est la marge qui couvre les coûts fixes.","hint2_nl":"CM% = 100% − 55% − 15% = 30%. BEP_omzet = 90.000 / 0,30 = ? VM% = (400.000 − BEP_omzet) / 400.000 × 100 = ?","hint2_en":"CM% = 100% − 55% − 15% = 30%. BEP_revenue = 90,000 / 0.30 = ? VM% = (400,000 − BEP_revenue) / 400,000 × 100 = ?","hint2_fr":"CM% = 100% − 55% − 15% = 30%. Seuil_CA = 90.000 / 0,30 = ? MS% = (400.000 − seuil) / 400.000 × 100 = ?","sol_nl":"Brutowinst = 100% − 55% = 45% van de omzet. Dekkingsbijdrage CM% = 45% − 15% = <strong>30%</strong>. BEP_omzet = C / CM% = 90.000 / 0,30 = <strong>€300.000</strong>. VM% = (400.000 − 300.000) / 400.000 × 100 = 100.000 / 400.000 × 100 = <strong>25%</strong>. De omzet mag nog 25% dalen voordat Lotte verlies maakt.","sol_en":"Gross profit = 100% − 55% = 45% of revenue. Contribution margin CM% = 45% − 15% = <strong>30%</strong>. BEP_revenue = C / CM% = 90,000 / 0.30 = <strong>€300,000</strong>. VM% = (400,000 − 300,000) / 400,000 × 100 = <strong>25%</strong>. Revenue can fall another 25% before Lotte makes a loss.","sol_fr":"Marge brute = 100% − 55% = 45% du CA. Marge sur coûts variables CM% = 45% − 15% = <strong>30%</strong>. Seuil_CA = C / CM% = 90.000 / 0,30 = <strong>€300.000</strong>. MS% = (400.000 − 300.000) / 400.000 × 100 = <strong>25%</strong>. Le CA peut encore baisser de 25% avant que Lotte ne soit en perte.","inputs":[{"label_nl":"Break-evenomzet (€)","label_en":"Break-even revenue (€)","label_fr":"Seuil en CA (€)","answer":300000},{"label_nl":"Veiligheidsmarge (%)","label_en":"Safety margin (%)","label_fr":"Marge de sécurité (%)","answer":25}]},{"id":"ex5_11","type":"mcq","style":"technical","diff":"easy","title_nl":"Terminologie: ex-ante en ex-post budget","title_en":"Terminology: ex-ante and ex-post budget","title_fr":"Terminologie: budget ex-ante et ex-post","text_nl":"Welke uitspraak over kostenbudgetten is juist?","text_en":"Which statement about cost budgets is correct?","text_fr":"Quelle affirmation sur les budgets de coûts est correcte ?","options_nl":["Het ex-ante budget heet ook nacalculatorisch budget en is gebaseerd op de werkelijke productie","Het ex-post budget heet ook voorcalculatorisch budget en is een voorlopig budget","Het ex-ante budget heet ook voorcalculatorisch budget en wordt vastgesteld op basis van de geplande productie","Het ex-post budget wordt vooraf opgesteld op basis van de geplande productie"],"options_en":["The ex-ante budget is also called the post-calculated budget and is based on actual production","The ex-post budget is also called the pre-calculated budget and is a provisional budget","The ex-ante budget is also called the pre-calculated (voorcalculatorisch) budget and is set based on planned production","The ex-post budget is drawn up in advance based on planned production"],"options_fr":["Le budget ex-ante s'appelle aussi budget postcalculé et se base sur la production réelle","Le budget ex-post s'appelle aussi budget précalculé et est un budget provisoire","Le budget ex-ante s'appelle aussi budget précalculé (voorcalculatorisch) et est établi sur la base de la production planifiée","Le budget ex-post est établi à l'avance sur la base de la production planifiée"],"correct":2,"hint1_nl":"'Ex-ante' betekent 'vooraf' en 'ex-post' betekent 'achteraf'. Koppel: vooraf → voorlopig → gepland; achteraf → definitief → werkelijk.","hint1_en":"'Ex-ante' means 'beforehand' and 'ex-post' means 'afterwards'. Match: beforehand → provisional → planned; afterwards → definitive → actual.","hint1_fr":"'Ex-ante' signifie 'avant' et 'ex-post' signifie 'après'. Associez: avant → provisoire → planifié; après → définitif → réel.","hint2_nl":"Ex-ante = voorcalculatorisch = voorlopig budget o.b.v. GEPLANDE productie. Ex-post = nacalculatorisch = definitief budget o.b.v. WERKELIJKE productie. Eén optie zegt precies dat.","hint2_en":"Ex-ante = pre-calculated = provisional budget based on PLANNED production. Ex-post = post-calculated = definitive budget based on ACTUAL production. One option says exactly that.","hint2_fr":"Ex-ante = précalculé = budget provisoire basé sur la production PLANIFIÉE. Ex-post = postcalculé = budget définitif basé sur la production RÉELLE. Une option dit exactement cela.","sol_nl":"Het juiste antwoord is C. Ex-ante budget = voorcalculatorisch budget: een voorlopig budget, vooraf vastgesteld op basis van de geplande productie. Het ex-post budget = nacalculatorisch budget: het definitieve budget, achteraf vastgesteld op basis van de werkelijke productie. De andere opties verwisselen telkens de termen.","sol_en":"The correct answer is C. Ex-ante budget = pre-calculated budget: a provisional budget set in advance based on planned production. The ex-post budget = post-calculated budget: the definitive budget set afterwards based on actual production. The other options mix up the terms.","sol_fr":"La bonne réponse est C. Budget ex-ante = budget précalculé: un budget provisoire établi à l'avance sur la base de la production planifiée. Le budget ex-post = budget postcalculé: le budget définitif établi après coup sur la base de la production réelle. Les autres options inversent les termes."}],"replace":false},"w6":{"theoryExtra":{"nl":"","en":"","fr":""},"exercises":[{"id":"ex6_1","type":"numeric","style":"technical","diff":"medium","title_nl":"W1+W2 — Afschrijving als enige vaste kost","title_en":"W1+W2 — Depreciation as only fixed cost","title_fr":"W1+W2 — Amortissement comme seul coût fixe","text_nl":"Gegeven: machine A=€120.000, R=€20.000, n=5 (lineair). De afschrijving is de ENIGE vaste kost. v=€8, N=10.000, p=€18, W=9.500, afzet=9.000. Bereken C (=d), k en BedR (AC).","text_en":"Given: machine A=€120,000, R=€20,000, n=5 (linear). Depreciation is the ONLY fixed cost. v=€8, N=10,000, p=€18, W=9,500, sales=9,000. Calculate C (=d), k and BedR (AC).","text_fr":"Données: machine A=120.000€, R=20.000€, n=5 (linéaire). L'amortissement est le SEUL coût fixe. v=8€, N=10.000, p=18€, W=9.500, ventes=9.000. Calculez C (=d), k et BedR (AC).","hint1_nl":"Stap 1 (W1): bereken de lineaire afschrijving d=(A−R)/n; dat is je C. Stap 2 (W2): k=C/N+v, dan VR=(p−k)×afzet en BezR=(W−N)×(C/N); BedR=VR+BezR.","hint1_en":"Step 1 (W1): compute linear depreciation d=(A−R)/n; that is your C. Step 2 (W2): k=C/N+v, then VR=(p−k)×sales and BezR=(W−N)×(C/N); BedR=VR+BezR.","hint1_fr":"Étape 1 (W1): calculez l'amortissement linéaire d=(A−R)/n; c'est votre C. Étape 2 (W2): k=C/N+v, puis VR=(p−k)×ventes et BezR=(W−N)×(C/N); BedR=VR+BezR.","hint2_nl":"d=(120.000−20.000)/5=20.000=C. k=20.000/10.000+8=2+8=10. VR=(18−10)×9.000. BezR=(9.500−10.000)×2.","hint2_en":"d=(120,000−20,000)/5=20,000=C. k=20,000/10,000+8=2+8=10. VR=(18−10)×9,000. BezR=(9,500−10,000)×2.","hint2_fr":"d=(120.000−20.000)/5=20.000=C. k=20.000/10.000+8=2+8=10. VR=(18−10)×9.000. BezR=(9.500−10.000)×2.","sol_nl":"C=d=(120.000−20.000)/5=<strong>€20.000</strong><br>k=20.000/10.000+8=2+8=<strong>€10</strong><br>VR=(18−10)×9.000=72.000<br>BezR=(9.500−10.000)×2=−1.000<br>BedR=72.000−1.000=<strong>€71.000</strong>","sol_en":"C=d=(120,000−20,000)/5=<strong>€20,000</strong><br>k=20,000/10,000+8=<strong>€10</strong><br>VR=(18−10)×9,000=72,000<br>BezR=(9,500−10,000)×2=−1,000<br>BedR=72,000−1,000=<strong>€71,000</strong>","sol_fr":"C=d=(120.000−20.000)/5=<strong>20.000€</strong><br>k=20.000/10.000+8=<strong>10€</strong><br>VR=(18−10)×9.000=72.000<br>BezR=(9.500−10.000)×2=−1.000<br>BedR=72.000−1.000=<strong>71.000€</strong>","inputs":[{"label_nl":"C = d (€)","label_en":"C = d (€)","label_fr":"C = d (€)","answer":20000},{"label_nl":"k (€)","label_en":"k (€)","label_fr":"k (€)","answer":10},{"label_nl":"BedR (€)","label_en":"BedR (€)","label_fr":"BedR (€)","answer":71000}]},{"id":"ex6_2","type":"numeric","style":"scenario","diff":"medium","title_nl":"W3+W5 — Bakkerij Lotte","title_en":"W3+W5 — Lotte's Bakery","title_fr":"W3+W5 — Boulangerie Lotte","text_nl":"Lotte runt een ambachtelijke bakkerij in Gent. Haar vaste kosten — huur, leningen en haar eigen loon — bedragen samen €120.000 per jaar. Elk brood kost haar €4 aan meel, energie en verpakking (variabele kosten) en ze verkoopt het voor €10. Dit jaar verkocht ze 25.000 broden. Bereken haar break-evenpunt (in broden), haar nettobedrijfsresultaat volgens direct costing, en haar veiligheidsmarge in %.","text_en":"Lotte runs an artisan bakery in Ghent. Her fixed costs — rent, loans and her own salary — total €120,000 per year. Each loaf costs her €4 in flour, energy and packaging (variable costs) and she sells it for €10. This year she sold 25,000 loaves. Calculate her break-even point (in loaves), her net operating result under direct costing, and her margin of safety in %.","text_fr":"Lotte tient une boulangerie artisanale à Gand. Ses coûts fixes — loyer, emprunts et son propre salaire — totalisent 120.000€ par an. Chaque pain lui coûte 4€ en farine, énergie et emballage (coûts variables) et elle le vend 10€. Cette année elle a vendu 25.000 pains. Calculez son seuil de rentabilité (en pains), son résultat net selon le direct costing, et sa marge de sécurité en %.","hint1_nl":"Eerst W5: BEP=C/(p−v). Dan W3: NBR=(p−v)×afzet−C. Tot slot W5: VM%=(werkelijke afzet−BEP)/werkelijke afzet×100.","hint1_en":"First W5: BEP=C/(p−v). Then W3: NBR=(p−v)×sales−C. Finally W5: VM%=(actual sales−BEP)/actual sales×100.","hint1_fr":"D'abord W5: BEP=C/(p−v). Puis W3: NBR=(p−v)×ventes−C. Enfin W5: MS%=(ventes réelles−BEP)/ventes réelles×100.","hint2_nl":"DB per brood=10−4=6. BEP=120.000/6. NBR=6×25.000−120.000. VM=(25.000−20.000)/25.000×100.","hint2_en":"CM per loaf=10−4=6. BEP=120,000/6. NBR=6×25,000−120,000. VM=(25,000−20,000)/25,000×100.","hint2_fr":"MC par pain=10−4=6. BEP=120.000/6. NBR=6×25.000−120.000. MS=(25.000−20.000)/25.000×100.","sol_nl":"DB=10−4=€6 per brood<br>BEP=120.000/6=<strong>20.000 broden</strong><br>NBR=6×25.000−120.000=150.000−120.000=<strong>€30.000</strong><br>VM=(25.000−20.000)/25.000×100=<strong>20%</strong>","sol_en":"CM=10−4=€6 per loaf<br>BEP=120,000/6=<strong>20,000 loaves</strong><br>NBR=6×25,000−120,000=150,000−120,000=<strong>€30,000</strong><br>VM=(25,000−20,000)/25,000×100=<strong>20%</strong>","sol_fr":"MC=10−4=6€ par pain<br>BEP=120.000/6=<strong>20.000 pains</strong><br>NBR=6×25.000−120.000=150.000−120.000=<strong>30.000€</strong><br>MS=(25.000−20.000)/25.000×100=<strong>20%</strong>","inputs":[{"label_nl":"BEP (broden)","label_en":"BEP (loaves)","label_fr":"BEP (pains)","answer":20000},{"label_nl":"NBR DC (€)","label_en":"NBR DC (€)","label_fr":"NBR DC (€)","answer":30000},{"label_nl":"VM (%)","label_en":"VM (%)","label_fr":"MS (%)","answer":20}]},{"id":"ex6_3","type":"numeric","style":"technical","diff":"medium","title_nl":"W4+W5 — Opslagmethode naar BEP","title_en":"W4+W5 — Markup method into BEP","title_fr":"W4+W5 — Méthode du coefficient vers BEP","text_nl":"Gegeven: indirecte kosten=€180.000 (volledig vast), directe kosten totaal=€450.000, directe kosten per eenheid v=€15, p=€27. Bereken: het opslagpercentage, de kostprijs per eenheid (opslagmethode) en het BEP (gebruik de indirecte kosten als C).","text_en":"Given: indirect costs=€180,000 (entirely fixed), total direct costs=€450,000, direct cost per unit v=€15, p=€27. Calculate: the markup percentage, the cost price per unit (markup method) and the BEP (use the indirect costs as C).","text_fr":"Données: coûts indirects=180.000€ (entièrement fixes), coûts directs totaux=450.000€, coût direct par unité v=15€, p=27€. Calculez: le pourcentage de majoration, le prix de revient par unité (méthode du coefficient) et le BEP (utilisez les coûts indirects comme C).","hint1_nl":"Stap 1 (W4): opslag%=indirecte kosten/directe kosten×100. Stap 2 (W4): kostprijs=v+opslag%×v. Stap 3 (W5): BEP=C/(p−v) met C=indirecte (vaste) kosten.","hint1_en":"Step 1 (W4): markup%=indirect costs/direct costs×100. Step 2 (W4): cost price=v+markup%×v. Step 3 (W5): BEP=C/(p−v) with C=indirect (fixed) costs.","hint1_fr":"Étape 1 (W4): majoration%=coûts indirects/coûts directs×100. Étape 2 (W4): prix de revient=v+majoration%×v. Étape 3 (W5): BEP=C/(p−v) avec C=coûts indirects (fixes).","hint2_nl":"Opslag=180.000/450.000×100=40%. Kostprijs=15+0,40×15=15+6=21. BEP=180.000/(27−15)=180.000/12.","hint2_en":"Markup=180,000/450,000×100=40%. Cost price=15+0.40×15=15+6=21. BEP=180,000/(27−15)=180,000/12.","hint2_fr":"Majoration=180.000/450.000×100=40%. Prix de revient=15+0,40×15=15+6=21. BEP=180.000/(27−15)=180.000/12.","sol_nl":"Opslag%=180.000/450.000×100=<strong>40%</strong><br>Kostprijs=15+0,40×15=15+6=<strong>€21</strong><br>BEP=180.000/(27−15)=180.000/12=<strong>15.000</strong>","sol_en":"Markup%=180,000/450,000×100=<strong>40%</strong><br>Cost price=15+0.40×15=15+6=<strong>€21</strong><br>BEP=180,000/(27−15)=180,000/12=<strong>15,000</strong>","sol_fr":"Majoration%=180.000/450.000×100=<strong>40%</strong><br>Prix de revient=15+0,40×15=15+6=<strong>21€</strong><br>BEP=180.000/(27−15)=180.000/12=<strong>15.000</strong>","inputs":[{"label_nl":"Opslag (%)","label_en":"Markup (%)","label_fr":"Majoration (%)","answer":40},{"label_nl":"Kostprijs (€)","label_en":"Cost price (€)","label_fr":"Prix de revient (€)","answer":21},{"label_nl":"BEP","label_en":"BEP","label_fr":"BEP","answer":15000}]},{"id":"ex6_4","type":"numeric","style":"scenario","diff":"hard","title_nl":"W3+W5 — Meubelmakerij Karim & de incidentele order","title_en":"W3+W5 — Karim's Furniture & the incidental order","title_fr":"W3+W5 — Menuiserie Karim & la commande ponctuelle","text_nl":"Karim maakt designstoelen in zijn atelier in Antwerpen. Zijn vaste kosten (atelierhuur, machines, verzekeringen) bedragen €240.000 per jaar. Per stoel betaalt hij €70 aan hout, stof en uurloon (variabel); de verkoopprijs is €130. Dit jaar verkocht hij 5.500 stoelen. Een hotelketen biedt nu een eenmalige order aan: 800 stoelen tegen €95 per stuk — onder zijn normale prijs, maar er is vrije capaciteit. Bereken: BEP, NBR vóór de order (DC), de extra winst van de order, en de totale winst mét order.","text_en":"Karim makes designer chairs in his Antwerp workshop. His fixed costs (workshop rent, machines, insurance) are €240,000 per year. Per chair he pays €70 for wood, fabric and labour (variable); the selling price is €130. This year he sold 5,500 chairs. A hotel chain now offers a one-off order: 800 chairs at €95 each — below his normal price, but he has spare capacity. Calculate: BEP, NBR before the order (DC), the extra profit from the order, and total profit with the order.","text_fr":"Karim fabrique des chaises design dans son atelier anversois. Ses coûts fixes (loyer de l'atelier, machines, assurances) s'élèvent à 240.000€ par an. Par chaise il paie 70€ de bois, tissu et main-d'œuvre (variable); le prix de vente est de 130€. Cette année il a vendu 5.500 chaises. Une chaîne hôtelière propose une commande ponctuelle: 800 chaises à 95€ pièce — sous son prix normal, mais il a de la capacité libre. Calculez: BEP, NBR avant la commande (DC), le profit supplémentaire de la commande, et le profit total avec la commande.","hint1_nl":"W5: BEP=C/(p−v). W3: NBR=(p−v)×afzet−C. Incidentele order: alleen de variabele kosten tellen — extra winst=(orderprijs−v)×orderhoeveelheid. De vaste kosten zijn al gedekt.","hint1_en":"W5: BEP=C/(p−v). W3: NBR=(p−v)×sales−C. Incidental order: only variable costs matter — extra profit=(order price−v)×order quantity. Fixed costs are already covered.","hint1_fr":"W5: BEP=C/(p−v). W3: NBR=(p−v)×ventes−C. Commande ponctuelle: seuls les coûts variables comptent — profit supp.=(prix de la commande−v)×quantité. Les coûts fixes sont déjà couverts.","hint2_nl":"BEP=240.000/(130−70)=240.000/60. NBR=60×5.500−240.000. Extra winst=(95−70)×800=25×800. Totaal=NBR+extra.","hint2_en":"BEP=240,000/(130−70)=240,000/60. NBR=60×5,500−240,000. Extra profit=(95−70)×800=25×800. Total=NBR+extra.","hint2_fr":"BEP=240.000/(130−70)=240.000/60. NBR=60×5.500−240.000. Profit supp.=(95−70)×800=25×800. Total=NBR+supp.","sol_nl":"BEP=240.000/(130−70)=240.000/60=<strong>4.000 stoelen</strong><br>NBR=(130−70)×5.500−240.000=330.000−240.000=<strong>€90.000</strong><br>Extra winst order=(95−70)×800=25×800=<strong>€20.000</strong> (95>v=70 → aanvaarden)<br>Totale winst=90.000+20.000=<strong>€110.000</strong>","sol_en":"BEP=240,000/(130−70)=240,000/60=<strong>4,000 chairs</strong><br>NBR=(130−70)×5,500−240,000=330,000−240,000=<strong>€90,000</strong><br>Extra profit=(95−70)×800=25×800=<strong>€20,000</strong> (95>v=70 → accept)<br>Total profit=90,000+20,000=<strong>€110,000</strong>","sol_fr":"BEP=240.000/(130−70)=240.000/60=<strong>4.000 chaises</strong><br>NBR=(130−70)×5.500−240.000=330.000−240.000=<strong>90.000€</strong><br>Profit supp.=(95−70)×800=25×800=<strong>20.000€</strong> (95>v=70 → accepter)<br>Profit total=90.000+20.000=<strong>110.000€</strong>","inputs":[{"label_nl":"BEP (stoelen)","label_en":"BEP (chairs)","label_fr":"BEP (chaises)","answer":4000},{"label_nl":"NBR vóór order (€)","label_en":"NBR before order (€)","label_fr":"NBR avant commande (€)","answer":90000},{"label_nl":"Extra winst order (€)","label_en":"Extra profit order (€)","label_fr":"Profit supp. commande (€)","answer":20000},{"label_nl":"Totale winst (€)","label_en":"Total profit (€)","label_fr":"Profit total (€)","answer":110000}]},{"id":"ex6_5","type":"numeric","style":"technical","diff":"hard","title_nl":"W2+W3 — AC vs DC volledig","title_en":"W2+W3 — AC vs DC complete","title_fr":"W2+W3 — AC vs DC complet","text_nl":"Gegeven: N=8.000, C=€160.000, v=€12, p=€40, W=8.400, afzet=7.800. Bereken: k (AC), BedR_AC, NBR_DC en het verschil AC−DC. Controleer het verschil met (W−afzet)×(C/N).","text_en":"Given: N=8,000, C=€160,000, v=€12, p=€40, W=8,400, sales=7,800. Calculate: k (AC), BedR_AC, NBR_DC and the AC−DC difference. Check the difference with (W−sales)×(C/N).","text_fr":"Données: N=8.000, C=160.000€, v=12€, p=40€, W=8.400, ventes=7.800. Calculez: k (AC), BedR_AC, NBR_DC et la différence AC−DC. Vérifiez la différence avec (W−ventes)×(C/N).","hint1_nl":"W2 (AC): k=C/N+v, VR=(p−k)×afzet, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3 (DC): NBR=(p−v)×afzet−C. Verschil=BedR_AC−NBR_DC.","hint1_en":"W2 (AC): k=C/N+v, VR=(p−k)×sales, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3 (DC): NBR=(p−v)×sales−C. Difference=BedR_AC−NBR_DC.","hint1_fr":"W2 (AC): k=C/N+v, VR=(p−k)×ventes, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3 (DC): NBR=(p−v)×ventes−C. Différence=BedR_AC−NBR_DC.","hint2_nl":"k=160.000/8.000+12=20+12=32. VR=(40−32)×7.800=62.400. BezR=(8.400−8.000)×20=8.000. DC=(40−12)×7.800−160.000=218.400−160.000.","hint2_en":"k=160,000/8,000+12=20+12=32. VR=(40−32)×7,800=62,400. BezR=(8,400−8,000)×20=8,000. DC=(40−12)×7,800−160,000=218,400−160,000.","hint2_fr":"k=160.000/8.000+12=20+12=32. VR=(40−32)×7.800=62.400. BezR=(8.400−8.000)×20=8.000. DC=(40−12)×7.800−160.000=218.400−160.000.","sol_nl":"k=160.000/8.000+12=20+12=<strong>€32</strong><br>VR=(40−32)×7.800=62.400, BezR=(8.400−8.000)×20=+8.000 → BedR_AC=62.400+8.000=<strong>€70.400</strong><br>NBR_DC=(40−12)×7.800−160.000=218.400−160.000=<strong>€58.400</strong><br>Verschil=70.400−58.400=<strong>€12.000</strong> — controle: (8.400−7.800)×20=600×20=12.000 ✓","sol_en":"k=160,000/8,000+12=<strong>€32</strong><br>VR=(40−32)×7,800=62,400, BezR=(8,400−8,000)×20=+8,000 → BedR_AC=<strong>€70,400</strong><br>NBR_DC=(40−12)×7,800−160,000=218,400−160,000=<strong>€58,400</strong><br>Difference=70,400−58,400=<strong>€12,000</strong> — check: (8,400−7,800)×20=12,000 ✓","sol_fr":"k=160.000/8.000+12=<strong>32€</strong><br>VR=(40−32)×7.800=62.400, BezR=(8.400−8.000)×20=+8.000 → BedR_AC=<strong>70.400€</strong><br>NBR_DC=(40−12)×7.800−160.000=218.400−160.000=<strong>58.400€</strong><br>Différence=70.400−58.400=<strong>12.000€</strong> — contrôle: (8.400−7.800)×20=12.000 ✓","inputs":[{"label_nl":"k (€)","label_en":"k (€)","label_fr":"k (€)","answer":32},{"label_nl":"BedR AC (€)","label_en":"BedR AC (€)","label_fr":"BedR AC (€)","answer":70400},{"label_nl":"NBR DC (€)","label_en":"NBR DC (€)","label_fr":"NBR DC (€)","answer":58400},{"label_nl":"Verschil (€)","label_en":"Difference (€)","label_fr":"Différence (€)","answer":12000}]},{"id":"ex6_6","type":"numeric","style":"scenario","diff":"hard","title_nl":"W1+W2+W3+W5 — Sofia's Brouwerij FINAL BOSS","title_en":"W1+W2+W3+W5 — Sofia's Brewery FINAL BOSS","title_fr":"W1+W2+W3+W5 — Brasserie de Sofia FINAL BOSS","text_nl":"Sofia start een ambachtelijke brouwerij in Leuven. Ze koopt één brouwinstallatie van €250.000 met een restwaarde van €10.000 na 6 jaar (lineaire afschrijving) — deze afschrijving is haar ENIGE vaste kost. Per krat bier betaalt ze €20 aan mout, hop, flessen en energie (variabel). Haar normale capaciteit is 8.000 kratten per jaar; de verkoopprijs is €45 per krat. Dit jaar produceerde ze 8.500 kratten maar verkocht er 7.500. Bereken: C (=afschrijving), k (AC), het BEP, BedR_AC, NBR_DC en het verschil AC−DC.","text_en":"Sofia starts a craft brewery in Leuven. She buys one brewing installation for €250,000 with a residual value of €10,000 after 6 years (linear depreciation) — this depreciation is her ONLY fixed cost. Per crate of beer she pays €20 for malt, hops, bottles and energy (variable). Her normal capacity is 8,000 crates per year; the selling price is €45 per crate. This year she produced 8,500 crates but sold 7,500. Calculate: C (=depreciation), k (AC), the BEP, BedR_AC, NBR_DC and the AC−DC difference.","text_fr":"Sofia lance une brasserie artisanale à Louvain. Elle achète une installation de brassage de 250.000€ avec une valeur résiduelle de 10.000€ après 6 ans (amortissement linéaire) — cet amortissement est son SEUL coût fixe. Par caisse de bière elle paie 20€ de malt, houblon, bouteilles et énergie (variable). Sa capacité normale est de 8.000 caisses par an; le prix de vente est de 45€ par caisse. Cette année elle a produit 8.500 caisses mais en a vendu 7.500. Calculez: C (=amortissement), k (AC), le BEP, BedR_AC, NBR_DC et la différence AC−DC.","hint1_nl":"Vier workshops in ketting: W1: d=(A−R)/n=C. W5: BEP=C/(p−v). W2: k=C/N+v, VR=(p−k)×afzet, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3: NBR_DC=(p−v)×afzet−C. Verschil=(W−afzet)×(C/N).","hint1_en":"Four workshops chained: W1: d=(A−R)/n=C. W5: BEP=C/(p−v). W2: k=C/N+v, VR=(p−k)×sales, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3: NBR_DC=(p−v)×sales−C. Difference=(W−sales)×(C/N).","hint1_fr":"Quatre ateliers enchaînés: W1: d=(A−R)/n=C. W5: BEP=C/(p−v). W2: k=C/N+v, VR=(p−k)×ventes, BezR=(W−N)×(C/N), BedR_AC=VR+BezR. W3: NBR_DC=(p−v)×ventes−C. Différence=(W−ventes)×(C/N).","hint2_nl":"C=(250.000−10.000)/6=40.000. k=40.000/8.000+20=5+20=25. BEP=40.000/(45−20)=1.600. VR=(45−25)×7.500=150.000. BezR=(8.500−8.000)×5=2.500. DC=(45−20)×7.500−40.000.","hint2_en":"C=(250,000−10,000)/6=40,000. k=40,000/8,000+20=5+20=25. BEP=40,000/(45−20)=1,600. VR=(45−25)×7,500=150,000. BezR=(8,500−8,000)×5=2,500. DC=(45−20)×7,500−40,000.","hint2_fr":"C=(250.000−10.000)/6=40.000. k=40.000/8.000+20=5+20=25. BEP=40.000/(45−20)=1.600. VR=(45−25)×7.500=150.000. BezR=(8.500−8.000)×5=2.500. DC=(45−20)×7.500−40.000.","sol_nl":"C=d=(250.000−10.000)/6=<strong>€40.000</strong><br>k=40.000/8.000+20=5+20=<strong>€25</strong><br>BEP=40.000/(45−20)=40.000/25=<strong>1.600 kratten</strong><br>VR=(45−25)×7.500=150.000, BezR=(8.500−8.000)×5=+2.500 → BedR_AC=<strong>€152.500</strong><br>NBR_DC=(45−20)×7.500−40.000=187.500−40.000=<strong>€147.500</strong><br>Verschil=152.500−147.500=<strong>€5.000</strong> — controle: (8.500−7.500)×5=5.000 ✓","sol_en":"C=d=(250,000−10,000)/6=<strong>€40,000</strong><br>k=40,000/8,000+20=<strong>€25</strong><br>BEP=40,000/25=<strong>1,600 crates</strong><br>VR=(45−25)×7,500=150,000, BezR=(8,500−8,000)×5=+2,500 → BedR_AC=<strong>€152,500</strong><br>NBR_DC=(45−20)×7,500−40,000=187,500−40,000=<strong>€147,500</strong><br>Difference=152,500−147,500=<strong>€5,000</strong> — check: (8,500−7,500)×5=5,000 ✓","sol_fr":"C=d=(250.000−10.000)/6=<strong>40.000€</strong><br>k=40.000/8.000+20=<strong>25€</strong><br>BEP=40.000/25=<strong>1.600 caisses</strong><br>VR=(45−25)×7.500=150.000, BezR=(8.500−8.000)×5=+2.500 → BedR_AC=<strong>152.500€</strong><br>NBR_DC=(45−20)×7.500−40.000=187.500−40.000=<strong>147.500€</strong><br>Différence=152.500−147.500=<strong>5.000€</strong> — contrôle: (8.500−7.500)×5=5.000 ✓","inputs":[{"label_nl":"C = d (€)","label_en":"C = d (€)","label_fr":"C = d (€)","answer":40000},{"label_nl":"k (€)","label_en":"k (€)","label_fr":"k (€)","answer":25},{"label_nl":"BEP (kratten)","label_en":"BEP (crates)","label_fr":"BEP (caisses)","answer":1600},{"label_nl":"BedR AC (€)","label_en":"BedR AC (€)","label_fr":"BedR AC (€)","answer":152500},{"label_nl":"NBR DC (€)","label_en":"NBR DC (€)","label_fr":"NBR DC (€)","answer":147500},{"label_nl":"Verschil (€)","label_en":"Difference (€)","label_fr":"Différence (€)","answer":5000}]}],"replace":true}};
const OMI_EXTRA = {"h1":{"theoryExtra":{"nl":"<h3>7. Gegevens versus informatie</h3><p>Een cruciaal onderscheid uit het boek: <strong>gegevens</strong> zijn vastgelegde feiten — representaties van de werkelijkheid (bijv. het getal \"7,4\" of de naam \"Jan\"). <strong>Informatie</strong> ontstaat pas wanneer gegevens <em>betekenis of nieuwswaarde</em> hebben voor de ontvanger (bijv. \"de klanttevredenheid is 7,4/10, onder het streefgetal\"). Dezelfde gegevens kunnen voor de ene persoon informatie zijn en voor de andere niet.</p><div class=\"tip-box\"><strong>Onthoud:</strong> gegevens + betekenis voor de ontvanger = informatie.</div><h3>8. B2C, B2B en productiefactoren</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Business-to-consumer (B2C)</strong><br>Een profitorganisatie die levert aan <em>consumenten</em> (bijv. Albert Heijn, een webshop).</div><div class=\"rule-card\"><strong>Business-to-business (B2B)</strong><br>Een profitorganisatie die levert aan <em>andere bedrijven</em> (bijv. Campina die aan supermarkten levert).</div><div class=\"rule-card\"><strong>Productiefactoren</strong><br>De middelen die een organisatie inzet in het transformatieproces: <strong>natuur</strong> (grondstoffen), <strong>arbeid</strong> (mensen), <strong>kapitaal</strong> (geld, machines, gebouwen) en <strong>ondernemerschap</strong>. Ook <strong>informatie</strong> is een onmisbaar middel in elk proces.</div></div><h3>9. De juiste hiërarchie van processen</h3><p>Het boek deelt processen eerst op in twee hoofdcategorieën: <strong>operationele processen</strong> (de uitvoerende activiteiten) en <strong>bestuurlijke processen</strong> (sturing en beheersing). De operationele processen vallen daarna uiteen in <strong>primaire</strong> processen en <strong>secundaire</strong> (ook wel <strong>ondersteunende</strong>) processen.</p><div class=\"note-box\"><strong>Schema:</strong> Processen → (1) Operationeel → primair + secundair/ondersteunend; (2) Bestuurlijk.</div><h3>10. Informatie als verbindende schakel</h3><p>Informatie verbindt de <strong>activiteiten binnen één bedrijfsproces</strong> (de output van activiteit 1, bijv. een bestelling, is de input van activiteit 2: bestelling verwerken) én verbindt <strong>bedrijfsprocessen onderling</strong>: het verkoopproces geeft via de voorraadgegevens een signaal aan het inkoopproces om bij te bestellen. Zonder die gegevensuitwisseling vallen processen uit elkaar.</p><div class=\"example-box\"><strong>Diagram in het boek (figuur 1.5/1.14, verkoop studieboeken):</strong> 7 activiteiten — 1 actualiseren website, 2 verwerken bestellingen, 3 inkopen boeken, 4 verwerken ontvangen boeken, 5 maken pakketten en facturen, 6 uitleveren pakketten, 7 verwerken ontvangen betalingen. De activiteiten zijn verbonden via <em>gegevensverzamelingen</em> zoals BESTELLINGEN, INKOOPORDERS en GROOTBOEK: activiteit 2 legt bestellingen vast die activiteit 3 en 5 weer gebruiken.</div><h3>11. Informatievoorziening en haar model</h3><p>De <strong>informatievoorziening</strong> is het proces dat ervoor zorgt dat iedereen in de organisatie op het juiste moment over de juiste informatie beschikt. Het <strong>model van de informatievoorziening</strong> (figuur 1.18) bestaat uit drie stappen:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Verzamelen en vastleggen</strong><br>Gegevens uit de werkelijkheid registreren (bijv. kassascan).</div><div class=\"rule-card\"><strong>2. Verwerken</strong><br>Gegevens bewerken, combineren, berekenen (bijv. dagomzet optellen).</div><div class=\"rule-card\"><strong>3. Verstrekken</strong><br>Informatie aanleveren aan wie ze nodig heeft (bijv. weekrapport voor de manager).</div></div><p>Een <strong>gedigitaliseerde (geautomatiseerde) informatievoorziening</strong> gebruikt computers hiervoor. <strong>Automatiseren</strong> levert twee soorten winst: <strong>efficiëntieverbetering</strong> (zelfde werk sneller en goedkoper) en <strong>effectiviteitsverbetering</strong> (nieuwe, betere mogelijkheden die handmatig onmogelijk zijn). Daarnaast verbetert de <strong>kwaliteit</strong> van informatie: betrouwbaarder, vollediger en sneller beschikbaar.</p><h3>12. Informatiekunde en ICT</h3><p><strong>Informatiekunde</strong> is het vakgebied dat de informatievoorziening bestudeert: het zit tussen de <em>organisatie</em> (wat is nodig?) en de <em>informatie- en communicatietechnologie (ICT)</em> (wat is technisch mogelijk?). ICT omvat computers, software, netwerken, communicatie- en opslagtechnologie.</p><h3>13. Soorten informatie: drie gebruiksdoelen</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Operationele informatie</strong><br>Nodig om uitvoerende activiteiten uit te voeren (bestelling, leveringsbon).</div><div class=\"rule-card\"><strong>Stuurinformatie</strong><br>Nodig om processen te besturen en beslissingen te nemen — op <em>elk</em> niveau, niet alleen de directie.</div><div class=\"rule-card\"><strong>Verantwoordingsinformatie</strong><br>Informatie waarmee je je <em>verantwoordt</em> aan anderen: jaarverslag aan aandeelhouders, btw-aangifte aan de overheid, rapportage aan een subsidiegever.</div></div><p>Ook met de <strong>omgeving</strong> wisselt een organisatie informatie uit: klanten, leveranciers, banken en overheidsinstellingen. Informatie moet <strong>betrouwbaar</strong> zijn: de hypotheekcrisis van 2008 ontstond mede doordat beslissingen op onbetrouwbare informatie gebaseerd waren.</p><h3>14. Procesbeheersing: plannen, meten, bijsturen</h3><p><strong>Procesbeheersing</strong> (figuur 1.10) is de besturingscyclus rond processen, met drie <strong>beheersactiviteiten</strong>:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Plannen</strong><br>Doelen en normen vastleggen (bijv. verkoopdoelen per vestiging).</div><div class=\"rule-card\"><strong>Meten en vergelijken</strong><br>Werkelijke prestaties (kengetallen) meten en vergelijken met de planning (streefgetallen).</div><div class=\"rule-card\"><strong>Bijsturen</strong><br>Bij afwijking actie ondernemen: het proces of de planning aanpassen.</div></div><div class=\"tip-box\">Dit is de <strong>plan-do-check-act</strong>-gedachte toegepast op bedrijfsprocessen. Kengetal en streefgetal zijn de meetinstrumenten van de stap \"meten en vergelijken\".</div><h3>15. Strategische doelen met ICT</h3><p>Volgens het boek (par. 1.6.2) investeren organisaties in ICT om strategische doelen te bereiken:</p><ul><li><strong>Operational excellence</strong>: efficiëntere en effectievere bedrijfsprocessen (bijv. Walmart);</li><li><strong>Nieuwe producten, diensten en verdienmodellen</strong>;</li><li><strong>Klant- en leveranciersintimiteit</strong>: hechtere relaties en betere afstemming;</li><li><strong>Betere besluitvorming</strong> dankzij actuele, betrouwbare informatie;</li><li><strong>Concurrentievoordeel</strong>;</li><li><strong>Overleven</strong>: soms is ICT simpelweg noodzakelijk om mee te kunnen blijven doen.</li></ul><p>Een <strong>digitale onderneming</strong> heeft vrijwel al haar bedrijfsprocessen en relaties met klanten en leveranciers digitaal ingericht. Door <strong>globalisering</strong> — Friedman noemde de wereld \"plat\" (<em>The World is Flat</em>) — kunnen organisaties wereldwijd samenwerken én concurreren.</p>","en":"<h3>7. Data versus information</h3><p>A crucial distinction from the book: <strong>data</strong> (gegevens) are recorded facts — representations of reality (e.g. the number \"7.4\" or the name \"Jan\"). <strong>Information</strong> only arises when data carry <em>meaning or news value</em> for the receiver (e.g. \"customer satisfaction is 7.4/10, below the target\"). The same data can be information for one person and not for another.</p><div class=\"tip-box\"><strong>Remember:</strong> data + meaning for the receiver = information.</div><h3>8. B2C, B2B and production factors</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Business-to-consumer (B2C)</strong><br>A profit organisation selling to <em>consumers</em> (e.g. a supermarket or webshop).</div><div class=\"rule-card\"><strong>Business-to-business (B2B)</strong><br>A profit organisation selling to <em>other companies</em> (e.g. Campina supplying supermarkets).</div><div class=\"rule-card\"><strong>Production factors</strong><br>The resources an organisation uses in the transformation process: <strong>nature</strong> (raw materials), <strong>labour</strong> (people), <strong>capital</strong> (money, machines, buildings) and <strong>entrepreneurship</strong>. <strong>Information</strong> is also an indispensable resource in every process.</div></div><h3>9. The correct hierarchy of processes</h3><p>The book first splits processes into two main categories: <strong>operational processes</strong> (the executing activities) and <strong>managerial (bestuurlijke) processes</strong> (steering and control). Operational processes then split into <strong>primary</strong> and <strong>secondary</strong> (also called <strong>supporting</strong>) processes.</p><div class=\"note-box\"><strong>Scheme:</strong> Processes → (1) Operational → primary + secondary/supporting; (2) Managerial.</div><h3>10. Information as the connecting link</h3><p>Information connects the <strong>activities within one business process</strong> (the output of activity 1, e.g. an order, is the input of activity 2: process the order) and connects <strong>business processes to each other</strong>: the sales process signals the purchasing process via stock data to reorder. Without that data exchange, processes fall apart.</p><div class=\"example-box\"><strong>Diagram in the book (fig. 1.5/1.14, selling study books):</strong> 7 activities — 1 update website, 2 process orders, 3 purchase books, 4 process received books, 5 make packages and invoices, 6 deliver packages, 7 process received payments. The activities are linked through <em>data collections</em> such as ORDERS, PURCHASE ORDERS and GENERAL LEDGER: activity 2 records orders that activities 3 and 5 reuse.</div><h3>11. Information supply and its model</h3><p>The <strong>information supply</strong> (informatievoorziening) is the process that ensures everyone in the organisation has the right information at the right time. The <strong>model of the information supply</strong> (fig. 1.18) has three steps:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Collect and record</strong><br>Register data from reality (e.g. checkout scan).</div><div class=\"rule-card\"><strong>2. Process</strong><br>Edit, combine, calculate data (e.g. sum daily revenue).</div><div class=\"rule-card\"><strong>3. Provide</strong><br>Deliver information to whoever needs it (e.g. weekly report for the manager).</div></div><p>A <strong>digitised (automated) information supply</strong> uses computers for this. <strong>Automation</strong> yields two kinds of gains: <strong>efficiency improvement</strong> (same work faster and cheaper) and <strong>effectiveness improvement</strong> (new, better possibilities impossible by hand). It also improves the <strong>quality</strong> of information: more reliable, more complete, available faster.</p><h3>12. Information science and ICT</h3><p><strong>Information science</strong> (informatiekunde) is the field that studies the information supply: it sits between the <em>organisation</em> (what is needed?) and <em>information and communication technology (ICT)</em> (what is technically possible?). ICT comprises computers, software, networks, communication and storage technology.</p><h3>13. Types of information: three purposes</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Operational information</strong><br>Needed to carry out executing activities (order, delivery note).</div><div class=\"rule-card\"><strong>Steering information</strong><br>Needed to control processes and make decisions — at <em>every</em> level, not just top management.</div><div class=\"rule-card\"><strong>Accountability information</strong><br>Information used to <em>account</em> to others: annual report to shareholders, VAT return to the government, report to a subsidy provider.</div></div><p>An organisation also exchanges information with its <strong>environment</strong>: customers, suppliers, banks and government bodies. Information must be <strong>reliable</strong>: the 2008 mortgage crisis partly arose because decisions were based on unreliable information.</p><h3>14. Process control: plan, measure, adjust</h3><p><strong>Process control</strong> (fig. 1.10) is the control cycle around processes, with three <strong>control activities</strong>:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Plan</strong><br>Set goals and norms (e.g. sales targets per branch).</div><div class=\"rule-card\"><strong>Measure and compare</strong><br>Measure actual performance (key figures) and compare with the plan (target figures).</div><div class=\"rule-card\"><strong>Adjust</strong><br>Take action on deviations: adapt the process or the plan.</div></div><div class=\"tip-box\">This is the <strong>plan-do-check-act</strong> idea applied to business processes. Key figure and target figure are the measuring instruments of the \"measure and compare\" step.</div><h3>15. Strategic goals through ICT</h3><p>According to the book (par. 1.6.2), organisations invest in ICT to achieve strategic goals:</p><ul><li><strong>Operational excellence</strong>: more efficient and effective business processes (e.g. Walmart);</li><li><strong>New products, services and business models</strong>;</li><li><strong>Customer and supplier intimacy</strong>: closer relationships and better alignment;</li><li><strong>Better decision-making</strong> thanks to up-to-date, reliable information;</li><li><strong>Competitive advantage</strong>;</li><li><strong>Survival</strong>: sometimes ICT is simply necessary to keep up.</li></ul><p>A <strong>digital enterprise</strong> has nearly all its business processes and relations with customers and suppliers organised digitally. Through <strong>globalisation</strong> — Friedman called the world \"flat\" (<em>The World is Flat</em>) — organisations can cooperate and compete worldwide.</p>","fr":"<h3>7. Données versus information</h3><p>Une distinction cruciale du livre: les <strong>données</strong> (gegevens) sont des faits enregistrés — des représentations de la réalité (p. ex. le nombre « 7,4 » ou le nom « Jan »). L'<strong>information</strong> n'apparaît que lorsque les données ont une <em>signification ou valeur de nouveauté</em> pour le destinataire (p. ex. « la satisfaction client est de 7,4/10, sous l'objectif »). Les mêmes données peuvent être de l'information pour une personne et pas pour une autre.</p><div class=\"tip-box\"><strong>À retenir:</strong> données + signification pour le destinataire = information.</div><h3>8. B2C, B2B et facteurs de production</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Business-to-consumer (B2C)</strong><br>Une organisation à but lucratif qui vend aux <em>consommateurs</em> (p. ex. un supermarché, une boutique en ligne).</div><div class=\"rule-card\"><strong>Business-to-business (B2B)</strong><br>Une organisation à but lucratif qui vend à <em>d'autres entreprises</em> (p. ex. Campina qui livre aux supermarchés).</div><div class=\"rule-card\"><strong>Facteurs de production</strong><br>Les ressources qu'une organisation utilise dans le processus de transformation: <strong>nature</strong> (matières premières), <strong>travail</strong> (personnes), <strong>capital</strong> (argent, machines, bâtiments) et <strong>esprit d'entreprise</strong>. L'<strong>information</strong> est aussi une ressource indispensable dans chaque processus.</div></div><h3>9. La bonne hiérarchie des processus</h3><p>Le livre divise d'abord les processus en deux catégories principales: les <strong>processus opérationnels</strong> (activités d'exécution) et les <strong>processus de gestion</strong> (pilotage et contrôle). Les processus opérationnels se divisent ensuite en processus <strong>primaires</strong> et <strong>secondaires</strong> (aussi appelés <strong>de soutien</strong>).</p><div class=\"note-box\"><strong>Schéma:</strong> Processus → (1) Opérationnel → primaire + secondaire/soutien; (2) De gestion.</div><h3>10. L'information comme maillon de liaison</h3><p>L'information relie les <strong>activités au sein d'un même processus</strong> (la sortie de l'activité 1, p. ex. une commande, est l'entrée de l'activité 2: traiter la commande) et relie <strong>les processus entre eux</strong>: le processus de vente signale au processus d'achat, via les données de stock, qu'il faut recommander. Sans cet échange de données, les processus se désagrègent.</p><div class=\"example-box\"><strong>Diagramme du livre (fig. 1.5/1.14, vente de manuels):</strong> 7 activités — 1 actualiser le site web, 2 traiter les commandes, 3 acheter les livres, 4 traiter les livres reçus, 5 préparer colis et factures, 6 livrer les colis, 7 traiter les paiements reçus. Les activités sont reliées par des <em>collections de données</em> telles que COMMANDES, ORDRES D'ACHAT et GRAND LIVRE: l'activité 2 enregistre des commandes que les activités 3 et 5 réutilisent.</div><h3>11. L'approvisionnement en information et son modèle</h3><p>L'<strong>approvisionnement en information</strong> (informatievoorziening) est le processus qui garantit que chacun dans l'organisation dispose de la bonne information au bon moment. Le <strong>modèle de l'approvisionnement en information</strong> (fig. 1.18) comporte trois étapes:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Collecter et enregistrer</strong><br>Enregistrer des données de la réalité (p. ex. scan en caisse).</div><div class=\"rule-card\"><strong>2. Traiter</strong><br>Manipuler, combiner, calculer les données (p. ex. additionner le chiffre d'affaires journalier).</div><div class=\"rule-card\"><strong>3. Fournir</strong><br>Livrer l'information à qui en a besoin (p. ex. rapport hebdomadaire pour le manager).</div></div><p>Un <strong>approvisionnement en information numérisé (automatisé)</strong> utilise des ordinateurs pour cela. L'<strong>automatisation</strong> apporte deux types de gains: l'<strong>amélioration de l'efficience</strong> (même travail, plus vite et moins cher) et l'<strong>amélioration de l'efficacité</strong> (nouvelles possibilités, impossibles à la main). Elle améliore aussi la <strong>qualité</strong> de l'information: plus fiable, plus complète, disponible plus vite.</p><h3>12. Informatique de gestion et TIC</h3><p>L'<strong>informatique de gestion</strong> (informatiekunde) est la discipline qui étudie l'approvisionnement en information: elle se situe entre l'<em>organisation</em> (que faut-il ?) et les <em>technologies de l'information et de la communication (TIC)</em> (qu'est-ce qui est techniquement possible ?). Les TIC comprennent ordinateurs, logiciels, réseaux, technologies de communication et de stockage.</p><h3>13. Types d'information: trois finalités</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Information opérationnelle</strong><br>Nécessaire pour exécuter les activités (commande, bon de livraison).</div><div class=\"rule-card\"><strong>Information de pilotage</strong><br>Nécessaire pour piloter les processus et décider — à <em>chaque</em> niveau, pas seulement la direction.</div><div class=\"rule-card\"><strong>Information de justification</strong><br>Information avec laquelle on <em>rend des comptes</em> à d'autres: rapport annuel aux actionnaires, déclaration TVA à l'État, rapport à un organisme subsidiant.</div></div><p>L'organisation échange aussi de l'information avec son <strong>environnement</strong>: clients, fournisseurs, banques et administrations. L'information doit être <strong>fiable</strong>: la crise des subprimes de 2008 est née en partie de décisions fondées sur des informations non fiables.</p><h3>14. Maîtrise des processus: planifier, mesurer, ajuster</h3><p>La <strong>maîtrise des processus</strong> (fig. 1.10) est le cycle de pilotage autour des processus, avec trois <strong>activités de contrôle</strong>:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Planifier</strong><br>Fixer objectifs et normes (p. ex. objectifs de vente par site).</div><div class=\"rule-card\"><strong>Mesurer et comparer</strong><br>Mesurer les performances réelles (indicateurs) et les comparer au plan (valeurs cibles).</div><div class=\"rule-card\"><strong>Ajuster</strong><br>Agir en cas d'écart: adapter le processus ou le plan.</div></div><div class=\"tip-box\">C'est l'idée <strong>plan-do-check-act</strong> appliquée aux processus d'entreprise. L'indicateur et la valeur cible sont les instruments de mesure de l'étape « mesurer et comparer ».</div><h3>15. Objectifs stratégiques grâce aux TIC</h3><p>Selon le livre (par. 1.6.2), les organisations investissent dans les TIC pour atteindre des objectifs stratégiques:</p><ul><li><strong>Excellence opérationnelle</strong>: des processus plus efficients et efficaces (p. ex. Walmart);</li><li><strong>Nouveaux produits, services et modèles économiques</strong>;</li><li><strong>Intimité client et fournisseur</strong>: relations plus étroites et meilleur alignement;</li><li><strong>Meilleure prise de décision</strong> grâce à une information actuelle et fiable;</li><li><strong>Avantage concurrentiel</strong>;</li><li><strong>Survie</strong>: parfois les TIC sont simplement nécessaires pour rester dans la course.</li></ul><p>Une <strong>entreprise numérique</strong> a presque tous ses processus et ses relations avec clients et fournisseurs organisés numériquement. Grâce à la <strong>mondialisation</strong> — Friedman parlait d'un monde « plat » (<em>The World is Flat</em>) — les organisations coopèrent et se concurrencent à l'échelle mondiale.</p>"},"exercises":[{"id":"h1_7","correct":1,"text_nl":"Wat is volgens het handboek het juiste onderscheid tussen gegevens en informatie?","text_en":"According to the textbook, what is the correct distinction between data and information?","text_fr":"Selon le manuel, quelle est la bonne distinction entre données et information ?","options_nl":["Gegevens zijn digitaal, informatie is op papier","Gegevens zijn vastgelegde feiten; informatie zijn gegevens die betekenis hebben voor de ontvanger","Informatie zijn vastgelegde feiten; gegevens zijn verwerkte informatie","Gegevens en informatie zijn synoniemen"],"options_en":["Data are digital, information is on paper","Data are recorded facts; information is data that has meaning for the receiver","Information consists of recorded facts; data are processed information","Data and information are synonyms"],"options_fr":["Les données sont numériques, l'information est sur papier","Les données sont des faits enregistrés; l'information est constituée de données ayant une signification pour le destinataire","L'information est constituée de faits enregistrés; les données sont de l'information traitée","Données et information sont des synonymes"],"hint1_nl":"Denk aan wat het getal '7,4' op zich betekent versus '7,4/10 klanttevredenheid, onder het doel'.","hint1_en":"Think of what the number '7.4' means on its own versus '7.4/10 customer satisfaction, below target'.","hint1_fr":"Pensez à ce que signifie le nombre « 7,4 » seul, par rapport à « 7,4/10 de satisfaction client, sous l'objectif ».","hint2_nl":"Regel: gegevens = representaties van de werkelijkheid; informatie = gegevens met betekenis/nieuwswaarde voor de ontvanger.","hint2_en":"Rule: data = representations of reality; information = data with meaning/news value for the receiver.","hint2_fr":"Règle: données = représentations de la réalité; information = données avec signification/valeur de nouveauté pour le destinataire.","sol_nl":"Gegevens zijn vastgelegde feiten (representaties van de werkelijkheid). Pas wanneer ze betekenis of nieuwswaarde hebben voor de ontvanger, worden ze informatie. Antwoord B.","sol_en":"Data are recorded facts (representations of reality). Only when they carry meaning or news value for the receiver do they become information. Answer B.","sol_fr":"Les données sont des faits enregistrés (représentations de la réalité). Elles ne deviennent de l'information que lorsqu'elles ont une signification ou une valeur de nouveauté pour le destinataire. Réponse B."},{"id":"h1_8","correct":2,"text_nl":"Bakkerij Korst plande 500 broden per dag te verkopen. Uit de kassagegevens blijkt dat er gemiddeld maar 410 verkocht worden. De zaakvoerder beslist daarom de productie te verlagen en een promotiecampagne te starten. Welke beheersactiviteit voert de zaakvoerder uit met deze beslissing?","text_en":"Korst bakery planned to sell 500 loaves per day. Checkout data show only 410 are sold on average. The owner therefore decides to lower production and start a promotion campaign. Which control activity is the owner performing with this decision?","text_fr":"La boulangerie Korst prévoyait de vendre 500 pains par jour. Les données de caisse montrent qu'il ne s'en vend en moyenne que 410. Le gérant décide donc de réduire la production et de lancer une promotion. Quelle activité de contrôle le gérant exécute-t-il avec cette décision ?","options_nl":["Plannen","Meten en vergelijken","Bijsturen","Verantwoorden"],"options_en":["Planning","Measuring and comparing","Adjusting","Accounting (justifying)"],"options_fr":["Planifier","Mesurer et comparer","Ajuster","Rendre des comptes"],"hint1_nl":"Het meten (410 vs 500) is al gebeurd. Wat doet hij nu met die afwijking?","hint1_en":"The measuring (410 vs 500) has already happened. What is he doing with that deviation now?","hint1_fr":"La mesure (410 vs 500) a déjà eu lieu. Que fait-il maintenant de cet écart ?","hint2_nl":"Procesbeheersing = plannen → meten en vergelijken → bijsturen. Actie ondernemen na een afwijking is de derde stap.","hint2_en":"Process control = plan → measure and compare → adjust. Taking action after a deviation is the third step.","hint2_fr":"Maîtrise des processus = planifier → mesurer et comparer → ajuster. Agir après un écart est la troisième étape.","sol_nl":"De planning (500) en de meting/vergelijking (410 vs 500) zijn al gebeurd. Door de productie aan te passen en een promotie te starten, onderneemt hij actie op de afwijking: dat is bijsturen. Antwoord C.","sol_en":"The planning (500) and the measuring/comparison (410 vs 500) have already taken place. By adapting production and launching a promotion he acts on the deviation: that is adjusting. Answer C.","sol_fr":"La planification (500) et la mesure/comparaison (410 vs 500) ont déjà eu lieu. En adaptant la production et en lançant une promotion, il agit sur l'écart: c'est l'ajustement. Réponse C."},{"id":"h1_9","correct":3,"text_nl":"Welke van de volgende is GEEN klassieke productiefactor in het transformatieproces?","text_en":"Which of the following is NOT a classic production factor in the transformation process?","text_fr":"Lequel des éléments suivants n'est PAS un facteur de production classique dans le processus de transformation ?","options_nl":["Natuur (grondstoffen)","Arbeid","Kapitaal","Verantwoordingsinformatie"],"options_en":["Nature (raw materials)","Labour","Capital","Accountability information"],"options_fr":["Nature (matières premières)","Travail","Capital","Information de justification"],"hint1_nl":"De productiefactoren zijn de middelen die een organisatie inzet om producten of diensten voort te brengen.","hint1_en":"Production factors are the resources an organisation deploys to produce goods or services.","hint1_fr":"Les facteurs de production sont les ressources qu'une organisation mobilise pour produire des biens ou services.","hint2_nl":"De klassieke productiefactoren zijn: natuur, arbeid, kapitaal (en ondernemerschap). Verantwoordingsinformatie is een soort informatie, geen productiefactor.","hint2_en":"The classic production factors are: nature, labour, capital (and entrepreneurship). Accountability information is a type of information, not a production factor.","hint2_fr":"Les facteurs de production classiques sont: nature, travail, capital (et esprit d'entreprise). L'information de justification est un type d'information, pas un facteur de production.","sol_nl":"Natuur, arbeid en kapitaal (plus ondernemerschap) zijn de productiefactoren. Verantwoordingsinformatie is een gebruiksdoel van informatie (je verantwoorden aan bijv. aandeelhouders of de overheid), geen productiefactor. Antwoord D.","sol_en":"Nature, labour and capital (plus entrepreneurship) are the production factors. Accountability information is a purpose of information (accounting to e.g. shareholders or the government), not a production factor. Answer D.","sol_fr":"Nature, travail et capital (plus l'esprit d'entreprise) sont les facteurs de production. L'information de justification est une finalité de l'information (rendre des comptes aux actionnaires ou à l'État), pas un facteur de production. Réponse D."},{"id":"h1_10","correct":2,"text_nl":"Brouwerij Hop BV stelt elk jaar een jaarverslag op voor haar aandeelhouders en dient een btw-aangifte in bij de overheid. Daarnaast levert ze aan supermarktketens, niet rechtstreeks aan consumenten. Welk type informatie zijn het jaarverslag en de btw-aangifte, en wat voor soort onderneming is Hop BV?","text_en":"Brewery Hop BV draws up an annual report for its shareholders every year and files a VAT return with the government. It also sells to supermarket chains, not directly to consumers. What type of information are the annual report and the VAT return, and what kind of company is Hop BV?","text_fr":"La brasserie Hop BV établit chaque année un rapport annuel pour ses actionnaires et dépose une déclaration TVA auprès de l'État. Elle vend en outre à des chaînes de supermarchés, pas directement aux consommateurs. De quel type d'information s'agit-il, et quel genre d'entreprise est Hop BV ?","options_nl":["Stuurinformatie; een B2C-onderneming","Operationele informatie; een non-profitorganisatie","Verantwoordingsinformatie; een B2B-onderneming","Managementinformatie; een publieke organisatie"],"options_en":["Steering information; a B2C company","Operational information; a non-profit organisation","Accountability information; a B2B company","Management information; a public organisation"],"options_fr":["Information de pilotage; une entreprise B2C","Information opérationnelle; une organisation sans but lucratif","Information de justification; une entreprise B2B","Information de gestion; une organisation publique"],"hint1_nl":"Aan wie is deze informatie gericht, en met welk doel? En aan wie verkoopt Hop BV?","hint1_en":"Who is this information addressed to, and for what purpose? And who does Hop BV sell to?","hint1_fr":"À qui cette information est-elle destinée, et dans quel but ? Et à qui Hop BV vend-elle ?","hint2_nl":"Verantwoordingsinformatie = informatie waarmee je je verantwoordt aan externe partijen (aandeelhouders, overheid). B2B = leveren aan andere bedrijven.","hint2_en":"Accountability information = information used to account to external parties (shareholders, government). B2B = selling to other companies.","hint2_fr":"Information de justification = information servant à rendre des comptes à des parties externes (actionnaires, État). B2B = vendre à d'autres entreprises.","sol_nl":"Een jaarverslag en een btw-aangifte dienen om verantwoording af te leggen aan aandeelhouders en overheid: verantwoordingsinformatie. Omdat Hop BV aan supermarktketens (bedrijven) levert, is ze business-to-business. Antwoord C.","sol_en":"An annual report and a VAT return serve to account to shareholders and the government: accountability information. Because Hop BV sells to supermarket chains (companies), it is business-to-business. Answer C.","sol_fr":"Un rapport annuel et une déclaration TVA servent à rendre des comptes aux actionnaires et à l'État: information de justification. Comme Hop BV vend à des chaînes de supermarchés (des entreprises), elle est en business-to-business. Réponse C."}]},"h2":{"theoryExtra":{"nl":"<h3>8. Gegevensrepresentatie: de werkelijkheid gevangen in gegevens</h3><p>Gegevens zijn een <strong>representatie van de werkelijkheid</strong>: ze beelden objecten en gebeurtenissen (voorraad, klanten, verkopen) af in symbolen, zodat je de werkelijkheid niet zelf hoeft waar te nemen. Een voorraadlijst vertelt je hoeveel folie er ligt zonder dat je het magazijn inloopt.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Voordelen van gegevensrepresentatie</strong><br>Overzicht zonder directe waarneming, sneller en op afstand raadpleegbaar, gegevens van verschillende plaatsen combineerbaar, en bruikbaar voor analyses die met het blote oog onmogelijk zijn.</div><div class=\"rule-card\"><strong>Nauwkeurige definities nodig</strong><br>Iedereen moet hetzelfde verstaan onder een gegeven. Wat telt als \\\"verkoop\\\": bij bestelling of bij levering? Zonder eenduidige definities is de representatie onbetrouwbaar.</div></div><h3>9. Gestructureerde vs. ongestructureerde gegevens</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Gestructureerde gegevens</strong><br>Vaste indeling: elk gegeven heeft een naam (veld) en een afgesproken vorm. Bijv. postcode, klantnummer, geboortedatum. Makkelijk automatisch te verwerken.</div><div class=\"rule-card\"><strong>Ongestructureerde gegevens</strong><br>Vrije vorm: teksten, e-mails, foto's, video's. Bevatten veel informatie maar zijn moeilijker automatisch te verwerken; vaak zoek je erin met zoekwoorden.</div></div><h3>10. Informatievoorziening als productieproces</h3><p>De <strong>informatiebehoefte</strong> is de informatie die een gebruiker nodig heeft voor zijn taken en beslissingen. De informatievoorziening werkt als een <strong>transformatieproces</strong>, vergelijkbaar met een fabriek (beschrijving van het schema in het boek): <em>invoer</em> (gegevens verzamelen en invoeren) &rarr; <em>verwerking</em> (vastleggen, bewaren, bewerken) &rarr; <em>uitvoer</em> (informatie verstrekken). Het beheren van dit proces is een <strong>kerntaak van het management</strong>.</p><h3>11. Verzamelen en invoeren van gegevens</h3><p>Gegevens komen uit <strong>interne bronnen</strong> (eigen kassa's, administratie) en <strong>externe bronnen</strong> (leveranciers, externe databanken, internet). Bij handmatige invoer ontstaan fouten (GIGO), daarom:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Invoer aan de bron</strong><br>Gegevens vastleggen op de plaats en het moment waar ze ontstaan, liefst door wie ze kent. Minder overtikken = minder fouten.</div><div class=\"rule-card\"><strong>Geautomatiseerde invoer</strong><br>Streepjescode (barcode), QR-code, RFID-chips, scanners en het Internet of Things leggen gegevens automatisch vast, zonder typwerk.</div><div class=\"rule-card\"><strong>Invoercontroles</strong><br>Geprogrammeerde controles (bijv. geldige datum), controlecijfers (zoals in rekeningnummers) en redundante (dubbele) invoer sporen fouten op.</div></div><h3>12. Opslag: sleutels en locatie</h3><p>Extra begrippen: een concrete waarde in een veld heet een <strong>gegevenswaarde</strong>; een afgesproken schrijfwijze heet een <strong>standaardnotatie</strong> (bijv. datum altijd dd-mm-jjjj). Het veld waarmee je records terugvindt heet de <strong>ingang</strong> of <strong>sleutel</strong> (bijv. KlantID).</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Centrale opslag</strong><br>Alle gegevens op één plaats (bijv. server hoofdkantoor). Eén versie van de waarheid, makkelijk beheer en beveiliging.</div><div class=\"rule-card\"><strong>Decentrale opslag</strong><br>Elke vestiging/afdeling bewaart haar eigen gegevens lokaal. Snel lokaal, maar risico op verschillende versies.</div><div class=\"rule-card\"><strong>Gedistribueerde opslag</strong><br>Gegevens verspreid over meerdere gekoppelde computers die als één geheel samenwerken (zoals bij cloud/SSP).</div></div><h3>13. Soorten rapportages</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Periodieke rapportage</strong><br>Op vaste tijdstippen, vaste inhoud. Bijv. maandelijks omzetrapport.</div><div class=\"rule-card\"><strong>Rapportage op uitzonderingsbasis</strong><br>Alleen wanneer iets afwijkt van de norm. Bijv. melding enkel als voorraad onder de drempel zakt.</div><div class=\"rule-card\"><strong>Rapportage op aanvraag</strong><br>De gebruiker vraagt eenmalig een specifiek rapport op wanneer hij het nodig heeft.</div><div class=\"rule-card\"><strong>Interactieve rapportage</strong><br>De gebruiker klikt zelf door de informatie en zoomt in, bijv. een digitaal dashboard met live cijfers.</div></div><div class=\"note-box\"><strong>Let op (boek vs. ezelsbrug):</strong> het boek noemt drie kwaliteitseisen voor uitvoergegevens: <strong>relevantie</strong>, <strong>betrouwbaarheid</strong> en <strong>toegankelijkheid</strong> — tijdigheid (op tijd beschikbaar) valt onder toegankelijkheid.</div><div class=\"tip-box\"><strong>Begrip uit de actualiteit:</strong> een <strong>digital twin</strong> is een digitale kopie van een echt object of systeem (machine, gebouw, zelfs een schaatser) waarmee je de werkelijkheid kunt simuleren en analyseren zonder het echte object te gebruiken — gegevensrepresentatie in het extreme.</div>","en":"<h3>8. Data representation: capturing reality in data</h3><p>Data is a <strong>representation of reality</strong>: it depicts objects and events (stock, customers, sales) in symbols, so you do not have to observe reality yourself. A stock list tells you how much foil is left without walking into the warehouse.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Benefits of data representation</strong><br>Overview without direct observation, faster and remotely accessible, data from different places can be combined, and usable for analyses impossible with the naked eye.</div><div class=\"rule-card\"><strong>Precise definitions needed</strong><br>Everyone must mean the same thing by a data item. What counts as a \\\"sale\\\": at order or at delivery? Without unambiguous definitions the representation is unreliable.</div></div><h3>9. Structured vs. unstructured data</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Structured data</strong><br>Fixed layout: each item has a name (field) and an agreed format. E.g. postcode, customer number, date of birth. Easy to process automatically.</div><div class=\"rule-card\"><strong>Unstructured data</strong><br>Free form: texts, e-mails, photos, videos. Rich in information but harder to process automatically; often searched with keywords.</div></div><h3>10. Information provision as a production process</h3><p>The <strong>information need</strong> is the information a user requires for their tasks and decisions. Information provision works as a <strong>transformation process</strong>, like a factory (description of the book diagram): <em>input</em> (collecting and entering data) &rarr; <em>processing</em> (recording, storing, manipulating) &rarr; <em>output</em> (providing information). Managing this process is a <strong>core task of management</strong>.</p><h3>11. Collecting and entering data</h3><p>Data comes from <strong>internal sources</strong> (own tills, administration) and <strong>external sources</strong> (suppliers, external databases, the internet). Manual entry creates errors (GIGO), hence:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Entry at the source</strong><br>Record data at the place and moment it arises, preferably by whoever knows it. Less retyping = fewer errors.</div><div class=\"rule-card\"><strong>Automated entry</strong><br>Barcodes, QR codes, RFID chips, scanners and the Internet of Things capture data automatically, without typing.</div><div class=\"rule-card\"><strong>Input controls</strong><br>Programmed checks (e.g. valid date), check digits (as in account numbers) and redundant (double) entry detect errors.</div></div><h3>12. Storage: keys and location</h3><p>Extra terms: a concrete value in a field is a <strong>data value</strong>; an agreed notation is a <strong>standard notation</strong> (e.g. dates always dd-mm-yyyy). The field used to retrieve records is the <strong>entry</strong> or <strong>key</strong> (e.g. CustomerID).</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Central storage</strong><br>All data in one place (e.g. head office server). One version of the truth, easy to manage and secure.</div><div class=\"rule-card\"><strong>Decentralised storage</strong><br>Each branch/department keeps its own data locally. Fast locally, but risk of diverging versions.</div><div class=\"rule-card\"><strong>Distributed storage</strong><br>Data spread over several linked computers working as one whole (as with cloud/SSP).</div></div><h3>13. Types of reports</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Periodic report</strong><br>Fixed times, fixed content. E.g. monthly revenue report.</div><div class=\"rule-card\"><strong>Exception report</strong><br>Only when something deviates from the norm. E.g. an alert only when stock drops below the threshold.</div><div class=\"rule-card\"><strong>Report on request</strong><br>The user asks for a specific one-off report when needed.</div><div class=\"rule-card\"><strong>Interactive report</strong><br>The user clicks through the information and zooms in, e.g. a digital dashboard with live figures.</div></div><div class=\"note-box\"><strong>Note (book vs. mnemonic):</strong> the book lists three quality requirements for output data: <strong>relevance</strong>, <strong>reliability</strong> and <strong>accessibility</strong> — timeliness (available on time) falls under accessibility.</div><div class=\"tip-box\"><strong>Current-affairs term:</strong> a <strong>digital twin</strong> is a digital copy of a real object or system (a machine, a building, even a speed skater) used to simulate and analyse reality without using the real object — data representation taken to the extreme.</div>","fr":"<h3>8. Représentation des données: capturer la réalité dans des données</h3><p>Les données sont une <strong>représentation de la réalité</strong>: elles décrivent des objets et des événements (stock, clients, ventes) sous forme de symboles, de sorte qu'il n'est pas nécessaire d'observer la réalité soi-même. Une liste de stock indique combien de film aluminium il reste sans entrer dans l'entrepôt.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Avantages de la représentation des données</strong><br>Vue d'ensemble sans observation directe, consultation plus rapide et à distance, combinaison de données de différents endroits, et analyses impossibles à l'œil nu.</div><div class=\"rule-card\"><strong>Définitions précises nécessaires</strong><br>Tout le monde doit entendre la même chose par une donnée. Qu'est-ce qu'une \\\"vente\\\": à la commande ou à la livraison ? Sans définitions univoques, la représentation n'est pas fiable.</div></div><h3>9. Données structurées vs non structurées</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Données structurées</strong><br>Format fixe: chaque donnée a un nom (champ) et une forme convenue. Ex. code postal, numéro de client, date de naissance. Faciles à traiter automatiquement.</div><div class=\"rule-card\"><strong>Données non structurées</strong><br>Forme libre: textes, e-mails, photos, vidéos. Riches en information mais plus difficiles à traiter automatiquement; on y cherche souvent par mots-clés.</div></div><h3>10. L'approvisionnement en information comme processus de production</h3><p>Le <strong>besoin d'information</strong> est l'information dont un utilisateur a besoin pour ses tâches et décisions. L'approvisionnement en information fonctionne comme un <strong>processus de transformation</strong>, comme une usine (description du schéma du livre): <em>entrée</em> (collecter et saisir les données) &rarr; <em>traitement</em> (enregistrer, conserver, manipuler) &rarr; <em>sortie</em> (fournir l'information). Gérer ce processus est une <strong>tâche essentielle du management</strong>.</p><h3>11. Collecter et saisir les données</h3><p>Les données proviennent de <strong>sources internes</strong> (caisses, administration) et de <strong>sources externes</strong> (fournisseurs, bases de données externes, internet). La saisie manuelle crée des erreurs (GIGO), d'où:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Saisie à la source</strong><br>Enregistrer les données à l'endroit et au moment où elles naissent, de préférence par celui qui les connaît. Moins de recopiage = moins d'erreurs.</div><div class=\"rule-card\"><strong>Saisie automatisée</strong><br>Codes-barres, codes QR, puces RFID, scanners et Internet des objets enregistrent les données automatiquement, sans frappe.</div><div class=\"rule-card\"><strong>Contrôles de saisie</strong><br>Contrôles programmés (ex. date valide), chiffres de contrôle (comme dans les numéros de compte) et saisie redondante (double) détectent les erreurs.</div></div><h3>12. Stockage: clés et localisation</h3><p>Termes supplémentaires: une valeur concrète dans un champ est une <strong>valeur de donnée</strong>; une écriture convenue est une <strong>notation standard</strong> (ex. date toujours jj-mm-aaaa). Le champ servant à retrouver les enregistrements est l'<strong>entrée</strong> ou la <strong>clé</strong> (ex. ClientID).</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Stockage central</strong><br>Toutes les données en un seul endroit (ex. serveur du siège). Une seule version de la vérité, gestion et sécurité faciles.</div><div class=\"rule-card\"><strong>Stockage décentralisé</strong><br>Chaque succursale/département conserve ses données localement. Rapide localement, mais risque de versions divergentes.</div><div class=\"rule-card\"><strong>Stockage distribué</strong><br>Données réparties sur plusieurs ordinateurs reliés fonctionnant comme un tout (comme le cloud/SSP).</div></div><h3>13. Types de rapports</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Rapport périodique</strong><br>Moments fixes, contenu fixe. Ex. rapport mensuel du chiffre d'affaires.</div><div class=\"rule-card\"><strong>Rapport d'exception</strong><br>Uniquement quand quelque chose s'écarte de la norme. Ex. alerte seulement si le stock passe sous le seuil.</div><div class=\"rule-card\"><strong>Rapport sur demande</strong><br>L'utilisateur demande un rapport spécifique ponctuel quand il en a besoin.</div><div class=\"rule-card\"><strong>Rapport interactif</strong><br>L'utilisateur navigue lui-même dans l'information et zoome, ex. un tableau de bord numérique avec des chiffres en direct.</div></div><div class=\"note-box\"><strong>Attention (livre vs moyen mnémotechnique):</strong> le livre cite trois exigences de qualité pour les données de sortie: <strong>pertinence</strong>, <strong>fiabilité</strong> et <strong>accessibilité</strong> — la ponctualité (disponible à temps) relève de l'accessibilité.</div><div class=\"tip-box\"><strong>Terme d'actualité:</strong> un <strong>jumeau numérique (digital twin)</strong> est une copie numérique d'un objet ou système réel (machine, bâtiment, même un patineur) permettant de simuler et d'analyser la réalité sans utiliser l'objet réel — la représentation des données poussée à l'extrême.</div>"},"exercises":[{"id":"h2_7","correct":2,"text_nl":"Welk van de volgende gegevens is een voorbeeld van ONgestructureerde gegevens?","text_en":"Which of the following is an example of UNstructured data?","text_fr":"Laquelle des données suivantes est un exemple de données NON structurées ?","options_nl":["Een postcode in het veld 'Postcode'","Een klantnummer in een klantentabel","De vrije tekst van een klachtenmail van een klant","De prijs per stuk in het veld 'Prijs'"],"options_en":["A postcode in the 'Postcode' field","A customer number in a customer table","The free text of a customer's complaint e-mail","The unit price in the 'Price' field"],"options_fr":["Un code postal dans le champ 'Code postal'","Un numéro de client dans une table clients","Le texte libre d'un e-mail de plainte d'un client","Le prix unitaire dans le champ 'Prix'"],"hint1_nl":"Denk na: welk gegeven heeft géén vaste indeling met velden en een afgesproken vorm?","hint1_en":"Think: which item has NO fixed layout with fields and an agreed format?","hint1_fr":"Réfléchis: quelle donnée n'a PAS de format fixe avec des champs et une forme convenue ?","hint2_nl":"Gestructureerde gegevens hebben een vaste vorm (veldnaam + afgesproken notatie); ongestructureerde gegevens zijn vrije vorm zoals teksten, foto's en e-mails.","hint2_en":"Structured data has a fixed form (field name + agreed notation); unstructured data is free-form, like texts, photos and e-mails.","hint2_fr":"Les données structurées ont une forme fixe (nom de champ + notation convenue); les données non structurées sont en forme libre, comme les textes, photos et e-mails.","sol_nl":"Een klachtenmail is vrije tekst zonder vaste indeling: ongestructureerd. Postcode, klantnummer en prijs staan in vaste velden met een afgesproken vorm en zijn dus gestructureerd.","sol_en":"A complaint e-mail is free text without a fixed layout: unstructured. Postcode, customer number and price sit in fixed fields with an agreed format, so they are structured.","sol_fr":"Un e-mail de plainte est un texte libre sans format fixe: non structuré. Le code postal, le numéro de client et le prix sont dans des champs fixes avec une forme convenue, donc structurés."},{"id":"h2_8","correct":0,"text_nl":"Supermarktketen VersPlus bewaart alle verkoop- en voorraadgegevens van haar 30 filialen op één server in het hoofdkantoor in Mechelen. De filialen raadplegen die gegevens via het netwerk. Welke vorm van gegevensopslag gebruikt VersPlus?","text_en":"Supermarket chain VersPlus stores all sales and stock data of its 30 branches on a single server at its head office in Mechelen. The branches consult that data over the network. Which form of data storage does VersPlus use?","text_fr":"La chaîne de supermarchés VersPlus conserve toutes les données de vente et de stock de ses 30 succursales sur un seul serveur au siège à Malines. Les succursales consultent ces données via le réseau. Quelle forme de stockage de données VersPlus utilise-t-elle ?","options_nl":["Centrale gegevensopslag","Decentrale gegevensopslag","Gedistribueerde gegevensopslag","Batchopslag"],"options_en":["Central data storage","Decentralised data storage","Distributed data storage","Batch storage"],"options_fr":["Stockage central des données","Stockage décentralisé des données","Stockage distribué des données","Stockage par lots"],"hint1_nl":"Kijk naar het aantal opslaglocaties: staan de gegevens op één plek of op meerdere plekken?","hint1_en":"Look at the number of storage locations: is the data in one place or in several?","hint1_fr":"Regarde le nombre d'emplacements de stockage: les données sont-elles à un seul endroit ou à plusieurs ?","hint2_nl":"Centraal = alles op één plaats; decentraal = elke vestiging bewaart eigen gegevens lokaal; gedistribueerd = gegevens verspreid over meerdere gekoppelde computers die als één geheel werken.","hint2_en":"Central = everything in one place; decentralised = each branch keeps its own data locally; distributed = data spread over several linked computers working as one whole.","hint2_fr":"Central = tout à un seul endroit; décentralisé = chaque succursale conserve ses données localement; distribué = données réparties sur plusieurs ordinateurs reliés fonctionnant comme un tout.","sol_nl":"Alle gegevens staan op één server op het hoofdkantoor: dat is centrale gegevensopslag. Voordelen: één versie van de waarheid, eenvoudiger beheer en beveiliging.","sol_en":"All data sits on one server at head office: that is central data storage. Benefits: one version of the truth, simpler management and security.","sol_fr":"Toutes les données sont sur un seul serveur au siège: c'est un stockage central. Avantages: une seule version de la vérité, gestion et sécurité plus simples."},{"id":"h2_9","correct":1,"text_nl":"De magazijnmanager van drankenhandel Bubbels wil niet elke dag een voorraadlijst doorlezen. Hij stelt het systeem zo in dat hij enkel een melding krijgt wanneer de voorraad van een product onder de minimumdrempel zakt. Welk soort rapportage is dit?","text_en":"The warehouse manager of drinks wholesaler Bubbels does not want to read through a stock list every day. He configures the system so he only gets a notification when a product's stock falls below the minimum threshold. What type of report is this?","text_fr":"Le responsable d'entrepôt du grossiste en boissons Bubbels ne veut pas parcourir une liste de stock chaque jour. Il configure le système pour ne recevoir une notification que lorsque le stock d'un produit passe sous le seuil minimum. De quel type de rapport s'agit-il ?","options_nl":["Periodieke rapportage","Rapportage op uitzonderingsbasis","Rapportage op aanvraag","Interactieve rapportage"],"options_en":["Periodic report","Exception report","Report on request","Interactive report"],"options_fr":["Rapport périodique","Rapport d'exception","Rapport sur demande","Rapport interactif"],"hint1_nl":"Wanneer krijgt de manager informatie: op vaste tijdstippen, op eigen vraag, of enkel bij een afwijking?","hint1_en":"When does the manager get information: at fixed times, on his own request, or only on a deviation?","hint1_fr":"Quand le manager reçoit-il l'information: à moments fixes, à sa demande, ou seulement en cas d'écart ?","hint2_nl":"Rapportage op uitzonderingsbasis: het systeem rapporteert alleen wanneer iets afwijkt van de norm (bijv. voorraad onder de drempel).","hint2_en":"Exception reporting: the system only reports when something deviates from the norm (e.g. stock below the threshold).","hint2_fr":"Rapport d'exception: le système ne rapporte que lorsqu'un élément s'écarte de la norme (ex. stock sous le seuil).","sol_nl":"Er wordt alleen gerapporteerd bij een afwijking van de norm (voorraad onder de drempel): rapportage op uitzonderingsbasis. Niet periodiek (geen vast tijdstip), niet op aanvraag (de gebruiker vraagt er niet telkens om).","sol_en":"It only reports on a deviation from the norm (stock below threshold): an exception report. Not periodic (no fixed time), not on request (the user does not ask each time).","sol_fr":"Le système ne rapporte qu'en cas d'écart par rapport à la norme (stock sous le seuil): rapport d'exception. Ni périodique (pas de moment fixe), ni sur demande (l'utilisateur ne le demande pas à chaque fois)."},{"id":"h2_10","correct":1,"text_nl":"Welke van de volgende situaties is het beste voorbeeld van geautomatiseerde gegevensinvoer aan de bron?","text_en":"Which of the following situations is the best example of automated data entry at the source?","text_fr":"Laquelle des situations suivantes est le meilleur exemple de saisie automatisée des données à la source ?","options_nl":["Een bediende tikt 's avonds de papieren bestelbonnen van de dag over in de computer","Een magazijnier scant bij levering de RFID-tags van binnenkomende paletten, waarna de voorraad automatisch wordt bijgewerkt","De manager vraagt aan het einde van de maand een omzetrapport op","Het systeem berekent elke nacht in batch de loyaliteitspunten"],"options_en":["A clerk retypes the day's paper order forms into the computer in the evening","A warehouse worker scans the RFID tags of incoming pallets on delivery, after which stock is updated automatically","The manager requests a revenue report at the end of the month","The system calculates loyalty points in batch every night"],"options_fr":["Un employé retape le soir les bons de commande papier de la journée dans l'ordinateur","Un magasinier scanne à la livraison les étiquettes RFID des palettes entrantes, après quoi le stock est mis à jour automatiquement","Le manager demande un rapport de chiffre d'affaires en fin de mois","Le système calcule chaque nuit les points de fidélité par lots"],"hint1_nl":"Zoek de situatie waarin gegevens worden vastgelegd op de plaats en het moment waar ze ontstaan, zonder typwerk.","hint1_en":"Find the situation where data is captured at the place and moment it arises, without typing.","hint1_fr":"Cherche la situation où les données sont enregistrées à l'endroit et au moment où elles naissent, sans frappe.","hint2_nl":"Geautomatiseerde invoer aan de bron = barcode, QR-code, RFID of sensoren leggen het gegeven direct vast waar het ontstaat; dat vermindert GIGO door overtikfouten te elimineren.","hint2_en":"Automated entry at the source = barcode, QR code, RFID or sensors capture the data directly where it arises; this reduces GIGO by eliminating retyping errors.","hint2_fr":"Saisie automatisée à la source = code-barres, code QR, RFID ou capteurs enregistrent la donnée directement là où elle naît; cela réduit le GIGO en éliminant les erreurs de recopiage.","sol_nl":"Het scannen van RFID-tags bij levering legt de gegevens automatisch vast op het moment en de plaats waar ze ontstaan: geautomatiseerde invoer aan de bron. Overtikken (optie 1) is handmatig en foutgevoelig; een rapport opvragen is verstrekking, niet invoer; de nachtelijke batchberekening is verwerking, niet invoer.","sol_en":"Scanning RFID tags on delivery captures the data automatically at the moment and place it arises: automated entry at the source. Retyping (option 1) is manual and error-prone; requesting a report is provision, not entry; the nightly batch calculation is processing, not entry.","sol_fr":"Scanner les étiquettes RFID à la livraison enregistre les données automatiquement au moment et à l'endroit où elles naissent: saisie automatisée à la source. Retaper (option 1) est manuel et source d'erreurs; demander un rapport relève de la fourniture, pas de la saisie; le calcul nocturne par lots est du traitement, pas de la saisie."}]},"h3":{"theoryExtra":{"nl":"<h3>Van afdelingen naar processen</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Functionele indeling</strong><br>Activiteiten worden traditioneel geclusterd in <em>bedrijfsfuncties</em> (afdelingen): Inkoop, Productie, Verkoop, Financiën... Nadeel: afdelingen worden 'eilandjes' die hun eigen belang nastreven in plaats van de klant — met fouten en te late leveringen als gevolg.</div><div class=\"rule-card\"><strong>Procesmatig werken</strong><br>Hier staat het <em>bedrijfsproces</em> centraal: een aaneenschakeling van activiteiten die samen een product of dienst voor de klant realiseren — <strong>van klant tot klant</strong>, dwars door de afdelingen heen (bv. bij TopToys: Verkoop → Financiën → Magazijn &amp; Distributie).</div></div><h3>Trigger en impuls</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Trigger</strong><br>Activiteiten starten niet spontaan. De <em>trigger</em> is het resultaat van de ene activiteit dat de volgende activiteit in gang zet. Zo ontstaat een <em>keten van activiteiten</em>.</div><div class=\"rule-card\"><strong>Impuls</strong><br>De <em>eerste</em> trigger die de hele keten op gang brengt. Een <strong>externe impuls</strong> komt van buiten (bv. een klant bestelt), een <strong>interne impuls</strong> van binnen het bedrijf (bv. de voorraad zakt onder het minimum, een geplande maandafsluiting).</div></div><h3>De activiteitenbeschrijving: 5 vaste onderdelen</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Nummer en naam</strong> — altijd met een werkwoord (bv. '2: ontvangen auto').</div><div class=\"rule-card\"><strong>2. Afdeling</strong> — waar de activiteit wordt uitgevoerd (balie, werkplaats...).</div><div class=\"rule-card\"><strong>3. Uitvoerende (actor)</strong> — wie de activiteit uitvoert (secretaresse, chef werkplaats, monteur...).</div><div class=\"rule-card\"><strong>4. Handelingen</strong> — de opsomming van handelingen, kernachtig met werkwoorden.</div><div class=\"rule-card\"><strong>5. Uitzonderingen</strong> — afwijkende situaties (bv. 'leg klantgegevens vast in geval van nieuwe klant').</div></div><div class=\"note-box\"><strong>Handelingen clusteren — wanneer is het één activiteit?</strong> Handelingen horen bij <em>dezelfde</em> activiteit als ze door dezelfde persoon, zonder tijdskloof, na elkaar worden uitgevoerd. Zit er een <strong>tijdskloof</strong> tussen, of doet een <strong>andere persoon of afdeling</strong> het vervolg, dan is het een <em>nieuwe</em> activiteit. Je beschrijft altijd vanuit het gezichtspunt van het <strong>bedrijf</strong> (dus 'ontvangen auto', niet 'afleveren auto').</div><h3>De symbolen volgens het handboek</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Genummerde cirkel = Activiteit</strong><br>Elke activiteit krijgt een nummer en een naam met werkwoord; activiteiten staan chronologisch van boven naar beneden.</div><div class=\"rule-card\"><strong>Rechthoek = Bron of bestemming</strong><br>De 'buitenwereld' van het proces: klant, bank, leverancier. Hier beginnen of eindigen gegevensstromen.</div><div class=\"rule-card\"><strong>Open rechthoek = Gegevensverzameling</strong><br>Opgeslagen gegevens; de naam schrijf je in <strong>HOOFDLETTERS</strong> (bv. KLANTEN, ARTIKELEN, VERKOOPORDERS, GROOTBOEK).</div><div class=\"rule-card\"><strong>Benoemde pijl = Gegevensstroom</strong><br>Gegevens in beweging; de naam zegt welke gegevens stromen (bv. 'bestelbon', 'factuur').</div></div><h3>Regels voor een leesbaar GSS</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Zo weinig mogelijk kruisende lijnen</strong> — een schema moet in één oogopslag leesbaar zijn.</div><div class=\"rule-card\"><strong>Herhalen mag</strong> — bronnen/bestemmingen én gegevensverzamelingen mag je op meer dan één plaats tekenen om kruisingen te vermijden.</div><div class=\"rule-card\"><strong>In- en uitgaande stromen</strong> — elke activiteit heeft minstens één ingaande en één uitgaande gegevensstroom; bronnen links/boven, bestemmingen rechts.</div><div class=\"rule-card\"><strong>Minimale tekst</strong> — kernachtige namen; activiteiten chronologisch van boven naar beneden.</div></div><div class=\"tip-box\"><strong>De 4 stappen volgens het boek (par. 3.6.2):</strong> 1) Benoem de <strong>activiteiten</strong> → 2) Benoem de gebruikte <strong>gegevensverzamelingen</strong> → 3) Bepaal <strong>bronnen en bestemmingen</strong> met hun gegevensstromen → 4) Stel de gegevensstromen vast die <strong>rechtstreeks tussen activiteiten</strong> lopen.</div><h3>Waarom processen beschrijven?</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Inzicht &amp; opleiding</strong> — overzicht van de organisatie; nieuwe medewerkers werken sneller in.</div><div class=\"rule-card\"><strong>Procesmanagement &amp; automatisering</strong> — knelpunten opsporen, prestaties meten, processen verbeteren of automatiseren (BPM).</div><div class=\"rule-card\"><strong>Kwaliteit &amp; regelgeving</strong> — basis voor kwaliteitscertificering (bv. ISO) en audits; aantonen dat je aan regels voldoet.</div><div class=\"rule-card\"><strong>Communicatie</strong> — iedereen spreekt dezelfde taal over het proces.</div></div><div class=\"note-box\"><strong>'Ceci n'est pas un processus':</strong> zoals Magrittes pijp geen echte pijp is, is een procesbeschrijving niet het proces zelf. Een model is altijd een <em>vereenvoudiging</em> van de werkelijkheid — nuttig, maar nooit volledig.</div>","en":"<h3>From departments to processes</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Functional structure</strong><br>Traditionally, activities are clustered into <em>business functions</em> (departments): Purchasing, Production, Sales, Finance... Drawback: departments become 'islands' pursuing their own interests instead of the customer — causing errors and late deliveries.</div><div class=\"rule-card\"><strong>Process-oriented working</strong><br>Here the <em>business process</em> is central: a chain of activities that together deliver a product or service — <strong>from customer to customer</strong>, cutting across departments (e.g. at TopToys: Sales → Finance → Warehouse &amp; Distribution).</div></div><h3>Trigger and impulse</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Trigger</strong><br>Activities do not start spontaneously. The <em>trigger</em> is the result of one activity that sets the next activity in motion, creating a <em>chain of activities</em>.</div><div class=\"rule-card\"><strong>Impulse</strong><br>The <em>first</em> trigger that starts the whole chain. An <strong>external impulse</strong> comes from outside (e.g. a customer orders); an <strong>internal impulse</strong> from inside the company (e.g. stock drops below minimum, a scheduled month-end close).</div></div><h3>The activity description: 5 fixed parts</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Number and name</strong> — always with a verb (e.g. '2: receive car').</div><div class=\"rule-card\"><strong>2. Department</strong> — where the activity is performed (front desk, workshop...).</div><div class=\"rule-card\"><strong>3. Performer (actor)</strong> — who performs it (secretary, workshop manager, mechanic...).</div><div class=\"rule-card\"><strong>4. Actions</strong> — the list of actions, concise, using verbs.</div><div class=\"rule-card\"><strong>5. Exceptions</strong> — deviating situations (e.g. 'record customer data if new customer').</div></div><div class=\"note-box\"><strong>Clustering actions — when is it one activity?</strong> Actions belong to the <em>same</em> activity if the same person performs them consecutively without a time gap. If there is a <strong>time gap</strong>, or a <strong>different person or department</strong> takes over, it is a <em>new</em> activity. Always describe from the <strong>company's</strong> point of view ('receive car', not 'deliver car').</div><h3>The symbols according to the textbook</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Numbered circle = Activity</strong><br>Each activity gets a number and a verb-based name; activities are placed chronologically top to bottom.</div><div class=\"rule-card\"><strong>Rectangle = Source or destination</strong><br>The 'outside world' of the process: customer, bank, supplier. Data flows start or end here.</div><div class=\"rule-card\"><strong>Open rectangle = Data store</strong><br>Stored data; its name is written in <strong>CAPITALS</strong> (e.g. CUSTOMERS, ARTICLES, SALES ORDERS, LEDGER).</div><div class=\"rule-card\"><strong>Named arrow = Data flow</strong><br>Data in motion; the name says which data flows (e.g. 'order form', 'invoice').</div></div><h3>Rules for a readable DFD</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>As few crossing lines as possible</strong> — a diagram must be readable at a glance.</div><div class=\"rule-card\"><strong>Repetition is allowed</strong> — sources/destinations and data stores may be drawn in more than one place to avoid crossings.</div><div class=\"rule-card\"><strong>Incoming and outgoing flows</strong> — every activity has at least one incoming and one outgoing data flow; sources left/top, destinations right.</div><div class=\"rule-card\"><strong>Minimal text</strong> — concise names; activities chronologically from top to bottom.</div></div><div class=\"tip-box\"><strong>The 4 steps according to the book (sec. 3.6.2):</strong> 1) Name the <strong>activities</strong> → 2) Name the <strong>data stores</strong> used → 3) Determine <strong>sources and destinations</strong> with their data flows → 4) Establish the data flows running <strong>directly between activities</strong>.</div><h3>Why describe processes?</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Insight &amp; training</strong> — overview of the organisation; new employees get up to speed faster.</div><div class=\"rule-card\"><strong>Process management &amp; automation</strong> — find bottlenecks, measure performance, improve or automate processes (BPM).</div><div class=\"rule-card\"><strong>Quality &amp; regulation</strong> — basis for quality certification (e.g. ISO) and audits; proving compliance.</div><div class=\"rule-card\"><strong>Communication</strong> — everyone speaks the same language about the process.</div></div><div class=\"note-box\"><strong>'Ceci n'est pas un processus':</strong> just as Magritte's pipe is not a real pipe, a process description is not the process itself. A model is always a <em>simplification</em> of reality — useful, but never complete.</div>","fr":"<h3>Des départements aux processus</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Structure fonctionnelle</strong><br>Traditionnellement, les activités sont regroupées en <em>fonctions d'entreprise</em> (départements): Achats, Production, Ventes, Finances... Inconvénient: les départements deviennent des 'îlots' qui poursuivent leurs propres intérêts au lieu de servir le client — d'où erreurs et livraisons tardives.</div><div class=\"rule-card\"><strong>Travail par processus</strong><br>Ici, le <em>processus d'entreprise</em> est central: un enchaînement d'activités qui réalisent ensemble un produit ou service — <strong>du client au client</strong>, à travers les départements (ex. chez TopToys: Ventes → Finances → Entrepôt &amp; Distribution).</div></div><h3>Trigger et impulsion</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Trigger (déclencheur)</strong><br>Les activités ne démarrent pas spontanément. Le <em>trigger</em> est le résultat d'une activité qui met en route l'activité suivante, créant une <em>chaîne d'activités</em>.</div><div class=\"rule-card\"><strong>Impulsion</strong><br>Le <em>premier</em> trigger qui lance toute la chaîne. Une <strong>impulsion externe</strong> vient de l'extérieur (ex. un client commande); une <strong>impulsion interne</strong> vient de l'entreprise (ex. le stock passe sous le minimum, une clôture mensuelle planifiée).</div></div><h3>La description d'activité: 5 éléments fixes</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Numéro et nom</strong> — toujours avec un verbe (ex. '2: réceptionner la voiture').</div><div class=\"rule-card\"><strong>2. Département</strong> — où l'activité est exécutée (accueil, atelier...).</div><div class=\"rule-card\"><strong>3. Exécutant (acteur)</strong> — qui l'exécute (secrétaire, chef d'atelier, mécanicien...).</div><div class=\"rule-card\"><strong>4. Opérations</strong> — la liste des opérations, concise, avec des verbes.</div><div class=\"rule-card\"><strong>5. Exceptions</strong> — situations particulières (ex. 'enregistrer les données client s'il s'agit d'un nouveau client').</div></div><div class=\"note-box\"><strong>Regrouper les opérations — quand est-ce une seule activité ?</strong> Des opérations appartiennent à la <em>même</em> activité si la même personne les exécute consécutivement, sans interruption de temps. S'il y a un <strong>intervalle de temps</strong>, ou si une <strong>autre personne ou un autre département</strong> prend le relais, c'est une <em>nouvelle</em> activité. On décrit toujours du point de vue de <strong>l'entreprise</strong> ('réceptionner la voiture', pas 'livrer la voiture').</div><h3>Les symboles selon le manuel</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Cercle numéroté = Activité</strong><br>Chaque activité reçoit un numéro et un nom avec verbe; les activités sont placées chronologiquement de haut en bas.</div><div class=\"rule-card\"><strong>Rectangle = Source ou destination</strong><br>Le 'monde extérieur' du processus: client, banque, fournisseur. Les flux de données y commencent ou s'y terminent.</div><div class=\"rule-card\"><strong>Rectangle ouvert = Collection de données</strong><br>Données stockées; le nom s'écrit en <strong>MAJUSCULES</strong> (ex. CLIENTS, ARTICLES, COMMANDES, GRAND LIVRE).</div><div class=\"rule-card\"><strong>Flèche nommée = Flux de données</strong><br>Données en mouvement; le nom indique quelles données circulent (ex. 'bon de commande', 'facture').</div></div><h3>Règles pour un GSS lisible</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Le moins de lignes croisées possible</strong> — un schéma doit être lisible d'un coup d'œil.</div><div class=\"rule-card\"><strong>La répétition est permise</strong> — sources/destinations et collections de données peuvent être dessinées à plusieurs endroits pour éviter les croisements.</div><div class=\"rule-card\"><strong>Flux entrants et sortants</strong> — chaque activité a au moins un flux entrant et un flux sortant; sources à gauche/en haut, destinations à droite.</div><div class=\"rule-card\"><strong>Texte minimal</strong> — noms concis; activités en ordre chronologique de haut en bas.</div></div><div class=\"tip-box\"><strong>Les 4 étapes selon le livre (par. 3.6.2):</strong> 1) Nommer les <strong>activités</strong> → 2) Nommer les <strong>collections de données</strong> utilisées → 3) Déterminer les <strong>sources et destinations</strong> avec leurs flux → 4) Établir les flux qui circulent <strong>directement entre activités</strong>.</div><h3>Pourquoi décrire les processus ?</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Compréhension &amp; formation</strong> — vue d'ensemble de l'organisation; les nouveaux collaborateurs s'intègrent plus vite.</div><div class=\"rule-card\"><strong>Gestion des processus &amp; automatisation</strong> — repérer les goulots d'étranglement, mesurer les performances, améliorer ou automatiser (BPM).</div><div class=\"rule-card\"><strong>Qualité &amp; réglementation</strong> — base de la certification qualité (ex. ISO) et des audits; prouver la conformité.</div><div class=\"rule-card\"><strong>Communication</strong> — tout le monde parle le même langage sur le processus.</div></div><div class=\"note-box\"><strong>« Ceci n'est pas un processus »:</strong> comme la pipe de Magritte n'est pas une vraie pipe, la description d'un processus n'est pas le processus lui-même. Un modèle est toujours une <em>simplification</em> de la réalité — utile, mais jamais complet.</div>"},"exercises":[{"id":"h3_7","correct":1,"text_nl":"Wat is het verschil tussen een trigger en een impuls bij bedrijfsprocessen?","text_en":"What is the difference between a trigger and an impulse in business processes?","text_fr":"Quelle est la différence entre un trigger et une impulsion dans les processus d'entreprise ?","options_nl":["Een trigger komt altijd van buiten het bedrijf, een impuls altijd van binnen","De impuls is de eerste trigger die de hele keten van activiteiten op gang brengt","Een impuls zet één activiteit in gang, een trigger start het hele proces","Trigger en impuls zijn synoniemen in het Nederlandse vakjargon"],"options_en":["A trigger always comes from outside the company, an impulse always from inside","The impulse is the first trigger that sets the whole chain of activities in motion","An impulse starts one activity, a trigger starts the whole process","Trigger and impulse are synonyms in the professional jargon"],"options_fr":["Un trigger vient toujours de l'extérieur, une impulsion toujours de l'intérieur","L'impulsion est le premier trigger qui met en route toute la chaîne d'activités","Une impulsion lance une seule activité, un trigger lance tout le processus","Trigger et impulsion sont des synonymes dans le jargon professionnel"],"hint1_nl":"Denk aan een keten van dominostenen: wat duwt de allereerste steen om?","hint1_en":"Think of a chain of dominoes: what pushes over the very first one?","hint1_fr":"Pensez à une chaîne de dominos: qu'est-ce qui pousse le tout premier ?","hint2_nl":"Een trigger zet de volgende activiteit in gang; de impuls is de eerste trigger van de hele keten en kan intern of extern zijn.","hint2_en":"A trigger sets the next activity in motion; the impulse is the first trigger of the whole chain and can be internal or external.","hint2_fr":"Un trigger met en route l'activité suivante; l'impulsion est le premier trigger de toute la chaîne et peut être interne ou externe.","sol_nl":"De impuls is de eerste trigger die de hele keten start (antwoord 2). Elke trigger zet de volgende activiteit in gang; de impuls kan zowel extern (een klantbestelling) als intern (voorraad onder minimum) zijn — dus antwoord 1 en 3 zijn fout.","sol_en":"The impulse is the first trigger that starts the whole chain (option 2). Every trigger sets the next activity in motion; the impulse can be external (a customer order) as well as internal (stock below minimum) — so options 1 and 3 are wrong.","sol_fr":"L'impulsion est le premier trigger qui lance toute la chaîne (réponse 2). Chaque trigger met en route l'activité suivante; l'impulsion peut être externe (commande client) ou interne (stock sous le minimum) — les réponses 1 et 3 sont donc fausses."},{"id":"h3_8","correct":2,"text_nl":"In een garage noteert de secretaresse 's ochtends de afspraak van een klant. Twee uur later neemt de chef werkplaats de auto in ontvangst en maakt hij de werkopdracht. Daarna voert een monteur de reparatie uit. Hoeveel afzonderlijke activiteiten zijn dit volgens de clusteringscriteria?","text_en":"In a garage, the secretary records a customer's appointment in the morning. Two hours later the workshop manager receives the car and creates the work order. Then a mechanic carries out the repair. According to the clustering criteria, how many separate activities is this?","text_fr":"Dans un garage, la secrétaire note le rendez-vous d'un client le matin. Deux heures plus tard, le chef d'atelier réceptionne la voiture et crée l'ordre de travail. Ensuite, un mécanicien effectue la réparation. Selon les critères de regroupement, combien d'activités distinctes cela représente-t-il ?","options_nl":["Eén activiteit: alles hoort bij hetzelfde reparatieproces","Twee activiteiten: balie en werkplaats","Drie activiteiten: tijdskloof én andere uitvoerenden scheiden de handelingen","Vier activiteiten: elke handeling is een aparte activiteit"],"options_en":["One activity: everything belongs to the same repair process","Two activities: front desk and workshop","Three activities: a time gap and different performers separate the actions","Four activities: every action is a separate activity"],"options_fr":["Une activité: tout appartient au même processus de réparation","Deux activités: accueil et atelier","Trois activités: un intervalle de temps et des exécutants différents séparent les opérations","Quatre activités: chaque opération est une activité distincte"],"hint1_nl":"Kijk naar wie elke handeling uitvoert en of er tijd tussen zit.","hint1_en":"Look at who performs each action and whether time passes in between.","hint1_fr":"Regardez qui exécute chaque opération et s'il y a un intervalle de temps entre elles.","hint2_nl":"Regel: een tijdskloof of een andere persoon/afdeling betekent een nieuwe activiteit.","hint2_en":"Rule: a time gap or a different person/department means a new activity.","hint2_fr":"Règle: un intervalle de temps ou une autre personne / un autre département signifie une nouvelle activité.","sol_nl":"Drie activiteiten (antwoord 3): 'afspraak maken' (secretaresse, balie), 'ontvangen auto' (chef werkplaats, na een tijdskloof) en 'uitvoeren reparatie' (monteur). Tijdskloof + andere uitvoerende = nieuwe activiteit.","sol_en":"Three activities (option 3): 'make appointment' (secretary, front desk), 'receive car' (workshop manager, after a time gap) and 'carry out repair' (mechanic). Time gap + different performer = new activity.","sol_fr":"Trois activités (réponse 3): 'prendre rendez-vous' (secrétaire, accueil), 'réceptionner la voiture' (chef d'atelier, après un intervalle de temps) et 'effectuer la réparation' (mécanicien). Intervalle de temps + autre exécutant = nouvelle activité."},{"id":"h3_9","correct":3,"text_nl":"Welk onderdeel hoort NIET thuis in de vaste structuur van een activiteitenbeschrijving?","text_en":"Which element does NOT belong in the fixed structure of an activity description?","text_fr":"Quel élément ne fait PAS partie de la structure fixe d'une description d'activité ?","options_nl":["Nummer en naam van de activiteit (met werkwoord)","Afdeling en uitvoerende (actor)","Handelingen en uitzonderingen","De kostprijs van de activiteit per uur"],"options_en":["Number and name of the activity (with a verb)","Department and performer (actor)","Actions and exceptions","The hourly cost of the activity"],"options_fr":["Numéro et nom de l'activité (avec un verbe)","Département et exécutant (acteur)","Opérations et exceptions","Le coût horaire de l'activité"],"hint1_nl":"Denk aan het voorbeeld van het garagebedrijf: wat stond er telkens onder elke activiteit?","hint1_en":"Think of the garage example: what was listed under each activity?","hint1_fr":"Pensez à l'exemple du garage: qu'y avait-il sous chaque activité ?","hint2_nl":"De vijf vaste onderdelen zijn: nummer en naam, afdeling, uitvoerende, handelingen, uitzonderingen.","hint2_en":"The five fixed parts are: number and name, department, performer, actions, exceptions.","hint2_fr":"Les cinq éléments fixes sont: numéro et nom, département, exécutant, opérations, exceptions.","sol_nl":"De kostprijs (antwoord 4) maakt geen deel uit van de activiteitenbeschrijving. De vijf vaste onderdelen zijn: nummer en naam (met werkwoord), afdeling, uitvoerende, handelingen en uitzonderingen.","sol_en":"The cost (option 4) is not part of the activity description. The five fixed parts are: number and name (with a verb), department, performer, actions and exceptions.","sol_fr":"Le coût (réponse 4) ne fait pas partie de la description d'activité. Les cinq éléments fixes sont: numéro et nom (avec verbe), département, exécutant, opérations et exceptions."},{"id":"h3_10","correct":1,"text_nl":"Een student tekent het gegevensstroomschema van een webwinkel. De gegevensverzameling ARTIKELEN wordt door drie activiteiten gebruikt, waardoor er veel kruisende lijnen ontstaan. Wat mag hij volgens de regels doen?","text_en":"A student draws the data flow diagram of a web shop. The data store ARTICLES is used by three activities, causing many crossing lines. According to the rules, what may he do?","text_fr":"Un étudiant dessine le schéma de flux de données d'une boutique en ligne. La collection de données ARTICLES est utilisée par trois activités, ce qui crée beaucoup de lignes croisées. Selon les règles, que peut-il faire ?","options_nl":["Niets: elk element mag maar één keer in het schema voorkomen","De gegevensverzameling ARTIKELEN op meerdere plaatsen in het schema herhalen","De gegevensstromen naar ARTIKELEN gewoon weglaten","ARTIKELEN vervangen door een activiteit met een werkwoord"],"options_en":["Nothing: each element may appear only once in the diagram","Repeat the data store ARTICLES in several places in the diagram","Simply omit the data flows to ARTICLES","Replace ARTICLES with an activity using a verb"],"options_fr":["Rien: chaque élément ne peut apparaître qu'une seule fois dans le schéma","Répéter la collection de données ARTICLES à plusieurs endroits du schéma","Simplement omettre les flux de données vers ARTICLES","Remplacer ARTICLES par une activité avec un verbe"],"hint1_nl":"Het hoofddoel van de tekenregels is leesbaarheid in één oogopslag.","hint1_en":"The main goal of the drawing rules is readability at a glance.","hint1_fr":"L'objectif principal des règles de dessin est la lisibilité d'un coup d'œil.","hint2_nl":"Regel: bronnen/bestemmingen en gegevensverzamelingen mogen herhaald worden om kruisende lijnen te vermijden.","hint2_en":"Rule: sources/destinations and data stores may be repeated to avoid crossing lines.","hint2_fr":"Règle: les sources/destinations et les collections de données peuvent être répétées pour éviter les lignes croisées.","sol_nl":"Antwoord 2: om kruisende lijnen te vermijden mag een gegevensverzameling (en ook een bron of bestemming) op meerdere plaatsen in het schema getekend worden. Stromen weglaten of de verzameling in een activiteit veranderen is fout.","sol_en":"Option 2: to avoid crossing lines, a data store (and also a source or destination) may be drawn in several places in the diagram. Omitting flows or turning the store into an activity is wrong.","sol_fr":"Réponse 2: pour éviter les lignes croisées, une collection de données (et aussi une source ou destination) peut être dessinée à plusieurs endroits du schéma. Omettre des flux ou transformer la collection en activité est incorrect."}]},"h4":{"theoryExtra":{"nl":"<h3>6. Systeem, informatiesysteem en de drie kernvragen</h3><p>Een <strong>systeem</strong> is een geheel van samenhangende onderdelen (componenten) dat gericht is op het bereiken van een bepaald doel. Een <strong>informatiesysteem</strong> is een systeem waarbij mensen, hulpmiddelen en programma's worden ingezet voor de verwerking van invoergegevens en bestaande gegevens uit gegevensverzamelingen tot de gewenste uitvoergegevens. Informatiesystemen worden vaak genoemd naar hun <strong>doelstelling</strong>: een verkoopinformatiesysteem legt verkoopgegevens vast, een salarissysteem verstrekt informatie voor salarisbetalingen.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Wat gebeurt er?</strong><br>Het systeem verwerkt ingevoerde en opgeslagen gegevens tot gewenste uitvoer (componenten 1-4 van het spinmodel).</div><div class=\"rule-card\"><strong>2. Hoe gebeurt dat?</strong><br>Volgens voorgeschreven werkinstructies: <strong>procedures</strong> en <strong>programma's</strong> (component 5).</div><div class=\"rule-card\"><strong>3. Waarmee wordt het gedaan?</strong><br>Met <strong>mensen</strong> (gebruikers én systeemspecialisten) en <strong>hulpmiddelen</strong> (hardware) — componenten 6 en 7.</div></div><div class=\"note-box\"><strong>Let op:</strong> klanten die gegevens aanleveren en managers die uitvoer ontvangen horen NIET bij het systeem, tenzij ze zelf de computer bedienen. Betrokken mensen = gebruikers + systeemspecialisten (ontwikkelaars en beheerders).</div><h3>7. Hardware, netwerken en software</h3><p><strong>Netwerken:</strong> computers zijn aan elkaar gekoppeld in netwerken. Het boek onderscheidt het <strong>gesloten bedrijfsnetwerk</strong> (alleen toegankelijk voor medewerkers, vaak via een beveiligde verbinding) en het <strong>publieke netwerk</strong> (internet, voor iedereen toegankelijk). Gegevens worden steeds vaker opgeslagen in <strong>extern geheugen in de cloud</strong> in plaats van op de eigen harde schijf.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Besturingssoftware</strong><br>Regelt de werking van de computer zelf en de communicatie met randapparatuur. Voorbeelden: Windows, Linux, macOS, iOS. Ook netwerkbesturingssystemen en databasemanagementsystemen (DBMS) horen hierbij.</div><div class=\"rule-card\"><strong>Toepassingssoftware (applicaties)</strong><br>Software waarmee de gebruiker zijn taken uitvoert: tekstverwerking, boekhouding, orderregistratie. Op smartphones spreken we van <strong>apps</strong>. De geboden mogelijkheden heten <strong>functionaliteit</strong>.</div><div class=\"rule-card\"><strong>Standaardsoftware</strong><br>Kant-en-klaar pakket, voor veel bedrijven tegelijk gemaakt. Goedkoper, sneller in te voeren, bewezen kwaliteit — maar sluit niet altijd perfect aan op de eigen werkwijze.</div><div class=\"rule-card\"><strong>Maatwerksoftware</strong><br>Speciaal voor één onderneming ontwikkeld. Sluit perfect aan op de eigen processen, maar is duurder en de ontwikkeling duurt langer.</div></div><h3>8. Extra soorten informatiesystemen</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Transactieverwerkende (administratieve) systemen</strong><br>Vervullen vooral registrerende taken: routinematige bewerkingen vastleggen (verkoop, facturering, salarisadministratie, voorraad). De basislaag van de informatievoorziening.</div><div class=\"rule-card\"><strong>Geïntegreerde administratieve systemen</strong><br>Voorloper van ERP: meerdere administratieve functies samengevoegd rond één gemeenschappelijke database, zodat gegevens maar één keer worden ingevoerd.</div><div class=\"rule-card\"><strong>Documentaire informatiesystemen (DIS/DMS)</strong><br>Beheren documenten digitaal: opslaan, terugvinden, versiebeheer, autorisatie. Belangrijk bij documentintensieve organisaties.</div><div class=\"rule-card\"><strong>Workflowmanagement (coördinatie)</strong><br>Stuurt de volgorde van werkstappen en bewaakt wie wat wanneer moet doen in een bedrijfsproces.</div><div class=\"rule-card\"><strong>Kantoorsoftware & datamining</strong><br>Tekstverwerking, spreadsheets (met grafieken en what-if-analyses), presentatiesoftware, e-mail/agenda. <strong>Datamining</strong>: in grote gegevensverzamelingen zoeken naar patronen voor marketing- en beleidsbeslissingen.</div><div class=\"rule-card\"><strong>CAD</strong><br>Computer Aided Design: producten op het scherm ontwerpen; onderdelen komen uit een productendatabase en kunnen direct doorgestuurd worden naar de productie.</div></div><div class=\"example-box\"><strong>Piramidemodel (figuur 4.17):</strong> stel je een piramide voor. Onderaan liggen de <strong>transactieverwerkende systemen</strong> (financieel, productie, personeel). Hun gegevens stromen omhoog naar een <strong>datawarehouse</strong>, en bovenaan halen de <strong>bestuurlijke informatiesystemen</strong> daaruit dashboards en managementinformatie. Bestuurlijke systemen beantwoorden vragen als: moet er personeel aangenomen worden? Moet de minimumvoorraad aangepast worden?</div><h3>9. Internet of Things (IoT)</h3><p><strong>IoT</strong> = apparaten ('things') die via sensoren gegevens verzamelen en die zelfstandig via internet met elkaar communiceren (machine-to-machine), zonder menselijke tussenkomst. Kenmerken: sensoren, internetverbinding, dataverzameling, automatische actie. Voorbeelden: slimme thermostaat, Smart Home, sensoren in vliegtuigmotoren.</p><div class=\"note-box\"><strong>Security-risico's van IoT:</strong> veel IoT-apparaten hebben zwakke standaardwachtwoorden, krijgen zelden updates en vormen zo een toegangspoort tot het hele netwerk. Gekaapte devices kunnen worden misbruikt (bijv. voor aanvallen). Maatregelen: wachtwoorden wijzigen, software up-to-date houden, IoT-apparaten in een apart netwerk plaatsen.</div><h3>10. Cloudvormen: openbaar, privé, hybride</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Openbare (publieke) cloud</strong><br>Diensten gedeeld door veel klanten op de infrastructuur van de provider.</div><div class=\"rule-card\"><strong>Privécloud</strong><br>Cloudomgeving exclusief voor één organisatie — meer controle en beveiliging.</div><div class=\"rule-card\"><strong>Hybride cloud</strong><br>Combinatie: gevoelige gegevens in de privécloud, generieke diensten uit de publieke cloud.</div></div><h3>11. Acht kwaliteitseisen (volledige lijst)</h3><p>Het boek noemt <strong>acht</strong> kwaliteitseisen — naast de zes die je al kent komen er twee bij:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Bescherming</strong><br>De privacy van personen van wie gegevens zijn vastgelegd moet gewaarborgd zijn (denk aan de AVG/GDPR). Gegevens mogen alleen gebruikt worden voor het doel waarvoor ze zijn verzameld.</div><div class=\"rule-card\"><strong>Gebruiksvriendelijkheid</strong><br>Het systeem moet eenvoudig te bedienen zijn: logische schermen, duidelijke meldingen, weinig opleiding nodig.</div></div><div class=\"tip-box\"><strong>Volledige lijst:</strong> betrouwbaarheid, integriteit, flexibiliteit, controleerbaarheid, beveiliging, <strong>bescherming</strong>, onderhoudbaarheid, <strong>gebruiksvriendelijkheid</strong>.</div><h3>12. Beveiligingsmaatregelen in detail</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Inloggen & autorisatie</strong><br>Inloggen bewijst wie je bent (authenticatie); <strong>autorisatie</strong> bepaalt daarna wat je mag: niet elke gebruiker krijgt toegang tot alle gegevens en functies.</div><div class=\"rule-card\"><strong>Codering (encryptie)</strong><br>Gegevens worden versleuteld opgeslagen of verzonden, zodat ze zonder sleutel onleesbaar zijn voor onbevoegden.</div><div class=\"rule-card\"><strong>Fysieke beveiliging</strong><br>Beveiliging van ruimtes (toegangspassen, sloten), afsluiten van apparatuur, beveiliging tegen diefstal van devices.</div><div class=\"rule-card\"><strong>Back-up, restore & uitwijk</strong><br><strong>Back-up</strong>: regelmatig reservekopieën maken. <strong>Restore</strong>: de kopie terugzetten na verlies. <strong>Uitwijk</strong>: bij een calamiteit de verwerking voortzetten op een andere locatie of andere apparatuur.</div><div class=\"rule-card\"><strong>Organisatorische maatregelen</strong><br>Regels en gedragscodes voor gebruikers: wachtwoordbeleid, functiescheiding, afspraken over gebruik van eigen apparatuur.</div><div class=\"rule-card\"><strong>Bescherming tegen calamiteiten</strong><br>Maatregelen tegen brand, wateroverlast en stroomuitval (blusinstallaties, noodstroom, gegevens op een tweede locatie).</div></div><h3>13. Beheer van informatiesystemen</h3><p>Een informatiesysteem moet in goede conditie gehouden worden. Het boek onderscheidt:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Functioneel beheer</strong><br>Gericht op het gebruik: gebruikers ondersteunen, gebruikersrechten toekennen, gegevensdefinities en procedures actueel houden, wijzigingen in de informatiebehoefte vertalen naar het systeem.</div><div class=\"rule-card\"><strong>Technisch beheer</strong><br>Gericht op de techniek: hardware onderhouden en vervangen, software-updates en nieuwe versies installeren, netwerk en opslag beheren.</div><div class=\"rule-card\"><strong>Gegevensbeheer</strong><br>Zorgen dat de gegevensverzamelingen juist, volledig en actueel blijven (bijv. vervuiling in het klantenbestand opruimen).</div></div><div class=\"example-box\"><strong>Voorbeeld De Leeuw BV:</strong> na de overstap op een ERP-pakket worden programma's en gegevens centraal aangeleverd, worden back-ups centraal en regelmatig gemaakt, en hoeven gebruikers hun eigen computer niet meer zelf te beheren — functioneel én technisch beheer zijn centraal georganiseerd en de kosten dalen.</div>","en":"<h3>6. System, information system and the three key questions</h3><p>A <strong>system</strong> is a coherent set of components aimed at achieving a specific goal. An <strong>information system</strong> is a system in which people, resources and programs are used to process input data and stored data from data collections into the desired output. Information systems are often named after their <strong>purpose</strong>: a sales information system records sales data, a payroll system provides information for salary payments.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. What happens?</strong><br>The system processes input and stored data into the desired output (components 1-4 of the spider model).</div><div class=\"rule-card\"><strong>2. How is it done?</strong><br>According to prescribed work instructions: <strong>procedures</strong> and <strong>programs</strong> (component 5).</div><div class=\"rule-card\"><strong>3. With what is it done?</strong><br>With <strong>people</strong> (users and system specialists) and <strong>resources</strong> (hardware) — components 6 and 7.</div></div><div class=\"note-box\"><strong>Note:</strong> customers who supply data and managers who receive output are NOT part of the system, unless they operate the computer themselves. People involved = users + system specialists (developers and administrators).</div><h3>7. Hardware, networks and software</h3><p><strong>Networks:</strong> computers are linked together in networks. The book distinguishes the <strong>closed company network</strong> (accessible only to employees, often via a secured connection) and the <strong>public network</strong> (the internet, open to everyone). Data is increasingly stored in <strong>external memory in the cloud</strong> instead of on a local hard disk.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Operating software</strong><br>Controls the computer itself and communication with peripherals. Examples: Windows, Linux, macOS, iOS. Network operating systems and database management systems (DBMS) also belong here.</div><div class=\"rule-card\"><strong>Application software</strong><br>Software with which the user performs tasks: word processing, accounting, order registration. On smartphones we call these <strong>apps</strong>. The features offered are called <strong>functionality</strong>.</div><div class=\"rule-card\"><strong>Standard software</strong><br>Off-the-shelf package made for many companies at once. Cheaper, faster to implement, proven quality — but does not always fit your own way of working perfectly.</div><div class=\"rule-card\"><strong>Custom (bespoke) software</strong><br>Developed specifically for one company. Fits its processes perfectly, but is more expensive and takes longer to develop.</div></div><h3>8. Additional types of information systems</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Transaction processing (administrative) systems</strong><br>Mainly perform recording tasks: routine operations (sales, invoicing, payroll, inventory). The foundation layer of information provision.</div><div class=\"rule-card\"><strong>Integrated administrative systems</strong><br>Forerunner of ERP: several administrative functions merged around one shared database, so data is entered only once.</div><div class=\"rule-card\"><strong>Document management systems (DMS/DIS)</strong><br>Manage documents digitally: store, retrieve, version control, authorisation. Important in document-intensive organisations.</div><div class=\"rule-card\"><strong>Workflow management (coordination)</strong><br>Controls the sequence of work steps and monitors who must do what and when in a business process.</div><div class=\"rule-card\"><strong>Office software & data mining</strong><br>Word processing, spreadsheets (with charts and what-if analyses), presentation software, e-mail/calendar. <strong>Data mining</strong>: searching large data collections for patterns for marketing and policy decisions.</div><div class=\"rule-card\"><strong>CAD</strong><br>Computer Aided Design: designing products on screen; parts come from a product database and can be sent directly to production.</div></div><div class=\"example-box\"><strong>Pyramid model (figure 4.17):</strong> picture a pyramid. At the bottom are the <strong>transaction processing systems</strong> (finance, production, personnel). Their data flows upwards into a <strong>data warehouse</strong>, and at the top the <strong>management information systems</strong> draw dashboards and management information from it. Management systems answer questions like: should staff be hired? Should the minimum stock level be adjusted?</div><h3>9. Internet of Things (IoT)</h3><p><strong>IoT</strong> = devices ('things') that collect data via sensors and communicate with each other autonomously over the internet (machine-to-machine), without human intervention. Characteristics: sensors, internet connection, data collection, automatic action. Examples: smart thermostat, Smart Home, sensors in aircraft engines.</p><div class=\"note-box\"><strong>IoT security risks:</strong> many IoT devices have weak default passwords, rarely receive updates and thus form a gateway into the entire network. Hijacked devices can be misused (e.g. for attacks). Measures: change passwords, keep software up to date, place IoT devices in a separate network.</div><h3>10. Cloud types: public, private, hybrid</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Public cloud</strong><br>Services shared by many customers on the provider's infrastructure.</div><div class=\"rule-card\"><strong>Private cloud</strong><br>Cloud environment exclusively for one organisation — more control and security.</div><div class=\"rule-card\"><strong>Hybrid cloud</strong><br>Combination: sensitive data in the private cloud, generic services from the public cloud.</div></div><h3>11. Eight quality requirements (complete list)</h3><p>The book lists <strong>eight</strong> quality requirements — besides the six you already know, two are added:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Protection (privacy)</strong><br>The privacy of people whose data is recorded must be guaranteed (think GDPR). Data may only be used for the purpose for which it was collected.</div><div class=\"rule-card\"><strong>User-friendliness</strong><br>The system must be easy to operate: logical screens, clear messages, little training required.</div></div><div class=\"tip-box\"><strong>Complete list:</strong> reliability, integrity, flexibility, auditability, security, <strong>protection</strong>, maintainability, <strong>user-friendliness</strong>.</div><h3>12. Security measures in detail</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Login & authorisation</strong><br>Logging in proves who you are (authentication); <strong>authorisation</strong> then determines what you may do: not every user gets access to all data and functions.</div><div class=\"rule-card\"><strong>Encryption (coding)</strong><br>Data is stored or transmitted in encrypted form, so it is unreadable to unauthorised parties without the key.</div><div class=\"rule-card\"><strong>Physical security</strong><br>Securing rooms (access badges, locks), locking down equipment, protection against theft of devices.</div><div class=\"rule-card\"><strong>Back-up, restore & fallback</strong><br><strong>Back-up</strong>: regularly make copies. <strong>Restore</strong>: put the copy back after loss. <strong>Fallback (uitwijk)</strong>: in a calamity, continue processing at another location or on other equipment.</div><div class=\"rule-card\"><strong>Organisational measures</strong><br>Rules and codes of conduct for users: password policy, segregation of duties, agreements on use of personal devices.</div><div class=\"rule-card\"><strong>Protection against calamities</strong><br>Measures against fire, flooding and power failure (extinguishing systems, emergency power, data at a second location).</div></div><h3>13. Management of information systems</h3><p>An information system must be kept in good condition. The book distinguishes:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Functional management</strong><br>Focused on use: supporting users, granting user rights, keeping data definitions and procedures up to date, translating changing information needs into the system.</div><div class=\"rule-card\"><strong>Technical management</strong><br>Focused on technology: maintaining and replacing hardware, installing software updates and new versions, managing network and storage.</div><div class=\"rule-card\"><strong>Data management</strong><br>Ensuring that data collections remain correct, complete and up to date (e.g. cleaning up pollution in the customer file).</div></div><div class=\"example-box\"><strong>Example De Leeuw BV:</strong> after switching to an ERP package, programs and data are delivered centrally, back-ups are made centrally and regularly, and users no longer have to manage their own computers — functional and technical management are organised centrally and costs drop.</div>","fr":"<h3>6. Système, système d'information et les trois questions clés</h3><p>Un <strong>système</strong> est un ensemble cohérent de composants visant un objectif déterminé. Un <strong>système d'information</strong> est un système dans lequel des personnes, des moyens et des programmes sont utilisés pour transformer des données d'entrée et des données stockées en la sortie souhaitée. Les systèmes d'information sont souvent nommés d'après leur <strong>objectif</strong>: un système d'information des ventes enregistre les ventes, un système de paie fournit les informations pour le paiement des salaires.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>1. Que se passe-t-il ?</strong><br>Le système transforme les données d'entrée et stockées en sortie souhaitée (composants 1-4 du modèle en araignée).</div><div class=\"rule-card\"><strong>2. Comment cela se fait-il ?</strong><br>Selon des instructions de travail prescrites: <strong>procédures</strong> et <strong>programmes</strong> (composant 5).</div><div class=\"rule-card\"><strong>3. Avec quoi ?</strong><br>Avec des <strong>personnes</strong> (utilisateurs et spécialistes système) et des <strong>moyens</strong> (matériel) — composants 6 et 7.</div></div><div class=\"note-box\"><strong>Attention:</strong> les clients qui fournissent des données et les managers qui reçoivent la sortie ne font PAS partie du système, sauf s'ils utilisent eux-mêmes l'ordinateur. Personnes concernées = utilisateurs + spécialistes système (développeurs et administrateurs).</div><h3>7. Matériel, réseaux et logiciels</h3><p><strong>Réseaux:</strong> les ordinateurs sont reliés en réseaux. Le livre distingue le <strong>réseau d'entreprise fermé</strong> (accessible uniquement aux employés, souvent via une connexion sécurisée) et le <strong>réseau public</strong> (Internet, ouvert à tous). Les données sont de plus en plus stockées dans une <strong>mémoire externe dans le cloud</strong> plutôt que sur le disque dur local.</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Logiciel d'exploitation</strong><br>Gère le fonctionnement de l'ordinateur lui-même et la communication avec les périphériques. Exemples: Windows, Linux, macOS, iOS. Les systèmes d'exploitation réseau et les systèmes de gestion de bases de données (SGBD) en font aussi partie.</div><div class=\"rule-card\"><strong>Logiciel applicatif</strong><br>Logiciel avec lequel l'utilisateur effectue ses tâches: traitement de texte, comptabilité, enregistrement des commandes. Sur smartphone: les <strong>apps</strong>. Les possibilités offertes s'appellent la <strong>fonctionnalité</strong>.</div><div class=\"rule-card\"><strong>Logiciel standard</strong><br>Progiciel prêt à l'emploi, conçu pour de nombreuses entreprises. Moins cher, plus rapide à mettre en place, qualité éprouvée — mais ne correspond pas toujours parfaitement à votre façon de travailler.</div><div class=\"rule-card\"><strong>Logiciel sur mesure</strong><br>Développé spécialement pour une seule entreprise. Correspond parfaitement à ses processus, mais coûte plus cher et le développement prend plus de temps.</div></div><h3>8. Autres types de systèmes d'information</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Systèmes transactionnels (administratifs)</strong><br>Remplissent surtout des tâches d'enregistrement: opérations routinières (ventes, facturation, paie, stocks). La couche de base de l'information.</div><div class=\"rule-card\"><strong>Systèmes administratifs intégrés</strong><br>Précurseur de l'ERP: plusieurs fonctions administratives fusionnées autour d'une base de données commune, les données ne sont saisies qu'une seule fois.</div><div class=\"rule-card\"><strong>Systèmes de gestion documentaire (DMS/DIS)</strong><br>Gèrent les documents numériquement: stockage, recherche, gestion des versions, autorisation. Important dans les organisations à forte intensité documentaire.</div><div class=\"rule-card\"><strong>Gestion des flux de travail (coordination)</strong><br>Pilote l'ordre des étapes de travail et contrôle qui doit faire quoi et quand dans un processus d'entreprise.</div><div class=\"rule-card\"><strong>Logiciels de bureau & data mining</strong><br>Traitement de texte, tableurs (graphiques et analyses « what-if »), logiciels de présentation, e-mail/agenda. <strong>Data mining</strong>: rechercher des motifs dans de grandes collections de données pour des décisions marketing et stratégiques.</div><div class=\"rule-card\"><strong>CAO (CAD)</strong><br>Conception assistée par ordinateur: concevoir des produits à l'écran; les pièces proviennent d'une base de données produits et peuvent être envoyées directement à la production.</div></div><div class=\"example-box\"><strong>Modèle pyramidal (figure 4.17):</strong> imaginez une pyramide. En bas se trouvent les <strong>systèmes transactionnels</strong> (finances, production, personnel). Leurs données remontent vers un <strong>entrepôt de données (data warehouse)</strong>, et au sommet les <strong>systèmes d'information de gestion</strong> en tirent des tableaux de bord et des informations de gestion. Ils répondent à des questions comme: faut-il embaucher ? Faut-il ajuster le stock minimum ?</div><h3>9. Internet des objets (IoT)</h3><p><strong>IoT</strong> = des appareils (« objets ») qui collectent des données via des capteurs et communiquent entre eux de façon autonome via Internet (machine à machine), sans intervention humaine. Caractéristiques: capteurs, connexion Internet, collecte de données, action automatique. Exemples: thermostat intelligent, Smart Home, capteurs dans les moteurs d'avion.</p><div class=\"note-box\"><strong>Risques de sécurité de l'IoT:</strong> beaucoup d'appareils IoT ont des mots de passe par défaut faibles, reçoivent rarement des mises à jour et constituent ainsi une porte d'entrée vers tout le réseau. Des appareils piratés peuvent être détournés (p. ex. pour des attaques). Mesures: changer les mots de passe, maintenir les logiciels à jour, placer les appareils IoT dans un réseau séparé.</div><h3>10. Formes de cloud: public, privé, hybride</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Cloud public</strong><br>Services partagés par de nombreux clients sur l'infrastructure du fournisseur.</div><div class=\"rule-card\"><strong>Cloud privé</strong><br>Environnement cloud exclusif à une seule organisation — plus de contrôle et de sécurité.</div><div class=\"rule-card\"><strong>Cloud hybride</strong><br>Combinaison: données sensibles dans le cloud privé, services génériques depuis le cloud public.</div></div><h3>11. Huit exigences de qualité (liste complète)</h3><p>Le livre cite <strong>huit</strong> exigences de qualité — aux six que vous connaissez déjà s'ajoutent:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Protection (vie privée)</strong><br>La vie privée des personnes dont les données sont enregistrées doit être garantie (pensez au RGPD). Les données ne peuvent être utilisées que pour le but pour lequel elles ont été collectées.</div><div class=\"rule-card\"><strong>Convivialité</strong><br>Le système doit être simple à utiliser: écrans logiques, messages clairs, peu de formation nécessaire.</div></div><div class=\"tip-box\"><strong>Liste complète:</strong> fiabilité, intégrité, flexibilité, contrôlabilité, sécurité, <strong>protection</strong>, maintenabilité, <strong>convivialité</strong>.</div><h3>12. Mesures de sécurité en détail</h3><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Connexion & autorisation</strong><br>La connexion prouve qui vous êtes (authentification); l'<strong>autorisation</strong> détermine ensuite ce que vous pouvez faire: tous les utilisateurs n'ont pas accès à toutes les données et fonctions.</div><div class=\"rule-card\"><strong>Chiffrement (codage)</strong><br>Les données sont stockées ou transmises sous forme chiffrée, illisibles sans la clé pour les personnes non autorisées.</div><div class=\"rule-card\"><strong>Sécurité physique</strong><br>Sécurisation des locaux (badges, serrures), verrouillage des équipements, protection contre le vol d'appareils.</div><div class=\"rule-card\"><strong>Back-up, restore & site de repli</strong><br><strong>Back-up</strong>: faire régulièrement des copies de sauvegarde. <strong>Restore</strong>: restaurer la copie après une perte. <strong>Repli (uitwijk)</strong>: en cas de sinistre, poursuivre le traitement sur un autre site ou un autre matériel.</div><div class=\"rule-card\"><strong>Mesures organisationnelles</strong><br>Règles et codes de conduite pour les utilisateurs: politique de mots de passe, séparation des fonctions, accords sur l'utilisation d'appareils personnels.</div><div class=\"rule-card\"><strong>Protection contre les calamités</strong><br>Mesures contre l'incendie, l'inondation et les pannes de courant (systèmes d'extinction, alimentation de secours, données sur un second site).</div></div><h3>13. Gestion des systèmes d'information</h3><p>Un système d'information doit être maintenu en bon état. Le livre distingue:</p><div class=\"rule-grid\"><div class=\"rule-card\"><strong>Gestion fonctionnelle</strong><br>Axée sur l'utilisation: soutenir les utilisateurs, attribuer les droits d'accès, tenir à jour les définitions de données et les procédures, traduire les nouveaux besoins d'information dans le système.</div><div class=\"rule-card\"><strong>Gestion technique</strong><br>Axée sur la technique: entretenir et remplacer le matériel, installer les mises à jour et nouvelles versions des logiciels, gérer le réseau et le stockage.</div><div class=\"rule-card\"><strong>Gestion des données</strong><br>Veiller à ce que les collections de données restent correctes, complètes et à jour (p. ex. nettoyer le fichier clients).</div></div><div class=\"example-box\"><strong>Exemple De Leeuw BV:</strong> après le passage à un progiciel ERP, les programmes et les données sont fournis de manière centralisée, les sauvegardes sont faites centralement et régulièrement, et les utilisateurs ne doivent plus gérer eux-mêmes leur ordinateur — la gestion fonctionnelle et technique est centralisée et les coûts diminuent.</div>"},"exercises":[{"id":"h4_7","correct":1,"text_nl":"Welke soort software regelt de werking van de computer zelf en de communicatie met randapparatuur (bijv. Windows, Linux, iOS)?","text_en":"Which type of software controls the operation of the computer itself and the communication with peripherals (e.g. Windows, Linux, iOS)?","text_fr":"Quel type de logiciel gère le fonctionnement de l'ordinateur lui-même et la communication avec les périphériques (p. ex. Windows, Linux, iOS) ?","options_nl":["Toepassingssoftware","Besturingssoftware","Maatwerksoftware","Groupware"],"options_en":["Application software","Operating software","Custom software","Groupware"],"options_fr":["Logiciel applicatif","Logiciel d'exploitation","Logiciel sur mesure","Groupware"],"hint1_nl":"Denk aan de software die er al is vóórdat je ook maar één programma opent.","hint1_en":"Think of the software that is already there before you open a single program.","hint1_fr":"Pensez au logiciel déjà présent avant même d'ouvrir un programme.","hint2_nl":"Besturingssoftware (operating system) regelt de computer zelf; toepassingssoftware is waarmee de gebruiker zijn taken uitvoert.","hint2_en":"Operating software (the operating system) controls the computer itself; application software is what the user works with.","hint2_fr":"Le logiciel d'exploitation (système d'exploitation) gère l'ordinateur lui-même; le logiciel applicatif sert aux tâches de l'utilisateur.","sol_nl":"Besturingssoftware. Windows, Linux en iOS zijn besturingssystemen: ze regelen de werking van de computer en de communicatie met randapparatuur. Toepassingssoftware (zoals Word of een boekhoudpakket) draait er bovenop.","sol_en":"Operating software. Windows, Linux and iOS are operating systems: they control the computer and the communication with peripherals. Application software (like Word or an accounting package) runs on top of it.","sol_fr":"Le logiciel d'exploitation. Windows, Linux et iOS sont des systèmes d'exploitation: ils gèrent l'ordinateur et la communication avec les périphériques. Le logiciel applicatif (comme Word ou un logiciel comptable) fonctionne par-dessus."},{"id":"h4_8","correct":2,"text_nl":"Bij bakkerij Korst BV breekt brand uit en het serverlokaal is onbruikbaar. Dankzij een vooraf gemaakte afspraak draait de orderverwerking dezelfde dag nog verder op computers op een andere locatie. Welke beveiligingsmaatregel is dit?","text_en":"A fire breaks out at bakery Korst BV and the server room is unusable. Thanks to a prior arrangement, order processing continues the same day on computers at another location. Which security measure is this?","text_fr":"Un incendie éclate à la boulangerie Korst BV et la salle des serveurs est inutilisable. Grâce à un accord préalable, le traitement des commandes continue le jour même sur des ordinateurs d'un autre site. De quelle mesure de sécurité s'agit-il ?","options_nl":["Back-up","Restore","Uitwijk","Codering (encryptie)"],"options_en":["Back-up","Restore","Fallback (uitwijk)","Encryption"],"options_fr":["Back-up (sauvegarde)","Restore (restauration)","Site de repli (uitwijk)","Chiffrement"],"hint1_nl":"Het gaat hier niet om het kopiëren of terugzetten van gegevens, maar om het VOORTZETTEN van de verwerking elders.","hint1_en":"This is not about copying or restoring data, but about CONTINUING processing elsewhere.","hint1_fr":"Il ne s'agit pas de copier ou restaurer des données, mais de POURSUIVRE le traitement ailleurs.","hint2_nl":"Back-up = reservekopie maken; restore = kopie terugzetten; uitwijk = bij een calamiteit verder werken op een andere locatie of andere apparatuur.","hint2_en":"Back-up = making a copy; restore = putting the copy back; fallback = continuing work at another location or on other equipment during a calamity.","hint2_fr":"Back-up = faire une copie; restore = restaurer la copie; repli = continuer le travail sur un autre site ou un autre matériel lors d'un sinistre.","sol_nl":"Uitwijk. De verwerking wordt na een calamiteit voortgezet op een andere locatie. Een back-up en restore zijn vaak nodig om de gegevens daar beschikbaar te krijgen, maar de maatregel 'elders verder draaien' heet uitwijk.","sol_en":"Fallback (uitwijk). After a calamity, processing continues at another location. A back-up and restore are often needed to get the data there, but the measure of 'running elsewhere' is called fallback.","sol_fr":"Le site de repli (uitwijk). Après un sinistre, le traitement se poursuit sur un autre site. Une sauvegarde et une restauration sont souvent nécessaires pour y rendre les données disponibles, mais la mesure « continuer ailleurs » s'appelle le repli."},{"id":"h4_9","correct":1,"text_nl":"Het onderhouden en vervangen van hardware en het installeren van software-updates valt onder welke vorm van beheer van informatiesystemen?","text_en":"Maintaining and replacing hardware and installing software updates falls under which form of information system management?","text_fr":"L'entretien et le remplacement du matériel ainsi que l'installation des mises à jour logicielles relèvent de quelle forme de gestion des systèmes d'information ?","options_nl":["Functioneel beheer","Technisch beheer","Gegevensbeheer","Workflowmanagement"],"options_en":["Functional management","Technical management","Data management","Workflow management"],"options_fr":["Gestion fonctionnelle","Gestion technique","Gestion des données","Gestion des flux de travail"],"hint1_nl":"Gaat het hier over de gebruikers en hun rechten, of over de techniek zelf?","hint1_en":"Is this about the users and their rights, or about the technology itself?","hint1_fr":"S'agit-il des utilisateurs et de leurs droits, ou de la technique elle-même ?","hint2_nl":"Functioneel beheer = gericht op het gebruik (gebruikersrechten, procedures); technisch beheer = gericht op hardware, software-updates, netwerk en opslag.","hint2_en":"Functional management = focused on use (user rights, procedures); technical management = focused on hardware, software updates, network and storage.","hint2_fr":"Gestion fonctionnelle = axée sur l'utilisation (droits d'accès, procédures); gestion technique = axée sur le matériel, les mises à jour, le réseau et le stockage.","sol_nl":"Technisch beheer. Hardware onderhouden/vervangen en updates installeren is techniek. Functioneel beheer gaat over het gebruik van het systeem (rechten toekennen, procedures actueel houden); gegevensbeheer over de juistheid van de gegevensverzamelingen.","sol_en":"Technical management. Maintaining/replacing hardware and installing updates is technology. Functional management concerns the use of the system (granting rights, keeping procedures up to date); data management concerns the correctness of the data collections.","sol_fr":"La gestion technique. Entretenir/remplacer le matériel et installer des mises à jour relève de la technique. La gestion fonctionnelle concerne l'utilisation du système (attribution des droits, procédures à jour); la gestion des données, l'exactitude des collections de données."},{"id":"h4_10","correct":1,"text_nl":"Machinefabriek De Leeuw BV voert een nieuw informatiesysteem in. Het systeem werkt foutloos en is goed beveiligd, maar de medewerkers vinden de schermen onlogisch opgebouwd, de meldingen onduidelijk en ze hebben weken training nodig. Welke kwaliteitseis schiet hier tekort?","text_en":"Machine factory De Leeuw BV implements a new information system. The system works flawlessly and is well secured, but the employees find the screens illogically structured, the messages unclear, and they need weeks of training. Which quality requirement falls short here?","text_fr":"L'usine de machines De Leeuw BV met en place un nouveau système d'information. Le système fonctionne sans erreur et est bien sécurisé, mais les employés trouvent les écrans illogiques, les messages peu clairs, et ils ont besoin de semaines de formation. Quelle exigence de qualité fait défaut ici ?","options_nl":["Betrouwbaarheid","Gebruiksvriendelijkheid","Integriteit","Controleerbaarheid"],"options_en":["Reliability","User-friendliness","Integrity","Auditability"],"options_fr":["Fiabilité","Convivialité","Intégrité","Contrôlabilité"],"hint1_nl":"Het systeem zelf werkt prima — het probleem ligt bij de bediening door de mensen.","hint1_en":"The system itself works fine — the problem lies in how people operate it.","hint1_fr":"Le système fonctionne bien — le problème se situe dans son utilisation par les personnes.","hint2_nl":"Gebruiksvriendelijkheid = het systeem moet eenvoudig te bedienen zijn: logische schermen, duidelijke meldingen, weinig opleiding nodig.","hint2_en":"User-friendliness = the system must be easy to operate: logical screens, clear messages, little training required.","hint2_fr":"Convivialité = le système doit être simple à utiliser: écrans logiques, messages clairs, peu de formation nécessaire.","sol_nl":"Gebruiksvriendelijkheid. Het systeem is betrouwbaar (werkt foutloos) en beveiligd, maar moeilijk te bedienen: onlogische schermen, onduidelijke meldingen en veel training nodig. Dat is precies de kwaliteitseis gebruiksvriendelijkheid die tekortschiet.","sol_en":"User-friendliness. The system is reliable (works flawlessly) and secure, but hard to operate: illogical screens, unclear messages and lots of training needed. That is exactly the quality requirement of user-friendliness falling short.","sol_fr":"La convivialité. Le système est fiable (fonctionne sans erreur) et sécurisé, mais difficile à utiliser: écrans illogiques, messages peu clairs et beaucoup de formation nécessaire. C'est exactement l'exigence de convivialité qui fait défaut."}]},"h5":{"theoryExtra":{"nl":"<h3>9. Schermformulieren, rapporten en menustructuur</h3>\n<p>Een gebruiker werkt nooit rechtstreeks in de bestanden, maar via een <strong>schermformulier</strong> (invulscherm). De <strong>blokstructuur</strong> van zo'n formulier toont welke blokken aan welke gegevensverzamelingen gekoppeld zijn: bij het invullen van een verkooporder haalt het systeem gegevens op uit MEDEWERKERS, KLANTEN en PRODUCTEN en slaat het resultaat op in VERKOOPORDERS en ORDERREGELS. Procesgegevens (bedragen) worden meteen berekend en niet ingetypt.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Schermformulier</strong><br>Invulscherm voor invoer; velden zijn gekoppeld aan bestanden, veel velden vult de computer automatisch in.</div>\n <div class=\"rule-card\"><strong>Standaardrapport</strong><br>Vast uitvoeroverzicht uit het systeem, bv. een verkoopoverzicht per klant over een periode.</div>\n <div class=\"rule-card\"><strong>Menustructuur</strong><br>Vaste boom van keuzes waarmee je formulieren en rapporten opent; bepaalt ook wie waar toegang toe heeft.</div>\n <div class=\"rule-card\"><strong>Online transacties</strong><br>Klanten vullen zelf een online schermformulier in (webshop); de bestelling komt rechtstreeks in de gegevensverzamelingen en de klant krijgt een orderbevestiging per e-mail.</div>\n</div>\n\n<h3>10. Kenmerken van gegevens: syntaxis, semantiek, pragmatiek</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Syntaxis</strong><br>De <em>vorm</em>: regels waaraan de schrijfwijze moet voldoen.<br><em>Bijv.: een klantnummer bestaat uit 3 letters + 5 cijfers.</em></div>\n <div class=\"rule-card\"><strong>Semantiek</strong><br>De <em>betekenis</em>: wat stelt het gegeven voor? \"Prijs\" — is dat met of zonder btw? Afdelingen kunnen aan hetzelfde woord een andere betekenis geven.</div>\n <div class=\"rule-card\"><strong>Pragmatiek</strong><br>Het <em>gebruik</em>: afspraken over hoe het gegeven in de praktijk gebruikt en bijgehouden wordt (wie werkt het bij, hoe actueel moet het zijn?).</div>\n</div>\n<div class=\"tip-box\"><strong>Standaardisatie:</strong> om syntactische en semantische spraakverwarring te vermijden legt een organisatie afspraken vast in <strong>metagegevens</strong>: gegevens óver de gegevens (naam, betekenis, schrijfwijze van elk veld).</div>\n\n<h3>11. Bestandsterminologie</h3>\n<p>Een bestand (op het scherm: <strong>tabel</strong>) heeft vaste standaardbegrippen:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Bestandsnaam</strong><br>Naam van de hele gegevensverzameling, bv. MEDEWERKERS.</div>\n <div class=\"rule-card\"><strong>Record</strong><br>Eén <em>rij</em>: alle bij elkaar horende gegevenswaarden van één concreet object (één medewerker). Elk record is uniek.</div>\n <div class=\"rule-card\"><strong>Veldnaam (attribuuttype)</strong><br>Naam van een <em>kolom</em>, bv. Naam, Afdeling, Functie.</div>\n <div class=\"rule-card\"><strong>Gegevenswaarde</strong><br>Eén concrete waarde in een cel, bv. \"Hendriks\" of \"Verkoop\".</div>\n</div>\n<p>Het <strong>entiteittype</strong> is het soort object waarover het bestand gegevens bevat (bv. medewerker, klant, product). De <strong>sleutel</strong> is ook een <em>zoeksleutel</em>: ermee vind je snel één record. Bestaat er geen enkel veld dat uniek is, dan combineer je velden tot een <strong>samengestelde sleutel</strong> (bv. bestelnr + productnr in ORDERREGELS).</p>\n\n<h3>12. Relationele database en het gegevensstructuurdiagram (GSD)</h3>\n<p>Een <strong>relationele database</strong> is een verzameling bestanden die via relaties (overeenkomende velden, zoals klantnr) aan elkaar gekoppeld zijn. Een <strong>centrale database</strong> betekent dat de gegevens op één plaats opgeslagen zijn en door alle informatiesystemen van het bedrijf gebruikt worden.</p>\n<p>Een <strong>gegevensstructuurdiagram (GSD)</strong> is een schematische tekening van de relaties tussen bestanden. Beschrijving van het diagram: elk bestand is een rechthoek; lijnen met pijlen verbinden de rechthoeken, met het overeenkomende veld (bv. klantnr) bij de lijn.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Enkele pijl →</strong><br>Een record van het ene bestand hoort bij <em>precies één</em> record van het andere bestand. Bv.: VERKOOPORDERS → MEDEWERKERS: één order hoort bij één medewerker.</div>\n <div class=\"rule-card\"><strong>Dubbele pijl ⇒</strong><br>Een record kan bij <em>meerdere</em> records horen. Bv.: MEDEWERKERS ⇒ VERKOOPORDERS: één medewerker kan meerdere orders afsluiten.</div>\n</div>\n<div class=\"note-box\"><strong>Directe vs. indirecte relatie:</strong> niet elke twee bestanden zijn rechtstreeks verbonden. MEDEWERKERS en KLANTEN hebben geen directe relatie, maar wel een <em>indirecte</em> via VERKOOPORDERS.</div>\n\n<h3>13. Het internet als informatiebron</h3>\n<p>Informatie op internet is — anders dan in een database — <strong>ongestructureerd</strong> en niet vooraf geordend of geselecteerd. Beoordeel gevonden informatie altijd op: <em>actualiteit, betrouwbaarheid, relevantie, volledigheid en herkomst</em>. Zoeken op internet is vaak <em>trial and error</em>; een systematische <strong>zoekstrategie</strong> helpt:</p>\n<ol>\n <li>Stel de informatiebehoefte vast</li>\n <li>Bepaal/formuleer vragen met relevante zoektermen</li>\n <li>Selecteer de benodigde zoekmachines</li>\n <li>Voer de zoekvragen in in de gekozen zoekmachines</li>\n <li>Evalueer de resultaten</li>\n <li>Herhaal indien nodig stap 2 tot en met 5</li>\n</ol>\n<div class=\"tip-box\"><strong>Geavanceerd zoeken:</strong> zet een zoekterm tussen <strong>aanhalingstekens \"...\"</strong> voor een exacte tekst. Een <strong>plusteken (+)</strong> werkt als AND, een <strong>minteken (−)</strong> als NOT. De operator <strong>NEAR</strong> heet ook <em>proximity search</em>: beide termen moeten dicht bij elkaar staan. Boole-expressies kun je combineren met haakjes, bv. Printers AND (HP OR Epson).</div>","en":"<h3>9. Screen forms, reports and menu structure</h3>\n<p>A user never works directly in the files, but through a <strong>screen form</strong> (input form). The form's <strong>block structure</strong> shows which blocks are linked to which data collections: when entering a sales order the system retrieves data from EMPLOYEES, CUSTOMERS and PRODUCTS and stores the result in SALESORDERS and ORDERLINES. Process data (amounts) are calculated instantly, never typed in.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Screen form</strong><br>Input screen; fields are linked to files, many fields are filled in automatically by the computer.</div>\n <div class=\"rule-card\"><strong>Standard report</strong><br>Fixed output overview from the system, e.g. a sales overview per customer over a period.</div>\n <div class=\"rule-card\"><strong>Menu structure</strong><br>Fixed tree of choices to open forms and reports; also determines who has access to what.</div>\n <div class=\"rule-card\"><strong>Online transactions</strong><br>Customers fill in an online screen form themselves (webshop); the order goes straight into the data collections and the customer receives an order confirmation by e-mail.</div>\n</div>\n\n<h3>10. Characteristics of data: syntax, semantics, pragmatics</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Syntax</strong><br>The <em>form</em>: rules the notation must follow.<br><em>E.g.: a customer number consists of 3 letters + 5 digits.</em></div>\n <div class=\"rule-card\"><strong>Semantics</strong><br>The <em>meaning</em>: what does the data represent? \"Price\" — with or without VAT? Departments may attach different meanings to the same word.</div>\n <div class=\"rule-card\"><strong>Pragmatics</strong><br>The <em>use</em>: agreements about how the data is used and maintained in practice (who updates it, how current must it be?).</div>\n</div>\n<div class=\"tip-box\"><strong>Standardisation:</strong> to avoid syntactic and semantic confusion, an organisation records agreements as <strong>metadata</strong>: data about the data (name, meaning, notation of each field).</div>\n\n<h3>11. File terminology</h3>\n<p>A file (on screen: a <strong>table</strong>) has fixed standard terms:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>File name</strong><br>Name of the whole data collection, e.g. EMPLOYEES.</div>\n <div class=\"rule-card\"><strong>Record</strong><br>One <em>row</em>: all related data values of one concrete object (one employee). Every record is unique.</div>\n <div class=\"rule-card\"><strong>Field name (attribute type)</strong><br>Name of a <em>column</em>, e.g. Name, Department, Function.</div>\n <div class=\"rule-card\"><strong>Data value</strong><br>One concrete value in a cell, e.g. \"Hendriks\" or \"Sales\".</div>\n</div>\n<p>The <strong>entity type</strong> is the kind of object the file holds data about (e.g. employee, customer, product). The <strong>key</strong> is also a <em>search key</em>: it lets you find one record quickly. If no single field is unique, combine fields into a <strong>composite key</strong> (e.g. ordernr + productnr in ORDERLINES).</p>\n\n<h3>12. Relational database and the data structure diagram (DSD)</h3>\n<p>A <strong>relational database</strong> is a set of files linked through relations (matching fields, such as customer number). A <strong>central database</strong> means the data is stored in one place and used by all the company's information systems.</p>\n<p>A <strong>data structure diagram (DSD/GSD)</strong> is a schematic drawing of the relations between files: each file is a rectangle; lines with arrows connect the rectangles, with the matching field (e.g. customer nr) next to the line.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Single arrow →</strong><br>A record of one file belongs to <em>exactly one</em> record of the other file. E.g.: SALESORDERS → EMPLOYEES: one order belongs to one employee.</div>\n <div class=\"rule-card\"><strong>Double arrow ⇒</strong><br>A record can belong to <em>several</em> records. E.g.: EMPLOYEES ⇒ SALESORDERS: one employee can close several orders.</div>\n</div>\n<div class=\"note-box\"><strong>Direct vs. indirect relation:</strong> not every pair of files is directly connected. EMPLOYEES and CUSTOMERS have no direct relation, but they have an <em>indirect</em> one via SALESORDERS.</div>\n\n<h3>13. The internet as a source of information</h3>\n<p>Unlike a database, information on the internet is <strong>unstructured</strong> and not pre-ordered or pre-selected. Always judge found information on: <em>currency, reliability, relevance, completeness and origin</em>. Searching is often <em>trial and error</em>; a systematic <strong>search strategy</strong> helps:</p>\n<ol>\n <li>Determine the information need</li>\n <li>Formulate questions with relevant search terms</li>\n <li>Select the required search engines</li>\n <li>Enter the queries in the chosen search engines</li>\n <li>Evaluate the results</li>\n <li>If needed, repeat steps 2 to 5</li>\n</ol>\n<div class=\"tip-box\"><strong>Advanced searching:</strong> put a term between <strong>quotation marks \"...\"</strong> for an exact text. A <strong>plus sign (+)</strong> works like AND, a <strong>minus sign (−)</strong> like NOT. The <strong>NEAR</strong> operator is also called <em>proximity search</em>: both terms must appear close together. Boolean expressions can be combined with brackets, e.g. Printers AND (HP OR Epson).</div>","fr":"<h3>9. Formulaires d'écran, rapports et structure de menu</h3>\n<p>Un utilisateur ne travaille jamais directement dans les fichiers, mais via un <strong>formulaire d'écran</strong> (écran de saisie). La <strong>structure en blocs</strong> du formulaire montre quels blocs sont liés à quelles collections de données: lors de la saisie d'un bon de commande, le système récupère les données dans EMPLOYÉS, CLIENTS et PRODUITS et enregistre le résultat dans COMMANDES et LIGNESCOMMANDE. Les données de traitement (montants) sont calculées immédiatement, jamais saisies.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Formulaire d'écran</strong><br>Écran de saisie; les champs sont liés aux fichiers, beaucoup de champs sont remplis automatiquement par l'ordinateur.</div>\n <div class=\"rule-card\"><strong>Rapport standard</strong><br>Sortie fixe du système, p. ex. un aperçu des ventes par client sur une période.</div>\n <div class=\"rule-card\"><strong>Structure de menu</strong><br>Arborescence fixe de choix pour ouvrir formulaires et rapports; détermine aussi qui a accès à quoi.</div>\n <div class=\"rule-card\"><strong>Transactions en ligne</strong><br>Les clients remplissent eux-mêmes un formulaire en ligne (boutique web); la commande entre directement dans les collections de données et le client reçoit une confirmation par e-mail.</div>\n</div>\n\n<h3>10. Caractéristiques des données: syntaxe, sémantique, pragmatique</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Syntaxe</strong><br>La <em>forme</em>: règles d'écriture à respecter.<br><em>P. ex.: un numéro client = 3 lettres + 5 chiffres.</em></div>\n <div class=\"rule-card\"><strong>Sémantique</strong><br>La <em>signification</em>: que représente la donnée ? « Prix » — avec ou sans TVA ? Des services peuvent donner un sens différent au même mot.</div>\n <div class=\"rule-card\"><strong>Pragmatique</strong><br>L'<em>usage</em>: accords sur la manière d'utiliser et de tenir à jour la donnée en pratique (qui la met à jour, quelle actualité ?).</div>\n</div>\n<div class=\"tip-box\"><strong>Standardisation:</strong> pour éviter les confusions syntaxiques et sémantiques, l'organisation fixe des accords dans des <strong>métadonnées</strong>: des données sur les données (nom, signification, notation de chaque champ).</div>\n\n<h3>11. Terminologie des fichiers</h3>\n<p>Un fichier (à l'écran: une <strong>table</strong>) possède des termes standard:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Nom de fichier</strong><br>Nom de toute la collection de données, p. ex. EMPLOYÉS.</div>\n <div class=\"rule-card\"><strong>Enregistrement (record)</strong><br>Une <em>ligne</em>: toutes les valeurs liées d'un objet concret (un employé). Chaque enregistrement est unique.</div>\n <div class=\"rule-card\"><strong>Nom de champ (type d'attribut)</strong><br>Nom d'une <em>colonne</em>, p. ex. Nom, Service, Fonction.</div>\n <div class=\"rule-card\"><strong>Valeur de donnée</strong><br>Une valeur concrète dans une cellule, p. ex. « Hendriks » ou « Ventes ».</div>\n</div>\n<p>Le <strong>type d'entité</strong> est le genre d'objet décrit par le fichier (employé, client, produit...). La <strong>clé</strong> est aussi une <em>clé de recherche</em>: elle permet de retrouver rapidement un enregistrement. S'il n'existe aucun champ unique, on combine des champs en une <strong>clé composée</strong> (p. ex. n° commande + n° produit dans LIGNESCOMMANDE).</p>\n\n<h3>12. Base de données relationnelle et diagramme de structure de données (GSD)</h3>\n<p>Une <strong>base de données relationnelle</strong> est un ensemble de fichiers reliés par des relations (champs communs, comme le n° client). Une <strong>base de données centrale</strong> signifie que les données sont stockées à un seul endroit et utilisées par tous les systèmes d'information de l'entreprise.</p>\n<p>Un <strong>diagramme de structure de données (GSD)</strong> est un schéma des relations entre fichiers: chaque fichier est un rectangle; des lignes avec des flèches relient les rectangles, le champ commun (p. ex. n° client) figurant près de la ligne.</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Flèche simple →</strong><br>Un enregistrement appartient à <em>exactement un</em> enregistrement de l'autre fichier. P. ex.: COMMANDES → EMPLOYÉS: une commande appartient à un seul employé.</div>\n <div class=\"rule-card\"><strong>Flèche double ⇒</strong><br>Un enregistrement peut appartenir à <em>plusieurs</em> enregistrements. P. ex.: EMPLOYÉS ⇒ COMMANDES: un employé peut conclure plusieurs commandes.</div>\n</div>\n<div class=\"note-box\"><strong>Relation directe vs indirecte:</strong> deux fichiers ne sont pas toujours reliés directement. EMPLOYÉS et CLIENTS n'ont pas de relation directe, mais une relation <em>indirecte</em> via COMMANDES.</div>\n\n<h3>13. L'internet comme source d'information</h3>\n<p>Contrairement à une base de données, l'information sur internet est <strong>non structurée</strong> et n'est ni triée ni sélectionnée à l'avance. Évaluez toujours l'information trouvée sur: <em>actualité, fiabilité, pertinence, exhaustivité et origine</em>. La recherche est souvent du <em>trial and error</em>; une <strong>stratégie de recherche</strong> systématique aide:</p>\n<ol>\n <li>Déterminer le besoin d'information</li>\n <li>Formuler des questions avec des termes de recherche pertinents</li>\n <li>Sélectionner les moteurs de recherche nécessaires</li>\n <li>Saisir les requêtes dans les moteurs choisis</li>\n <li>Évaluer les résultats</li>\n <li>Si nécessaire, répéter les étapes 2 à 5</li>\n</ol>\n<div class=\"tip-box\"><strong>Recherche avancée:</strong> mettez un terme entre <strong>guillemets \"...\"</strong> pour un texte exact. Le <strong>signe plus (+)</strong> agit comme AND, le <strong>signe moins (−)</strong> comme NOT. L'opérateur <strong>NEAR</strong> s'appelle aussi <em>proximity search</em>: les deux termes doivent être proches l'un de l'autre. Les expressions booléennes se combinent avec des parenthèses, p. ex. Printers AND (HP OR Epson).</div>"},"exercises":[{"id":"h5_7","correct":1,"text_nl":"Twee afdelingen van een bedrijf gebruiken allebei het veld 'Prijs', maar bij de verkoopafdeling is dat de prijs inclusief btw en bij de boekhouding exclusief btw. Op welk kenmerk van gegevens slaat dit probleem?","text_en":"Two departments of a company both use the field 'Price', but for the sales department it means the price including VAT and for accounting excluding VAT. Which characteristic of data does this problem concern?","text_fr":"Deux services d'une entreprise utilisent le champ « Prix », mais pour le service des ventes c'est le prix TVA comprise et pour la comptabilité hors TVA. À quelle caractéristique des données ce problème se rapporte-t-il ?","options_nl":["Syntaxis: de schrijfwijze van het gegeven","Semantiek: de betekenis van het gegeven","Pragmatiek: het praktische gebruik van het gegeven","Redundantie: dubbele opslag van het gegeven"],"options_en":["Syntax: the notation of the data","Semantics: the meaning of the data","Pragmatics: the practical use of the data","Redundancy: duplicate storage of the data"],"options_fr":["La syntaxe: la notation de la donnée","La sémantique: la signification de la donnée","La pragmatique: l'usage pratique de la donnée","La redondance: le stockage en double de la donnée"],"hint1_nl":"Het gaat hier niet over hoe het gegeven geschreven wordt, maar over wat het voorstelt.","hint1_en":"This is not about how the data is written, but about what it represents.","hint1_fr":"Il ne s'agit pas de la manière d'écrire la donnée, mais de ce qu'elle représente.","hint2_nl":"Syntaxis = vorm, semantiek = betekenis, pragmatiek = gebruik. Hetzelfde woord met een andere betekenis is een semantisch probleem.","hint2_en":"Syntax = form, semantics = meaning, pragmatics = use. The same word with a different meaning is a semantic problem.","hint2_fr":"Syntaxe = forme, sémantique = signification, pragmatique = usage. Le même mot avec un sens différent est un problème sémantique.","sol_nl":"Semantiek gaat over de betekenis van een gegeven. Hier geven twee afdelingen een verschillende betekenis aan hetzelfde veld 'Prijs' (incl. vs. excl. btw): een semantisch probleem dat je oplost met standaardisatie en metagegevens.","sol_en":"Semantics concerns the meaning of data. Here two departments give a different meaning to the same field 'Price' (incl. vs. excl. VAT): a semantic problem solved with standardisation and metadata.","sol_fr":"La sémantique concerne la signification d'une donnée. Ici, deux services donnent un sens différent au même champ « Prix » (TVAC vs HTVA): un problème sémantique que l'on résout par la standardisation et les métadonnées."},{"id":"h5_8","correct":2,"text_nl":"In een gegevensstructuurdiagram (GSD) staat een dubbele pijl van MEDEWERKERS naar VERKOOPORDERS en een enkele pijl van VERKOOPORDERS naar MEDEWERKERS. Wat betekent dit?","text_en":"In a data structure diagram (DSD) there is a double arrow from EMPLOYEES to SALESORDERS and a single arrow from SALESORDERS to EMPLOYEES. What does this mean?","text_fr":"Dans un diagramme de structure de données (GSD), une flèche double va de EMPLOYÉS vers COMMANDES et une flèche simple de COMMANDES vers EMPLOYÉS. Qu'est-ce que cela signifie ?","options_nl":["Elke medewerker hoort bij precies één verkooporder","De bestanden hebben een indirecte relatie zonder overeenkomend veld","Eén medewerker kan meerdere verkooporders hebben, maar elke verkooporder hoort bij precies één medewerker","Elke verkooporder kan bij meerdere medewerkers horen"],"options_en":["Each employee belongs to exactly one sales order","The files have an indirect relation without a matching field","One employee can have several sales orders, but each sales order belongs to exactly one employee","Each sales order can belong to several employees"],"options_fr":["Chaque employé appartient à exactement une commande","Les fichiers ont une relation indirecte sans champ commun","Un employé peut avoir plusieurs commandes, mais chaque commande appartient à exactement un employé","Chaque commande peut appartenir à plusieurs employés"],"hint1_nl":"Kijk per pijl: van welk bestand vertrekt hij en wat zegt enkel vs. dubbel over het aantal records aan de andere kant?","hint1_en":"Look at each arrow: where does it start and what does single vs. double say about the number of records on the other side?","hint1_fr":"Regardez chaque flèche: d'où part-elle et que dit simple vs double sur le nombre d'enregistrements de l'autre côté ?","hint2_nl":"Enkele pijl = een record hoort bij precies één record van het andere bestand; dubbele pijl = een record kan bij meerdere records horen.","hint2_en":"Single arrow = a record belongs to exactly one record of the other file; double arrow = a record can belong to several records.","hint2_fr":"Flèche simple = un enregistrement appartient à exactement un enregistrement de l'autre fichier; flèche double = il peut appartenir à plusieurs.","sol_nl":"De dubbele pijl van MEDEWERKERS naar VERKOOPORDERS zegt dat één medewerker meerdere orders kan afsluiten; de enkele pijl terug zegt dat elke order bij precies één medewerker hoort. Samen vormen ze een 1-op-n relatie.","sol_en":"The double arrow from EMPLOYEES to SALESORDERS says one employee can close several orders; the single arrow back says each order belongs to exactly one employee. Together they form a 1-to-n relation.","sol_fr":"La flèche double de EMPLOYÉS vers COMMANDES indique qu'un employé peut conclure plusieurs commandes; la flèche simple en retour indique que chaque commande appartient à exactement un employé. Ensemble, elles forment une relation 1-à-n."},{"id":"h5_9","correct":1,"text_nl":"In de tabel MEDEWERKERS van Supermarkt Jan staat in de kolom 'Afdeling' bij medewerker Hendriks de waarde 'Verkoop'. Hoe noem je de hele rij met alle gegevens van Hendriks, en hoe noem je de waarde 'Verkoop'?","text_en":"In Supermarket Jan's EMPLOYEES table, the column 'Department' shows the value 'Sales' for employee Hendriks. What do you call the whole row with all of Hendriks' data, and what do you call the value 'Sales'?","text_fr":"Dans la table EMPLOYÉS du Supermarché Jan, la colonne « Service » affiche la valeur « Ventes » pour l'employé Hendriks. Comment appelle-t-on la ligne entière avec toutes les données de Hendriks, et comment appelle-t-on la valeur « Ventes » ?","options_nl":["De rij is een veldnaam, 'Verkoop' is een record","De rij is een record, 'Verkoop' is een gegevenswaarde","De rij is een entiteittype, 'Verkoop' is een veldnaam","De rij is een gegevenswaarde, 'Verkoop' is een attribuuttype"],"options_en":["The row is a field name, 'Sales' is a record","The row is a record, 'Sales' is a data value","The row is an entity type, 'Sales' is a field name","The row is a data value, 'Sales' is an attribute type"],"options_fr":["La ligne est un nom de champ, « Ventes » est un enregistrement","La ligne est un enregistrement, « Ventes » est une valeur de donnée","La ligne est un type d'entité, « Ventes » est un nom de champ","La ligne est une valeur de donnée, « Ventes » est un type d'attribut"],"hint1_nl":"Een rij beschrijft één concreet object; een cel bevat één concrete waarde.","hint1_en":"A row describes one concrete object; a cell contains one concrete value.","hint1_fr":"Une ligne décrit un objet concret; une cellule contient une valeur concrète.","hint2_nl":"Record = rij met alle bij elkaar horende gegevenswaarden van één object. Gegevenswaarde = één waarde in een cel. Veldnaam = naam van de kolom.","hint2_en":"Record = row with all related data values of one object. Data value = one value in a cell. Field name = name of the column.","hint2_fr":"Enregistrement = ligne avec toutes les valeurs liées d'un objet. Valeur de donnée = une valeur dans une cellule. Nom de champ = nom de la colonne.","sol_nl":"De rij met alle gegevens van Hendriks is een record (elke rij is uniek en representeert één medewerker). 'Verkoop' is een gegevenswaarde in de kolom met veldnaam 'Afdeling'. Het entiteittype van dit bestand is 'medewerker'.","sol_en":"The row with all of Hendriks' data is a record (each row is unique and represents one employee). 'Sales' is a data value in the column with field name 'Department'. The entity type of this file is 'employee'.","sol_fr":"La ligne avec toutes les données de Hendriks est un enregistrement (chaque ligne est unique et représente un employé). « Ventes » est une valeur de donnée dans la colonne dont le nom de champ est « Service ». Le type d'entité de ce fichier est « employé »."},{"id":"h5_10","correct":2,"text_nl":"Een inkoper bij BitbyBit zoekt op internet handleidingen waarin de exacte zin 'drivers voor HP-printers' voorkomt, maar wil geen resultaten over Epson. Welke zoekopdracht past het best, en waarom?","text_en":"A buyer at BitbyBit searches the internet for manuals containing the exact phrase 'drivers for HP printers', but wants no results about Epson. Which query fits best, and why?","text_fr":"Un acheteur chez BitbyBit cherche sur internet des manuels contenant la phrase exacte « drivers pour imprimantes HP », mais ne veut aucun résultat sur Epson. Quelle requête convient le mieux, et pourquoi ?","options_nl":["drivers voor HP-printers OR Epson — OR vergroot het resultaat","drivers NEAR HP-printers AND Epson — NEAR zoekt de exacte zin","\"drivers voor HP-printers\" NOT Epson — aanhalingstekens zoeken de exacte tekst, NOT sluit Epson uit","drivers AND HP-printers AND Epson — AND verkleint het resultaat"],"options_en":["drivers for HP printers OR Epson — OR enlarges the result","drivers NEAR HP printers AND Epson — NEAR searches the exact phrase","\"drivers for HP printers\" NOT Epson — quotation marks search the exact text, NOT excludes Epson","drivers AND HP printers AND Epson — AND narrows the result"],"options_fr":["drivers pour imprimantes HP OR Epson — OR élargit le résultat","drivers NEAR imprimantes HP AND Epson — NEAR cherche la phrase exacte","\"drivers pour imprimantes HP\" NOT Epson — les guillemets cherchent le texte exact, NOT exclut Epson","drivers AND imprimantes HP AND Epson — AND réduit le résultat"],"hint1_nl":"Welk teken gebruik je voor een exacte tekst, en welke operator om iets uit te sluiten?","hint1_en":"Which sign do you use for an exact text, and which operator to exclude something?","hint1_fr":"Quel signe utilise-t-on pour un texte exact, et quel opérateur pour exclure quelque chose ?","hint2_nl":"Aanhalingstekens \"...\" = exact zoeken; NOT (of een minteken −) sluit een term uit; NEAR betekent alleen dat termen dicht bij elkaar staan.","hint2_en":"Quotation marks \"...\" = exact search; NOT (or a minus sign −) excludes a term; NEAR only means terms must be close together.","hint2_fr":"Les guillemets \"...\" = recherche exacte; NOT (ou un signe moins −) exclut un terme; NEAR signifie seulement que les termes doivent être proches.","sol_nl":"Tekst tussen aanhalingstekens wordt letterlijk als exacte zin gezocht. NOT (of het minteken) sluit de term Epson uit. NEAR is proximity search (termen dicht bij elkaar) en garandeert geen exacte zin; OR en AND met Epson zouden juist Epson-resultaten toelaten of vereisen.","sol_en":"Text between quotation marks is searched literally as an exact phrase. NOT (or the minus sign) excludes the term Epson. NEAR is proximity search (terms close together) and does not guarantee an exact phrase; OR and AND with Epson would allow or require Epson results.","sol_fr":"Un texte entre guillemets est recherché littéralement comme phrase exacte. NOT (ou le signe moins) exclut le terme Epson. NEAR est une recherche de proximité (termes proches) et ne garantit pas une phrase exacte; OR et AND avec Epson autoriseraient ou exigeraient des résultats Epson."}]},"h6":{"theoryExtra":{"nl":"<h3>7. Toegevoegde waarde — drie aandachtsgebieden</h3>\n<p>Bedrijven bestaan omdat ze een product of dienst leveren waaraan klanten behoefte hebben. Om die toegevoegde waarde in stand te houden zijn er <strong>drie aandachtsgebieden</strong>:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Uitstekende werking van de operationele bedrijfsprocessen</strong><br/>Kwaliteitsproducten snel, goed en goedkoop leveren; middelen efficiënt gebruiken, voortdurend meten, controleren en bijsturen.</div>\n <div class=\"rule-card\"><strong>2. Uitstekende servicegerichtheid</strong><br/>De klant krijgt precies wat hij wil, toezeggingen worden nagekomen, problemen en klachten worden adequaat afgewerkt.</div>\n <div class=\"rule-card\"><strong>3. Innovatief vermogen</strong><br/>Voortdurend nieuwe producten of diensten realiseren; kennis van marktontwikkelingen en klantbehoeften is essentieel.</div>\n</div>\n<div class=\"note-box\"><strong>Verbindende schakel:</strong> de verschillende bedrijfsprocessen staan niet los van elkaar — <strong>gegevens</strong> vormen de verbindende schakel. Het proces <em>Administreren</em> staat daarom centraal in het gegevensstroomschema van de organisatie: bijna alle stromen (orders, facturen, nota's) lopen erlangs. Parallel aan de gegevensstromen loopt een geld- en goederenstroom.</div>\n\n<h3>8. Het besturingsmodel volledig — alle onderdelen</h3>\n<p>Naast besturend orgaan, uitvoerend orgaan, stuur- en verantwoordingsinformatie kent het besturingsmodel (het <strong>besturingsparadigma</strong>) nog deze onderdelen — beschrijf het diagram als volgt: bovenaan het besturend orgaan, onderaan het bestuurd orgaan (uitvoerder), daaromheen de omgeving; links komt invoer binnen, rechts gaat uitvoer naar buiten:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Externe informatie</strong><br/>Informatie die het besturend orgaan van buiten ontvangt (markt, klachten, planning van de onderneming).</div>\n <div class=\"rule-card\"><strong>Berichten en stuuracties extern</strong><br/>Informatie die het besturend orgaan afgeeft aan de omgeving: rapportages, orders, verzoeken om onderhoud.</div>\n <div class=\"rule-card\"><strong>Invoer</strong><br/>Wat het uitvoerend orgaan transformeert tot uitvoer: grondstoffen óf gegevens (bijv. klantorders).</div>\n <div class=\"rule-card\"><strong>Uitvoer</strong><br/>Niet alleen de gerealiseerde producten, maar ook <em>afval en reststoffen</em>, en eventueel gegevens.</div>\n</div>\n<p><strong>Stuurinformatie kent twee soorten:</strong></p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Aansturingsinformatie</strong><br/>Zet het uitvoerend orgaan aan tot actie (\"start deze productieopdracht\").</div>\n <div class=\"rule-card\"><strong>Bijsturingsinformatie</strong><br/>Berichten waarmee wordt <em>ingegrepen op lopende activiteiten</em> (\"versnel order X, hij is te laat\").</div>\n</div>\n<div class=\"tip-box\"><strong>Binnencirkel:</strong> bij het besturen concentreert de informatie-uitwisseling zich op de <em>binnencirkel</em> van het model: stuurinformatie en verantwoordingsinformatie (met prestatie-indicatoren) tussen bestuurder en uitvoerder.</div>\n\n<h3>9. Norm, prestatie-indicator definiëren & de regelkring opzetten</h3>\n<p>Bij elke prestatie-indicator hoort een vooraf vastgestelde <strong>norm</strong> — die moet realistisch zijn en kan worden bepaald uit de bedrijfsdatabase of uit andere bronnen. Een prestatie-indicator moet expliciet benoemd worden en bevat:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Naam</strong><br/>Logisch en kernachtig (voor communicatie).</div>\n <div class=\"rule-card\"><strong>2. Berekenwijze</strong><br/>Hoe wordt hij berekend (meestal uit gegevens van de database)?</div>\n <div class=\"rule-card\"><strong>3. Norm</strong><br/>De waarde waaraan voldaan moet worden.</div>\n</div>\n<div class=\"example-box\"><strong>Voorbeeld 'Voorraadverschil':</strong> berekenwijze = (voorraad volgens kantoorvoorraadadministratie − aanwezige voorraad in magazijn)/(voorraad volgens kantooradministratie) × 100%; norm: kleiner dan 3%.</div>\n<p>Een goed werkende <strong>regelkring</strong> zet je op in <strong>vier stappen</strong>: 1) bepaal realistische doelen, 2) stel prestatie-indicatoren vast, 3) bepaal beperkingen en randvoorwaarden, 4) bepaal de meting.</p>\n<div class=\"note-box\">Prestatie-indicatoren verschillen per managementlaag: operationeel = functioneren van één proces binnen de afdeling; tactisch = performance van het totale bedrijfsproces of de afdeling; strategisch = functioneren van het totale bedrijf.</div>\n\n<h3>10. Integratie van databases — het iteratieve stappenplan</h3>\n<p>Gegevensverzamelingen van verschillende bedrijfsprocessen worden samengesmolten tot één gemeenschappelijke database via een <strong>iteratief proces</strong> (tabel 6.5):</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Stap 1</strong><br/>Neem twee databases en voeg ze samen.</div>\n <div class=\"rule-card\"><strong>Stap 2</strong><br/>Zoek alle <em>homoniemen</em> en 'verwijder' ze: geef een van beide begrippen een <em>nieuwe naam</em> (bijv. 'factuurdatum' en 'orderdatum' i.p.v. tweemaal 'datum').</div>\n <div class=\"rule-card\"><strong>Stap 3</strong><br/>Zoek alle <em>synoniemen</em> en 'verwijder' ze: gebruik overal <em>dezelfde naam</em> voor hetzelfde begrip (bijv. overal 'artikelnummer' i.p.v. ook 'productnummer').</div>\n <div class=\"rule-card\"><strong>Stap 4</strong><br/>Voeg bestanden met exact dezelfde sleutel samen (bijv. twee bestanden KLANTEN): alle attributen in één gemeenschappelijk bestand.</div>\n <div class=\"rule-card\"><strong>Stap 5</strong><br/>Controleer of het resultaat voldoet aan de ontwerpeisen voor een database.</div>\n <div class=\"rule-card\"><strong>Stap 6 & 7</strong><br/>Herhaal stap 1–5 tot alle databases geïntegreerd zijn; teken het <strong>gegevensstructuurdiagram</strong> van het geheel.</div>\n</div>\n<div class=\"note-box\"><strong>Gegevensstructuurdiagram:</strong> een schema met de gegevensverzamelingen (rechthoeken zoals KLANTEN, FACTUREN, FACTUURREGELS, ARTIKELEN) en pijlen die de relaties tussen die bestanden tonen. Let op: worden homoniemen <em>niet</em> verwijderd, dan ontstaan fouten omdat één naam twee betekenissen blijft hebben.</div>\n\n<h3>11. Managementinformatiesysteem (MIS) & dashboards</h3>\n<p>Een <strong>managementinformatiesysteem (MIS)</strong> geeft het management toegang tot de gegevensverzamelingen en kan gegevens <em>aggregeren, vergelijken, analyseren en samenbrengen</em> tot managementrapportages. Het levert standaardrapportages én laat slimme vragen (<strong>query's</strong>) op de database toe. Resultaten verschijnen zelden nog op papier maar op <strong>digitale dashboards</strong>: één oogopslag overzicht, vaak met <strong>stoplichtrapportages</strong> (groen/oranje/rood) die als alert tonen waar het anders loopt dan gepland.</p>\n\n<h3>12. Informatie per managementniveau</h3>\n<p>Beschrijf figuur 6.26 als een piramide (uitvoerend → operationeel → tactisch → strategisch) met twee driehoeken ernaast: onderaan domineert het ene profiel (±80%), bovenaan het andere (±80%):</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Operationeel niveau (±80% intern)</strong><br/>Intern, korte termijn, historischgericht, gedetailleerd, hoogfrequent, formeel, gestandaardiseerd. Smalle scoop.</div>\n <div class=\"rule-card\"><strong>Strategisch niveau (±80% extern)</strong><br/>Extern, lange termijn, toekomstgericht, geaggregeerd, onregelmatig, informeel, niet-gestandaardiseerd. Brede scoop.</div>\n</div>\n<p>Verwant onderscheid: <strong>procesgerichte (processpecifieke) informatie</strong> blijft binnen één bedrijfsproces; <strong>bedrijfsbrede informatie</strong> overstijgt de processen en is vooral voor het (top)management.</p>\n\n<h3>13. Standaardinformatie vs. ad-hocinformatie</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Standaard(management)informatie</strong><br/>Voorgeprogrammeerde uitvoer van het informatiesysteem. Drie kenmerken: <strong>periodiek</strong> (vaste regelmaat: per week/maand/kwartaal), <strong>comparatief</strong> (vergeleken met standaardwaarden zoals de norm van een prestatie-indicator) en <strong>geaggregeerd</strong>.</div>\n <div class=\"rule-card\"><strong>Ad-hoc(management)informatie</strong><br/>Eenmalig nodig, naar aanleiding van een specifieke situatie (bijv. 'budgetten onder druk'). Niet standaard in het systeem: wordt via query's uit de database of zelfs uit externe bronnen gehaald.</div>\n</div>\n<div class=\"tip-box\"><strong>Aggregeren</strong> = een groot aantal gegevens samenvoegen tot één grootheid: sommeren, het gemiddelde nemen, of de grootste/kleinste waarde bepalen. Hoe hoger het managementniveau, hoe sterker geaggregeerd de informatie.</div>\n<div class=\"note-box\"><strong>Business intelligence (BI):</strong> dankzij big data, Internet of Things en artificiële intelligentie evolueert BI van <em>historische</em> rapportages naar <em>voorspellende</em> (predictieve) analyses.</div>\n\n<h3>14. Verdieping ERP & SCM</h3>\n<p><strong>ERP-modules:</strong> verkoop, voorraadbeheer, productieplanning, capaciteitsplanning, distributieplanning, inkoop, financiële administratie — vaak aangevuld met debiteuren-, crediteuren-, inventaris- en budgetbeheer. ERP is in essentie een <strong>standaardsoftwarepakket</strong>; leveranciers maken <strong>branchegerichte oplossingen</strong> (bijv. confectie, voeding). De kracht van ERP in drie punten: fundamentele procesverbetering door de hele waardeketen, integrale managementinformatie van operationeel tot top, en vervanging van losse afdelingssystemen door één geïntegreerd systeem met één database.</p>\n<p><strong>SCM</strong> heet ook <strong>integraal ketenbeheer</strong>. Een belangrijk doel is het beperken van het <strong>opslingereffect</strong> (bullwhip): kleine schommelingen in de vraag bij de klant leiden — door vertraagde, indirecte informatie — tot steeds grotere voorraad- en productieschommelingen verderop in de keten. Door directe informatiedeling kunnen leveranciers <em>just-in-time</em> leveren. Ook logistieke dienstverleners passen SCM toe met eigen distributiecentra.</p>\n<div class=\"note-box\"><strong>Besturingshiërarchie als piramide (figuur 6.21):</strong> bovenaan de <em>besturende processen</em> (strategisch, tactisch, operationeel niveau), onderaan de <em>operationele processen</em>: de ondersteunende processen en helemaal onderaan het primaire proces. Operationele managers worden zelf weer gemanaged — zo ontstaan besturingslagen (geleding).</div>","en":"<h3>7. Added value — three areas of attention</h3>\n<p>Companies exist because they deliver a product or service customers need. To sustain that added value there are <strong>three areas of attention</strong>:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Excellent operation of the operational business processes</strong><br/>Deliver quality products fast, well and cheaply; use resources efficiently, continuously measure, control and adjust.</div>\n <div class=\"rule-card\"><strong>2. Excellent service orientation</strong><br/>The customer gets exactly what was promised; problems and complaints are handled adequately.</div>\n <div class=\"rule-card\"><strong>3. Innovative capacity</strong><br/>Continuously realise new products or services; knowledge of market developments and customer needs is essential.</div>\n</div>\n<div class=\"note-box\"><strong>Connecting link:</strong> business processes are not isolated — <strong>data</strong> is the connecting link between them. The process <em>Administration</em> is therefore central in the organisation's data flow diagram: almost all flows (orders, invoices, credit notes) pass through it. A money and goods flow runs parallel to the data flows.</div>\n\n<h3>8. The complete control model — all components</h3>\n<p>Besides controlling body, executing body, steering and accountability information, the control model (the <strong>control paradigm</strong>) has these components — picture the diagram as: controlling body on top, controlled body (executor) below, the environment around them; input enters on the left, output leaves on the right:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>External information</strong><br/>Information the controlling body receives from outside (market, complaints, company planning).</div>\n <div class=\"rule-card\"><strong>External messages and steering actions</strong><br/>Information the controlling body sends to the environment: reports, orders, maintenance requests.</div>\n <div class=\"rule-card\"><strong>Input</strong><br/>What the executing body transforms into output: raw materials or data (e.g. customer orders).</div>\n <div class=\"rule-card\"><strong>Output</strong><br/>Not only finished products, but also <em>waste and residual materials</em>, and possibly data.</div>\n</div>\n<p><strong>Steering information comes in two kinds:</strong></p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Initiating information</strong><br/>Triggers the executing body into action (\"start this production order\").</div>\n <div class=\"rule-card\"><strong>Adjustment information</strong><br/>Messages that <em>intervene in ongoing activities</em> (\"speed up order X, it is late\").</div>\n</div>\n<div class=\"tip-box\"><strong>Inner circle:</strong> when controlling a process, the information exchange concentrates on the <em>inner circle</em> of the model: steering information and accountability information (with performance indicators) between manager and executor.</div>\n\n<h3>9. Norm, defining a performance indicator & setting up the control loop</h3>\n<p>Every performance indicator has a predefined <strong>norm</strong> — it must be realistic and can be derived from the company database or other sources. A performance indicator must be explicitly defined and contains:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Name</strong><br/>Logical and concise (for communication).</div>\n <div class=\"rule-card\"><strong>2. Calculation method</strong><br/>How is it computed (usually from database data)?</div>\n <div class=\"rule-card\"><strong>3. Norm</strong><br/>The value that must be met.</div>\n</div>\n<div class=\"example-box\"><strong>Example 'Stock difference':</strong> calculation = (stock according to office records − actual stock in warehouse)/(stock according to office records) × 100%; norm: less than 3%.</div>\n<p>A well-functioning <strong>control loop</strong> is set up in <strong>four steps</strong>: 1) set realistic goals, 2) define performance indicators, 3) determine constraints and preconditions, 4) define the measurement.</p>\n<div class=\"note-box\">Performance indicators differ per management layer: operational = functioning of one process within the department; tactical = performance of the whole business process or department; strategic = functioning of the entire company.</div>\n\n<h3>10. Database integration — the iterative step plan</h3>\n<p>Data collections of different business processes are merged into one common database via an <strong>iterative process</strong>:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Step 1</strong><br/>Take two databases and merge them.</div>\n <div class=\"rule-card\"><strong>Step 2</strong><br/>Find all <em>homonyms</em> and 'remove' them: give one of the two concepts a <em>new name</em> (e.g. 'invoice date' and 'order date' instead of 'date' twice).</div>\n <div class=\"rule-card\"><strong>Step 3</strong><br/>Find all <em>synonyms</em> and 'remove' them: use the <em>same name</em> everywhere for the same concept (e.g. 'article number' everywhere instead of also 'product number').</div>\n <div class=\"rule-card\"><strong>Step 4</strong><br/>Merge files with exactly the same key (e.g. two CUSTOMERS files): all attributes in one common file.</div>\n <div class=\"rule-card\"><strong>Step 5</strong><br/>Check that the result meets the database design requirements.</div>\n <div class=\"rule-card\"><strong>Steps 6 & 7</strong><br/>Repeat steps 1–5 until all databases are integrated; draw the <strong>data structure diagram</strong> of the whole.</div>\n</div>\n<div class=\"note-box\"><strong>Data structure diagram:</strong> a schema showing the data collections (rectangles such as CUSTOMERS, INVOICES, INVOICE LINES, ARTICLES) with arrows showing the relations between them. Note: if homonyms are <em>not</em> removed, errors occur because one name keeps two meanings.</div>\n\n<h3>11. Management information system (MIS) & dashboards</h3>\n<p>A <strong>management information system (MIS)</strong> gives management access to the data collections and can <em>aggregate, compare, analyse and combine</em> data into management reports. It delivers standard reports and allows smart questions (<strong>queries</strong>) on the database. Results rarely appear on paper anymore but on <strong>digital dashboards</strong>: overview at a glance, often with <strong>traffic-light reporting</strong> (green/orange/red) acting as an alert showing where things deviate from plan.</p>\n\n<h3>12. Information per management level</h3>\n<p>Picture figure 6.26 as a pyramid (executing → operational → tactical → strategic) with two triangles beside it: at the bottom one profile dominates (±80%), at the top the other (±80%):</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Operational level (±80% internal)</strong><br/>Internal, short term, history-oriented, detailed, high-frequency, formal, standardised. Narrow scope.</div>\n <div class=\"rule-card\"><strong>Strategic level (±80% external)</strong><br/>External, long term, future-oriented, aggregated, irregular, informal, non-standardised. Broad scope.</div>\n</div>\n<p>Related distinction: <strong>process-specific information</strong> stays within one business process; <strong>company-wide information</strong> transcends the processes and is mainly for (top) management.</p>\n\n<h3>13. Standard vs. ad-hoc information</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Standard (management) information</strong><br/>Pre-programmed output of the information system. Three characteristics: <strong>periodic</strong> (fixed regularity: per week/month/quarter), <strong>comparative</strong> (compared against standard values such as a performance indicator's norm) and <strong>aggregated</strong>.</div>\n <div class=\"rule-card\"><strong>Ad-hoc (management) information</strong><br/>Needed once, prompted by a specific situation (e.g. 'budgets under pressure'). Not standard in the system: retrieved via queries on the database or even from external sources.</div>\n</div>\n<div class=\"tip-box\"><strong>Aggregating</strong> = combining a large number of data into one quantity: summing, averaging, or taking the largest/smallest value. The higher the management level, the more aggregated the information.</div>\n<div class=\"note-box\"><strong>Business intelligence (BI):</strong> thanks to big data, the Internet of Things and artificial intelligence, BI is evolving from <em>historical</em> reporting to <em>predictive</em> analytics.</div>\n\n<h3>14. ERP & SCM in depth</h3>\n<p><strong>ERP modules:</strong> sales, inventory management, production planning, capacity planning, distribution planning, purchasing, financial administration — often extended with accounts receivable/payable, inventory and budget management. ERP is essentially a <strong>standard software package</strong>; vendors build <strong>industry-specific solutions</strong> (e.g. fashion, food). ERP's strength in three points: fundamental process improvement across the whole value chain, integral management information from operational level to the top, and replacing separate departmental systems with one integrated system and one database.</p>\n<p><strong>SCM</strong> is also called <strong>integral chain management</strong>. A key goal is limiting the <strong>bullwhip effect</strong>: small fluctuations in end-customer demand lead — through delayed, indirect information — to ever larger stock and production swings further up the chain. Direct information sharing lets suppliers deliver <em>just in time</em>. Logistics service providers also apply SCM with their own distribution centres.</p>\n<div class=\"note-box\"><strong>Control hierarchy as a pyramid (figure 6.21):</strong> at the top the <em>controlling processes</em> (strategic, tactical, operational level), below them the <em>operational processes</em>: supporting processes and, at the very bottom, the primary process. Operational managers are themselves managed — creating control layers.</div>","fr":"<h3>7. Valeur ajoutée — trois domaines d'attention</h3>\n<p>Les entreprises existent parce qu'elles fournissent un produit ou un service dont les clients ont besoin. Pour maintenir cette valeur ajoutée, il y a <strong>trois domaines d'attention</strong>:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Excellent fonctionnement des processus opérationnels</strong><br/>Livrer des produits de qualité, vite, bien et à bas coût; utiliser les moyens efficacement, mesurer, contrôler et ajuster en continu.</div>\n <div class=\"rule-card\"><strong>2. Excellente orientation service</strong><br/>Le client reçoit exactement ce qui a été promis; les problèmes et plaintes sont traités correctement.</div>\n <div class=\"rule-card\"><strong>3. Capacité d'innovation</strong><br/>Réaliser continuellement de nouveaux produits ou services; la connaissance du marché et des besoins clients est essentielle.</div>\n</div>\n<div class=\"note-box\"><strong>Maillon de liaison:</strong> les processus d'entreprise ne sont pas isolés — les <strong>données</strong> sont le maillon qui les relie. Le processus <em>Administration</em> est donc central dans le diagramme de flux de données de l'organisation: presque tous les flux (commandes, factures, notes) y passent. Un flux d'argent et de marchandises circule parallèlement aux flux de données.</div>\n\n<h3>8. Le modèle de pilotage complet — tous les composants</h3>\n<p>Outre l'organe dirigeant, l'organe exécutant, l'information de pilotage et de justification, le modèle de pilotage (le <strong>paradigme de pilotage</strong>) comporte ces éléments — représentez le schéma ainsi: l'organe dirigeant en haut, l'organe dirigé (exécutant) en bas, l'environnement autour; l'entrée arrive à gauche, la sortie part à droite:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Information externe</strong><br/>Information que l'organe dirigeant reçoit de l'extérieur (marché, plaintes, planification de l'entreprise).</div>\n <div class=\"rule-card\"><strong>Messages et actions de pilotage externes</strong><br/>Information que l'organe dirigeant transmet à l'environnement: rapports, commandes, demandes d'entretien.</div>\n <div class=\"rule-card\"><strong>Entrée (input)</strong><br/>Ce que l'organe exécutant transforme en sortie: matières premières ou données (p.ex. commandes clients).</div>\n <div class=\"rule-card\"><strong>Sortie (output)</strong><br/>Pas seulement les produits réalisés, mais aussi les <em>déchets et résidus</em>, et éventuellement des données.</div>\n</div>\n<p><strong>L'information de pilotage existe en deux sortes:</strong></p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Information de lancement (aansturing)</strong><br/>Met l'organe exécutant en action (« lance cet ordre de production »).</div>\n <div class=\"rule-card\"><strong>Information d'ajustement (bijsturing)</strong><br/>Messages qui <em>interviennent sur des activités en cours</em> (« accélère la commande X, elle est en retard »).</div>\n</div>\n<div class=\"tip-box\"><strong>Cercle intérieur:</strong> lors du pilotage, l'échange d'informations se concentre sur le <em>cercle intérieur</em> du modèle: information de pilotage et de justification (avec indicateurs de performance) entre dirigeant et exécutant.</div>\n\n<h3>9. Norme, définition d'un indicateur de performance & mise en place de la boucle de régulation</h3>\n<p>Chaque indicateur de performance a une <strong>norme</strong> fixée à l'avance — elle doit être réaliste et peut être déterminée à partir de la base de données de l'entreprise ou d'autres sources. Un indicateur de performance doit être défini explicitement et contient:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>1. Nom</strong><br/>Logique et concis (pour la communication).</div>\n <div class=\"rule-card\"><strong>2. Mode de calcul</strong><br/>Comment est-il calculé (généralement à partir des données de la base) ?</div>\n <div class=\"rule-card\"><strong>3. Norme</strong><br/>La valeur à respecter.</div>\n</div>\n<div class=\"example-box\"><strong>Exemple « Écart de stock »:</strong> calcul = (stock selon l'administration − stock présent en magasin)/(stock selon l'administration) × 100 %; norme: inférieur à 3 %.</div>\n<p>Une <strong>boucle de régulation</strong> efficace se met en place en <strong>quatre étapes</strong>: 1) fixer des objectifs réalistes, 2) définir les indicateurs de performance, 3) déterminer les contraintes et conditions, 4) définir la mesure.</p>\n<div class=\"note-box\">Les indicateurs diffèrent selon le niveau de management: opérationnel = fonctionnement d'un processus au sein du département; tactique = performance du processus complet ou du département; stratégique = fonctionnement de toute l'entreprise.</div>\n\n<h3>10. Intégration de bases de données — le plan d'étapes itératif</h3>\n<p>Les collections de données des différents processus sont fusionnées en une base commune via un <strong>processus itératif</strong>:</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Étape 1</strong><br/>Prendre deux bases de données et les fusionner.</div>\n <div class=\"rule-card\"><strong>Étape 2</strong><br/>Chercher tous les <em>homonymes</em> et les « supprimer »: donner un <em>nouveau nom</em> à l'un des deux concepts (p.ex. « date de facture » et « date de commande » au lieu de deux fois « date »).</div>\n <div class=\"rule-card\"><strong>Étape 3</strong><br/>Chercher tous les <em>synonymes</em> et les « supprimer »: utiliser partout le <em>même nom</em> pour le même concept (p.ex. partout « numéro d'article » au lieu d'aussi « numéro de produit »).</div>\n <div class=\"rule-card\"><strong>Étape 4</strong><br/>Fusionner les fichiers ayant exactement la même clé (p.ex. deux fichiers CLIENTS): tous les attributs dans un fichier commun.</div>\n <div class=\"rule-card\"><strong>Étape 5</strong><br/>Vérifier que le résultat respecte les exigences de conception d'une base de données.</div>\n <div class=\"rule-card\"><strong>Étapes 6 & 7</strong><br/>Répéter les étapes 1–5 jusqu'à intégration complète; dessiner le <strong>diagramme de structure de données</strong> de l'ensemble.</div>\n</div>\n<div class=\"note-box\"><strong>Diagramme de structure de données:</strong> un schéma avec les collections de données (rectangles comme CLIENTS, FACTURES, LIGNES DE FACTURE, ARTICLES) et des flèches montrant leurs relations. Attention: si les homonymes ne sont <em>pas</em> supprimés, des erreurs apparaissent car un même nom garde deux significations.</div>\n\n<h3>11. Système d'information de gestion (MIS) & tableaux de bord</h3>\n<p>Un <strong>système d'information de gestion (MIS)</strong> donne au management l'accès aux collections de données et peut <em>agréger, comparer, analyser et combiner</em> les données en rapports de gestion. Il fournit des rapports standard et permet des questions intelligentes (<strong>requêtes / query's</strong>) sur la base. Les résultats apparaissent rarement sur papier mais sur des <strong>tableaux de bord numériques</strong>: vue d'ensemble en un coup d'œil, souvent avec des <strong>rapports « feux tricolores »</strong> (vert/orange/rouge) servant d'alerte là où les choses dévient du plan.</p>\n\n<h3>12. Caractéristiques de l'information par niveau de management</h3>\n<p>Représentez la figure 6.26 comme une pyramide (exécutant → opérationnel → tactique → stratégique) avec deux triangles à côté: en bas un profil domine (±80 %), en haut l'autre (±80 %):</p>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Niveau opérationnel (±80 % interne)</strong><br/>Interne, court terme, orienté historique, détaillé, haute fréquence, formel, standardisé. Portée étroite.</div>\n <div class=\"rule-card\"><strong>Niveau stratégique (±80 % externe)</strong><br/>Externe, long terme, orienté futur, agrégé, irrégulier, informel, non standardisé. Portée large.</div>\n</div>\n<p>Distinction liée: l'<strong>information spécifique au processus</strong> reste dans un seul processus; l'<strong>information à l'échelle de l'entreprise</strong> dépasse les processus et sert surtout au (top) management.</p>\n\n<h3>13. Information standard vs ad hoc</h3>\n<div class=\"rule-grid\">\n <div class=\"rule-card\"><strong>Information de gestion standard</strong><br/>Sortie préprogrammée du système d'information. Trois caractéristiques: <strong>périodique</strong> (régularité fixe: par semaine/mois/trimestre), <strong>comparative</strong> (comparée à des valeurs standard comme la norme d'un indicateur) et <strong>agrégée</strong>.</div>\n <div class=\"rule-card\"><strong>Information de gestion ad hoc</strong><br/>Nécessaire une seule fois, suite à une situation spécifique (p.ex. « budgets sous pression »). Pas standard dans le système: obtenue via des requêtes sur la base ou même des sources externes.</div>\n</div>\n<div class=\"tip-box\"><strong>Agréger</strong> = combiner un grand nombre de données en une seule grandeur: sommer, faire la moyenne, ou prendre la valeur la plus grande/petite. Plus le niveau de management est élevé, plus l'information est agrégée.</div>\n<div class=\"note-box\"><strong>Business intelligence (BI):</strong> grâce au big data, à l'Internet des objets et à l'intelligence artificielle, la BI évolue de rapports <em>historiques</em> vers des analyses <em>prédictives</em>.</div>\n\n<h3>14. ERP & SCM en profondeur</h3>\n<p><strong>Modules ERP:</strong> ventes, gestion des stocks, planification de production, planification de capacité, planification de distribution, achats, administration financière — souvent complétés par la gestion des débiteurs, créanciers, inventaires et budgets. L'ERP est essentiellement un <strong>progiciel standard</strong>; les fournisseurs créent des <strong>solutions sectorielles</strong> (p.ex. confection, alimentation). La force de l'ERP en trois points: amélioration fondamentale des processus sur toute la chaîne de valeur, information de gestion intégrale du niveau opérationnel au sommet, et remplacement des systèmes départementaux séparés par un seul système intégré avec une seule base de données.</p>\n<p>Le <strong>SCM</strong> s'appelle aussi <strong>gestion intégrale de la chaîne</strong>. Un objectif clé est de limiter l'<strong>effet coup de fouet (opslingereffect / bullwhip)</strong>: de petites fluctuations de la demande du client final entraînent — par une information retardée et indirecte — des variations de stock et de production de plus en plus grandes en amont de la chaîne. Le partage direct d'informations permet aux fournisseurs de livrer en <em>juste-à-temps</em>. Les prestataires logistiques appliquent aussi le SCM avec leurs propres centres de distribution.</p>\n<div class=\"note-box\"><strong>La hiérarchie de pilotage en pyramide (figure 6.21):</strong> en haut les <em>processus de pilotage</em> (niveaux stratégique, tactique, opérationnel), en dessous les <em>processus opérationnels</em>: les processus de soutien et, tout en bas, le processus primaire. Les managers opérationnels sont eux-mêmes managés — d'où des couches de pilotage.</div>"},"exercises":[{"id":"h6_7","correct":1,"text_nl":"Een manager stuurt een bericht naar de productielijn: 'Order 4512 loopt vertraging op — zet er vandaag een extra ploeg op.' Welk soort informatie is dit volgens het besturingsmodel?","text_en":"A manager sends a message to the production line: 'Order 4512 is delayed — put an extra team on it today.' According to the control model, what kind of information is this?","text_fr":"Un manager envoie un message à la ligne de production: « La commande 4512 a du retard — mettez une équipe supplémentaire dessus aujourd'hui. » Selon le modèle de pilotage, de quel type d'information s'agit-il ?","options_nl":["Aansturingsinformatie","Bijsturingsinformatie","Verantwoordingsinformatie","Externe informatie"],"options_en":["Initiating information","Adjustment information","Accountability information","External information"],"options_fr":["Information de lancement","Information d'ajustement","Information de justification","Information externe"],"hint1_nl":"De order is al gestart — er wordt ingegrepen op iets dat al loopt.","hint1_en":"The order has already started — someone is intervening in something already in progress.","hint1_fr":"La commande a déjà commencé — on intervient sur quelque chose en cours.","hint2_nl":"Stuurinformatie kent twee soorten: aansturingsinformatie zet aan tot actie, bijsturingsinformatie grijpt in op lopende activiteiten.","hint2_en":"Steering information has two kinds: initiating information triggers action, adjustment information intervenes in ongoing activities.","hint2_fr":"L'information de pilotage a deux formes: le lancement déclenche l'action, l'ajustement intervient sur des activités en cours.","sol_nl":"Dit is bijsturingsinformatie: de activiteit loopt al en de manager grijpt in om de lopende uitvoering te corrigeren. Aansturingsinformatie zou het zijn als de manager de order voor het eerst liet starten.","sol_en":"This is adjustment information: the activity is already running and the manager intervenes to correct ongoing execution. It would be initiating information if the manager were starting the order for the first time.","sol_fr":"C'est de l'information d'ajustement: l'activité est déjà en cours et le manager intervient pour corriger l'exécution. Ce serait de l'information de lancement si le manager démarrait la commande pour la première fois."},{"id":"h6_8","correct":2,"text_nl":"Standaardmanagementinformatie heeft drie belangrijke kenmerken. Welke combinatie is juist?","text_en":"Standard management information has three key characteristics. Which combination is correct?","text_fr":"L'information de gestion standard possède trois caractéristiques clés. Quelle combinaison est correcte ?","options_nl":["Eenmalig, gedetailleerd, extern","Periodiek, gedetailleerd, intern","Periodiek, comparatief, geaggregeerd","Ad hoc, comparatief, gestandaardiseerd"],"options_en":["One-off, detailed, external","Periodic, detailed, internal","Periodic, comparative, aggregated","Ad hoc, comparative, standardised"],"options_fr":["Ponctuelle, détaillée, externe","Périodique, détaillée, interne","Périodique, comparative, agrégée","Ad hoc, comparative, standardisée"],"hint1_nl":"Denk aan een maandelijks omzetoverzicht: hoe vaak, waarmee vergeleken, en hoe samengevat?","hint1_en":"Think of a monthly revenue report: how often, compared with what, and how summarised?","hint1_fr":"Pensez à un rapport mensuel de chiffre d'affaires: à quelle fréquence, comparé à quoi, et comment résumé ?","hint2_nl":"Standaardinformatie is periodiek (vaste regelmaat), comparatief (vergeleken met normen/standaardwaarden) en geaggregeerd (samengevoegd tot grootheden).","hint2_en":"Standard information is periodic (fixed regularity), comparative (compared with norms/standard values) and aggregated (combined into totals).","hint2_fr":"L'information standard est périodique (régularité fixe), comparative (comparée aux normes) et agrégée (combinée en grandeurs).","sol_nl":"De drie kenmerken zijn: periodiek (per week/maand/kwartaal opgesteld), comparatief (vergeleken met standaardwaarden zoals de norm van een prestatie-indicator) en geaggregeerd (gegevens samengevoegd door sommeren, gemiddelde of grootste/kleinste waarde). 'Eenmalig/ad hoc' hoort bij ad-hocinformatie.","sol_en":"The three characteristics are: periodic (produced weekly/monthly/quarterly), comparative (compared against standard values such as a performance indicator's norm) and aggregated (data combined by summing, averaging or min/max). 'One-off/ad hoc' belongs to ad-hoc information.","sol_fr":"Les trois caractéristiques sont: périodique (produite par semaine/mois/trimestre), comparative (comparée à des valeurs standard comme la norme d'un indicateur) et agrégée (données combinées par somme, moyenne ou min/max). « Ponctuelle/ad hoc » relève de l'information ad hoc."},{"id":"h6_9","correct":1,"text_nl":"Bierbrouwerij Hop ziet dat een kleine stijging van 5% in de verkoop bij supermarkten leidt tot een bestelling van +15% bij de groothandel, +30% bij de brouwerij en +50% bij de moutleverancier. Iedereen bouwt 'voor de zekerheid' extra voorraad op. Welk verschijnsel treedt hier op, en wat is de SCM-oplossing?","text_en":"Brewery Hop sees that a small 5% rise in supermarket sales leads to a +15% order at the wholesaler, +30% at the brewery and +50% at the malt supplier. Everyone builds extra stock 'just in case'. Which phenomenon is occurring, and what is the SCM solution?","text_fr":"La brasserie Hop constate qu'une petite hausse de 5 % des ventes en supermarché entraîne une commande de +15 % chez le grossiste, +30 % à la brasserie et +50 % chez le fournisseur de malt. Chacun constitue du stock supplémentaire « au cas où ». Quel phénomène se produit, et quelle est la solution SCM ?","options_nl":["Homoniem — los het op door begrippen te hernoemen","Opslingereffect — los het op door verkoopdata direct te delen door de hele keten","Veracity-probleem — los het op door datakwaliteit te controleren","Explosie — los het op door het GSS te detailleren"],"options_en":["Homonym — solve it by renaming concepts","Bullwhip effect — solve it by sharing sales data directly across the whole chain","Veracity problem — solve it by checking data quality","Explosion — solve it by detailing the DFD"],"options_fr":["Homonyme — résoudre en renommant les concepts","Effet coup de fouet — résoudre en partageant directement les données de vente dans toute la chaîne","Problème de véracité — résoudre en contrôlant la qualité des données","Explosion — résoudre en détaillant le diagramme de flux"],"hint1_nl":"Kleine schommelingen bij de eindklant worden steeds groter naarmate je verder de keten in gaat.","hint1_en":"Small fluctuations at the end customer grow larger the further up the chain you go.","hint1_fr":"De petites fluctuations chez le client final s'amplifient en remontant la chaîne.","hint2_nl":"Dit heet het opslingereffect; SCM beperkt het tot een minimum doordat leveranciers de werkelijke vraag direct zien en just-in-time kunnen leveren.","hint2_en":"This is called the bullwhip effect; SCM reduces it to a minimum because suppliers see real demand directly and can deliver just in time.","hint2_fr":"C'est l'effet coup de fouet; le SCM le réduit au minimum car les fournisseurs voient la demande réelle directement et peuvent livrer en juste-à-temps.","sol_nl":"Dit is het opslingereffect (bullwhip): door vertraagde en indirecte informatie versterken vraagschommelingen zich stroomopwaarts in de keten. Supplychainmanagement beperkt dit door directe informatiedeling: leveranciers zien de werkelijke verkoopcijfers en stemmen productie en leveringen (just-in-time) daarop af.","sol_en":"This is the bullwhip effect: through delayed and indirect information, demand fluctuations amplify upstream in the chain. Supply chain management limits this through direct information sharing: suppliers see actual sales figures and align production and deliveries (just in time) accordingly.","sol_fr":"C'est l'effet coup de fouet: à cause d'une information retardée et indirecte, les fluctuations de la demande s'amplifient en amont de la chaîne. Le supply chain management limite cela par le partage direct d'informations: les fournisseurs voient les ventes réelles et adaptent production et livraisons (juste-à-temps)."},{"id":"h6_10","correct":3,"text_nl":"De CEO van kledingbedrijf Mia bereidt een vijfjarenstrategie voor. Welk informatieprofiel past het best bij wat zij nodig heeft?","text_en":"The CEO of clothing company Mia is preparing a five-year strategy. Which information profile best fits what she needs?","text_fr":"La CEO de l'entreprise de vêtements Mia prépare une stratégie à cinq ans. Quel profil d'information correspond le mieux à ses besoins ?","options_nl":["Vooral interne, gedetailleerde, hoogfrequente en gestandaardiseerde informatie","Vooral interne, historische informatie met een smalle scoop","Uitsluitend financiële informatie uit de boekhouding","Vooral externe, geaggregeerde, toekomstgerichte en niet-gestandaardiseerde informatie"],"options_en":["Mainly internal, detailed, high-frequency and standardised information","Mainly internal, historical information with a narrow scope","Exclusively financial information from the accounts","Mainly external, aggregated, future-oriented and non-standardised information"],"options_fr":["Surtout de l'information interne, détaillée, à haute fréquence et standardisée","Surtout de l'information interne et historique à portée étroite","Exclusivement de l'information financière issue de la comptabilité","Surtout de l'information externe, agrégée, orientée futur et non standardisée"],"hint1_nl":"Hoe hoger in de bestuurshiërarchie, hoe meer de blik naar buiten en naar de toekomst gericht is.","hint1_en":"The higher in the control hierarchy, the more the view turns outward and toward the future.","hint1_fr":"Plus on monte dans la hiérarchie de pilotage, plus le regard se tourne vers l'extérieur et l'avenir.","hint2_nl":"Strategisch niveau: ±80% externe informatie — lange termijn, toekomstgericht, geaggregeerd, onregelmatig, informeel, niet-gestandaardiseerd. Operationeel niveau is het spiegelbeeld (±80% intern, gedetailleerd, historisch).","hint2_en":"Strategic level: ±80% external information — long term, future-oriented, aggregated, irregular, informal, non-standardised. The operational level is the mirror image (±80% internal, detailed, historical).","hint2_fr":"Niveau stratégique: ±80 % d'information externe — long terme, orientée futur, agrégée, irrégulière, informelle, non standardisée. Le niveau opérationnel est l'image inverse (±80 % interne, détaillée, historique).","sol_nl":"Op strategisch niveau bestaat de informatie voor ±80% uit externe bronnen en is ze lange termijn, toekomstgericht, sterk geaggregeerd, onregelmatig, informeel en niet-gestandaardiseerd, met een brede scoop. Gedetailleerde, hoogfrequente, interne en historische informatie hoort bij het operationele niveau.","sol_en":"At strategic level, information is ±80% from external sources and is long-term, future-oriented, highly aggregated, irregular, informal and non-standardised, with a broad scope. Detailed, high-frequency, internal and historical information belongs to the operational level.","sol_fr":"Au niveau stratégique, l'information provient à ±80 % de sources externes et est à long terme, orientée futur, fortement agrégée, irrégulière, informelle et non standardisée, avec une portée large. L'information détaillée, fréquente, interne et historique relève du niveau opérationnel."}]}};

Object.assign(ANS, {ex1_9:{inputs:[[26,0]]},ex1_10:{inputs:[[2500,0]]},ex1_11:{mcq:1},ex1_12:{mcq:1},ex2_8:{inputs:[[6.25,0.1],[90000,0]]},ex2_9:{inputs:[[11,0],[170000,0]]},ex2_10:{mcq:2},ex2_11:{mcq:2},ex3_7:{inputs:[[54000,0],[-6000,0],[48000,0]]},ex3_8:{inputs:[[4750,0],[3000,0],[1750,0]]},ex3_9:{mcq:1},ex3_10:{inputs:[[27500,0],[29500,0],[-2000,0]]},ex4_7:{inputs:[[4,0]]},ex4_8:{mcq:2},ex4_9:{inputs:[[20,0],[55,0],[6.33,0.05],[3333.3,1]]},ex4_10:{inputs:[[1090.01,0.1],[5450.05,0.1]]},ex5_8:{inputs:[[50000,0],[44.44,0.1]]},ex5_9:{mcq:3},ex5_10:{inputs:[[300000,0],[25,0]]},ex5_11:{mcq:2},ex6_1:{inputs:[[20000,0],[10,0],[71000,0]]},ex6_2:{inputs:[[20000,0],[30000,0],[20,0]]},ex6_3:{inputs:[[40,0],[21,0],[15000,0]]},ex6_4:{inputs:[[4000,0],[90000,0],[20000,0],[110000,0]]},ex6_5:{inputs:[[32,0],[70400,0],[58400,0],[12000,0]]},ex6_6:{inputs:[[40000,0],[25,0],[1600,0],[152500,0],[147500,0],[5000,0]]}});

function locF(o, f){ const k=f+'_'+lang; return o[k]!==undefined?o[k]:(o[f+'_nl']!==undefined?o[f+'_nl']:''); }

function convMacEx(ex){
 const out = { id:ex.id, diff:ex.diff||'medium',
 title:locF(ex,'title'), text:locF(ex,'text'),
 hints:[locF(ex,'hint1'), locF(ex,'hint2')].filter(Boolean),
 sol:locF(ex,'sol') };
 if(ex.type==='mcq' && ex.options_nl){
 out.mcq = (lang==='fr'?ex.options_fr:lang==='en'?ex.options_en:ex.options_nl)||ex.options_nl;
 }
 if(ex.type!=='mcq' && ex.inputs && ex.inputs.length){
 out.inputs = ex.inputs.map((inp,i)=>({label:locF(inp,'label'), id:ex.id+'_'+i}));
 }
 return out;
}

const __origGetExercises = getExercises;
getExercises = function(){
 const data = __origGetExercises();
 for(const [wk, extra] of Object.entries(MAC_EXTRA)){
 if(!data[wk]) continue;
 const conv = extra.exercises.map(convMacEx);
 if(extra.replace) data[wk].exercises = conv;
 else data[wk].exercises = data[wk].exercises.concat(conv);
 if(extra.theoryExtra && extra.theoryExtra.nl){
 const th = data[wk].theory;
 th.nl += extra.theoryExtra.nl; th.en += extra.theoryExtra.en; th.fr += extra.theoryExtra.fr;
 }
 }
 return data;
};

// merge OmI extras into OMI_CHAPTERS (once per load; idempotent guard)
(function(){
 OMI_CHAPTERS.forEach(ch=>{
 const extra = OMI_EXTRA[ch.key];
 if(!extra || ch.__merged) return;
 ch.__merged = true;
 if(extra.theoryExtra && extra.theoryExtra.nl){
 ch.theory_nl += extra.theoryExtra.nl;
 ch.theory_en += extra.theoryExtra.en;
 ch.theory_fr += extra.theoryExtra.fr;
 }
 ch.exercises = ch.exercises.concat(extra.exercises);
 });
})();

// populate exams
EXAMS.push(...[{"key":"exam1","title_nl":"Proefexamen 1 — MAC & Ondernemen met Informatie","title_en":"Mock Exam 1 — MAC & Doing Business with Information","title_fr":"Examen blanc 1 — MAC & Entreprendre avec l'information","duration_min":60,"questions":[{"id":"t1_q1","subject":"mac","type":"numeric","points":2,"text_nl":"Een machine wordt aangekocht voor A = €80.000, restwaarde R = €8.000, levensduur n = 6 jaar. Er wordt lineair afgeschreven. Bereken het jaarlijkse afschrijvingsbedrag d en de boekwaarde na 4 jaar.","text_en":"A machine is purchased for A = €80,000, residual value R = €8,000, useful life n = 6 years. Straight-line depreciation is used. Calculate the annual depreciation d and the book value after 4 years.","text_fr":"Une machine est achetée pour A = 80 000 €, valeur résiduelle R = 8 000 €, durée de vie n = 6 ans. On amortit de façon linéaire. Calculez l'amortissement annuel d et la valeur comptable après 4 ans.","inputs":[{"label_nl":"Afschrijving per jaar d (€)","label_en":"Annual depreciation d (€)","label_fr":"Amortissement annuel d (€)","answer":12000},{"label_nl":"Boekwaarde na 4 jaar (€)","label_en":"Book value after 4 years (€)","label_fr":"Valeur comptable après 4 ans (€)","answer":32000}],"sol_nl":"Lineair: d = (A − R)/n = (80.000 − 8.000)/6 = **€12.000** per jaar. Na 4 jaar is er 4 × 12.000 = 48.000 afgeschreven, dus BW = 80.000 − 48.000 = **€32.000**.","sol_en":"Straight-line: d = (A − R)/n = (80,000 − 8,000)/6 = **€12,000** per year. After 4 years total depreciation = 4 × 12,000 = 48,000, so BV = 80,000 − 48,000 = **€32,000**.","sol_fr":"Linéaire: d = (A − R)/n = (80 000 − 8 000)/6 = **12 000 €** par an. Après 4 ans: 4 × 12 000 = 48 000 amortis, donc VC = 80 000 − 48 000 = **32 000 €**."},{"id":"t1_q2","subject":"mac","type":"numeric","points":2,"text_nl":"Fabriek Belco werkt met absorption costing. Constante kosten C = €120.000, normale productie N = 10.000 stuks, variabele kosten v = €15/stuk, verkoopprijs p = €40. Dit jaar: werkelijke productie W = 12.000 stuks, afzet = 9.000 stuks. Bereken de kostprijs k, het verkoopresultaat VR en het bedrijfsresultaat BedR.","text_en":"Factory Belco uses absorption costing. Fixed costs C = €120,000, normal production N = 10,000 units, variable cost v = €15/unit, selling price p = €40. This year: actual production W = 12,000 units, sales = 9,000 units. Calculate the cost price k, the sales result VR and the operating result BedR.","text_fr":"L'usine Belco applique l'absorption costing. Coûts fixes C = 120 000 €, production normale N = 10 000 unités, coût variable v = 15 €/unité, prix de vente p = 40 €. Cette année: production réelle W = 12 000 unités, ventes = 9 000 unités. Calculez le coût de revient k, le résultat sur ventes VR et le résultat d'exploitation BedR.","inputs":[{"label_nl":"Kostprijs k (€)","label_en":"Cost price k (€)","label_fr":"Coût de revient k (€)","answer":27},{"label_nl":"Verkoopresultaat VR (€)","label_en":"Sales result VR (€)","label_fr":"Résultat sur ventes VR (€)","answer":117000},{"label_nl":"Bedrijfsresultaat BedR (€)","label_en":"Operating result BedR (€)","label_fr":"Résultat d'exploitation BedR (€)","answer":141000}],"sol_nl":"k = C/N + v = 120.000/10.000 + 15 = 12 + 15 = **€27**. VR = (p − k) × afzet = (40 − 27) × 9.000 = **€117.000**. BezR = (W − N) × C/N = (12.000 − 10.000) × 12 = +€24.000. BedR = VR + BezR = 117.000 + 24.000 = **€141.000**.","sol_en":"k = C/N + v = 120,000/10,000 + 15 = 12 + 15 = **€27**. VR = (p − k) × sales = (40 − 27) × 9,000 = **€117,000**. Capacity result = (W − N) × C/N = (12,000 − 10,000) × 12 = +€24,000. BedR = 117,000 + 24,000 = **€141,000**.","sol_fr":"k = C/N + v = 120 000/10 000 + 15 = 12 + 15 = **27 €**. VR = (p − k) × ventes = (40 − 27) × 9 000 = **117 000 €**. Résultat d'occupation = (W − N) × C/N = (12 000 − 10 000) × 12 = +24 000 €. BedR = 117 000 + 24 000 = **141 000 €**."},{"id":"t1_q3","subject":"mac","type":"numeric","points":2,"text_nl":"Direct costing: p = €25, v = €10, constante kosten C = €60.000, afzet = 5.500 stuks. Bereken de dekkingsbijdrage per stuk (DB) en het nettobedrijfsresultaat (NBR).","text_en":"Direct costing: p = €25, v = €10, fixed costs C = €60,000, sales = 5,500 units. Calculate the contribution margin per unit (DB) and the net operating result (NBR).","text_fr":"Direct costing: p = 25 €, v = 10 €, coûts fixes C = 60 000 €, ventes = 5 500 unités. Calculez la marge sur coûts variables par unité (DB) et le résultat net d'exploitation (NBR).","inputs":[{"label_nl":"DB per stuk (€)","label_en":"Contribution margin per unit (€)","label_fr":"DB par unité (€)","answer":15},{"label_nl":"NBR (€)","label_en":"NBR (€)","label_fr":"NBR (€)","answer":22500}],"sol_nl":"DB = p − v = 25 − 10 = **€15** per stuk. Totale DB = 15 × 5.500 = 82.500. NBR = DB_tot − C = 82.500 − 60.000 = **€22.500**.","sol_en":"DB = p − v = 25 − 10 = **€15** per unit. Total DB = 15 × 5,500 = 82,500. NBR = total DB − C = 82,500 − 60,000 = **€22,500**.","sol_fr":"DB = p − v = 25 − 10 = **15 €** par unité. DB totale = 15 × 5 500 = 82 500. NBR = DB totale − C = 82 500 − 60 000 = **22 500 €**."},{"id":"t1_q4","subject":"mac","type":"numeric","points":2,"text_nl":"Koffiebar 'Mokka' verkoopt een box voor p = €30, variabele kosten v = €12, constante kosten C = €90.000 per jaar. Verwachte verkoop: 6.500 boxen. Bereken het break-evenpunt in stuks, de break-evenomzet en de veiligheidsmarge in stuks.","text_en":"Coffee bar 'Mokka' sells a box at p = €30, variable cost v = €12, fixed costs C = €90,000 per year. Expected sales: 6,500 boxes. Calculate the break-even point in units, the break-even revenue and the safety margin in units.","text_fr":"Le café 'Mokka' vend une boîte à p = 30 €, coût variable v = 12 €, coûts fixes C = 90 000 € par an. Ventes prévues: 6 500 boîtes. Calculez le seuil de rentabilité en unités, le chiffre d'affaires au seuil et la marge de sécurité en unités.","inputs":[{"label_nl":"BEP (stuks)","label_en":"BEP (units)","label_fr":"Seuil (unités)","answer":5000},{"label_nl":"Break-evenomzet (€)","label_en":"Break-even revenue (€)","label_fr":"CA au seuil (€)","answer":150000},{"label_nl":"Veiligheidsmarge (stuks)","label_en":"Safety margin (units)","label_fr":"Marge de sécurité (unités)","answer":1500}],"sol_nl":"BEP = C/(p − v) = 90.000/(30 − 12) = 90.000/18 = **5.000 stuks**. BEP-omzet = 5.000 × 30 = **€150.000**. Veiligheidsmarge = 6.500 − 5.000 = **1.500 stuks**.","sol_en":"BEP = C/(p − v) = 90,000/(30 − 12) = 90,000/18 = **5,000 units**. Break-even revenue = 5,000 × 30 = **€150,000**. Safety margin = 6,500 − 5,000 = **1,500 units**.","sol_fr":"Seuil = C/(p − v) = 90 000/(30 − 12) = 90 000/18 = **5 000 unités**. CA au seuil = 5 000 × 30 = **150 000 €**. Marge de sécurité = 6 500 − 5 000 = **1 500 unités**."},{"id":"t1_q5","subject":"mac","type":"mcq","points":1.5,"correct":1,"text_nl":"Een fabrikant heeft overcapaciteit. Kostprijs k = €27 (waarvan v = €15). Een buitenlandse klant biedt een incidentele order aan tegen €18 per stuk, zonder invloed op de gewone afzet. Wat doe je?","text_en":"A manufacturer has spare capacity. Cost price k = €27 (of which v = €15). A foreign customer offers a one-off order at €18 per unit, with no impact on regular sales. What should you do?","text_fr":"Un fabricant a une surcapacité. Coût de revient k = 27 € (dont v = 15 €). Un client étranger propose une commande ponctuelle à 18 € l'unité, sans impact sur les ventes habituelles. Que faire ?","options_nl":["Weigeren, want €18 < kostprijs €27","Aanvaarden, want €18 > variabele kosten €15: elke stuk levert €3 dekkingsbijdrage op","Weigeren, want incidentele orders verhogen de constante kosten","Aanvaarden enkel als €18 > k"],"options_en":["Refuse, because €18 < cost price €27","Accept, because €18 > variable cost €15: each unit adds €3 contribution margin","Refuse, because one-off orders increase fixed costs","Accept only if €18 > k"],"options_fr":["Refuser, car 18 € < coût de revient 27 €","Accepter, car 18 € > coût variable 15 €: chaque unité apporte 3 € de marge","Refuser, car les commandes ponctuelles augmentent les coûts fixes","Accepter seulement si 18 € > k"],"inputs":[],"sol_nl":"Bij overcapaciteit is een incidentele order voordelig zodra **p > v**. Hier 18 > 15: elke verkochte eenheid draagt **€3** bij aan de dekking van de constante kosten, die er toch al zijn. Antwoord **B**.","sol_en":"With spare capacity a one-off order is profitable as soon as **p > v**. Here 18 > 15: each unit contributes **€3** towards fixed costs that exist anyway. Answer **B**.","sol_fr":"Avec surcapacité, une commande ponctuelle est rentable dès que **p > v**. Ici 18 > 15: chaque unité apporte **3 €** pour couvrir des coûts fixes existants de toute façon. Réponse **B**."},{"id":"t1_q6","subject":"mac","type":"mcq","points":1.5,"correct":2,"text_nl":"In een periode is de productie W groter dan de afzet. Wat geldt voor het bedrijfsresultaat volgens absorption costing (AC) tegenover direct costing (DC)?","text_en":"In a period, production W exceeds sales. What is true about the operating result under absorption costing (AC) versus direct costing (DC)?","text_fr":"Sur une période, la production W dépasse les ventes. Qu'en est-il du résultat selon l'absorption costing (AC) par rapport au direct costing (DC) ?","options_nl":["AC = DC, de methode maakt nooit een verschil","AC < DC, want de voorraad wordt lager gewaardeerd","AC > DC, met verschil = (W − afzet) × C/N","DC > AC, met verschil = (W − afzet) × v"],"options_en":["AC = DC, the method never matters","AC < DC, because inventory is valued lower","AC > DC, with difference = (W − sales) × C/N","DC > AC, with difference = (W − sales) × v"],"options_fr":["AC = DC, la méthode ne change jamais rien","AC < DC, car le stock est valorisé plus bas","AC > DC, avec un écart = (W − ventes) × C/N","DC > AC, avec un écart = (W − ventes) × v"],"inputs":[],"sol_nl":"Bij AC schuift een deel van de constante kosten via de voorraad door naar later: verschil AC − DC = (W − afzet) × (C/N). Als W > afzet is dit positief, dus **AC > DC**. Antwoord **C**.","sol_en":"Under AC part of the fixed costs is carried into inventory: difference AC − DC = (W − sales) × (C/N). If W > sales this is positive, so **AC > DC**. Answer **C**.","sol_fr":"En AC, une partie des coûts fixes est stockée: écart AC − DC = (W − ventes) × (C/N). Si W > ventes, c'est positif, donc **AC > DC**. Réponse **C**."},{"id":"t1_q7","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Wat is het verschil tussen gegevens en informatie?","text_en":"What is the difference between data and information?","text_fr":"Quelle est la différence entre données et information ?","options_nl":["Gegevens zijn digitaal, informatie is op papier","Informatie = gegevens die betekenis hebben voor de ontvanger en zijn kennis vergroten","Gegevens en informatie zijn synoniemen","Informatie wordt enkel door computers gemaakt, gegevens door mensen"],"options_en":["Data is digital, information is on paper","Information = data that has meaning for the receiver and increases their knowledge","Data and information are synonyms","Information is only produced by computers, data by humans"],"options_fr":["Les données sont numériques, l'information est sur papier","Information = données ayant une signification pour le destinataire et augmentant ses connaissances","Données et information sont des synonymes","L'information vient des ordinateurs, les données des humains"],"inputs":[],"sol_nl":"Gegevens zijn ruwe feiten; **informatie** ontstaat wanneer gegevens betekenis krijgen voor de ontvanger en zijn kennis vergroten. Slechte input geeft slechte output: **GIGO** (garbage in, garbage out). Antwoord **B**.","sol_en":"Data are raw facts; **information** arises when data acquires meaning for the receiver and increases their knowledge. Bad input gives bad output: **GIGO**. Answer **B**.","sol_fr":"Les données sont des faits bruts; l'**information** naît quand les données prennent un sens pour le destinataire et accroissent ses connaissances. Mauvaise entrée = mauvaise sortie: **GIGO**. Réponse **B**."},{"id":"t1_q8","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Een productieleider krijgt elke ochtend een rapport met het aantal geproduceerde stuks per lijn, vergeleken met de norm, om bij te sturen waar nodig. Welk type informatie is dit vooral?","text_en":"Every morning a production manager receives a report with units produced per line, compared with the norm, in order to make adjustments where needed. What type of information is this primarily?","text_fr":"Chaque matin, un chef de production reçoit un rapport avec le nombre d'unités produites par ligne, comparé à la norme, afin d'ajuster si nécessaire. De quel type d'information s'agit-il principalement ?","options_nl":["Operationele informatie voor het uitvoeren van één transactie","Stuurinformatie: vergelijking met een norm om bij te sturen","Verantwoordingsinformatie aan externe partijen","Strategische informatie voor de lange termijn"],"options_en":["Operational information for executing a single transaction","Steering information: comparison with a norm in order to adjust","Accountability information for external parties","Strategic long-term information"],"options_fr":["Information opérationnelle pour exécuter une transaction","Information de pilotage: comparaison avec une norme pour ajuster","Information de justification destinée à des tiers","Information stratégique de long terme"],"inputs":[],"sol_nl":"Het rapport vergelijkt de werkelijke prestatie (kengetal) met een norm (streefgetal) om te kunnen bijsturen: dat is typisch **stuurinformatie** binnen de regelkring van het besturingsmodel. Antwoord **B**.","sol_en":"The report compares actual performance (indicator) with a norm (target) so action can be taken: that is classic **steering information** within the control loop. Answer **B**.","sol_fr":"Le rapport compare la performance réelle (indicateur) à une norme (valeur cible) pour ajuster: c'est de l'**information de pilotage** dans la boucle de régulation. Réponse **B**."},{"id":"t1_q9","subject":"omi","type":"mcq","points":1.5,"correct":2,"text_nl":"Een bedrijf huurt via de cloud een volledig werkende boekhoudtoepassing die het via de browser gebruikt, zonder zelf iets te installeren of te beheren. Welk cloudmodel is dit?","text_en":"A company rents a fully working accounting application in the cloud, used through the browser, without installing or managing anything itself. Which cloud model is this?","text_fr":"Une entreprise loue dans le cloud une application comptable entièrement fonctionnelle, utilisée via le navigateur, sans rien installer ni gérer elle-même. De quel modèle cloud s'agit-il ?","options_nl":["IaaS","PaaS","SaaS","EDI"],"options_en":["IaaS","PaaS","SaaS","EDI"],"options_fr":["IaaS","PaaS","SaaS","EDI"],"inputs":[],"sol_nl":"Een kant-en-klare toepassing via internet = **SaaS** (Software as a Service). IaaS = enkel infrastructuur (servers, opslag), PaaS = platform om zelf toepassingen op te bouwen. Antwoord **C**.","sol_en":"A ready-to-use application over the internet = **SaaS** (Software as a Service). IaaS = infrastructure only (servers, storage), PaaS = a platform to build your own applications. Answer **C**.","sol_fr":"Une application prête à l'emploi via internet = **SaaS** (Software as a Service). IaaS = infrastructure seule, PaaS = plateforme pour développer ses propres applications. Réponse **C**."},{"id":"t1_q10","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"De directie wil ondersteuning bij een slecht gestructureerde beslissing: 'Openen we een tweede vestiging, en waar?' Met simulaties en what-if-analyses. Welk systeem past hier het best?","text_en":"Management wants support for a poorly structured decision: 'Should we open a second site, and where?' Using simulations and what-if analyses. Which system fits best?","text_fr":"La direction veut un appui pour une décision peu structurée: « Ouvrons-nous un deuxième site, et où ? » Avec simulations et analyses what-if. Quel système convient le mieux ?","options_nl":["TPS (transactieverwerkend systeem)","DSS (beslissingsondersteunend systeem)","DMS (documentmanagementsysteem)","CAD/CAM"],"options_en":["TPS (transaction processing system)","DSS (decision support system)","DMS (document management system)","CAD/CAM"],"options_fr":["TPS (système transactionnel)","DSS (système d'aide à la décision)","DMS (gestion documentaire)","CAD/CAM"],"inputs":[],"sol_nl":"Slecht gestructureerde beslissingen met modellen, simulaties en what-if-analyses worden ondersteund door een **DSS**. TPS verwerkt routinetransacties, DMS beheert documenten, CAD/CAM ondersteunt ontwerp/productie. Antwoord **B**.","sol_en":"Poorly structured decisions supported by models, simulations and what-if analyses call for a **DSS**. TPS handles routine transactions, DMS manages documents, CAD/CAM supports design/manufacturing. Answer **B**.","sol_fr":"Les décisions peu structurées appuyées par des modèles et des analyses what-if relèvent d'un **DSS**. Le TPS traite les transactions de routine, le DMS gère les documents, la CAD/CAM le design/la production. Réponse **B**."},{"id":"t1_q11","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Bij het inloggen geeft een medewerker zijn wachtwoord in én een code uit een app op zijn smartphone. Welke combinatie van authenticatiefactoren is dit?","text_en":"When logging in, an employee enters his password plus a code from an app on his smartphone. Which combination of authentication factors is this?","text_fr":"À la connexion, un employé saisit son mot de passe plus un code généré par une appli sur son smartphone. Quelle combinaison de facteurs d'authentification est-ce ?","options_nl":["Twee keer 'iets dat je weet'","'Iets dat je weet' + 'iets dat je hebt' (MFA)","'Iets dat je bent' + 'iets dat je hebt'","Dit is geen multifactorauthenticatie"],"options_en":["Twice 'something you know'","'Something you know' + 'something you have' (MFA)","'Something you are' + 'something you have'","This is not multi-factor authentication"],"options_fr":["Deux fois « quelque chose que vous savez »","« Quelque chose que vous savez » + « quelque chose que vous avez » (MFA)","« Quelque chose que vous êtes » + « quelque chose que vous avez »","Ce n'est pas de l'authentification multifacteur"],"inputs":[],"sol_nl":"Wachtwoord = **iets dat je weet**; de smartphone met app = **iets dat je hebt**. Twee verschillende factoren = **MFA**. ('Iets dat je bent' zou biometrie zijn, zoals een vingerafdruk.) Antwoord **B**.","sol_en":"Password = **something you know**; the smartphone app = **something you have**. Two different factors = **MFA**. ('Something you are' would be biometrics.) Answer **B**.","sol_fr":"Mot de passe = **quelque chose que vous savez**; le smartphone = **quelque chose que vous avez**. Deux facteurs différents = **MFA**. (« Ce que vous êtes » = biométrie.) Réponse **B**."},{"id":"t1_q12","subject":"omi","type":"mcq","points":1.5,"correct":0,"text_nl":"Het adres van klant Janssens staat zowel in het verkoopbestand als in het facturatiebestand. Na een verhuis is het enkel in het verkoopbestand aangepast. Hoe noem je deze situatie?","text_en":"Customer Janssens' address is stored both in the sales file and in the invoicing file. After a move it was updated only in the sales file. What do you call this situation?","text_fr":"L'adresse du client Janssens figure à la fois dans le fichier ventes et dans le fichier facturation. Après un déménagement, elle n'a été modifiée que dans le fichier ventes. Comment appelle-t-on cette situation ?","options_nl":["Redundantie die geleid heeft tot inconsistentie","Een synoniem","Een n-m-relatie","GIGO zonder redundantie"],"options_en":["Redundancy that has led to inconsistency","A synonym","An n-to-m relationship","GIGO without redundancy"],"options_fr":["Une redondance qui a conduit à une incohérence","Un synonyme","Une relation n-m","GIGO sans redondance"],"inputs":[],"sol_nl":"Hetzelfde gegeven dat meermaals wordt opgeslagen = **redundantie**. Wanneer de kopieën niet meer overeenstemmen = **inconsistentie**. Een goede database vermijdt dit door het adres één keer op te slaan. Antwoord **A**.","sol_en":"The same data stored more than once = **redundancy**. When the copies no longer match = **inconsistency**. A good database stores the address only once. Answer **A**.","sol_fr":"La même donnée stockée plusieurs fois = **redondance**. Quand les copies divergent = **incohérence**. Une bonne base de données stocke l'adresse une seule fois. Réponse **A**."}]},{"key":"exam2","title_nl":"Proefexamen 2 — MAC & Ondernemen met Informatie (geïntegreerd)","title_en":"Mock Exam 2 — MAC & Doing Business with Information (integrated)","title_fr":"Examen blanc 2 — MAC & Entreprendre avec l'information (intégré)","duration_min":60,"questions":[{"id":"t2_q1","subject":"mac","type":"numeric","points":2,"text_nl":"Een bestelwagen van A = €100.000 wordt afgeschreven met een vast percentage van de boekwaarde: p = 20% per jaar. Bereken de afschrijving in jaar 2 en de boekwaarde na 3 jaar.","text_en":"A van of A = €100,000 is depreciated at a fixed percentage of book value: p = 20% per year. Calculate the depreciation in year 2 and the book value after 3 years.","text_fr":"Une camionnette de A = 100 000 € est amortie à un pourcentage fixe de la valeur comptable: p = 20 % par an. Calculez l'amortissement de l'année 2 et la valeur comptable après 3 ans.","inputs":[{"label_nl":"Afschrijving jaar 2 (€)","label_en":"Depreciation year 2 (€)","label_fr":"Amortissement année 2 (€)","answer":16000},{"label_nl":"Boekwaarde na 3 jaar (€)","label_en":"Book value after 3 years (€)","label_fr":"Valeur comptable après 3 ans (€)","answer":51200}],"sol_nl":"Jaar 1: 20% × 100.000 = 20.000 → BW = 80.000. Jaar 2: 20% × 80.000 = **€16.000** → BW = 64.000. Jaar 3: 20% × 64.000 = 12.800 → BW = 100.000 × 0,8³ = **€51.200**. Kenmerk: dalende afschrijvingsbedragen.","sol_en":"Year 1: 20% × 100,000 = 20,000 → BV = 80,000. Year 2: 20% × 80,000 = **€16,000** → BV = 64,000. Year 3: 20% × 64,000 = 12,800 → BV = 100,000 × 0.8³ = **€51,200**. Note: declining depreciation amounts.","sol_fr":"Année 1: 20 % × 100 000 = 20 000 → VC = 80 000. Année 2: 20 % × 80 000 = **16 000 €** → VC = 64 000. Année 3: 20 % × 64 000 = 12 800 → VC = 100 000 × 0,8³ = **51 200 €**. Caractéristique: amortissements décroissants."},{"id":"t2_q2","subject":"mac","type":"numeric","points":2,"text_nl":"Een machine: A = €50.000, R = €5.000, n = 4 jaar. Afschrijving volgens de cijfersommethode (sum-of-the-years'-digits). Bereken de afschrijving in jaar 1 en in jaar 3.","text_en":"A machine: A = €50,000, R = €5,000, n = 4 years. Depreciation by the sum-of-the-years'-digits method. Calculate the depreciation in year 1 and in year 3.","text_fr":"Une machine: A = 50 000 €, R = 5 000 €, n = 4 ans. Amortissement selon la méthode de la somme des chiffres des années. Calculez l'amortissement de l'année 1 et de l'année 3.","inputs":[{"label_nl":"Afschrijving jaar 1 (€)","label_en":"Depreciation year 1 (€)","label_fr":"Amortissement année 1 (€)","answer":18000},{"label_nl":"Afschrijving jaar 3 (€)","label_en":"Depreciation year 3 (€)","label_fr":"Amortissement année 3 (€)","answer":9000}],"sol_nl":"Cijfersom = 1+2+3+4 = 10. Af te schrijven bedrag = A − R = 45.000. Jaar 1: 4/10 × 45.000 = **€18.000**. Jaar 2: 3/10 × 45.000 = 13.500. Jaar 3: 2/10 × 45.000 = **€9.000**. Jaar 4: 1/10 × 45.000 = 4.500.","sol_en":"Sum of digits = 1+2+3+4 = 10. Depreciable base = A − R = 45,000. Year 1: 4/10 × 45,000 = **€18,000**. Year 2: 3/10 × 45,000 = 13,500. Year 3: 2/10 × 45,000 = **€9,000**. Year 4: 4,500.","sol_fr":"Somme des chiffres = 1+2+3+4 = 10. Base amortissable = A − R = 45 000. Année 1: 4/10 × 45 000 = **18 000 €**. Année 2: 13 500. Année 3: 2/10 × 45 000 = **9 000 €**. Année 4: 4 500."},{"id":"t2_q3","subject":"mac","type":"numeric","points":2,"text_nl":"Metaalbedrijf Ferro past Activity Based Costing toe met twee kostenpools: machinekosten €200.000 met als cost driver machine-uren (8.000 uren) en instelkosten €60.000 met als cost driver setups (400 setups). Een order vraagt 120 machine-uren en 5 setups. Bereken het tarief per machine-uur, het tarief per setup en de toegerekende indirecte kosten van de order.","text_en":"Metal company Ferro applies Activity Based Costing with two cost pools: machine costs €200,000 with cost driver machine hours (8,000 hours) and setup costs €60,000 with cost driver setups (400 setups). An order requires 120 machine hours and 5 setups. Calculate the rate per machine hour, the rate per setup and the indirect costs allocated to the order.","text_fr":"L'entreprise Ferro applique l'Activity Based Costing avec deux pools de coûts: coûts machines 200 000 € (inducteur: heures machine, 8 000 heures) et coûts de réglage 60 000 € (inducteur: setups, 400 setups). Une commande demande 120 heures machine et 5 setups. Calculez le taux par heure machine, le taux par setup et les coûts indirects imputés à la commande.","inputs":[{"label_nl":"Tarief per machine-uur (€)","label_en":"Rate per machine hour (€)","label_fr":"Taux par heure machine (€)","answer":25},{"label_nl":"Tarief per setup (€)","label_en":"Rate per setup (€)","label_fr":"Taux par setup (€)","answer":150},{"label_nl":"Indirecte kosten order (€)","label_en":"Indirect costs of order (€)","label_fr":"Coûts indirects de la commande (€)","answer":3750}],"sol_nl":"Tarief machine-uren = 200.000/8.000 = **€25/uur**. Tarief setups = 60.000/400 = **€150/setup**. Order: 120 × 25 + 5 × 150 = 3.000 + 750 = **€3.750**. ABC rekent indirecte kosten toe via activiteiten en cost drivers, fijner dan de primitieve opslagmethode.","sol_en":"Machine-hour rate = 200,000/8,000 = **€25/hour**. Setup rate = 60,000/400 = **€150/setup**. Order: 120 × 25 + 5 × 150 = 3,000 + 750 = **€3,750**. ABC allocates indirect costs via activities and cost drivers, more refined than a simple overhead percentage.","sol_fr":"Taux heure machine = 200 000/8 000 = **25 €/h**. Taux setup = 60 000/400 = **150 €/setup**. Commande: 120 × 25 + 5 × 150 = 3 000 + 750 = **3 750 €**. L'ABC impute les coûts indirects via les activités et les inducteurs, plus fin que la méthode du taux global."},{"id":"t2_q4","subject":"mac","type":"numeric","points":2,"text_nl":"Webshop 'Vela' verkoopt fietstassen aan p = €50, variabele kosten v = €15 per stuk, constante kosten C = €140.000 per jaar. Het ERP-systeem toont elke week op een dashboard de cumulatieve verkoop tegenover het break-evenpunt, zodat de zaakvoerster kan bijsturen. Bereken het break-evenpunt in stuks en de break-evenomzet. (De informatiekant van deze case komt terug in vraag 7.)","text_en":"Webshop 'Vela' sells bike bags at p = €50, variable cost v = €15 per unit, fixed costs C = €140,000 per year. The ERP system shows a weekly dashboard with cumulative sales against the break-even point, so the owner can adjust. Calculate the break-even point in units and the break-even revenue. (The information side of this case returns in question 7.)","text_fr":"La boutique en ligne « Vela » vend des sacoches à p = 50 €, coût variable v = 15 €, coûts fixes C = 140 000 € par an. L'ERP affiche chaque semaine un tableau de bord avec les ventes cumulées face au seuil de rentabilité, pour que la gérante puisse ajuster. Calculez le seuil de rentabilité en unités et le chiffre d'affaires au seuil. (Le volet information de ce cas revient à la question 7.)","inputs":[{"label_nl":"BEP (stuks)","label_en":"BEP (units)","label_fr":"Seuil (unités)","answer":4000},{"label_nl":"Break-evenomzet (€)","label_en":"Break-even revenue (€)","label_fr":"CA au seuil (€)","answer":200000}],"sol_nl":"DB per stuk = p − v = 50 − 15 = €35. BEP = C/(p − v) = 140.000/35 = **4.000 stuks**. BEP-omzet = 4.000 × 50 = **€200.000**. Het dashboard dat de werkelijke verkoop met dit BEP vergelijkt, levert stuurinformatie (zie vraag 7).","sol_en":"Contribution margin = p − v = 50 − 15 = €35. BEP = C/(p − v) = 140,000/35 = **4,000 units**. Break-even revenue = 4,000 × 50 = **€200,000**. The dashboard comparing actual sales with this BEP provides steering information (see question 7).","sol_fr":"Marge unitaire = p − v = 50 − 15 = 35 €. Seuil = C/(p − v) = 140 000/35 = **4 000 unités**. CA au seuil = 4 000 × 50 = **200 000 €**. Le tableau de bord qui compare les ventes réelles à ce seuil fournit de l'information de pilotage (voir question 7)."},{"id":"t2_q5","subject":"mac","type":"mcq","points":1.5,"correct":1,"text_nl":"Primitieve opslagmethode: directe kosten in totaal €200.000, indirecte kosten €50.000. Een product heeft €800 directe kosten. Wat is de kostprijs?","text_en":"Simple overhead-percentage method: total direct costs €200,000, indirect costs €50,000. A product has €800 of direct costs. What is its cost price?","text_fr":"Méthode du taux global: coûts directs totaux 200 000 €, coûts indirects 50 000 €. Un produit a 800 € de coûts directs. Quel est son coût de revient ?","options_nl":["€850","€1.000","€1.040","€800, indirecte kosten tellen niet mee"],"options_en":["€850","€1,000","€1,040","€800, indirect costs are excluded"],"options_fr":["850 €","1 000 €","1 040 €","800 €, les coûts indirects ne comptent pas"],"inputs":[],"sol_nl":"Opslagpercentage = indirecte/directe kosten = 50.000/200.000 = 25%. Kostprijs = 800 + 25% × 800 = 800 + 200 = **€1.000**. Antwoord **B**.","sol_en":"Overhead rate = indirect/direct = 50,000/200,000 = 25%. Cost price = 800 + 25% × 800 = 800 + 200 = **€1,000**. Answer **B**.","sol_fr":"Taux = indirects/directs = 50 000/200 000 = 25 %. Coût de revient = 800 + 25 % × 800 = 800 + 200 = **1 000 €**. Réponse **B**."},{"id":"t2_q6","subject":"mac","type":"mcq","points":1.5,"correct":1,"text_nl":"De begroting voorzag 10.000 stuks; er werden er 11.000 geproduceerd. Om de werkelijke kosten zinvol te beoordelen vergelijkt de controller ze met een begroting herrekend naar 11.000 stuks. Hoe heet die herrekende begroting?","text_en":"The budget assumed 10,000 units; 11,000 were produced. To assess actual costs meaningfully, the controller compares them with a budget recalculated for 11,000 units. What is that recalculated budget called?","text_fr":"Le budget prévoyait 10 000 unités; 11 000 ont été produites. Pour évaluer correctement les coûts réels, le contrôleur les compare à un budget recalculé pour 11 000 unités. Comment s'appelle ce budget recalculé ?","options_nl":["De ex-ante begroting","De ex-post begroting (flexibele begroting)","De balanced scorecard","Het bezettingsresultaat"],"options_en":["The ex-ante budget","The ex-post budget (flexible budget)","The balanced scorecard","The capacity result"],"options_fr":["Le budget ex-ante","Le budget ex-post (budget flexible)","Le balanced scorecard","Le résultat d'occupation"],"inputs":[],"sol_nl":"Een begroting herrekend naar het werkelijke activiteitsniveau heet de **ex-post begroting**. Werkelijke kosten − ex-post begroting = het zuivere **kostenverschil** (efficiëntie/prijs), gezuiverd van het volume-effect. Antwoord **B**.","sol_en":"A budget recalculated to the actual activity level is the **ex-post (flexible) budget**. Actual costs − ex-post budget = the pure **cost variance**, cleaned of the volume effect. Answer **B**.","sol_fr":"Un budget recalculé au niveau d'activité réel est le **budget ex-post (flexible)**. Coûts réels − budget ex-post = l'**écart de coûts** pur, débarrassé de l'effet volume. Réponse **B**."},{"id":"t2_q7","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Zelfde case als vraag 4: het dashboard van Vela toont wekelijks de cumulatieve verkoop (werkelijke waarde) naast het break-evenpunt van 4.000 stuks dat als doel dient. In OmI-termen: de verkochte aantallen zijn een..., het break-evenpunt is een..., en het rapport is...","text_en":"Same case as question 4: Vela's dashboard shows weekly cumulative sales (actual value) next to the break-even point of 4,000 units, used as a target. In information-management terms: the units sold are a..., the break-even point is a..., and the report is...","text_fr":"Même cas que la question 4: le tableau de bord de Vela affiche chaque semaine les ventes cumulées (valeur réelle) à côté du seuil de 4 000 unités qui sert d'objectif. En termes de gestion de l'information: les ventes sont un..., le seuil est un..., et le rapport est...","options_nl":["streefgetal / kengetal / operationele informatie","kengetal / streefgetal / stuurinformatie","kengetal / streefgetal / verantwoordingsinformatie aan de overheid","streefgetal / streefgetal / strategische informatie"],"options_en":["target value / indicator / operational information","indicator / target value / steering information","indicator / target value / accountability information for the government","target / target / strategic information"],"options_fr":["valeur cible / indicateur / information opérationnelle","indicateur / valeur cible / information de pilotage","indicateur / valeur cible / information de justification pour l'État","cible / cible / information stratégique"],"inputs":[],"sol_nl":"De gemeten werkelijke waarde (verkochte stuks) is het **kengetal**; de norm waaraan getoetst wordt (BEP = 4.000) is het **streefgetal**; informatie die toelaat bij te sturen is **stuurinformatie** in de regelkring. Antwoord **B**.","sol_en":"The measured actual value (units sold) is the **indicator**; the norm it is tested against (BEP = 4,000) is the **target value**; information used to adjust course is **steering information** in the control loop. Answer **B**.","sol_fr":"La valeur réelle mesurée (unités vendues) est l'**indicateur**; la norme de référence (seuil = 4 000) est la **valeur cible**; l'information servant à ajuster est de l'**information de pilotage**. Réponse **B**."},{"id":"t2_q8","subject":"omi","type":"mcq","points":1.5,"correct":2,"text_nl":"Welk van de volgende is GEEN perspectief van de Balanced Scorecard?","text_en":"Which of the following is NOT a perspective of the Balanced Scorecard?","text_fr":"Lequel des éléments suivants n'est PAS une perspective du Balanced Scorecard ?","options_nl":["Financieel perspectief","Klantenperspectief","Concurrentieperspectief","Leer- en groeiperspectief"],"options_en":["Financial perspective","Customer perspective","Competitor perspective","Learning and growth perspective"],"options_fr":["Perspective financière","Perspective client","Perspective concurrence","Perspective apprentissage et croissance"],"inputs":[],"sol_nl":"De vier perspectieven van de Balanced Scorecard zijn: **financieel**, **klanten**, **interne processen** en **leren & groeien**. Een concurrentieperspectief bestaat niet. Antwoord **C**.","sol_en":"The four Balanced Scorecard perspectives are: **financial**, **customer**, **internal processes** and **learning & growth**. There is no competitor perspective. Answer **C**.","sol_fr":"Les quatre perspectives du Balanced Scorecard: **financière**, **client**, **processus internes** et **apprentissage & croissance**. Pas de perspective concurrence. Réponse **C**."},{"id":"t2_q9","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Een retailer analyseert enorme stromen kassagegevens, sensorgegevens en sociale media. De gegevens komen snel binnen, in vele formaten, en de kwaliteit is niet altijd betrouwbaar. Welke drie V's van big data worden hier letterlijk beschreven?","text_en":"A retailer analyses huge streams of till data, sensor data and social media. The data arrives fast, in many formats, and its quality is not always reliable. Which three V's of big data are literally described here?","text_fr":"Un détaillant analyse d'énormes flux de données de caisse, de capteurs et de réseaux sociaux. Les données arrivent vite, sous de nombreux formats, et leur qualité n'est pas toujours fiable. Quels trois V du big data sont décrits ici littéralement ?","options_nl":["Volume, velocity, variety","Velocity, variety, veracity","Volume, value, veracity","Variety, value, volume"],"options_en":["Volume, velocity, variety","Velocity, variety, veracity","Volume, value, veracity","Variety, value, volume"],"options_fr":["Volume, vélocité, variété","Vélocité, variété, véracité","Volume, valeur, véracité","Variété, valeur, volume"],"inputs":[],"sol_nl":"'Komen snel binnen' = **velocity**, 'vele formaten' = **variety**, 'kwaliteit niet altijd betrouwbaar' = **veracity**. (De 5 V's: volume, velocity, variety, veracity, value — volume staat er ook, maar de drie letterlijk beschreven kenmerken zijn snelheid, formaat en betrouwbaarheid.) Antwoord **B**.","sol_en":"'Arrives fast' = **velocity**, 'many formats' = **variety**, 'quality not always reliable' = **veracity**. (The 5 V's: volume, velocity, variety, veracity, value — the three literally described traits are speed, format and reliability.) Answer **B**.","sol_fr":"« Arrivent vite » = **vélocité**, « nombreux formats » = **variété**, « qualité pas toujours fiable » = **véracité**. (Les 5 V: volume, vélocité, variété, véracité, valeur.) Réponse **B**."},{"id":"t2_q10","subject":"omi","type":"mcq","points":1.5,"correct":0,"text_nl":"Supermarktketen Delfra stuurt haar bestellingen automatisch en gestructureerd van computer naar computer naar de leverancier, zonder menselijke tussenkomst. De voorraadstanden worden echter maar één keer per nacht in bulk bijgewerkt. Welke combinatie beschrijft dit?","text_en":"Supermarket chain Delfra sends its purchase orders automatically and in a structured format from computer to computer to the supplier, without human intervention. Stock levels, however, are updated in bulk only once a night. Which combination describes this?","text_fr":"La chaîne Delfra envoie ses commandes automatiquement et de façon structurée d'ordinateur à ordinateur vers le fournisseur, sans intervention humaine. Les stocks, eux, ne sont mis à jour en masse qu'une fois par nuit. Quelle combinaison décrit cela ?","options_nl":["EDI voor de bestellingen; batchverwerking voor de voorraad","E-mail voor de bestellingen; real-time verwerking voor de voorraad","EDI voor de bestellingen; real-time verwerking voor de voorraad","Groupware voor de bestellingen; batchverwerking voor de voorraad"],"options_en":["EDI for the orders; batch processing for the stock","E-mail for the orders; real-time processing for the stock","EDI for the orders; real-time processing for the stock","Groupware for the orders; batch processing for the stock"],"options_fr":["EDI pour les commandes; traitement par lots pour les stocks","E-mail pour les commandes; traitement en temps réel pour les stocks","EDI pour les commandes; traitement en temps réel pour les stocks","Groupware pour les commandes; traitement par lots pour les stocks"],"inputs":[],"sol_nl":"Gestructureerde, geautomatiseerde uitwisseling van handelsdocumenten tussen computers = **EDI**. Eén keer per nacht in bulk verwerken = **batchverwerking** (tegenover real-time, waarbij elke wijziging onmiddellijk wordt verwerkt). Antwoord **A**.","sol_en":"Structured, automated exchange of trade documents between computers = **EDI**. Processing once a night in bulk = **batch processing** (versus real-time, where each change is processed immediately). Answer **A**.","sol_fr":"Échange structuré et automatisé de documents commerciaux entre ordinateurs = **EDI**. Traitement en masse une fois par nuit = **traitement par lots** (par opposition au temps réel). Réponse **A**."},{"id":"t2_q11","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"Bij het ontwerp van de Vela-database geldt: één klant kan meerdere bestellingen plaatsen, maar elke bestelling hoort bij precies één klant. Welk relatietype is dit, en hoe los je het op in het ontwerp?","text_en":"When designing the Vela database: one customer can place several orders, but each order belongs to exactly one customer. What relationship type is this, and how is it handled in the design?","text_fr":"Dans la base de données Vela: un client peut passer plusieurs commandes, mais chaque commande appartient à exactement un client. Quel est ce type de relation, et comment le traiter dans la conception ?","options_nl":["1-1-relatie; beide tabellen samenvoegen","1-n-relatie; de sleutel van de klant als verwijzend veld opnemen in de bestellingstabel","n-m-relatie; een tussentabel aanmaken","Geen relatie; klantgegevens in elke bestelling kopiëren"],"options_en":["1-to-1; merge both tables","1-to-n; include the customer's key as a referencing field in the orders table","n-to-m; create a junction table","No relationship; copy customer data into each order"],"options_fr":["Relation 1-1; fusionner les deux tables","Relation 1-n; placer la clé du client comme champ de référence dans la table des commandes","Relation n-m; créer une table intermédiaire","Pas de relation; copier les données client dans chaque commande"],"inputs":[],"sol_nl":"Eén klant ↔ veel bestellingen = een **1-n-relatie**. Oplossing: het sleutelveld (bv. klantnummer) van de '1'-kant opnemen als verwijzend veld in de tabel aan de 'n'-kant. Een tussentabel is enkel nodig bij n-m; gegevens kopiëren zou redundantie creëren. Antwoord **B**.","sol_en":"One customer ↔ many orders = a **1-to-n relationship**. Solution: include the key (e.g. customer number) of the '1' side as a referencing field in the table on the 'n' side. A junction table is only needed for n-to-m; copying data would create redundancy. Answer **B**.","sol_fr":"Un client ↔ plusieurs commandes = une **relation 1-n**. Solution: placer la clé (n° de client) du côté « 1 » comme champ de référence dans la table du côté « n ». La table intermédiaire ne sert que pour n-m; copier les données créerait de la redondance. Réponse **B**."},{"id":"t2_q12","subject":"omi","type":"mcq","points":1.5,"correct":1,"text_nl":"In het besturingsmodel (regelkring) rapporteert de afdeling Verkoop maandelijks aan de directie wat ze gerealiseerd heeft tegenover de opgelegde normen. De directie stuurt op basis daarvan nieuwe richtlijnen terug. Hoe heten de twee informatiestromen?","text_en":"In the control model (control loop), the Sales department reports monthly to management what it achieved against the imposed norms. Based on this, management sends new directives back. What are the two information flows called?","text_fr":"Dans le modèle de pilotage (boucle de régulation), le service Ventes rapporte chaque mois à la direction ce qu'il a réalisé par rapport aux normes imposées. Sur cette base, la direction renvoie de nouvelles directives. Comment s'appellent ces deux flux d'information ?","options_nl":["Omhoog: stuurinformatie; omlaag: verantwoordingsinformatie","Omhoog: verantwoordingsinformatie; omlaag: stuurinformatie","Beide zijn operationele informatie","Omhoog: streefgetallen; omlaag: kengetallen"],"options_en":["Upwards: steering information; downwards: accountability information","Upwards: accountability information; downwards: steering information","Both are operational information","Upwards: targets; downwards: indicators"],"options_fr":["Vers le haut: information de pilotage; vers le bas: information de justification","Vers le haut: information de justification; vers le bas: information de pilotage","Les deux sont de l'information opérationnelle","Vers le haut: valeurs cibles; vers le bas: indicateurs"],"inputs":[],"sol_nl":"In de regelkring rapporteert het uitvoerende orgaan **omhoog** over zijn prestaties = **verantwoordingsinformatie**; het besturende orgaan stuurt **omlaag** normen en richtlijnen = **stuurinformatie**. Antwoord **B**.","sol_en":"In the control loop the executing unit reports **upwards** on its performance = **accountability information**; the governing unit sends norms and directives **downwards** = **steering information**. Answer **B**.","sol_fr":"Dans la boucle de régulation, l'unité exécutante rapporte **vers le haut** sur ses performances = **information de justification**; l'organe de direction envoie **vers le bas** normes et directives = **information de pilotage**. Réponse **B**."}]}]);

// ═══════════════════════════════════════════════════════════════════
// Attempt tracking, dashboard home, dark mode, flashcards, exam timer
// ═══════════════════════════════════════════════════════════════════
let attempts = JSON.parse(localStorage.getItem('esther_attempts')||'[]');

function recordAttempt(exId, ok){
 attempts.push({id:exId, ok:!!ok, ts:Date.now()});
 if(attempts.length>3000) attempts = attempts.slice(-3000);
 localStorage.setItem('esther_attempts', JSON.stringify(attempts));
 gameOnAttempt(exId, !!ok);
 if(typeof logEvent==='function') logEvent('answer', { ref: exId, ok: !!ok });
 if(typeof schedulePush==='function') schedulePush();
}

// ═══════════════════════════════════════════════════════════════════
// Gamification engine — XP, levels, badges, daily goal, SRS, fun feedback
// ═══════════════════════════════════════════════════════════════════
let XP = +(localStorage.getItem('esther_xp')||0);
let xpIds = new Set(JSON.parse(localStorage.getItem('esther_xp_ids')||'[]'));
let badges = new Set(JSON.parse(localStorage.getItem('esther_badges')||'[]'));
let srs = JSON.parse(localStorage.getItem('esther_srs')||'{}');
let muted = localStorage.getItem('esther_mute')==='1';
const DAILY_GOAL = 10;

function saveGame(){ try{
 localStorage.setItem('esther_xp', String(XP));
 localStorage.setItem('esther_xp_ids', JSON.stringify([...xpIds]));
 localStorage.setItem('esther_badges', JSON.stringify([...badges]));
 localStorage.setItem('esther_srs', JSON.stringify(srs));
}catch(e){} }

const LEVELS = [0,100,250,450,700,1000,1400,1900,2500,3200,4000,5000,6200,7600,9200,11000];
function lvlTitle(l){
 const fr=['Débutante','Apprentie','Élève appliquée','Étudiante','Stratège','Experte','As de la matière','Maître','Légende','Génie absolu'];
 const en=['Beginner','Apprentice','Diligent','Student','Strategist','Expert','Subject ace','Master','Legend','Absolute genius'];
 const nl=['Beginner','Leerling','IJverig','Student','Strateeg','Expert','Vakheld','Meester','Legende','Absoluut genie'];
 const arr=lang==='fr'?fr:lang==='en'?en:nl; return arr[Math.min(l-1,arr.length-1)];
}
function levelInfo(xp){
 let l=1; for(let i=0;i<LEVELS.length;i++){ if(xp>=LEVELS[i]) l=i+1; }
 const cur=LEVELS[l-1]||0; const next=LEVELS[l]!==undefined?LEVELS[l]:cur;
 const span=Math.max(1,next-cur); const into=xp-cur;
 return {level:l, title:lvlTitle(l), cur, next, into, span, pct:next>cur?Math.min(100,Math.round(into/span*100)):100, max:l>=LEVELS.length};
}

// ── Sound (WebAudio) ──
let _ac=null;
function chime(type){
 if(muted) return;
 try{ _ac=_ac||new (window.AudioContext||window.webkitAudioContext)();
 const seq = type==='level'?[523,659,784,1047]:type==='win'?[659,784,1047]:type==='badge'?[784,1047,1319]:[880];
 seq.forEach((f,i)=>{ const o=_ac.createOscillator(),g=_ac.createGain(); o.type='sine'; o.frequency.value=f;
 const t=_ac.currentTime+i*0.09; g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.18,t+0.02); g.gain.exponentialRampToValueAtTime(0.0001,t+0.16);
 o.connect(g); g.connect(_ac.destination); o.start(t); o.stop(t+0.18); });
 }catch(e){}
}
function toggleMute(){ muted=!muted; localStorage.setItem('esther_mute', muted?'1':'0'); const b=document.getElementById('muteBtn'); if(b) b.textContent=muted?'🔇':'🔊'; }

// ── Confetti ──
function confetti(power){
 const cv=document.getElementById('confettiCanvas'); if(!cv) return;
 cv.style.display='block'; cv.width=innerWidth; cv.height=innerHeight;
 const ctx=cv.getContext('2d'); const cols=['#f59e0b','#fb923c','#D4537E','#60AEDF','#0d9488','#10b981','#a855f7'];
 const N=power||120; const ps=[];
 for(let i=0;i<N;i++) ps.push({x:innerWidth/2+(Math.random()-0.5)*200,y:innerHeight/3,vx:(Math.random()-0.5)*9,vy:Math.random()*-9-3,g:0.22+Math.random()*0.1,s:5+Math.random()*6,c:cols[i%cols.length],r:Math.random()*6,vr:(Math.random()-0.5)*0.4,life:0});
 let frames=0;
 (function anim(){ ctx.clearRect(0,0,cv.width,cv.height); frames++;
 ps.forEach(p=>{ p.vy+=p.g; p.x+=p.vx; p.y+=p.vy; p.r+=p.vr; ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.r); ctx.fillStyle=p.c; ctx.fillRect(-p.s/2,-p.s/2,p.s,p.s*0.6); ctx.restore(); });
 if(frames<130) requestAnimationFrame(anim); else cv.style.display='none';
 })();
}

// ── Toasts ──
function showToast(icon, title, sub, dur){
 const w=document.getElementById('toastWrap'); if(!w) return;
 const el=document.createElement('div'); el.className='toast';
 el.innerHTML=`<span class="tic">${icon}</span><div><div class="tt">${title}</div>${sub?`<div class="ts">${sub}</div>`:''}</div>`;
 w.appendChild(el);
 setTimeout(()=>{ el.style.transition='opacity.4s,transform.4s'; el.style.opacity='0'; el.style.transform='translateY(-10px)'; setTimeout(()=>el.remove(),400); }, dur||3200);
}

