function gameCtx(){
 const totalCorrect = xpIds.size;
 const today = dayKey(Date.now());
 const todayCount = attempts.filter(a=>dayKey(a.ts)===today).length;
 // any unit/chapter at 100%
 let anyUnit100=false, macDone=true;
 try{ const d=getExercises(); ['w1','w2','w3','w4','w5','w6'].forEach(wk=>{ const ids=(d[wk].exercises||[]).map(e=>e.id); const ok=ids.filter(id=>correctSet.has(id)).length; if(ids.length&&ok===ids.length) anyUnit100=true; if(ids.length&&ok<ids.length) macDone=false; });
 OMI_CHAPTERS.forEach(ch=>{ const ids=ch.exercises.map(e=>e.id); const ok=ids.filter(id=>omiCorrectSet.has(id)).length; if(ids.length&&ok===ids.length) anyUnit100=true; });
 PM_UNITS.forEach(u=>{ const ids=u.exercises.map(e=>e.id); const ok=ids.filter(id=>pmCorrectSet.has(id)).length; if(ids.length&&ok===ids.length) anyUnit100=true; });
 }catch(e){ macDone=false; }
 return {totalCorrect, streak:calcStreak(), todayCount, level:levelInfo(XP).level, examBestPct:_examBestPct, anyUnit100, macDone};
}
function checkBadges(){
 const ctx=gameCtx(); let newly=[];
 BADGES.forEach(b=>{ if(!badges.has(b.key) && b.test(ctx)){ badges.add(b.key); newly.push(b); } });
 if(newly.length){ saveGame(); newly.forEach((b,i)=>setTimeout(()=>{ showToast(b.ic, (lang==='fr'?'Badge débloqué !':lang==='en'?'Badge unlocked!':'Badge ontgrendeld!'), b[lang]); chime('badge'); confetti(90); }, i*700)); }
}

let _dailyCelebrated = localStorage.getItem('esther_dailycelebrated')||'';
function gameOnAttempt(exId, ok){
 // SRS (Leitner)
 const box = ok ? Math.min(5,(srs[exId]&&srs[exId].box||0)+1): 1;
 srs[exId] = {box, last:Date.now()};
 const before = levelInfo(XP).level;
 if(ok && !xpIds.has(exId)){ XP += 10; xpIds.add(exId); }
 saveGame();
 refreshXpChip();
 if(ok) chime('correct');
 const after = levelInfo(XP).level;
 if(after>before){ setTimeout(()=>{ showToast('⭐', (lang==='fr'?'Niveau '+after+' !':lang==='en'?'Level '+after+'!':'Niveau '+after+'!'), lvlTitle(after)); chime('level'); confetti(160); }, 300); }
 // daily goal
 const today=dayKey(Date.now());
 const todayCount=attempts.filter(a=>dayKey(a.ts)===today).length;
 if(todayCount>=DAILY_GOAL && _dailyCelebrated!==today){ _dailyCelebrated=today; localStorage.setItem('esther_dailycelebrated',today); setTimeout(()=>{ showToast('🎯',(lang==='fr'?'Objectif du jour atteint !':lang==='en'?'Daily goal reached!':'Dagdoel gehaald!'),DAILY_GOAL+(lang==='fr'?' exercices 💪':lang==='en'?' exercises 💪':' oefeningen 💪')); chime('win'); confetti(120); },400); }
 checkBadges();
 if(currentSubject==='home'){ /* refresh handled by callers */ }
}

function startReview(){
 const due=dueReviewIds();
 if(!due.length) return;
 goToExercise(due[0].id);
 showToast('🔁', (lang==='fr'?'Révision':lang==='en'?'Review':'Herhaling'), (lang==='fr'?due.length+' exercices à revoir':lang==='en'?due.length+' to review':due.length+' te herhalen'), 2600);
}
function refreshXpChip(){
 const li=levelInfo(XP);
 const l=document.getElementById('xpChipLvl'), x=document.getElementById('xpChipXp');
 if(l) l.textContent=li.level; if(x) x.textContent=XP+' XP';
}

// SRS due items for current exam (failed soon, or correct-but-old by box)
function dueReviewIds(){
 const isPm=currentExam===2;
 const boxDays=[0,0,1,3,7,16]; // days until due per box (box1 soonest)
 const now=Date.now(); const out=[];
 for(const id in srs){ if(id.startsWith('lvl_')) continue;
 const pm=/^u\d+_/.test(id); if(pm!==isPm) continue;
 const done = isPm?pmCorrectSet.has(id):(correctSet.has(id)||omiCorrectSet.has(id));
 const s=srs[id]; const dueAfter=(boxDays[s.box]||16)*86400000;
 if(!done) out.push({id,ts:s.last,why:'failed'});
 else if(now - s.last >= dueAfter) out.push({id,ts:s.last,why:'due'});
 }
 out.sort((a,b)=>a.ts-b.ts);
 return out;
}

function dayKey(ts){ const d=new Date(ts); return d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate(); }

function calcStreak(){
 const days = new Set(attempts.map(a=>dayKey(a.ts)));
 let streak = 0;
 const now = new Date();
 for(let i=0;;i++){
 const d = new Date(now.getFullYear(), now.getMonth(), now.getDate()-i);
 if(days.has(dayKey(d.getTime()))) streak++;
 else if(i===0) continue; // today not yet studied doesn't break streak
 else break;
 }
 return streak;
}

