function calcStreakFrom(list){
 const days = new Set(list.map(a=>dayKey(a.ts)));
 let streak = 0; const now = new Date();
 for(let i=0;;i++){ const d=new Date(now.getFullYear(),now.getMonth(),now.getDate()-i);
 if(days.has(dayKey(d.getTime()))) streak++; else if(i===0) continue; else break; }
 return streak;
}
function pmMasteryData(){
 return PM_UNITS.map((u,i)=>{ const ids=u.exercises.map(e=>e.id); const ok=ids.filter(id=>pmCorrectSet.has(id)).length;
 return {key:'pm', idx:i, label:'U'+(i+1), n:ids.length, ok}; });
}
function weakSpots(scope){
 // scope: 'mac' (exam 1) or 'pm' (exam 2)
 const isPm = scope==='pm';
 const last = {};
 attempts.forEach(a=>{ if(a.id.startsWith('lvl_')) return; const pm=/^u\d+_/.test(a.id); if(pm===isPm) last[a.id]=a; });
 const weekAgo = Date.now()-7*86400000;
 const out=[];
 for(const [id,a] of Object.entries(last)){
 const done = isPm ? pmCorrectSet.has(id): (correctSet.has(id)||omiCorrectSet.has(id));
 if(!a.ok && !done) out.push({id,why:'failed',ts:a.ts});
 else if(a.ok && a.ts<weekAgo) out.push({id,why:'stale',ts:a.ts});
 }
 out.sort((x,y)=>x.ts-y.ts);
 return out.slice(0,8);
}
function goToExercise(id){
 if(/^u\d+_/.test(id)){
 const u = parseInt(id.match(/^u(\d+)/)[1],10)-1;
 switchSubject('pm'); switchPmTab(u);
 setTimeout(()=>{ const c=document.getElementById('pmCard_'+id); if(c){c.scrollIntoView({behavior:'smooth',block:'center'});} },100);
 } else if(id.startsWith('ex')){
 const w = parseInt(id.match(/^ex(\d+)/)[1],10)-1;
 switchSubject('mac'); switchTab(w);
 setTimeout(()=>{ const c=document.getElementById('card_'+id); if(c){c.scrollIntoView({behavior:'smooth',block:'center'});} },100);
 } else if(id.startsWith('h')){
 const h = parseInt(id.match(/^h(\d+)/)[1],10)-1;
 switchSubject('omi'); switchOmiTab(h);
 setTimeout(()=>{ const c=document.getElementById('omiCard_'+id); if(c){c.scrollIntoView({behavior:'smooth',block:'center'});} },100);
 }
}
function exTitleOf(id){
 if(/^u\d+_/.test(id)){
 for(const u of PM_UNITS){ const e=u.exercises.find(e=>e.id===id); if(e){ const t=lang==='fr'?e.text_fr:lang==='en'?e.text_en:e.text_nl; return (t||'').replace(/<[^>]+>/g,'').substring(0,70)+'…'; } }
 } else if(id.startsWith('ex')){
 const data = getExercises();
 for(const w of Object.values(data)){ const e=(w.exercises||[]).find(e=>e.id===id); if(e) return e.title||id; }
 } else {
 for(const ch of OMI_CHAPTERS){ const e=ch.exercises.find(e=>e.id===id); if(e){ const t = lang==='fr'?e.text_fr:lang==='en'?e.text_en:e.text_nl; return (t||'').replace(/<[^>]+>/g,'').substring(0,70)+'…'; } }
 }
 return id;
}

